            'permission_callback' => [ $this->config, 'check_permission' ],
        ]);
        register_rest_route('gcrev_insights/v1', '/strategy-report/status', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_strategy_report_status' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
            'args'                => [
