        register_rest_route('gcrev/v1', '/dashboard/score', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_calc_dashboard_score' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
            'args'                => [
                'curr' => [ 'required' => true ],
                'prev' => [ 'required' => true ],
            ]
        ]);

