            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_get_annual_report' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
            'args'                => [
                'year' => [
                    'required'          => true,
                    'validate_callback' => function( $param ) {
