        register_rest_route('gcrev/v1', '/analysis/page', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_get_page_analysis' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
            'args'                => [
                'period' => [
                    'required'          => false,
                    'default'           => 'last30',
