            'permission_callback' => [ $this->config, 'check_permission' ],
        ]);
        register_rest_route('gcrev/v1', '/survey/ai-generation/status', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_survey_ai_generation_status' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
        ]);
        register_rest_route('gcrev/v1', '/survey/analytics', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_survey_analytics' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
        ]);
        register_rest_route('gcrev/v1', '/survey/analysis', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_survey_analysis' ],
            'permission_callback' => [ $this->config, 'check_permission' ],
        ]);
        register_rest_route('gcrev/v1', '/survey/colors', [
            [
                'methods'             => 'GET',
                'callback'            => [ $this, 'rest_survey_colors_get' ],
                'permission_callback' => [ $this->config, 'check_permission' ],
            ],
            [
                'methods'             => 'POST',
                'callback'            => [ $this, 'rest_survey_colors_save' ],
                'permission_callback' => [ $this->config, 'check_permission' ],
            ],
        ]);

        // =========================================================
        // QA Prompt Registry 管理ダッシュボード用（Phase 3）
        // 全て manage_options 権限必須
        // =========================================================
        $qa_admin_permission = static function () {
            return current_user_can( 'manage_options' );
        };

        register_rest_route( 'gcrev/v1', '/qa-registry', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_qa_registry_get' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/history', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_qa_registry_history' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/promote', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_qa_registry_promote' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/rollback', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_qa_registry_rollback' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/reject', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_qa_registry_reject' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/runs', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_qa_registry_runs' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/compare', [
            'methods'             => 'GET',
            'callback'            => [ $this, 'rest_qa_registry_compare' ],
            'permission_callback' => $qa_admin_permission,
        ] );

        // Phase 4: Staged Rollout
        register_rest_route( 'gcrev/v1', '/qa-registry/stage', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_qa_registry_stage' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/unstage', [
            'methods'             => 'POST',
            'callback'            => [ $this, 'rest_qa_registry_unstage' ],
            'permission_callback' => $qa_admin_permission,
        ] );
        register_rest_route( 'gcrev/v1', '/qa-registry/canary', [
            [
                'methods'             => 'GET',
                'callback'            => [ $this, 'rest_qa_registry_canary_get' ],
                'permission_callback' => $qa_admin_permission,
            ],
            [
                'methods'             => 'POST',
                'callback'            => [ $this, 'rest_qa_registry_canary_set' ],
                'permission_callback' => $qa_admin_permission,
            ],
        ] );
    }

    // =========================================================
    // キャッシュ
    // =========================================================
    /**
     * 海外アクセス除外設定の判定
     */
    private function is_exclude_foreign( int $user_id ): bool {
        return get_user_meta( $user_id, 'report_exclude_foreign', true ) === '1';
    }

    /**
     * 海外アクセス除外が有効ならGA4国フィルタを設定し、状態を返す。
     * 呼び出し後は必ず restore_country_filter() で元に戻すこと。
     *
     * 再入可能: 外側の呼び出しで既にフィルタが設定済みの場合は false を返し、
     * restore_country_filter(false) で解除されないようにする。
     */
    /** @var bool パスフィルタ（include/exclude）が設定されているか */
    private bool $path_filters_set = false;

    private function maybe_set_country_filter( int $user_id ): bool {
        if ( $this->ga4->has_country_filter() ) {
            return false; // 外側で既に設定済み — 内側では解除しない
        }

        $was_set = false;
        if ( $this->is_exclude_foreign( $user_id ) ) {
            $this->ga4->set_country_filter( 'Japan' );
            $was_set = true;
        }

        // 解析対象URL条件 + 解析除外URL条件を適用（GA4 + GSC 両方に伝播）
        if ( ! $this->path_filters_set ) {
            $include_paths = get_user_meta( $user_id, '_gcrev_include_paths', true );
            $exclude_paths = get_user_meta( $user_id, '_gcrev_exclude_paths', true );

            if ( is_array( $include_paths ) && ! empty( $include_paths ) ) {
                $this->ga4->set_include_paths_filter( $include_paths );
                $this->path_filters_set = true;
            }
            if ( is_array( $exclude_paths ) && ! empty( $exclude_paths ) ) {
                $this->ga4->set_exclude_paths_filter( $exclude_paths );
                $this->path_filters_set = true;
            }

            // GSC 側にも同じフィルタを伝播（page+query で取得した行を path で絞り込み再集計）
            if ( $this->path_filters_set ) {
                $this->gsc->set_include_paths_filter( is_array( $include_paths ) ? $include_paths : [] );
                $this->gsc->set_exclude_paths_filter( is_array( $exclude_paths ) ? $exclude_paths : [] );
            }
        }

        return $was_set;
    }

    /**
     * 国フィルタ + パスフィルタを解除する（maybe_set_country_filter の対）
     */
    private function restore_country_filter( bool $was_set ): void {
        if ( $was_set ) {
            $this->ga4->set_country_filter( null );
        }
        if ( $this->path_filters_set ) {
            $this->ga4->clear_include_paths_filter();
            $this->ga4->set_page_path_filter( null );
            $this->gsc->clear_path_filters();
            $this->path_filters_set = false;
        }
    }

    private function cache_key_dashboard(int $user_id, string $range): string {
        $suffix = $this->ga4->has_country_filter() ? '_jp' : '';
        // パスフィルタ設定がある場合はキャッシュキーを差別化
        if ( $this->path_filters_set ) {
            $suffix .= '_ex';
        }
        return "gcrev_dash_{$user_id}_{$range}{$suffix}";
    }

    private function dashboard_cache_get(int $user_id, string $range): ?array {
        $key = $this->cache_key_dashboard($user_id, $range);
        $cached = get_transient($key);
        if ($cached === false || $cached === null) return null;
        return is_array($cached) ? $cached : null;
    }

    /**
     * TTL切れの transient を直接DBから取得する（フォールバック用）
     *
     * get_transient() は TTL 切れで false を返すが、
     * wp_options テーブルにはデータが残っている場合がある。
     * APIエラー時に古いデータを表示するために使用する。
     */
    private function get_stale_dashboard_cache( int $user_id, string $range ): ?array {
        // まず通常のキャッシュを確認
        $cached = $this->dashboard_cache_get( $user_id, $range );
        if ( $cached ) {
            return $cached;
        }

        // TTL切れの transient を直接DBから取得
        global $wpdb;
        $key = $this->cache_key_dashboard( $user_id, $range );
        $option_name = '_transient_' . $key;
        $value = $wpdb->get_var( $wpdb->prepare(
            "SELECT option_value FROM {$wpdb->options} WHERE option_name = %s LIMIT 1",
            $option_name
        ) );

        if ( $value === null ) {
            return null;
        }

        $data = maybe_unserialize( $value );
        return is_array( $data ) ? $data : null;
    }

    /**
     * 任意の transient を「fresh → stale」の順で取得する。
     *
     * - 通常の get_transient() がヒットすればそれを返す
     * - TTL 切れだが option_value が wp_options に残っていれば maybe_unserialize して返す
     * - option ごと削除されている場合は false を返す
     *
     * page-dashboard.php の `gcrev_dash_bydate_*` / `gcrev_meo_perf_*` 等、
     * dashboard_cache_get の対象外キーで stale-while-revalidate するために使用する。
     */
    public function get_transient_with_stale( string $key ) {
        $fresh = get_transient( $key );
        if ( $fresh !== false ) {
            return $fresh;
        }

        global $wpdb;
        $value = $wpdb->get_var( $wpdb->prepare(
            "SELECT option_value FROM {$wpdb->options} WHERE option_name = %s LIMIT 1",
            '_transient_' . $key
        ) );
        if ( $value === null ) {
            return false;
        }
        return maybe_unserialize( $value );
    }

    private function dashboard_cache_set(int $user_id, string $range, array $data): void {
        $key = $this->cache_key_dashboard($user_id, $range);
        // 月固定期間（prev-month / prev-prev-month / last180 / last365）: 35日
        // 日次期間(last90): 48h（重い）
        // 日次期間(last30 等): 24h
        if ( Gcrev_Date_Helper::is_monthly_fixed_period( $range ) ) {
            $ttl = 3024000;  // 35日
        } elseif ( $range === 'last90' ) {
            $ttl = 172800;   // 48h
        } else {
            $ttl = $this->dashboard_cache_ttl;  // 24h
        }
        set_transient($key, $data, $ttl);
    }

    /**
     * Effective CVトランジェントキャッシュを一括クリア
     * functions.php の gcrev_invalidate_user_cv_cache() に依存しない独立クリア
     */
    private function invalidate_effective_cv_transients(int $user_id): void {
        global $wpdb;
        $like         = $wpdb->esc_like("_transient_gcrev_effcv_{$user_id}_") . '%';
        $like_timeout = $wpdb->esc_like("_transient_timeout_gcrev_effcv_{$user_id}_") . '%';
        $wpdb->query($wpdb->prepare(
            "DELETE FROM {$wpdb->options} WHERE option_name LIKE %s OR option_name LIKE %s",
            $like, $like_timeout
        ));
        // インスタンスキャッシュもクリア
        $this->effective_cv_cache = [];
    }

    /**
     * レポートキャッシュキーの生成
     * period / site / user を含む
     */
    private function build_report_cache_key(int $user_id, array $client_info, array $prev_data, array $two_data): string {
        $site_hash = md5((string)($client_info['site_url'] ?? ''));
        $prev_period = $prev_data['current_period']['display'] ?? ($prev_data['current_period'] ?? 'unknown');
        $two_period  = $two_data['current_period']['display']  ?? ($two_data['current_period']  ?? 'unknown');
        
        // 出力モードをキャッシュキーに含める
        $output_mode = $client_info['output_mode'] ?? 'normal';

        $payload = wp_json_encode([
            'client_info' => $client_info,
            'prev_period' => $prev_period,
            'two_period'  => $two_period,
            'output_mode' => $output_mode,  // モードを追加
        ], JSON_UNESCAPED_UNICODE);

        return "gcrev_report_{$user_id}_{$output_mode}_{$site_hash}_" . md5($payload);
    }

    /**
     * 管理者専用：全キャッシュ削除
     */
    /**
     * 全 gcrev_ transient プレフィックス一覧（一元管理）
     */
    public static function get_all_cache_prefixes(): array {
        return [
            'gcrev_dash_',
            'gcrev_report_',
            'gcrev_effcv_',
            'gcrev_phone_tap_',
            'gcrev_ga4cv_',
            'gcrev_ga4kevt_daily_',
            'gcrev_ga4_kevt_list_',
            'gcrev_source_',
            'gcrev_region_',
            'gcrev_region_trend_',
            'gcrev_page_',
            'gcrev_keywords_',
            'gcrev_meo_',
            'gcrev_cv_analysis_',
            'gcrev_trend_',
            'gcrev_beginner_rw_',
            'gcrev_title_',
        ];
    }

    // =========================================================
    // プリフェッチステータス記録
    // =========================================================

    /**
     * プリフェッチステータスを記録する（UPSERT）
     *
     * @param int         $user_id   ユーザーID
     * @param string      $period    期間キー（last30, prev-month 等）
     * @param string      $data_type データ種別（all, dashboard, source, region, page, keywords）
     * @param string      $status    ステータス（success, error, skip）
     * @param string|null $error     エラーメッセージ
     * @param string      $source    ソース（cron, manual）
     */
    public function record_prefetch_status( int $user_id, string $period, string $data_type, string $status, ?string $error = null, string $source = 'cron', string $batch_type = 'daily' ): void {
        global $wpdb;
        $table = $wpdb->prefix . 'gcrev_prefetch_status';
        $wpdb->replace( $table, [
            'user_id'       => $user_id,
            'period'        => $period,
            'data_type'     => $data_type,
            'status'        => $status,
            'fetched_at'    => current_time( 'mysql', false ),
            'error_message' => $error,
            'source'        => $source,
            'batch_type'    => $batch_type,
        ], [ '%d', '%s', '%s', '%s', '%s', '%s', '%s', '%s' ] );
    }

    /**
     * プリフェッチステータスを取得する
     *
     * @param int|null $user_id  指定時はそのユーザーのみ、null で全ユーザー
     * @return array
     */
    public function get_prefetch_statuses( ?int $user_id = null ): array {
        global $wpdb;
        $table = $wpdb->prefix . 'gcrev_prefetch_status';
        if ( $user_id !== null ) {
            return $wpdb->get_results( $wpdb->prepare(
                "SELECT * FROM {$table} WHERE user_id = %d ORDER BY period, data_type",
                $user_id
            ) ) ?: [];
        }
        return $wpdb->get_results(
            "SELECT * FROM {$table} ORDER BY user_id, period, data_type"
        ) ?: [];
    }

    /**
     * 特定ユーザー × 特定期間のデータを手動取得する
     *
     * @param int    $user_id ユーザーID
     * @param string $period  期間キー（last30, last90, previousMonth 等）
     * @return array  ['status' => string, 'error' => ?string]
     */
    public function manual_fetch_for_user( int $user_id, string $period ): array {
        try {
            $config = $this->config->get_user_config( $user_id );
        } catch ( \Exception $e ) {
            $this->record_prefetch_status( $user_id, $period, 'all', 'error', $e->getMessage(), 'manual', 'manual' );
            return [ 'status' => 'error', 'error' => $e->getMessage() ];
        }

        // 国フィルタ + パスフィルタ適用（REST エンドポイントと同じ関数を使用）
        $filter_set      = $this->maybe_set_country_filter( $user_id );
        $exclude_foreign = $this->is_exclude_foreign( $user_id );

        $had_error = false;
        $error_msg = '';

        try {
            // ダッシュボードキャッシュ
            $dash_range = $period;
            // period-selector 値をダッシュボード range 値に変換
            if ( $period === 'prev-month' )      $dash_range = 'previousMonth';
            if ( $period === 'prev-prev-month' ) $dash_range = 'twoMonthsAgo';

            // 既存キャッシュを削除して強制再取得
            $cache_key = $this->cache_key_dashboard( $user_id, $dash_range );
            delete_transient( $cache_key );

            $data = $this->fetch_dashboard_data_internal( $config, $dash_range );
            $this->dashboard_cache_set( $user_id, $dash_range, $data );

            // 分析ページキャッシュ
            $this->prefetch_analysis_caches( $user_id, $config, $period );

            // MEOパフォーマンスキャッシュ（ダッシュボードKPI用）
            $meo_dates = $this->dates->calculate_period_dates( $period );
            $this->fetch_meo_metrics_safe( $user_id, $meo_dates['start'], $meo_dates['end'], $period );

        } catch ( \Exception $e ) {
            $had_error = true;
            $error_msg = $e->getMessage();
        }

        $this->restore_country_filter( $filter_set );

        $status = $had_error ? 'error' : 'success';
        $this->record_prefetch_status( $user_id, $period, 'all', $status, $had_error ? $error_msg : null, 'manual', 'manual' );

        return [ 'status' => $status, 'error' => $had_error ? $error_msg : null ];
    }

    /**
     * REST: 全ユーザーのキャッシュ削除（管理者限定）
     */
    public function clear_all_cache(WP_REST_Request $request): WP_REST_Response {
        global $wpdb;
        $deleted = 0;

        foreach (self::get_all_cache_prefixes() as $prefix) {
            $deleted += (int)$wpdb->query(
                $wpdb->prepare(
                    "DELETE FROM {$wpdb->options} WHERE option_name LIKE %s OR option_name LIKE %s",
                    $wpdb->esc_like('_transient_' . $prefix) . '%',
                    $wpdb->esc_like('_transient_timeout_' . $prefix) . '%'
                )
            );
        }

        error_log("[GCREV] Cache cleared (ALL): {$deleted} transients deleted");

        return new WP_REST_Response([
            'success' => true,
            'deleted' => $deleted,
            'message' => "{$deleted}件のキャッシュを削除しました",
        ], 200);
    }

    /**
     * REST: 自分のキャッシュのみ削除（ログインユーザー用）
     */
    public function clear_my_cache(WP_REST_Request $request): WP_REST_Response {
        global $wpdb;

        $user_id = get_current_user_id();
        if (!$user_id) {
            return new WP_REST_Response(['error' => 'ログインが必要です'], 401);
        }

        $deleted = 0;

        // user_id を含むプレフィックスでフィルタ
        foreach (self::get_all_cache_prefixes() as $prefix) {
            $user_prefix = $prefix . $user_id . '_';
            $deleted += (int)$wpdb->query(
                $wpdb->prepare(
                    "DELETE FROM {$wpdb->options} WHERE option_name LIKE %s OR option_name LIKE %s",
                    $wpdb->esc_like('_transient_' . $user_prefix) . '%',
                    $wpdb->esc_like('_transient_timeout_' . $user_prefix) . '%'
                )
            );
        }

        error_log("[GCREV] Cache cleared (user={$user_id}): {$deleted} transients deleted");

        return new WP_REST_Response([
            'success' => true,
            'deleted' => $deleted,
            'message' => "{$deleted}件のキャッシュを削除しました",
        ], 200);
    }

    // =========================================================
    // REST: /dashboard
    // =========================================================
    public function get_dashboard_data(WP_REST_Request $request): WP_REST_Response {

        $user_id = get_current_user_id();
        $range   = (string)($request->get_param('range') ?: 'last30');

        // 海外アクセス除外フィルタ
        $filter_set = $this->maybe_set_country_filter( $user_id );

        try {
            $cached = $this->dashboard_cache_get($user_id, $range);
            if ($cached) {

                // キャッシュに流入元データがない場合は追加してキャッシュ更新
                if (!isset($cached['channels_summary'])) {
                    try {
                        $config = $this->config->get_user_config($user_id);
                        $dates = $this->dates->get_date_range($range);
                        $comparison = $this->dates->get_comparison_range($dates['start'], $dates['end']);

                        $source_current = $this->ga4->fetch_source_data_from_ga4($config['ga4_id'], $dates['start'], $dates['end']);
                        $source_previous = $this->ga4->fetch_source_data_from_ga4($config['ga4_id'], $comparison['start'], $comparison['end']);
                        $source_analysis = $this->format_source_analysis_data($source_current, $source_previous);

                        $cached['channels_summary'] = $source_analysis['channels_summary'] ?? [];
                        $cached['sources_detail'] = $source_analysis['sources_detail'] ?? [];
                        $cached['channels_daily_series'] = $source_analysis['channels_daily_series'] ?? [];

                        // キャッシュに書き戻す（次回以降GA4 API不要）
                        $this->dashboard_cache_set($user_id, $range, $cached);
                    } catch (\Exception $e) {
                        error_log("[GCREV] ERROR adding source data to cache: " . $e->getMessage());
                        $cached['channels_summary'] = [];
                        $cached['sources_detail'] = [];
                        $cached['channels_daily_series'] = [];
                    }
                }

                return new WP_REST_Response([
                    'success' => true,
                    'data'    => $cached,
                    'cached'  => true,
                ], 200);
            }

            $config = $this->config->get_user_config($user_id);

            $data   = $this->fetch_dashboard_data_internal($config, $range);

            $this->dashboard_cache_set($user_id, $range, $data);

            return new WP_REST_Response([
                'success' => true,
                'data'    => $data,
                'cached'  => false,
            ], 200);

        } catch (\Google\Service\Exception $e) {
            // Google API 固有のエラー — stale データがあればそれを返す
            $status  = $e->getCode() ?: 500;
            $errors  = $e->getErrors();
            $reason  = ! empty( $errors[0]['reason'] ) ? $errors[0]['reason'] : 'unknown';
            $domain  = ! empty( $errors[0]['domain'] ) ? $errors[0]['domain'] : 'unknown';
            file_put_contents( '/tmp/gcrev_dash_debug.log',
                date( 'Y-m-d H:i:s' ) . sprintf(
                    " [REST /dashboard] Google API ERROR — user=%d, range=%s, HTTP %d, reason=%s, message=%s\n",
                    $user_id, $range, $status, $reason, mb_substr( $e->getMessage(), 0, 300 )
                ), FILE_APPEND
            );

            // stale データのフォールバック: TTL切れでも get_transient は値を返す場合がある（WP内部キャッシュ）
            // 直接DBからTTL無視で取得する
            $stale_data = $this->get_stale_dashboard_cache( $user_id, $range );
            if ( $stale_data ) {
                return new WP_REST_Response([
                    'success' => true,
                    'data'    => $stale_data,
                    'cached'  => true,
                    'stale'   => true,
                    'message' => '最新データの取得に失敗したため、前回のデータを表示しています。',
                ], 200);
            }

            if ( current_user_can( 'manage_options' ) ) {
                $front_msg = sprintf( 'Google API エラー (HTTP %d / %s): %s', $status, $reason, mb_substr( $e->getMessage(), 0, 200 ) );
            } else {
                $front_msg = 'データの取得に失敗しました。しばらくしてからお試しください。';
            }
            return new WP_REST_Response([
                'success' => false,
                'message' => $front_msg,
            ], 500);

        } catch (\Exception $e) {
            file_put_contents( '/tmp/gcrev_dash_debug.log',
                date( 'Y-m-d H:i:s' ) . sprintf(
                    " [REST /dashboard] ERROR — user=%d, range=%s, class=%s, message=%s\n",
                    $user_id, $range, get_class( $e ), mb_substr( $e->getMessage(), 0, 300 )
                ), FILE_APPEND
            );

            // stale データのフォールバック
            $stale_data = $this->get_stale_dashboard_cache( $user_id, $range );
            if ( $stale_data ) {
                return new WP_REST_Response([
                    'success' => true,
                    'data'    => $stale_data,
                    'cached'  => true,
                    'stale'   => true,
                    'message' => '最新データの取得に失敗したため、前回のデータを表示しています。',
                ], 200);
            }

            if ( current_user_can( 'manage_options' ) ) {
                $front_msg = 'エラー: ' . mb_substr( $e->getMessage(), 0, 200 );
            } else {
                $front_msg = 'データの取得に失敗しました。しばらくしてからお試しください。';
            }
            return new WP_REST_Response([
                'success' => false,
                'message' => $front_msg,
            ], 500);
        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    // =========================================================
    // REST: /kpi
    // =========================================================
    public function get_kpi_data(WP_REST_Request $request): WP_REST_Response {

        $user_id = get_current_user_id();

        // 海外アクセス除外フィルタ
        $filter_set = $this->maybe_set_country_filter( $user_id );

        try {
            $config = $this->config->get_user_config($user_id);
            $dates  = $this->dates->get_kpi_dates();

            $trends = $this->ga4->fetch_kpi_trends($config, $dates);

            return new WP_REST_Response([
                'success' => true,
                'data'    => $trends,
            ], 200);

        } catch (\Exception $e) {
            error_log("[GCREV] REST /kpi ERROR (user_id={$user_id}): " . $e->getMessage());
            return new WP_REST_Response([
                'success' => false,
                'message' => $e->getMessage(),
            ], 500);
        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    // =========================================================
    // 単一ユーザーのダッシュボード初回表示用キャッシュ温め
    //
    // 用途: ログイン直後 / ダッシュボードキャッシュミス時の背景プリフェッチ。
    // page-dashboard.php の同期読み出しに必要な最小キャッシュだけを温める：
    //   - gcrev_dash_{user_id}_last30{_jp?_ex?}             （主要KPI）
    //   - gcrev_dash_bydate_{user_id}_last30_comp{_filtered?_pf?} （比較期間、period ベース安定キー）
    //   - gcrev_meo_perf_{user_id}_last30 / _last30_comp    （MEO 当期 + 前期、period ベース安定キー）
    //   - 上記 KPI に _cached_score をマージ
    // =========================================================
    public function prefetch_user_dashboard( int $user_id ): void {
        $log = '/tmp/gcrev_dash_warm_debug.log';
        $start_ts = microtime( true );

        try {
            $config = $this->config->get_user_config( $user_id );
        } catch ( \Throwable $e ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " warm SKIP user_id={$user_id}: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return;
        }

        // 海外除外 + 解析対象/除外URL条件 を GA4 + GSC へ反映
        $filter_set      = $this->maybe_set_country_filter( $user_id );
        $exclude_foreign = $this->is_exclude_foreign( $user_id );

        try {
            $last30      = $this->dates->get_date_range( 'last30' );
            $last30_comp = $this->dates->get_comparison_range( $last30['start'], $last30['end'] );

            // (1) last30 ダッシュボード KPI
            if ( ! $this->dashboard_cache_get( $user_id, 'last30' ) ) {
                $data = $this->fetch_dashboard_data_internal( $config, 'last30' );
                $this->dashboard_cache_set( $user_id, 'last30', $data );
            }

            // (2) 比較期間 (gcrev_dash_bydate_{uid}_last30_comp{filter})
            // cache_scope='last30_comp' 指定で、日付スライドしてもキーは固定
            $filter_suffix_pf = $exclude_foreign ? '_filtered' : '';
            if ( class_exists( 'Gcrev_Path_Filter' ) ) {
                $filter_suffix_pf .= Gcrev_Path_Filter::cache_suffix( $user_id );
            }
            $comp_cache_key = "gcrev_dash_bydate_{$user_id}_last30_comp{$filter_suffix_pf}";
            $comp_data      = get_transient( $comp_cache_key );
            if ( ! $comp_data ) {
                $comp_data = $this->get_dashboard_kpi_by_dates( $last30_comp['start'], $last30_comp['end'], $user_id, 'last30_comp' );
            }

            // (3) MEO 当期 + 前期（period ベース安定キー）
            try {
                $this->fetch_meo_metrics_safe( $user_id, $last30['start'], $last30['end'], 'last30' );
                $this->fetch_meo_metrics_safe( $user_id, $last30_comp['start'], $last30_comp['end'], 'last30_comp' );
            } catch ( \Throwable $e ) {
                // MEO 失敗は致命ではない（未連携ユーザー等）
            }

            // (4) スコア事前計算 → KPI キャッシュへマージ
            $kpi_filter_suffix = $exclude_foreign ? '_jp' : '';
            if ( $this->path_filters_set ) { $kpi_filter_suffix .= '_ex'; }
            $kpi_cache_key = "gcrev_dash_{$user_id}_last30{$kpi_filter_suffix}";
            $kpi_cached    = get_transient( $kpi_cache_key );

            if ( $kpi_cached && is_array( $kpi_cached ) && ! isset( $kpi_cached['_cached_score'] )
                 && is_array( $comp_data ) && ! empty( $comp_data ) ) {

                $sess_c = (int) str_replace( ',', '', (string) ( $kpi_cached['sessions']    ?? '0' ) );
                $sess_p = (int) str_replace( ',', '', (string) ( $comp_data['sessions']    ?? '0' ) );
                $cv_c   = (int) str_replace( ',', '', (string) ( $kpi_cached['conversions'] ?? '0' ) );
                $cv_p   = (int) str_replace( ',', '', (string) ( $comp_data['conversions'] ?? '0' ) );
                $gsc_c  = (int) str_replace( ',', '', (string) ( $kpi_cached['gsc']['total']['clicks'] ?? $kpi_cached['gsc']['total']['impressions'] ?? '0' ) );
                $gsc_p  = (int) str_replace( ',', '', (string) ( $comp_data['gsc']['total']['clicks']  ?? $comp_data['gsc']['total']['impressions']  ?? '0' ) );

                $meo_c_cache = get_transient( "gcrev_meo_perf_{$user_id}_last30" );
                $meo_p_cache = get_transient( "gcrev_meo_perf_{$user_id}_last30_comp" );
                $meo_c = ( is_array( $meo_c_cache ) ) ? (int) ( $meo_c_cache['total_impressions'] ?? 0 ) : 0;
                $meo_p = ( is_array( $meo_p_cache ) ) ? (int) ( $meo_p_cache['total_impressions'] ?? 0 ) : 0;

                $score_curr = [ 'traffic' => $sess_c, 'cv' => $cv_c, 'gsc' => $gsc_c, 'meo' => $meo_c ];
                $score_prev = [ 'traffic' => $sess_p, 'cv' => $cv_p, 'gsc' => $gsc_p, 'meo' => $meo_p ];
                $health     = $this->calc_monthly_health_score( $score_curr, $score_prev, [], $user_id );

                $kpi_cached['_cached_score'] = [
                    'score'      => $health['score'],
                    'status'     => $health['status'],
                    'breakdown'  => $health['breakdown'],
                    'components' => $health['components'],
                ];
                set_transient( $kpi_cache_key, $kpi_cached, self::DASHBOARD_CACHE_TTL );
            }

            $elapsed = round( microtime( true ) - $start_ts, 1 );
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " warm OK user_id={$user_id} elapsed={$elapsed}s\n",
                FILE_APPEND
            );

        } catch ( \Throwable $e ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " warm ERROR user_id={$user_id}: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    // =========================================================
    // Prefetch処理（Cronから呼ばれる）
    // =========================================================
    public function prefetch_chunk(int $offset, int $limit): void {

        // ─── 重複実行防止ロック（最初のチャンクのみ設定） ───
        if ( $offset === 0 ) {
            if ( ! $this->acquire_lock( self::LOCK_PREFETCH ) ) {
                $this->prefetch_log( '[PREFETCH] LOCKED — skipping duplicate run' );
                if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                    $locked_id = Gcrev_Cron_Logger::start( 'prefetch', [ 'note' => 'locked' ] );
                    Gcrev_Cron_Logger::finish( $locked_id, 'locked' );
                }
                return;
            }
            // Cron Logger: ジョブ開始
            if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                $log_id = Gcrev_Cron_Logger::start( 'prefetch', [ 'chunk_limit' => $limit ] );
                set_transient( 'gcrev_current_prefetch_log_id', $log_id, self::LOCK_TTL );
            }
            $this->prefetch_log( '[PREFETCH] ===== DAILY PREFETCH START =====' );
        } else {
            // 後続チャンク: heartbeat 更新
            $this->heartbeat_lock( self::LOCK_PREFETCH );
        }

        // Cron Logger: log_id を取得
        $log_id = class_exists( 'Gcrev_Cron_Logger' ) ? (int) get_transient( 'gcrev_current_prefetch_log_id' ) : 0;

        $this->prefetch_log( "[PREFETCH] chunk START: offset={$offset}, limit={$limit}" );

        $users = get_users([
            'number' => $limit,
            'offset' => $offset,
            'fields' => ['ID'],
        ]);

        if (empty($users)) {
            $this->prefetch_log( "[PREFETCH] No users found (offset={$offset}). DONE." );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( 'gcrev_current_prefetch_log_id' );
            }
            return;
        }

        // 日次プリフェッチ: 全期間を毎日取得
        $ranges = ['last30', 'last90', 'previousMonth', 'twoMonthsAgo', 'last180', 'last365'];
        $chunk_start = microtime( true );
        $chunk_success = 0;
        $chunk_fail    = 0;
        $chunk_skip    = 0;

        foreach ($users as $u) {
            $user_id = (int)$u->ID;
            $user_start = microtime( true );
            $this->prefetch_log( "[PREFETCH] START user_id={$user_id} ranges=" . implode( ',', $ranges ) );
            $user_had_error = false;

            try {
                $config = $this->config->get_user_config($user_id);
            } catch (\Exception $e) {
                $this->prefetch_log( "[PREFETCH] SKIP user_id={$user_id}: " . $e->getMessage() );
                $chunk_skip++;
                if ( $log_id > 0 ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', $e->getMessage() );
                }
                continue;
            }

            // 国フィルタ + パスフィルタ適用（REST エンドポイントと同じ関数を使用）
            $filter_set = $this->maybe_set_country_filter( $user_id );
            $exclude_foreign = $this->is_exclude_foreign( $user_id );

            // 期間別のエラー記録用
            $period_errors = [];

            // --- (1) ダッシュボード／デバイスキャッシュ ---
            foreach ($ranges as $range) {
                $cached = $this->dashboard_cache_get($user_id, $range);
                if ($cached) {
                    $this->prefetch_log( "[PREFETCH] SKIP user_id={$user_id} period={$range} reason=cache_hit" );
                    continue;
                }

                try {
                    $range_start = microtime( true );
                    $data = $this->fetch_dashboard_data_internal($config, $range);
                    $this->dashboard_cache_set($user_id, $range, $data);
                    $elapsed = round( microtime( true ) - $range_start, 1 );
                    $this->prefetch_log( "[PREFETCH] OK user_id={$user_id} period={$range} elapsed={$elapsed}s" );
                    // 期間単位で成功を記録
                    $this->record_prefetch_status( $user_id, $range, 'all', 'success', null, 'cron' );
                } catch (\Exception $e) {
                    $error_msg = mb_substr( $e->getMessage(), 0, 500 );
                    $this->prefetch_log( "[PREFETCH] FAIL user_id={$user_id} period={$range} error=" . $error_msg );
                    $user_had_error = true;
                    $period_errors[ $range ] = $error_msg;
                    // 期間単位で失敗を記録（エラーメッセージ付き）
                    $this->record_prefetch_status( $user_id, $range, 'all', 'error', $error_msg, 'cron' );
                }

                usleep(self::PREFETCH_SLEEP_US);
            }

            // --- (2) 各分析ページキャッシュ ---
            // 日次プリフェッチ: 全期間の分析キャッシュを事前取得
            $analysis_periods = ['last30', 'last90', 'prev-month', 'prev-prev-month', 'last180', 'last365'];

            foreach ($analysis_periods as $period) {
                $this->prefetch_analysis_caches($user_id, $config, $period);
            }

            // --- (3) KPIトレンド（過去12ヶ月推移）キャッシュ ---
            $trend_filter_sfx = $this->ga4->has_country_filter() ? '_jp' : '';
            if ( $this->path_filters_set ) { $trend_filter_sfx .= '_ex'; }
            foreach (['sessions', 'cv', 'meo'] as $trend_metric) {
                $trend_cache_key = "gcrev_trend_{$user_id}_{$trend_metric}_" . date('Y-m') . $trend_filter_sfx;
                if (get_transient($trend_cache_key) !== false) {
                    continue;
                }
                try {
                    $this->get_monthly_metric_trend($user_id, $trend_metric, 12);
                } catch (\Exception $e) {
                    $this->prefetch_log( "[PREFETCH] FAIL trend user_id={$user_id} metric={$trend_metric} error=" . $e->getMessage() );
                    $user_had_error = true;
                }
                usleep(self::PREFETCH_SLEEP_US);
            }

            // --- (3b) 日次トレンド（ダッシュボードグラフ用）---
            $today_str = date('Y-m-d');
            foreach ( ['sessions', 'cv', 'meo'] as $daily_metric ) {
                $daily_trend_key = "gcrev_trend_daily_{$user_id}_{$daily_metric}_{$today_str}{$trend_filter_sfx}";
                if ( get_transient( $daily_trend_key ) !== false ) {
                    continue;
                }
                try {
                    $this->get_daily_metric_trend( $user_id, $daily_metric, 30 );
                } catch ( \Exception $e ) {
                    // 日次トレンドの失敗はユーザーエラーにカウントしない（補助データ）
                }
                usleep( self::PREFETCH_SLEEP_US );
            }

            // --- (3c) MEOパフォーマンス（ダッシュボードKPI用）---
            // last30 の current / comparison 期間の MEO perf を事前取得（period ベース安定キー）
            try {
                $meo_last30      = $this->dates->get_date_range('last30');
                $meo_last30_comp = $this->dates->get_comparison_range($meo_last30['start'], $meo_last30['end']);
                $this->fetch_meo_metrics_safe($user_id, $meo_last30['start'], $meo_last30['end'], 'last30');
                usleep(self::PREFETCH_SLEEP_US);
                $this->fetch_meo_metrics_safe($user_id, $meo_last30_comp['start'], $meo_last30_comp['end'], 'last30_comp');
                $this->prefetch_log("[PREFETCH] MEO perf OK user_id={$user_id}");
            } catch (\Exception $e) {
                $this->prefetch_log("[PREFETCH] MEO perf FAIL user_id={$user_id}: " . $e->getMessage());
            }
            usleep(self::PREFETCH_SLEEP_US);

            // --- (4) 比較期間キャッシュ + スコア事前計算 ---
            // ダッシュボード表示時にPHPキャッシュヒットで即表示するために
            // last30 の比較期間（その前の30日間）も事前取得し、スコアも計算・保存する
            try {
                $last30_dates = $this->dates->get_date_range('last30');
                $last30_comp  = $this->dates->get_comparison_range($last30_dates['start'], $last30_dates['end']);
                $filter_suffix_pf = $exclude_foreign ? '_filtered' : '';
                if ( class_exists( 'Gcrev_Path_Filter' ) ) {
                    $filter_suffix_pf .= Gcrev_Path_Filter::cache_suffix( $user_id );
                }
                // 比較期間は period ベースの安定キー
                $comp_cache_key   = "gcrev_dash_bydate_{$user_id}_last30_comp{$filter_suffix_pf}";
                $comp_cached      = get_transient( $comp_cache_key );

                if ( ! $comp_cached ) {
                    $comp_data = $this->get_dashboard_kpi_by_dates( $last30_comp['start'], $last30_comp['end'], $user_id, 'last30_comp' );
                    $this->prefetch_log("[PREFETCH] comparison SUCCESS user_id={$user_id}");
                } else {
                    $comp_data = $comp_cached;
                    $this->prefetch_log("[PREFETCH] comparison SKIP user_id={$user_id}: already cached");
                }

                // スコア事前計算・KPI transient に保存
                $kpi_filter_suffix = $exclude_foreign ? '_jp' : '';
                $kpi_cache_key = "gcrev_dash_{$user_id}_last30{$kpi_filter_suffix}";
                $kpi_cached    = get_transient( $kpi_cache_key );
                if ( $kpi_cached && is_array( $kpi_cached ) && ! isset( $kpi_cached['_cached_score'] ) ) {
                    $sess_c  = (int) str_replace( ',', '', (string)( $kpi_cached['sessions'] ?? '0' ) );
                    $sess_p  = (int) str_replace( ',', '', (string)( $comp_data['sessions'] ?? '0' ) );
                    $cv_c    = (int) str_replace( ',', '', (string)( $kpi_cached['conversions'] ?? '0' ) );
                    $cv_p    = (int) str_replace( ',', '', (string)( $comp_data['conversions'] ?? '0' ) );
                    $gsc_c   = (int) str_replace( ',', '', (string)( $kpi_cached['gsc']['total']['clicks'] ?? $kpi_cached['gsc']['total']['impressions'] ?? '0' ) );
                    $gsc_p   = (int) str_replace( ',', '', (string)( $comp_data['gsc']['total']['clicks'] ?? $comp_data['gsc']['total']['impressions'] ?? '0' ) );

                    // MEO（period ベース安定キー）
                    $meo_cache_c = get_transient( "gcrev_meo_perf_{$user_id}_last30" );
                    $meo_cache_p = get_transient( "gcrev_meo_perf_{$user_id}_last30_comp" );
                    $meo_c = ( $meo_cache_c !== false && is_array( $meo_cache_c ) ) ? (int)( $meo_cache_c['total_impressions'] ?? 0 ) : 0;
                    $meo_p = ( $meo_cache_p !== false && is_array( $meo_cache_p ) ) ? (int)( $meo_cache_p['total_impressions'] ?? 0 ) : 0;

                    $score_curr = [ 'traffic' => $sess_c, 'cv' => $cv_c, 'gsc' => $gsc_c, 'meo' => $meo_c ];
                    $score_prev = [ 'traffic' => $sess_p, 'cv' => $cv_p, 'gsc' => $gsc_p, 'meo' => $meo_p ];
                    $health = $this->calc_monthly_health_score( $score_curr, $score_prev, [], $user_id );

                    $kpi_cached['_cached_score'] = [
                        'score'      => $health['score'],
                        'status'     => $health['status'],
                        'breakdown'  => $health['breakdown'],
                        'components' => $health['components'],
                    ];
                    set_transient( $kpi_cache_key, $kpi_cached, self::DASHBOARD_CACHE_TTL );
                    $this->prefetch_log("[PREFETCH] score SUCCESS user_id={$user_id}, score={$health['score']}");
                }
            } catch ( \Exception $e ) {
                $this->prefetch_log( "[PREFETCH] FAIL comparison/score user_id={$user_id} error=" . $e->getMessage() );
                $user_had_error = true;
            }
            usleep( self::PREFETCH_SLEEP_US );

            // 国フィルタ + パスフィルタ解除（REST エンドポイントと同じ関数を使用）
            $this->restore_country_filter( $filter_set );

            // ステータス記録は期間ごとに上の (1) ループで既に記録済み

            $user_elapsed = round( microtime( true ) - $user_start, 1 );
            $fail_count = count( $period_errors );
            if ( $user_had_error ) {
                $chunk_fail++;
                $this->prefetch_log( "[PREFETCH] DONE user_id={$user_id} status=error failed_periods={$fail_count} elapsed={$user_elapsed}s" );
            } else {
                $chunk_success++;
                $this->prefetch_log( "[PREFETCH] DONE user_id={$user_id} status=success elapsed={$user_elapsed}s" );
            }

            // Cron Logger: ユーザー単位の結果を記録
            if ( $log_id > 0 ) {
                $error_detail = $user_had_error
                    ? 'Failed periods: ' . implode( ', ', array_keys( $period_errors ) )
                    : null;
                Gcrev_Cron_Logger::log_user(
                    $log_id,
                    $user_id,
                    $user_had_error ? 'error' : 'success',
                    $error_detail
                );
            }
        }

        $chunk_elapsed = round( microtime( true ) - $chunk_start, 1 );
        $this->prefetch_log( "[PREFETCH] chunk DONE: success={$chunk_success} fail={$chunk_fail} skip={$chunk_skip} elapsed={$chunk_elapsed}s" );

        $next_offset = $offset + $limit;
        $next_users  = get_users(['number' => 1, 'offset' => $next_offset, 'fields' => ['ID']]);

        if (!empty($next_users)) {
            wp_schedule_single_event(time() + 10, 'gcrev_prefetch_chunk_event', [$next_offset, $limit]);
            $this->prefetch_log( "[PREFETCH] Scheduled next chunk: offset={$next_offset}" );
        } else {
            $this->release_lock( self::LOCK_PREFETCH );
            $this->prefetch_log( '[PREFETCH] ===== DAILY PREFETCH COMPLETE =====' );
            // Cron Logger: ジョブ完了
            if ( $log_id > 0 ) {
                $final_status = $chunk_fail > 0 ? 'partial_error' : 'success';
                Gcrev_Cron_Logger::finish( $log_id, $final_status );
                delete_transient( 'gcrev_current_prefetch_log_id' );
            }
        }
    }

    // =========================================================
    // スロット別プリフェッチ処理（Phase 3: 時間帯分散用）
    // =========================================================

    /**
     * 特定スロットのユーザーをプリフェッチする。
     *
     * @param int $slot   スロット番号
     * @param int $offset チャンクオフセット
     * @param int $limit  チャンクサイズ
     */
    public function prefetch_chunk_for_slot( int $slot, int $offset, int $limit ): void {

        $lock_key     = "gcrev_lock_prefetch_slot_{$slot}";
        $log_id_key   = "gcrev_current_prefetch_slot_{$slot}_log_id";
        $chunk_hook   = "gcrev_prefetch_chunk_slot_{$slot}_event";

        $log_file = '/tmp/gcrev_prefetch_debug.log';

        // ─── 重複実行防止ロック（最初のチャンクのみ設定） ───
        if ( $offset === 0 ) {
            if ( ! $this->acquire_lock( $lock_key ) ) {
                $this->prefetch_log_file( $log_file, "slot_{$slot}: LOCKED, skipping" );
                if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                    $locked_id = Gcrev_Cron_Logger::start( "prefetch_slot_{$slot}", [ 'note' => 'locked' ] );
                    Gcrev_Cron_Logger::finish( $locked_id, 'locked' );
                }
                return;
            }

            if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                $log_id = Gcrev_Cron_Logger::start( "prefetch_slot_{$slot}", [ 'slot' => $slot, 'chunk_limit' => $limit ] );
                set_transient( $log_id_key, $log_id, self::LOCK_TTL );
            }
        } else {
            // 後続チャンク: heartbeat 更新
            $this->heartbeat_lock( $lock_key );
        }

        $log_id = class_exists( 'Gcrev_Cron_Logger' ) ? (int) get_transient( $log_id_key ) : 0;

        $this->prefetch_log_file( $log_file, "slot_{$slot} chunk START: offset={$offset}, limit={$limit}" );

        // スロット別ユーザー取得
        if ( ! class_exists( 'Gcrev_Prefetch_Scheduler' ) ) {
            $this->prefetch_log_file( $log_file, "slot_{$slot}: Gcrev_Prefetch_Scheduler not loaded, aborting" );
            return;
        }

        $user_ids = Gcrev_Prefetch_Scheduler::get_users_for_slot( $slot, $limit, $offset );

        if ( empty( $user_ids ) ) {
            $this->prefetch_log_file( $log_file, "slot_{$slot}: No users at offset={$offset}. DONE." );
            delete_transient( $lock_key );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( $log_id_key );
            }
            return;
        }

        // 日次プリフェッチ: 全期間を毎日取得（スロット版もレガシー版と同じ全期間対応）
        $ranges = ['last30', 'last90', 'previousMonth', 'twoMonthsAgo', 'last180', 'last365'];
        $analysis_periods = ['last30', 'last90', 'prev-month', 'prev-prev-month', 'last180', 'last365'];
        $log_file = '/tmp/gcrev_prefetch_debug.log';

        foreach ( $user_ids as $user_id ) {
            $this->prefetch_log_file( $log_file, "slot_{$slot} START user_id={$user_id} ranges=" . implode( ',', $ranges ) );
            $user_had_error = false;

            try {
                $config = $this->config->get_user_config( $user_id );
            } catch ( \Exception $e ) {
                $this->prefetch_log_file( $log_file, "slot_{$slot} SKIP user_id={$user_id}: " . $e->getMessage() );
                if ( $log_id > 0 ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', $e->getMessage() );
                }
                continue;
            }

            // 国フィルタ + パスフィルタ適用（REST エンドポイントと同じ関数を使用）
            $filter_set      = $this->maybe_set_country_filter( $user_id );
            $exclude_foreign = $this->is_exclude_foreign( $user_id );

            // 期間別のエラー記録用
            $period_errors = [];

            // --- (1) ダッシュボード（全6期間） ---
            foreach ( $ranges as $range ) {
                $cached = $this->dashboard_cache_get( $user_id, $range );
                if ( $cached ) {
                    $this->prefetch_log_file( $log_file, "slot_{$slot} SKIP user_id={$user_id} period={$range} reason=cache_hit" );
                    continue;
                }
                try {
                    $range_start = microtime( true );
                    $data = $this->fetch_dashboard_data_internal( $config, $range );
                    $this->dashboard_cache_set( $user_id, $range, $data );
                    $elapsed = round( microtime( true ) - $range_start, 1 );
                    $this->prefetch_log_file( $log_file, "slot_{$slot} OK user_id={$user_id} period={$range} elapsed={$elapsed}s" );
                    $this->record_prefetch_status( $user_id, $range, 'all', 'success', null, 'cron' );
                } catch ( \Exception $e ) {
                    $error_msg = mb_substr( $e->getMessage(), 0, 500 );
                    $this->prefetch_log_file( $log_file, "slot_{$slot} FAIL user_id={$user_id} period={$range} error=" . $error_msg );
                    $user_had_error = true;
                    $period_errors[ $range ] = $error_msg;
                    $this->record_prefetch_status( $user_id, $range, 'all', 'error', $error_msg, 'cron' );
                }
                usleep( self::PREFETCH_SLEEP_US );
            }

            // --- (2) 分析ページ（全期間） ---
            foreach ( $analysis_periods as $period ) {
                $this->prefetch_analysis_caches( $user_id, $config, $period );
            }

            // --- (3) KPIトレンド ---
            $trend_filter_sfx = $this->ga4->has_country_filter() ? '_jp' : '';
            if ( $this->path_filters_set ) { $trend_filter_sfx .= '_ex'; }
            foreach ( ['sessions', 'cv', 'meo'] as $trend_metric ) {
                $trend_cache_key = "gcrev_trend_{$user_id}_{$trend_metric}_" . date( 'Y-m' ) . $trend_filter_sfx;
                if ( get_transient( $trend_cache_key ) !== false ) {
                    continue;
                }
                try {
                    $this->get_monthly_metric_trend( $user_id, $trend_metric, 12 );
                } catch ( \Exception $e ) {
                    $this->prefetch_log_file( $log_file, "slot_{$slot} trend FAIL user_id={$user_id} metric={$trend_metric} error=" . $e->getMessage() );
                    $user_had_error = true;
                }
                usleep( self::PREFETCH_SLEEP_US );
            }

            // --- (3b) 日次トレンド（ダッシュボードグラフ用）---
            $today_str = date('Y-m-d');
            foreach ( ['sessions', 'cv', 'meo'] as $daily_metric ) {
                $daily_trend_key = "gcrev_trend_daily_{$user_id}_{$daily_metric}_{$today_str}{$trend_filter_sfx}";
                if ( get_transient( $daily_trend_key ) !== false ) {
                    continue;
                }
                try {
                    $this->get_daily_metric_trend( $user_id, $daily_metric, 30 );
                } catch ( \Exception $e ) {
                    // 日次トレンドの失敗はユーザーエラーにカウントしない（補助データ）
                }
                usleep( self::PREFETCH_SLEEP_US );
            }

            // --- (4) 比較期間キャッシュ + スコア事前計算（ダッシュボード即表示用） ---
            try {
                $last30_dates = $this->dates->get_date_range('last30');
                $last30_comp  = $this->dates->get_comparison_range($last30_dates['start'], $last30_dates['end']);
                $filter_suffix_pf = $exclude_foreign ? '_filtered' : '';
                if ( class_exists( 'Gcrev_Path_Filter' ) ) {
                    $filter_suffix_pf .= Gcrev_Path_Filter::cache_suffix( $user_id );
                }
                $comp_cache_key   = "gcrev_dash_bydate_{$user_id}_last30_comp{$filter_suffix_pf}";
                $comp_cached      = get_transient( $comp_cache_key );

                if ( ! $comp_cached ) {
                    $comp_data = $this->get_dashboard_kpi_by_dates( $last30_comp['start'], $last30_comp['end'], $user_id, 'last30_comp' );
                    $this->prefetch_log_file( $log_file, "slot_{$slot} comparison OK user_id={$user_id}" );
                } else {
                    $comp_data = $comp_cached;
                }

                // スコア事前計算・KPI transient に保存
                $kpi_filter_suffix = $exclude_foreign ? '_jp' : '';
                $kpi_cache_key = "gcrev_dash_{$user_id}_last30{$kpi_filter_suffix}";
                $kpi_cached    = get_transient( $kpi_cache_key );
                if ( $kpi_cached && is_array( $kpi_cached ) && ! isset( $kpi_cached['_cached_score'] ) ) {
                    $sess_c  = (int) str_replace( ',', '', (string)( $kpi_cached['sessions'] ?? '0' ) );
                    $sess_p  = (int) str_replace( ',', '', (string)( $comp_data['sessions'] ?? '0' ) );
                    $cv_c    = (int) str_replace( ',', '', (string)( $kpi_cached['conversions'] ?? '0' ) );
                    $cv_p    = (int) str_replace( ',', '', (string)( $comp_data['conversions'] ?? '0' ) );
                    $gsc_c   = (int) str_replace( ',', '', (string)( $kpi_cached['gsc']['total']['clicks'] ?? $kpi_cached['gsc']['total']['impressions'] ?? '0' ) );
                    $gsc_p   = (int) str_replace( ',', '', (string)( $comp_data['gsc']['total']['clicks'] ?? $comp_data['gsc']['total']['impressions'] ?? '0' ) );

                    $meo_cache_c = get_transient( "gcrev_meo_perf_{$user_id}_last30" );
                    $meo_cache_p = get_transient( "gcrev_meo_perf_{$user_id}_last30_comp" );
                    $meo_c = ( $meo_cache_c !== false && is_array( $meo_cache_c ) ) ? (int)( $meo_cache_c['total_impressions'] ?? 0 ) : 0;
                    $meo_p = ( $meo_cache_p !== false && is_array( $meo_cache_p ) ) ? (int)( $meo_cache_p['total_impressions'] ?? 0 ) : 0;

                    $score_curr = [ 'traffic' => $sess_c, 'cv' => $cv_c, 'gsc' => $gsc_c, 'meo' => $meo_c ];
                    $score_prev = [ 'traffic' => $sess_p, 'cv' => $cv_p, 'gsc' => $gsc_p, 'meo' => $meo_p ];
                    $health = $this->calc_monthly_health_score( $score_curr, $score_prev, [], $user_id );

                    $kpi_cached['_cached_score'] = [
                        'score'      => $health['score'],
                        'status'     => $health['status'],
                        'breakdown'  => $health['breakdown'],
                        'components' => $health['components'],
                    ];
                    set_transient( $kpi_cache_key, $kpi_cached, self::DASHBOARD_CACHE_TTL );
                    $this->prefetch_log_file( $log_file, "slot_{$slot} score OK user_id={$user_id} score={$health['score']}" );
                }
            } catch ( \Exception $e ) {
                $this->prefetch_log_file( $log_file, "slot_{$slot} comparison/score FAIL user_id={$user_id} error=" . $e->getMessage() );
                $user_had_error = true;
            }
            usleep( self::PREFETCH_SLEEP_US );

            // 国フィルタ + パスフィルタ解除（REST エンドポイントと同じ関数を使用）
            $this->restore_country_filter( $filter_set );

            // ステータス記録は期間ごとに上の (1) ループで既に記録済み

            $fail_count = count( $period_errors );
            $this->prefetch_log_file( $log_file, "slot_{$slot} DONE user_id={$user_id} status=" . ( $user_had_error ? "error (failed={$fail_count})" : 'success' ) );

            if ( $log_id > 0 ) {
                $error_detail = $user_had_error
                    ? 'Failed periods: ' . implode( ', ', array_keys( $period_errors ) )
                    : null;
                Gcrev_Cron_Logger::log_user(
                    $log_id,
                    $user_id,
                    $user_had_error ? 'error' : 'success',
                    $error_detail
                );
            }
        }

        // ─── 次チャンクのスケジュール ───
        $next_offset = $offset + $limit;

        if ( Gcrev_Prefetch_Scheduler::has_more_users( $slot, $next_offset ) ) {
            wp_schedule_single_event( time() + 10, $chunk_hook, [ $slot, $next_offset, $limit ] );
            $this->prefetch_log_file( $log_file, "slot_{$slot}: Scheduled next chunk offset={$next_offset}" );
        } else {
            $this->release_lock( $lock_key );
            $this->prefetch_log_file( $log_file, "slot_{$slot}: ALL DONE." );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( $log_id_key );
            }
        }
    }

    /**
     * 各分析ページ（流入元・地域・ページ・キーワード）のキャッシュをプリフェッチ
     * 既存の REST コールバック内部と同一のキャッシュキー／ロジックを使用
     */
    public function prefetch_analysis_caches(int $user_id, array $config, string $period): void {

        $ga4_id  = $config['ga4_id'];
        $gsc_url = $config['gsc_url'] ?? '';

        $dates      = $this->dates->calculate_period_dates($period);
        $comparison  = $this->dates->calculate_comparison_dates($period);

        // 月固定期間は35日、日次期間は 7 日（cron が毎日更新する前提の余裕枠）
        $cache_ttl = Gcrev_Date_Helper::is_monthly_fixed_period( $period ) ? 3024000 : self::DASHBOARD_CACHE_TTL;

        // フィルタサフィックス（REST エンドポイントと同じキー形式にする）
        $filter_sfx = $this->ga4->has_country_filter() ? '_jp' : '';
        if ( $this->path_filters_set ) { $filter_sfx .= '_ex'; }

        // source 用の period 正規化（get_source_analysis は previousMonth/twoMonthsAgo を期待）
        $source_period = $period;
        if ($period === 'prev-month')      $source_period = 'previousMonth';
        elseif ($period === 'prev-prev-month') $source_period = 'twoMonthsAgo';

        // ----- 流入元 -----
        // period だけでキー一意化（last30 のように日付がスライドする期間でも 0 時跨ぎで無効化されない）
        $key_source   = "gcrev_source_{$user_id}_{$source_period}{$filter_sfx}";
        if (get_transient($key_source) === false) {
            try {
                // get_source_analysis は内部でキャッシュ保存するので呼ぶだけでOK
                $this->get_source_analysis($source_period, $user_id);
                error_log("[GCREV] Prefetch SOURCE OK: user={$user_id}, period={$period}");
            } catch (\Exception $e) {
                error_log("[GCREV] Prefetch SOURCE ERR: user={$user_id}, period={$period}: " . $e->getMessage());
            }
            usleep(self::PREFETCH_SLEEP_US);
        }

        // ----- 地域 -----
        $key_region = "gcrev_region_{$user_id}_{$period}{$filter_sfx}";
        if (get_transient($key_region) === false) {
            try {
                $regions       = $this->ga4->fetch_region_details($ga4_id, $dates['start'], $dates['end']);
                $regions_prev  = $this->ga4->fetch_region_details($ga4_id, $comparison['start'], $comparison['end']);
                $regions_result = $this->calculate_region_changes($regions, $regions_prev);
                set_transient($key_region, [
                    'success'        => true,
                    'period'         => $period,
                    'period_display' => $dates['display'] ?? '',
                    'regions_detail' => $regions_result,
                ], $cache_ttl);
                error_log("[GCREV] Prefetch REGION OK: user={$user_id}, period={$period}");
            } catch (\Exception $e) {
                error_log("[GCREV] Prefetch REGION ERR: user={$user_id}, period={$period}: " . $e->getMessage());
            }
            usleep(self::PREFETCH_SLEEP_US);
        }

        // ----- ページ分析 -----
        $key_page = "gcrev_page_{$user_id}_{$period}{$filter_sfx}";
        if (get_transient($key_page) === false) {
            try {
                $pages      = $this->ga4->fetch_page_details($ga4_id, $dates['start'], $dates['end'], $gsc_url);
                $pages_prev = $this->ga4->fetch_page_details($ga4_id, $comparison['start'], $comparison['end'], $gsc_url);
                $pages_result = $this->calculate_page_changes($pages, $pages_prev);
                set_transient($key_page, [
                    'success' => true,
                    'data'    => [
                        'pages_detail'        => $pages_result,
                        'current_period'      => ['start' => $dates['start'], 'end' => $dates['end']],
                        'comparison_period'    => ['start' => $comparison['start'], 'end' => $comparison['end']],
                        'current_range_label'  => str_replace('-', '/', $dates['start']) . ' 〜 ' . str_replace('-', '/', $dates['end']),
                        'compare_range_label'  => str_replace('-', '/', $comparison['start']) . ' 〜 ' . str_replace('-', '/', $comparison['end']),
                    ],
                ], $cache_ttl);
                error_log("[GCREV] Prefetch PAGE OK: user={$user_id}, period={$period}");
            } catch (\Exception $e) {
                error_log("[GCREV] Prefetch PAGE ERR: user={$user_id}, period={$period}: " . $e->getMessage());
            }
            usleep(self::PREFETCH_SLEEP_US);
        }

        // ----- キーワード -----
        $key_kw = "gcrev_keywords_{$user_id}_{$period}{$filter_sfx}";
        if (get_transient($key_kw) === false) {
            try {
                $current_gsc = $this->gsc->fetch_gsc_data($gsc_url, $dates['start'], $dates['end']);
                $prev_gsc    = $this->gsc->fetch_gsc_data($gsc_url, $comparison['start'], $comparison['end']);
                $kw_result   = $this->calculate_keyword_changes(
                    $current_gsc['keywords'] ?? [],
                    $prev_gsc['keywords'] ?? []
                );
                set_transient($key_kw, [
                    'success' => true,
                    'data'    => [
                        'keywords_detail'     => $kw_result,
                        'gsc_total'           => $current_gsc['total'] ?? [],
                        'current_period'      => ['start' => $dates['start'], 'end' => $dates['end']],
                        'comparison_period'    => ['start' => $comparison['start'], 'end' => $comparison['end']],
                        'current_range_label'  => str_replace('-', '/', $dates['start']) . ' 〜 ' . str_replace('-', '/', $dates['end']),
                        'compare_range_label'  => str_replace('-', '/', $comparison['start']) . ' 〜 ' . str_replace('-', '/', $comparison['end']),
                    ],
                ], $cache_ttl);
                error_log("[GCREV] Prefetch KEYWORD OK: user={$user_id}, period={$period}");
            } catch (\Exception $e) {
                error_log("[GCREV] Prefetch KEYWORD ERR: user={$user_id}, period={$period}: " . $e->getMessage());
            }
            usleep(self::PREFETCH_SLEEP_US);
        }
    }

    // =========================================================
    // 月次プリフェッチ処理（月初にCronから呼ばれる）
    // =========================================================

    private const LOCK_MONTHLY_PREFETCH = 'gcrev_lock_monthly_prefetch';

    /**
     * 月次データプリフェッチの起動（月初のみ実行）
     */
    public function auto_monthly_data_prefetch(): void {
        $tz  = wp_timezone();
        $now = new \DateTimeImmutable( 'now', $tz );
        if ( (int) $now->format( 'd' ) !== 1 ) {
            error_log( '[GCREV] monthly_data_prefetch: Not 1st of month, skipping.' );
            return;
        }
        $this->monthly_data_prefetch_chunk( 0, self::PREFETCH_CHUNK_LIMIT );
    }

    /**
     * 月次データプリフェッチのチャンク処理
     */
    public function monthly_data_prefetch_chunk( int $offset, int $limit ): void {

        if ( $offset === 0 ) {
            if ( ! $this->acquire_lock( self::LOCK_MONTHLY_PREFETCH ) ) {
                $this->prefetch_log( '[MONTHLY_PREFETCH] LOCKED, skipping' );
                if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                    $locked_id = Gcrev_Cron_Logger::start( 'monthly_prefetch', [ 'note' => 'locked' ] );
                    Gcrev_Cron_Logger::finish( $locked_id, 'locked' );
                }
                return;
            }
            if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                $log_id = Gcrev_Cron_Logger::start( 'monthly_prefetch', [ 'chunk_limit' => $limit ] );
                set_transient( 'gcrev_current_monthly_prefetch_log_id', $log_id, self::LOCK_TTL );
            }
        } else {
            $this->heartbeat_lock( self::LOCK_MONTHLY_PREFETCH );
        }

        $log_id = class_exists( 'Gcrev_Cron_Logger' ) ? (int) get_transient( 'gcrev_current_monthly_prefetch_log_id' ) : 0;

        $this->prefetch_log( "[MONTHLY_PREFETCH] START: offset={$offset}, limit={$limit}" );

        $users = get_users( [ 'number' => $limit, 'offset' => $offset, 'fields' => ['ID'] ] );

        if ( empty( $users ) ) {
            $this->prefetch_log( "[MONTHLY_PREFETCH] No users at offset={$offset}. DONE." );
            $this->release_lock( self::LOCK_MONTHLY_PREFETCH );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( 'gcrev_current_monthly_prefetch_log_id' );
            }
            return;
        }

        // 月次プリフェッチ: 月固定期間のみ
        $dash_ranges      = [ 'previousMonth', 'twoMonthsAgo', 'last180', 'last365' ];
        $analysis_periods = [ 'prev-month', 'prev-prev-month', 'last180', 'last365' ];
        $chunk_fail = 0;

        foreach ( $users as $u ) {
            $user_id = (int) $u->ID;
            $this->prefetch_log( "[MONTHLY_PREFETCH] processing: user_id={$user_id}" );
            $user_had_error = false;
            $period_errors  = [];

            try {
                $config = $this->config->get_user_config( $user_id );
            } catch ( \Exception $e ) {
                $this->prefetch_log( "[MONTHLY_PREFETCH] SKIP user_id={$user_id}: " . $e->getMessage() );
                if ( $log_id > 0 ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', $e->getMessage() );
                }
                continue;
            }

            // 国フィルタ + パスフィルタ適用（REST エンドポイントと同じ関数を使用）
            $filter_set      = $this->maybe_set_country_filter( $user_id );
            $exclude_foreign = $this->is_exclude_foreign( $user_id );

            // --- (1) ダッシュボードキャッシュ（月固定期間） ---
            foreach ( $dash_ranges as $range ) {
                // 月次は強制再取得（前月データが確定するため）
                $cache_key = $this->cache_key_dashboard( $user_id, $range );
                delete_transient( $cache_key );

                try {
                    $data = $this->fetch_dashboard_data_internal( $config, $range );
                    $this->dashboard_cache_set( $user_id, $range, $data );
                    $this->prefetch_log( "[MONTHLY_PREFETCH] SUCCESS user_id={$user_id}, range={$range}" );
                    $this->record_prefetch_status( $user_id, $range, 'all', 'success', null, 'cron', 'monthly' );
                } catch ( \Exception $e ) {
                    $error_msg = mb_substr( $e->getMessage(), 0, 500 );
                    $this->prefetch_log( "[MONTHLY_PREFETCH] ERROR user_id={$user_id}, range={$range}: " . $error_msg );
                    $user_had_error = true;
                    $period_errors[ $range ] = $error_msg;
                    $this->record_prefetch_status( $user_id, $range, 'all', 'error', $error_msg, 'cron', 'monthly' );
                }
                usleep( self::PREFETCH_SLEEP_US );
            }

            // --- (2) 分析ページキャッシュ（月固定期間） ---
            foreach ( $analysis_periods as $period ) {
                $this->prefetch_analysis_caches( $user_id, $config, $period );
            }

            // 国フィルタ + パスフィルタ解除（REST エンドポイントと同じ関数を使用）
            $this->restore_country_filter( $filter_set );

            if ( $user_had_error ) {
                $chunk_fail++;
            }

            if ( $log_id > 0 ) {
                $error_detail = $user_had_error
                    ? 'Failed periods: ' . implode( ', ', array_keys( $period_errors ) )
                    : null;
                Gcrev_Cron_Logger::log_user(
                    $log_id,
                    $user_id,
                    $user_had_error ? 'error' : 'success',
                    $error_detail
                );
            }
        }

        // 次チャンク
        $next_offset = $offset + $limit;
        $next_users  = get_users( [ 'number' => 1, 'offset' => $next_offset, 'fields' => ['ID'] ] );

        if ( ! empty( $next_users ) ) {
            wp_schedule_single_event( time() + 10, 'gcrev_monthly_prefetch_chunk_event', [ $next_offset, $limit ] );
            $this->prefetch_log( "[MONTHLY_PREFETCH] Scheduled next chunk offset={$next_offset}" );
        } else {
            $this->release_lock( self::LOCK_MONTHLY_PREFETCH );
            $final_status = $chunk_fail > 0 ? 'partial_error' : 'success';
            $this->prefetch_log( "[MONTHLY_PREFETCH] DONE. status={$final_status}" );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, $final_status );
                delete_transient( 'gcrev_current_monthly_prefetch_log_id' );
            }
        }
    }

    /**
     * 月次データプリフェッチ — スロット別チャンク処理
     *
     * prefetch_chunk_for_slot() の月次版。月固定期間のみ取得。
     * 月初（1日）以外に呼ばれた場合はスキップ。
     */
    public function monthly_prefetch_chunk_for_slot( int $slot, int $offset, int $limit ): void {

        // 月初のみ実行（自動Cron経由の場合。手動は monthly_data_prefetch_chunk 経由）
        $now = new \DateTimeImmutable('now', wp_timezone());
        if ( (int) $now->format('d') !== 1 ) {
            $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot}: Not 1st of month, skipping" );
            return;
        }

        $lock_key     = "gcrev_lock_monthly_prefetch_slot_{$slot}";
        $log_id_key   = "gcrev_current_monthly_prefetch_slot_{$slot}_log_id";
        $chunk_hook   = "gcrev_monthly_data_chunk_slot_{$slot}_event";

        // ─── 重複実行防止ロック ───
        if ( $offset === 0 ) {
            if ( ! $this->acquire_lock( $lock_key ) ) {
                $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot}: LOCKED, skipping" );
                if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                    $locked_id = Gcrev_Cron_Logger::start( "monthly_prefetch_slot_{$slot}", [ 'note' => 'locked' ] );
                    Gcrev_Cron_Logger::finish( $locked_id, 'locked' );
                }
                return;
            }

            if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                $log_id = Gcrev_Cron_Logger::start( "monthly_prefetch_slot_{$slot}", [ 'slot' => $slot, 'chunk_limit' => $limit ] );
                set_transient( $log_id_key, $log_id, self::LOCK_TTL );
            }
        } else {
            $this->heartbeat_lock( $lock_key );
        }

        $log_id = class_exists( 'Gcrev_Cron_Logger' ) ? (int) get_transient( $log_id_key ) : 0;

        $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot} START: offset={$offset}, limit={$limit}" );

        if ( ! class_exists( 'Gcrev_Prefetch_Scheduler' ) ) {
            $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot}: Gcrev_Prefetch_Scheduler not loaded, aborting" );
            return;
        }

        $user_ids = Gcrev_Prefetch_Scheduler::get_users_for_slot( $slot, $limit, $offset );

        if ( empty( $user_ids ) ) {
            $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot}: No users at offset={$offset}. DONE." );
            $this->release_lock( $lock_key );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( $log_id_key );
            }
            return;
        }

        $dash_ranges      = [ 'previousMonth', 'twoMonthsAgo', 'last180', 'last365' ];
        $analysis_periods = [ 'prev-month', 'prev-prev-month', 'last180', 'last365' ];

        foreach ( $user_ids as $user_id ) {
            $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot} processing: user_id={$user_id}" );
            $user_had_error = false;
            $period_errors  = [];

            try {
                $config = $this->config->get_user_config( $user_id );
            } catch ( \Exception $e ) {
                $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot} SKIP user_id={$user_id}: " . $e->getMessage() );
                if ( $log_id > 0 ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', $e->getMessage() );
                }
                continue;
            }

            // 国フィルタ + パスフィルタ適用（REST エンドポイントと同じ関数を使用）
            $filter_set      = $this->maybe_set_country_filter( $user_id );
            $exclude_foreign = $this->is_exclude_foreign( $user_id );

            // --- (1) ダッシュボードキャッシュ（月固定期間、強制再取得） ---
            foreach ( $dash_ranges as $range ) {
                $cache_key = $this->cache_key_dashboard( $user_id, $range );
                delete_transient( $cache_key );

                try {
                    $data = $this->fetch_dashboard_data_internal( $config, $range );
                    $this->dashboard_cache_set( $user_id, $range, $data );
                    $this->record_prefetch_status( $user_id, $range, 'all', 'success', null, 'cron', 'monthly' );
                } catch ( \Exception $e ) {
                    $error_msg = mb_substr( $e->getMessage(), 0, 500 );
                    $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot} ERROR user_id={$user_id}, range={$range}: " . $error_msg );
                    $user_had_error = true;
                    $period_errors[ $range ] = $error_msg;
                    $this->record_prefetch_status( $user_id, $range, 'all', 'error', $error_msg, 'cron', 'monthly' );
                }
                usleep( self::PREFETCH_SLEEP_US );
            }

            // --- (2) 分析ページキャッシュ（月固定期間） ---
            foreach ( $analysis_periods as $period ) {
                $this->prefetch_analysis_caches( $user_id, $config, $period );
            }

            // 国フィルタ + パスフィルタ解除（REST エンドポイントと同じ関数を使用）
            $this->restore_country_filter( $filter_set );

            if ( $log_id > 0 ) {
                $error_detail = $user_had_error
                    ? 'Failed periods: ' . implode( ', ', array_keys( $period_errors ) )
                    : null;
                Gcrev_Cron_Logger::log_user(
                    $log_id,
                    $user_id,
                    $user_had_error ? 'error' : 'success',
                    $error_detail
                );
            }
        }

        // ─── 次チャンクのスケジュール ───
        $next_offset = $offset + $limit;

        if ( Gcrev_Prefetch_Scheduler::has_more_users( $slot, $next_offset ) ) {
            wp_schedule_single_event( time() + 10, $chunk_hook, [ $slot, $next_offset, $limit ] );
            $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot}: Scheduled next chunk offset={$next_offset}" );
        } else {
            $this->release_lock( $lock_key );
            $this->prefetch_log( "[MONTHLY_PREFETCH] slot_{$slot}: DONE." );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( $log_id_key );
            }
        }
    }

    /**
     * API 接続テスト
     *
     * @param int $user_id
     * @return array ['ga4' => bool, 'gsc' => bool, 'ga4_error' => ?string, 'gsc_error' => ?string]
     */
    public function check_api_connection( int $user_id ): array {
        $result = [ 'ga4' => false, 'gsc' => false, 'ga4_error' => null, 'gsc_error' => null ];

        try {
            $config = $this->config->get_user_config( $user_id );
        } catch ( \Exception $e ) {
            $result['ga4_error'] = $e->getMessage();
            $result['gsc_error'] = $e->getMessage();
            return $result;
        }

        // GA4 テスト（最小リクエスト: 昨日1日・sessions のみ）
        try {
            $tz       = wp_timezone();
            $yesterday = ( new \DateTimeImmutable( 'yesterday', $tz ) )->format( 'Y-m-d' );
            $this->ga4->fetch_ga4_summary( $config['ga4_id'], $yesterday, $yesterday );
            $result['ga4'] = true;
        } catch ( \Exception $e ) {
            $result['ga4_error'] = $e->getMessage();
        }

        // GSC テスト（最小リクエスト）
        try {
            $tz        = wp_timezone();
            $week_ago  = ( new \DateTimeImmutable( '-7 days', $tz ) )->format( 'Y-m-d' );
            $yesterday = ( new \DateTimeImmutable( 'yesterday', $tz ) )->format( 'Y-m-d' );
            $this->gsc->fetch_gsc_data( $config['gsc_url'], $week_ago, $yesterday );
            $result['gsc'] = true;
        } catch ( \Exception $e ) {
            $result['gsc_error'] = $e->getMessage();
        }

        return $result;
    }

    // =========================================================
    // 内部ヘルパー: ダッシュボードデータ取得
    // =========================================================
    private function fetch_dashboard_data_internal(array $config, string $range): array {

        $ga4_id  = $config['ga4_id'];
        $gsc_url = $config['gsc_url'];
        $site_url = $config['site_url'] ?? '';

        $dates = $this->dates->get_date_range($range);

        // 比較期間（同日数の直前期間）
        $comparison = $this->dates->get_comparison_range($dates['start'], $dates['end']);

        // デバッグ: 実際に使われる日付範囲をログ
        file_put_contents('/tmp/gcrev_dash_debug.log',
            date('Y-m-d H:i:s') . " [fetch_internal] range={$range}, dates={$dates['start']}~{$dates['end']}, comp={$comparison['start']}~{$comparison['end']}\n",
            FILE_APPEND
        );

        // GA4 / GSC 取得
        $ga4_pages = $this->ga4->fetch_ga4_data($ga4_id, $dates['start'], $dates['end'], $site_url);

        $ga4_summary = $this->ga4->fetch_ga4_summary($ga4_id, $dates['start'], $dates['end']);
        $ga4_prev    = $this->ga4->fetch_ga4_summary($ga4_id, $comparison['start'], $comparison['end']);

        $daily = $this->ga4->fetch_ga4_daily_series($ga4_id, $dates['start'], $dates['end']);

        $devices = $this->ga4->fetch_ga4_breakdown($ga4_id, $dates['start'], $dates['end'], 'deviceCategory', 'sessions');
        $devices_detail      = $this->ga4->fetch_device_details($ga4_id, $dates['start'], $dates['end']);
        $devices_prev_detail = $this->ga4->fetch_device_details($ga4_id, $comparison['start'], $comparison['end']);
        $devices_daily_series = $this->ga4->fetch_device_daily_series($ga4_id, $dates['start'], $dates['end']);

        $medium  = $this->ga4->fetch_ga4_breakdown($ga4_id, $dates['start'], $dates['end'], 'sessionMedium', 'sessions');
        $geo     = $this->ga4->fetch_ga4_breakdown($ga4_id, $dates['start'], $dates['end'], 'city', 'sessions');
        
        $geo_region = $this->ga4->fetch_ga4_breakdown($ga4_id, $dates['start'], $dates['end'], 'region', 'sessions');
        $age     = $this->ga4->fetch_ga4_age_breakdown($ga4_id, $dates['start'], $dates['end']);
        $age_demographics      = $this->ga4->fetch_age_demographics($ga4_id, $dates['start'], $dates['end']);
        $age_prev_demographics = $this->ga4->fetch_age_demographics($ga4_id, $comparison['start'], $comparison['end']);

        // 性別 × 年齢（Google Signals 必須）
        $gender_age_cross = $this->ga4->fetch_ga4_gender_age_cross(
            $ga4_id,
            $dates['start'],
            $dates['end']
        );


        // 年齢別データに前期比を追加
        if (!empty($age_demographics) && !empty($age_prev_demographics)) {
            foreach ($age_demographics as &$current) {
                $age_range = $current['age_range'];
                // 前期の同じ年齢層を探す
                foreach ($age_prev_demographics as $prev) {
                    if ($prev['age_range'] === $age_range) {
                        $current_sessions = $current['sessions'];
                        $prev_sessions = $prev['sessions'];
                        if ($prev_sessions > 0) {
                            $change_percent = (($current_sessions - $prev_sessions) / $prev_sessions) * 100.0;
                            $current['change_percent'] = round($change_percent, 1);
                        } else {
                            $current['change_percent'] = 0.0;
                        }
                        break;
                    }
                }
                // 前期にデータがない場合は0
                if (!isset($current['change_percent'])) {
                    $current['change_percent'] = 0.0;
                }
            }
            unset($current);
        }


        $gsc_data = $this->gsc->fetch_gsc_data($gsc_url, $dates['start'], $dates['end']);

        // 変化率（%）
        $trends = $this->build_trends($ga4_summary, $ga4_prev);

        // 流入元詳細データ（流入元ページ用）
        $source_analysis = [
            'channels_summary' => [],
            'sources_detail' => [],
            'channels_daily_series' => [],
        ];
        
        try {
            error_log("[GCREV] Fetching source data for range: {$dates['start']} to {$dates['end']}");
            $source_current = $this->ga4->fetch_source_data_from_ga4($ga4_id, $dates['start'], $dates['end']);
            $source_previous = $this->ga4->fetch_source_data_from_ga4($ga4_id, $comparison['start'], $comparison['end']);
            $source_analysis = $this->format_source_analysis_data($source_current, $source_previous);
            error_log("[GCREV] Source data fetched successfully: " . count($source_analysis['channels_summary'] ?? []) . " channels");
        } catch (\Exception $e) {
            error_log("[GCREV] ERROR fetching source data: " . $e->getMessage());
            // エラー時は空配列のまま（他のデータは正常に返す）
        }

        // ダッシュボードJSが期待する「フラット構造」＋ 既存の ga4/gsc ネスト構造（レポート側互換）
        return [
            // 表示用期間
            'current_period'    => [
                'start'   => $dates['start'],
                'end'     => $dates['end'],
                'display' => $dates['display'],
            ],
            'comparison_period' => [
                'start'   => $comparison['start'],
                'end'     => $comparison['end'],
                'display' => $comparison['display'],
            ],

            // KPI（ダッシュボード用）
            'pageViews'      => $ga4_summary['pageViews'],
            'sessions'       => $ga4_summary['sessions'],
            'users'          => $ga4_summary['users'],
            'newUsers'       => $ga4_summary['newUsers'],
            'returningUsers' => $ga4_summary['returningUsers'],
            'avgDuration'    => $ga4_summary['avgDuration'],
            'conversions'    => $ga4_summary['conversions'] ?? '0',

            // 増減（前期比）
            'trends' => $trends,

            // 日次スパークライン
            'daily' => $daily,

            // 内訳（円グラフ/表）
            'devices' => $devices,
            'devices_detail'       => $devices_detail,
            'devices_prev_detail'  => $devices_prev_detail,
            'devices_daily_series' => $devices_daily_series,
            'medium'  => $medium,
            'geo'     => $geo,
            'geo_region' => $geo_region,
            'age'     => $age,
            'age_demographics'      => $age_demographics,
            'age_prev_demographics' => $age_prev_demographics,
            'gender_age_cross'      => $gender_age_cross,

            // 流入元詳細（流入元ページ用）
            'channels_summary'       => $source_analysis['channels_summary'] ?? [],
            'sources_detail'         => $source_analysis['sources_detail'] ?? [],
            'channels_daily_series'  => $source_analysis['channels_daily_series'] ?? [],

            // ランキング（表）
            'pages'    => $ga4_pages['pages'] ?? [],
            'keywords' => $gsc_data['keywords'] ?? [],

            // 既存（レポート側が利用）
            'ga4' => [
                'total' => $ga4_summary,
                'pages' => $ga4_pages['pages'] ?? [],
            ],
            'gsc' => $gsc_data,

            // データ不足検出: daily series の先頭日付がリクエスト開始日より大幅に後ろの場合
            'actual_data_start' => $this->detect_actual_data_start( $daily, $dates['start'] ),
        ];
    }

    /**
     * daily series の先頭日付を確認し、リクエスト開始日との乖離を検出する。
     * GA4プロパティの作成日が浅い場合、リクエスト期間の前半にデータが存在しない。
     *
     * @param  array  $daily  fetch_ga4_daily_series() の戻り値
     * @param  string $requested_start リクエストされた開始日 (Y-m-d)
     * @return ?string 実際のデータ開始日 (Y-m-d)。乖離がなければ null
     */
    private function detect_actual_data_start( array $daily, string $requested_start ): ?string {
        $labels = $daily['sessions']['labels'] ?? [];
        if ( empty( $labels ) ) {
            return null;
        }
        $first_label = (string) $labels[0]; // YYYYMMDD（GA4 APIがintで返す場合あり）
        $first_date  = substr( $first_label, 0, 4 ) . '-' . substr( $first_label, 4, 2 ) . '-' . substr( $first_label, 6, 2 );

        $req   = new \DateTimeImmutable( $requested_start );
        $actual = new \DateTimeImmutable( $first_date );
        // 7日以上の乖離がある場合のみ通知対象
        if ( $actual > $req->modify( '+7 days' ) ) {
            return $first_date;
        }
        return null;
    }

    // =========================================================
    // 前々月データ存在チェック（共通ヘルパー）
    // =========================================================

    /**
     * GA4 プロパティに前々月データが存在するかを判定する。
     *
     * fetch_dashboard_data_internal('twoMonthsAgo') を呼び、
     * 最低限の KPI（sessions / pageViews）が取得できるかを確認する。
     *
     * @param  int $user_id ユーザーID
     * @return array{available: bool, reason?: string, period?: array}
     */
    public function has_prev2_data(int $user_id): array {
        try {
            $config = $this->config->get_user_config($user_id);
            if (empty($config['ga4_id'])) {
                return [
                    'available' => false,
                    'reason'    => 'GA4プロパティが設定されていません',
                ];
            }

            $two_data = $this->fetch_dashboard_data_internal($config, 'twoMonthsAgo');

            $sessions   = (int) ($two_data['ga4']['total']['sessions']  ?? 0);
            $page_views = (int) ($two_data['ga4']['total']['pageViews'] ?? 0);
            $is_zero    = ($sessions === 0 && $page_views === 0);

            return [
                'available' => true,
                'is_zero'   => $is_zero,
                'period'    => $two_data['current_period'] ?? null,
            ];

        } catch (\Throwable $e) {
            error_log("[GCREV] has_prev2_data: ERROR user_id={$user_id}: " . $e->getMessage());
            return [
                'available' => false,
                'reason'    => '前々月データの取得に失敗しました: ' . $e->getMessage(),
            ];
        }
    }

    // =========================================================
    // 前期比の増減（%）オブジェクトを生成
    // =========================================================
    private function build_trends(array $current, array $prev): array {

        $calc = function (int|float $cur, int|float $prv): array {
            // より安全なゼロチェック（0, 0.0, null, 極小値すべて対応）
            if (empty($prv) || abs($prv) < 0.0001) {
                if (empty($cur) || abs($cur) < 0.0001) {
                    return ['value' => 0, 'text' => '±0.0%', 'color' => '#666'];
                }
                return ['value' => 100, 'text' => '+∞', 'color' => '#3b82f6'];
            }

            $val = (($cur - $prv) / $prv) * 100.0;
            $text = ($val > 0 ? '+' : '') . number_format($val, 1) . '%';

            $color = '#666';
            if ($val > 0) $color = '#3b82f6';
            if ($val < 0) $color = '#ef4444';

            return ['value' => $val, 'text' => $text, 'color' => $color];
        };

        return [
            'pageViews'      => $calc((float)($current['_pageViews'] ?? 0), (float)($prev['_pageViews'] ?? 0)),
            'sessions'       => $calc((float)($current['_sessions'] ?? 0), (float)($prev['_sessions'] ?? 0)),
            'users'          => $calc((float)($current['_users'] ?? 0), (float)($prev['_users'] ?? 0)),
            'newUsers'       => $calc((float)($current['_newUsers'] ?? 0), (float)($prev['_newUsers'] ?? 0)),
            'returningUsers' => $calc((float)($current['_returningUsers'] ?? 0), (float)($prev['_returningUsers'] ?? 0)),
            'avgDuration'    => $calc((float)($current['_avgDuration'] ?? 0), (float)($prev['_avgDuration'] ?? 0)),
            'conversions'    => $calc((float)($current['_conversions'] ?? 0), (float)($prev['_conversions'] ?? 0)),
        ];
    }


    // =========================================================
    // クライアント情報の保存
    // =========================================================
    public function save_client_info(WP_REST_Request $request): WP_REST_Response {

        $user_id = get_current_user_id();
        $params  = $request->get_json_params();

        // 月次戦略情報のみ保存（site_url / target はクライアント設定へ移管済み）
        update_user_meta($user_id, 'report_issue',            sanitize_text_field($params['issue'] ?? ''));
        update_user_meta($user_id, 'report_goal_monthly',     sanitize_text_field($params['goal_monthly'] ?? ''));
        update_user_meta($user_id, 'report_focus_numbers',    sanitize_text_field($params['focus_numbers'] ?? ''));
        update_user_meta($user_id, 'report_current_state',    sanitize_text_field($params['current_state'] ?? ''));
        update_user_meta($user_id, 'report_goal_main',        sanitize_text_field($params['goal_main'] ?? ''));
        update_user_meta($user_id, 'report_additional_notes', sanitize_text_field($params['additional_notes'] ?? ''));

        // 出力モードの保存
        $output_mode = $params['output_mode'] ?? 'normal';
        if (!in_array($output_mode, ['normal', 'easy'], true)) {
            $output_mode = 'normal';
        }
        update_user_meta($user_id, 'report_output_mode', $output_mode);

        error_log("[GCREV] Client info saved for user_id={$user_id}, output_mode={$output_mode}");

        return new WP_REST_Response([
            'success' => true,
            'message' => '月次レポート設定を保存しました',
        ], 200);
    }

    /**
     * クライアント固定設定を保存
     */
    public function save_client_settings(WP_REST_Request $request): WP_REST_Response {
        $user_id = get_current_user_id();
        $params  = $request->get_json_params();

        // URL バリデーション
        $site_url = esc_url_raw($params['site_url'] ?? '');
        if (empty($site_url)) {
            return new WP_REST_Response([
                'success' => false,
                'message' => '対象サイトURLは必須です',
            ], 400);
        }

        // 商圏タイプ バリデーション
        $valid_area_types = ['nationwide', 'prefecture', 'city', 'custom', ''];
        $area_type = sanitize_text_field($params['area_type'] ?? '');
        if (!in_array($area_type, $valid_area_types, true)) {
            $area_type = '';
        }

        update_user_meta($user_id, 'gcrev_client_site_url',      $site_url);

        // Maps（GBP）用ドメイン
        $maps_domain = sanitize_text_field( $params['maps_domain'] ?? '' );
        // www. / プロトコル付きで入力された場合はドメイン部分を正規化
        if ( $maps_domain !== '' ) {
            if ( preg_match( '#^https?://#i', $maps_domain ) ) {
                $parsed_md = wp_parse_url( $maps_domain );
                $maps_domain = $parsed_md['host'] ?? $maps_domain;
            }
            $maps_domain = preg_replace( '/^www\./i', '', strtolower( trim( $maps_domain, '/' ) ) );
        }
        update_user_meta( $user_id, '_gcrev_maps_domain', $maps_domain );

        // 解析対象URL条件（1行1パス、配列で保存）
        $include_paths_raw = $params['include_paths'] ?? '';
        $include_paths = [];
        if ( is_string( $include_paths_raw ) && $include_paths_raw !== '' ) {
            $lines = explode( "\n", $include_paths_raw );
            foreach ( $lines as $line ) {
                $path = trim( sanitize_text_field( $line ) );
                if ( $path !== '' ) {
                    if ( $path[0] !== '/' ) {
                        $path = '/' . $path;
                    }
                    $include_paths[] = $path;
                }
            }
        }

        // 解析除外URL条件（1行1パス、配列で保存）
        $exclude_paths_raw = $params['exclude_paths'] ?? '';
        $exclude_paths = [];
        if ( is_string( $exclude_paths_raw ) && $exclude_paths_raw !== '' ) {
            $lines = explode( "\n", $exclude_paths_raw );
            foreach ( $lines as $line ) {
                $path = trim( sanitize_text_field( $line ) );
                if ( $path !== '' ) {
                    // 先頭 / を保証
                    if ( $path[0] !== '/' ) {
                        $path = '/' . $path;
                    }
                    $exclude_paths[] = $path;
                }
            }
        }

        // 旧設定との差分を確認 → 変化があれば GSC 由来の集計キャッシュを一括削除
        $prev_include = get_user_meta( $user_id, '_gcrev_include_paths', true );
        $prev_exclude = get_user_meta( $user_id, '_gcrev_exclude_paths', true );
        $prev_include = is_array( $prev_include ) ? $prev_include : [];
        $prev_exclude = is_array( $prev_exclude ) ? $prev_exclude : [];

        $paths_changed = ( $prev_include !== $include_paths ) || ( $prev_exclude !== $exclude_paths );

        update_user_meta( $user_id, '_gcrev_include_paths', $include_paths );
        update_user_meta( $user_id, '_gcrev_exclude_paths', $exclude_paths );

        if ( $paths_changed && class_exists( 'Gcrev_Path_Filter' ) ) {
            $deleted = Gcrev_Path_Filter::purge_user_caches( $user_id );
            error_log( "[GCREV] Path filter changed for user_id={$user_id} — purged {$deleted} stale GSC/dashboard cache rows" );
        }

        // 海外アクセス除外
        if ( isset( $params['exclude_foreign'] ) ) {
            $exclude_foreign = $params['exclude_foreign'] === '1' ? '1' : '';
            update_user_meta( $user_id, 'report_exclude_foreign', $exclude_foreign );
        }

        update_user_meta($user_id, 'gcrev_client_area_type',      $area_type);
        update_user_meta($user_id, 'gcrev_client_area_pref',      sanitize_text_field($params['area_pref'] ?? ''));
        update_user_meta($user_id, 'gcrev_client_area_city',      sanitize_text_field($params['area_city'] ?? ''));
        update_user_meta($user_id, 'gcrev_client_area_custom',    sanitize_text_field($params['area_custom'] ?? ''));

        // 商圏（市区町村）変更時：手動MEO座標が未設定ならMEOキャッシュを無効化
        // （自動検出の市区町村中心部が変わるため）
        $manual_lat = get_user_meta( $user_id, '_gcrev_meo_lat', true );
        if ( empty( $manual_lat ) ) {
            global $wpdb;
            $like = $wpdb->esc_like( '_transient_gcrev_meo_rank_' . $user_id ) . '%';
            $wpdb->query( $wpdb->prepare(
                "DELETE FROM {$wpdb->options} WHERE option_name LIKE %s",
                $like
            ) );
            $like_timeout = $wpdb->esc_like( '_transient_timeout_gcrev_meo_rank_' . $user_id ) . '%';
            $wpdb->query( $wpdb->prepare(
                "DELETE FROM {$wpdb->options} WHERE option_name LIKE %s",
                $like_timeout
            ) );
        }

        // 業種（大分類）— 64文字以内
        $category = sanitize_text_field($params['industry_category'] ?? '');
        if (mb_strlen($category) > 64) { $category = mb_substr($category, 0, 64); }
        update_user_meta($user_id, 'gcrev_client_industry_category', $category);

        // 業態（小分類）— 配列、各 value 64文字以内
        $subcategory_raw = $params['industry_subcategory'] ?? [];
        $subcategory = [];
        if (is_array($subcategory_raw)) {
            foreach ($subcategory_raw as $v) {
                $v = sanitize_text_field($v);
                if ($v !== '' && mb_strlen($v) <= 64) {
                    $subcategory[] = $v;
                }
            }
        }
        update_user_meta($user_id, 'gcrev_client_industry_subcategory', $subcategory);

        // 詳細 — 160文字以内
        $detail = sanitize_text_field($params['industry_detail'] ?? '');
        if (mb_strlen($detail) > 160) { $detail = mb_substr($detail, 0, 160); }
        update_user_meta($user_id, 'gcrev_client_industry_detail', $detail);

        // ビジネス形態（複数選択 — 配列で保存）
        $bt_raw = $params['business_type'] ?? '';
        $valid_bt_keys = array_keys( gcrev_get_business_type_master() );
        if ( is_array( $bt_raw ) ) {
            $bt_clean = [];
            foreach ( $bt_raw as $v ) {
                $v = sanitize_text_field( $v );
                if ( in_array( $v, $valid_bt_keys, true ) ) {
                    $bt_clean[] = $v;
                }
            }
            update_user_meta( $user_id, 'gcrev_client_business_type', $bt_clean );
        } else {
            // 後方互換: 旧クライアントからの単一string
            $v = sanitize_text_field( $bt_raw );
            update_user_meta( $user_id, 'gcrev_client_business_type', $v !== '' ? [ $v ] : [] );
        }

        // --- 成長ステージ（200文字以内） ---
        $stage = sanitize_text_field( $params['stage'] ?? '' );
        if ( mb_strlen( $stage ) > 200 ) { $stage = mb_substr( $stage, 0, 200 ); }
        update_user_meta( $user_id, 'gcrev_client_stage', $stage );

        // --- ゴール種別（300文字以内） ---
        $main_conversions = sanitize_text_field( $params['main_conversions'] ?? '' );
        if ( mb_strlen( $main_conversions ) > 300 ) { $main_conversions = mb_substr( $main_conversions, 0, 300 ); }
        update_user_meta( $user_id, 'gcrev_client_main_conversions', $main_conversions );

        // --- 口コミアンケート AI生成用フィールド ---
        $service_description = sanitize_textarea_field( $params['service_description'] ?? '' );
        if ( mb_strlen( $service_description ) > 1000 ) { $service_description = mb_substr( $service_description, 0, 1000 ); }
        update_user_meta( $user_id, 'gcrev_client_service_description', $service_description );

        $strengths = sanitize_textarea_field( $params['strengths'] ?? '' );
        if ( mb_strlen( $strengths ) > 1000 ) { $strengths = mb_substr( $strengths, 0, 1000 ); }
        update_user_meta( $user_id, 'gcrev_client_strengths', $strengths );

        $review_emphasis = sanitize_textarea_field( $params['review_emphasis'] ?? '' );
        if ( mb_strlen( $review_emphasis ) > 500 ) { $review_emphasis = mb_substr( $review_emphasis, 0, 500 ); }
        update_user_meta( $user_id, 'gcrev_client_review_emphasis', $review_emphasis );

        // --- ペルソナ: 配列フィールド（年齢層 / 性別 / 属性 / 意思決定） ---
        $persona_array_fields = [
            'persona_age_ranges'       => 'gcrev_client_persona_age_ranges',
            'persona_genders'          => 'gcrev_client_persona_genders',
            'persona_attributes'       => 'gcrev_client_persona_attributes',
            'persona_decision_factors' => 'gcrev_client_persona_decision_factors',
        ];
        foreach ($persona_array_fields as $param_key => $meta_key) {
            $raw = $params[$param_key] ?? [];
            $clean = [];
            if (is_array($raw)) {
                foreach ($raw as $v) {
                    $v = sanitize_text_field($v);
                    if ($v !== '' && mb_strlen($v) <= 64) {
                        $clean[] = $v;
                    }
                }
            }
            update_user_meta($user_id, $meta_key, $clean);
        }

        // ペルソナ: ひとこと（200文字）
        $one_liner = sanitize_text_field($params['persona_one_liner'] ?? '');
        if (mb_strlen($one_liner) > 200) { $one_liner = mb_substr($one_liner, 0, 200); }
        update_user_meta($user_id, 'gcrev_client_persona_one_liner', $one_liner);

        // ペルソナ: 詳細テキスト（4000文字、改行保持）
        $detail_text = sanitize_textarea_field($params['persona_detail_text'] ?? '');
        if (mb_strlen($detail_text) > 4000) { $detail_text = mb_substr($detail_text, 0, 4000); }
        update_user_meta($user_id, 'gcrev_client_persona_detail_text', $detail_text);

        // ペルソナ: 参考URL（最大5件）
        $ref_urls_raw = $params['persona_reference_urls'] ?? [];
        $ref_urls = [];
        if (is_array($ref_urls_raw)) {
            $count = 0;
            foreach ($ref_urls_raw as $item) {
                if ($count >= 5) break;
                if (!is_array($item)) continue;
                $url  = esc_url_raw($item['url'] ?? '');
                $note = sanitize_text_field($item['note'] ?? '');
                if (empty($url)) continue;
                if (mb_strlen($url) > 2048)  { $url  = mb_substr($url, 0, 2048); }
                if (mb_strlen($note) > 120)  { $note = mb_substr($note, 0, 120); }
                $ref_urls[] = ['url' => $url, 'note' => $note];
                $count++;
            }
        }
        update_user_meta($user_id, 'gcrev_client_persona_reference_urls', $ref_urls);

        // === Clarity 連携設定 ===
        if ( class_exists( 'Gcrev_Clarity_Client' ) ) {
            $clarity_data = [];
            if ( isset( $params['clarity_enabled'] ) ) {
                $clarity_data['clarity_enabled'] = $params['clarity_enabled'];
            }
            if ( isset( $params['clarity_api_token'] ) ) {
                $clarity_data['clarity_api_token'] = $params['clarity_api_token'];
            }
            if ( isset( $params['clarity_project_name'] ) ) {
                $clarity_data['clarity_project_name'] = $params['clarity_project_name'];
            }
            if ( isset( $params['clarity_project_id'] ) ) {
                $clarity_data['clarity_project_id'] = $params['clarity_project_id'];
            }
            if ( ! empty( $clarity_data ) ) {
                Gcrev_Clarity_Client::save_settings( $user_id, $clarity_data );
            }
        }

        error_log("[GCREV] Client settings saved for user_id={$user_id}, site_url={$site_url}");

        return new WP_REST_Response([
            'success' => true,
            'message' => 'クライアント設定を保存しました',
        ], 200);
    }

    /**
     * AI で詳細ペルソナを生成
     */
    public function generate_persona(WP_REST_Request $request): WP_REST_Response {
        $user_id = get_current_user_id();

        // 連打防止（30秒）
        $throttle_key = 'gcrev_persona_gen_' . $user_id;
        if (get_transient($throttle_key)) {
            return new WP_REST_Response([
                'success' => false,
                'message' => '連続生成はできません。30秒後に再度お試しください。',
            ], 429);
        }
        set_transient($throttle_key, 1, 30);

        $params  = $request->get_json_params();
        $context = $params['context'] ?? [];

        // コンテキスト情報の組み立て
        $industry_category    = sanitize_text_field($context['industry_category'] ?? '');
        $industry_subcategory = $context['industry_subcategory'] ?? [];
        $industry_sub_labels  = $context['industry_subcategory_labels'] ?? [];
        $industry_label       = sanitize_text_field($context['industry_label'] ?? '');
        $industry_detail      = sanitize_text_field($context['industry_detail'] ?? '');
        $age_ranges           = $context['persona_age_ranges'] ?? [];
        $genders              = $context['persona_genders'] ?? [];
        $attributes           = $context['persona_attributes'] ?? [];
        $decision_factors     = $context['persona_decision_factors'] ?? [];
        $one_liner            = sanitize_text_field($context['persona_one_liner'] ?? '');
        $ref_urls             = $context['reference_urls'] ?? [];
        $extra                = $context['extra'] ?? [];

        // 業種詳細: リクエストに含まれていなければ保存済みuser metaをフォールバック
        if (empty($industry_detail)) {
            $industry_detail = sanitize_text_field(get_user_meta($user_id, 'gcrev_client_industry_detail', true) ?: '');
        }
        // 業態ラベル: リクエストに含まれていなければ保存済みuser metaから解決
        if (empty($industry_sub_labels) && !empty($industry_subcategory)) {
            $master = gcrev_get_industry_master();
            $subs_map = $master[$industry_category]['subcategories'] ?? [];
            foreach ($industry_subcategory as $sv) {
                $sv = sanitize_text_field($sv);
                if (isset($subs_map[$sv])) {
                    $industry_sub_labels[] = $subs_map[$sv];
                }
            }
        }

        // プロンプト構築
        $prompt_parts = [];
        $prompt_parts[] = "あなたはWeb集客・マーケティングのペルソナ設計の専門家です。";
        $prompt_parts[] = "以下の情報をもとに、この事業者が想定すべき「典型的な見込み客ペルソナ」を作成してください。";
        $prompt_parts[] = "";

        // 業種・業態
        if ($industry_label) {
            $industry_line = $industry_label;
            if (!empty($industry_sub_labels)) {
                $industry_line .= '（' . implode('、', array_map('sanitize_text_field', $industry_sub_labels)) . '）';
            }
            $prompt_parts[] = "【業種・業態】" . $industry_line;
        }
        if ($industry_detail) {
            $prompt_parts[] = "【業種の詳細・特徴】" . $industry_detail;
        }

        // 簡易ペルソナ情報
        if (!empty($age_ranges)) {
            $prompt_parts[] = "【想定年齢層】" . implode(', ', array_map('sanitize_text_field', $age_ranges));
        }
        if (!empty($genders)) {
            $prompt_parts[] = "【想定性別】" . implode(', ', array_map('sanitize_text_field', $genders));
        }
        if (!empty($attributes)) {
            $prompt_parts[] = "【ターゲット属性】" . implode(', ', array_map('sanitize_text_field', $attributes));
        }
        if (!empty($decision_factors)) {
            $prompt_parts[] = "【検討・意思決定の特徴】" . implode(', ', array_map('sanitize_text_field', $decision_factors));
        }
        if ($one_liner) {
            $prompt_parts[] = "【ひとこと補足】" . $one_liner;
        }

        // 参考URL
        if (!empty($ref_urls) && is_array($ref_urls)) {
            $url_lines = [];
            foreach ($ref_urls as $idx => $ru) {
                if (!is_array($ru)) continue;
                $u = sanitize_text_field($ru['url'] ?? '');
                $n = sanitize_text_field($ru['note'] ?? '');
                if ($u) {
                    $url_lines[] = ($idx + 1) . ". " . $u . ($n ? " （意図: {$n}）" : '');
                }
            }
            if (!empty($url_lines)) {
                $prompt_parts[] = "【参考URL】";
                $prompt_parts[] = implode("\n", $url_lines);
            }
        }

        // 対応エリア: extra.area が空なら保存済みの商圏設定をフォールバック
        if (is_array($extra) && empty(trim($extra['area'] ?? ''))) {
            $area_type   = get_user_meta($user_id, 'gcrev_client_area_type', true);
            $area_pref   = get_user_meta($user_id, 'gcrev_client_area_pref', true);
            $area_city   = get_user_meta($user_id, 'gcrev_client_area_city', true);
            $area_custom = get_user_meta($user_id, 'gcrev_client_area_custom', true);
            $fallback = '';
            if ($area_type === 'nationwide') {
                $fallback = '全国';
            } elseif ($area_type === 'city' && $area_pref) {
                $fallback = $area_pref . ($area_city ? ' ' . $area_city : '');
            } elseif ($area_type === 'prefecture' && $area_pref) {
                $fallback = $area_pref;
            } elseif ($area_type === 'custom' && $area_custom) {
                $fallback = $area_custom;
            }
            if ($fallback) {
                $extra['area'] = $fallback;
            }
        }

        // 追加情報
        if (!empty($extra) && is_array($extra)) {
            $extra_lines = [];
            $extra_labels = [
                'service'             => '主なサービス・商品',
                'price_range'         => '価格帯',
                'area'                => '対応エリア',
                'competitor_features' => '競合との違い・強み',
                'avoid_notes'         => '避けたい表現・方針',
            ];
            foreach ($extra_labels as $key => $label) {
                $val = sanitize_text_field($extra[$key] ?? '');
                if ($val) {
                    $extra_lines[] = "・{$label}: {$val}";
                }
            }
            if (!empty($extra_lines)) {
                $prompt_parts[] = "";
                $prompt_parts[] = "【追加情報】";
                $prompt_parts[] = implode("\n", $extra_lines);
            }
        }

        $prompt_parts[] = "";
        $prompt_parts[] = "---";
        $prompt_parts[] = "以下のフォーマットで、800〜1600字程度の詳細ペルソナを出力してください。";
        $prompt_parts[] = "テンプレート的な表現は避け、この業種・業態・詳細情報に固有の具体的な人物像を描写してください。";
        $prompt_parts[] = "業種・業態・詳細が指定されている場合は、その業界特有のサービス内容・顧客ニーズ・来店動機・不安要素を具体的に反映してください。";
        $prompt_parts[] = "「対応エリア」が指定されている場合は、その地域に住んでいる、またはその地域でサービスを探している人物として、地域特有の生活環境・交通事情・地名などを具体的に反映してください。";
        $prompt_parts[] = "";
        $prompt_parts[] = "■ 基本プロフィール";
        $prompt_parts[] = "年齢・性別・職業・家族構成・居住エリア（対応エリアが指定されている場合はその地域内の具体的な地名を使用）など";
        $prompt_parts[] = "";
        $prompt_parts[] = "■ 日常と課題";
        $prompt_parts[] = "普段の生活・仕事の中で感じている不満や課題";
        $prompt_parts[] = "";
        $prompt_parts[] = "■ 情報収集の行動パターン";
        $prompt_parts[] = "どのように検索し、比較し、意思決定するか";
        $prompt_parts[] = "";
        $prompt_parts[] = "■ このサービスに求めること";
        $prompt_parts[] = "期待する価値、不安に思うこと、決め手になる要素";
        $prompt_parts[] = "";
        $prompt_parts[] = "■ 響くメッセージ・表現";
        $prompt_parts[] = "この人に刺さるキーワードや訴求ポイント";

        $prompt = implode("\n", $prompt_parts);

        try {
            $result = $this->ai->call_gemini_api($prompt);

            if (empty($result)) {
                delete_transient($throttle_key);
                return new WP_REST_Response([
                    'success' => false,
                    'message' => 'AIからの応答が空でした。時間をおいて再度お試しください。',
                ], 500);
            }

            return new WP_REST_Response([
                'success'        => true,
                'generated_text' => $result,
                'generated_at'   => current_time('Y-m-d H:i:s'),
            ], 200);

        } catch (\Exception $e) {
            delete_transient($throttle_key);
            error_log("[GCREV] Persona generation failed for user_id={$user_id}: " . $e->getMessage());
            return new WP_REST_Response([
                'success' => false,
                'message' => 'ペルソナ生成中にエラーが発生しました: ' . $e->getMessage(),
            ], 500);
        }
    }

    /**
     * AI による業種提案
     */
    public function suggest_industry( WP_REST_Request $request ): WP_REST_Response {
        $user_id = get_current_user_id();

        // スロットル（10秒）
        $throttle_key = 'gcrev_suggest_ind_' . $user_id;
        if ( get_transient( $throttle_key ) ) {
            return new WP_REST_Response( [
                'success' => false,
                'message' => '連続リクエストはできません。少し待ってから再度お試しください。',
            ], 429 );
        }
        set_transient( $throttle_key, 1, 10 );

        $keyword = sanitize_text_field( $request->get_json_params()['keyword'] ?? '' );
        if ( mb_strlen( $keyword ) < 2 || mb_strlen( $keyword ) > 100 ) {
            return new WP_REST_Response( [
                'success' => false,
                'message' => 'キーワードは2〜100文字で入力してください。',
            ], 400 );
        }

        $industry_master = gcrev_get_industry_master();
        $btype_master    = gcrev_get_business_type_master();

        // マスターデータをコンパクトにシリアライズ
        $categories = [];
        foreach ( $industry_master as $key => $data ) {
            $categories[ $key ] = [
                'label'         => $data['label'],
                'subcategories' => $data['subcategories'],
            ];
        }
        $cat_json = wp_json_encode( $categories, JSON_UNESCAPED_UNICODE );
        $bt_json  = wp_json_encode( $btype_master, JSON_UNESCAPED_UNICODE );

        $prompt = <<<PROMPT
あなたは日本のビジネス分類の専門家です。

ユーザーが入力したキーワードから、最も適切な業種分類を提案してください。

【キーワード】
{$keyword}

【業種マスターデータ（この中から選ぶこと）】
{$cat_json}

【ビジネス形態マスターデータ（この中から選ぶこと、複数可）】
{$bt_json}

【出力ルール】
1. category: 業種マスターのキーから最も適切な1つを選ぶ
2. subcategories: 選んだcategoryのsubcategoriesキーから適切なものを1〜3個選ぶ
3. detail: そのビジネスの代表的な特徴・サービス内容を「/」区切りで簡潔に記述（日本語、最大100文字）。例: 小児歯科 / 矯正歯科 / 予防歯科
4. business_types: ビジネス形態マスターのキーから該当するものを1〜4個選ぶ
5. confidence: 提案の確信度（high / medium / low）

マスターデータに存在しないキーは絶対に使わないこと。
JSONのみ出力すること（コードブロック・説明文は不要）。

出力形式:
{"category":"キー","subcategories":["キー1","キー2"],"detail":"説明文","business_types":["キー1","キー2"],"confidence":"high"}
PROMPT;

        try {
            $raw = $this->ai->call_gemini_api( $prompt, [
                'temperature'     => 0.3,
                'maxOutputTokens' => 2048,
            ] );

            // JSON パース（コードブロックが含まれる場合も対応）
            $json_str = $raw;
            if ( preg_match( '/```(?:json)?\s*(.*?)\s*```/s', $raw, $m ) ) {
                $json_str = $m[1];
            }
            $suggestion = json_decode( trim( $json_str ), true );
            if ( ! is_array( $suggestion ) ) {
                throw new \Exception( 'AI応答のJSONパース失敗: ' . mb_substr( $raw, 0, 200 ) );
            }

            // マスターデータに対してバリデーション
            $result = [
                'category'       => '',
                'category_label' => '',
                'subcategories'  => [],
                'detail'         => '',
                'business_types' => [],
                'confidence'     => sanitize_text_field( $suggestion['confidence'] ?? 'low' ),
            ];

            $cat = $suggestion['category'] ?? '';
            if ( isset( $industry_master[ $cat ] ) ) {
                $result['category']       = $cat;
                $result['category_label'] = $industry_master[ $cat ]['label'];

                $valid_subs = $industry_master[ $cat ]['subcategories'] ?? [];
                foreach ( ( $suggestion['subcategories'] ?? [] ) as $sub ) {
                    if ( isset( $valid_subs[ $sub ] ) ) {
                        $result['subcategories'][] = [
                            'key'   => $sub,
                            'label' => $valid_subs[ $sub ],
                        ];
                    }
                }
            }

            $detail = sanitize_text_field( $suggestion['detail'] ?? '' );
            if ( mb_strlen( $detail ) > 160 ) {
                $detail = mb_substr( $detail, 0, 160 );
            }
            $result['detail'] = $detail;

            $valid_bt = array_keys( $btype_master );
            foreach ( ( $suggestion['business_types'] ?? [] ) as $bt ) {
                if ( in_array( $bt, $valid_bt, true ) ) {
                    $result['business_types'][] = [
                        'key'   => $bt,
                        'label' => $btype_master[ $bt ],
                    ];
                }
            }

            return new WP_REST_Response( [
                'success'    => true,
                'suggestion' => $result,
            ] );

        } catch ( \Throwable $e ) {
            file_put_contents( '/tmp/gcrev_chat_debug.log',
                date( 'Y-m-d H:i:s' ) . " suggest_industry ERROR: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            delete_transient( $throttle_key );
            return new WP_REST_Response( [
                'success' => false,
                'message' => '業種の提案に失敗しました。もう一度お試しください。',
            ], 500 );
        }
    }

    /**
     * POST /gcrev_insights/v1/analyze-website
     *
     * ホームページ URL を取得し、Gemini に分析させてクライアント情報一式を推定する。
     * 推定結果は保存せず、フロントに返すのみ。ユーザーが確認・編集後に通常の save-client-settings で保存する。
     */
    public function rest_analyze_website( WP_REST_Request $request ): WP_REST_Response {
        $user_id = get_current_user_id();
        if ( $user_id <= 0 ) {
            return new WP_REST_Response( [ 'success' => false, 'message' => 'ログインが必要です。' ], 401 );
        }

        // 30秒スロットル
        $throttle_key = 'gcrev_analyze_site_' . $user_id;
        if ( get_transient( $throttle_key ) ) {
            return new WP_REST_Response( [
                'success' => false,
                'message' => '連続実行はできません。30秒後に再度お試しください。',
            ], 429 );
        }
        set_transient( $throttle_key, 1, 30 );

        $params = $request->get_json_params();
        $url    = esc_url_raw( $params['url'] ?? '' );
        if ( $url === '' ) {
            $client = function_exists( 'gcrev_get_client_settings' ) ? gcrev_get_client_settings( $user_id ) : [];
            $url = (string) ( $client['site_url'] ?? '' );
        }
        if ( $url === '' ) {
            delete_transient( $throttle_key );
            return new WP_REST_Response( [
                'success' => false,
                'message' => 'URL が指定されておらず、クライアント情報にも site_url が未登録です。',
            ], 400 );
        }

        $service_file = get_template_directory() . '/inc/gcrev-api/modules/class-client-info-extractor-service.php';
        if ( ! file_exists( $service_file ) ) {
            delete_transient( $throttle_key );
            return new WP_REST_Response( [ 'success' => false, 'message' => '抽出サービスが見つかりません。' ], 500 );
        }
        require_once $service_file;

        if ( ! class_exists( 'Gcrev_Client_Info_Extractor_Service' ) ) {
            delete_transient( $throttle_key );
            return new WP_REST_Response( [ 'success' => false, 'message' => '抽出サービスクラスが読み込めません。' ], 500 );
        }

        @set_time_limit( 180 );
        try {
            $service = new \Gcrev_Client_Info_Extractor_Service();
            $result  = $service->extract( $url );

            if ( ! $result['success'] ) {
                return new WP_REST_Response( $result, 502 );
            }

            return new WP_REST_Response( $result, 200 );
        } catch ( \Throwable $e ) {
            file_put_contents(
                '/tmp/gcrev_client_extract_debug.log',
                date( 'Y-m-d H:i:s' ) . ' analyze_website ERROR: ' . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return new WP_REST_Response( [
                'success' => false,
                'message' => 'サーバーエラー: ' . $e->getMessage(),
            ], 500 );
        }
    }

    /**
     * AIレポート生成用のクライアント情報を構築（クライアント設定 + 月次設定を統合）
     *
     * @param int $user_id ユーザーID
     * @return array client_info 配列
     */
    public function build_client_info_for_report(int $user_id): array {
        $client = gcrev_get_client_settings($user_id);

        // ドメイン判定（統合型 / 分離型）
        $site_url     = $client['site_url'] ?? '';
        $maps_domain  = get_user_meta($user_id, '_gcrev_maps_domain', true) ?: '';

        // 解析対象サイトURLからドメインを抽出（正規化）
        $site_domain = '';
        if ($site_url) {
            $parsed = wp_parse_url($site_url);
            $site_domain = isset($parsed['host']) ? strtolower($parsed['host']) : '';
            $site_domain = preg_replace('/^www\./', '', $site_domain);
        }
        // maps_domain も正規化（保存時に正規化済みだが念のため）
        $maps_norm = $maps_domain ? strtolower(preg_replace('/^www\./', '', $maps_domain)) : '';

        // 判定: maps未入力 or 同一ドメイン → 統合型、異なる → 分離型
        if (empty($maps_norm) || $maps_norm === $site_domain) {
            $report_type = 'integrated'; // 統合型
        } else {
            $report_type = 'separated';  // 分離型
        }

        return [
            'site_url'         => $site_url,
            'site_domain'      => $site_domain,
            'maps_domain'      => $maps_domain ?: $site_domain,
            'report_type'      => $report_type,
            'area_label'       => gcrev_get_client_area_label($client),
            'industry'         => $client['industry'],
            'business_type'    => $client['business_type'],
            'issue'            => get_user_meta($user_id, 'report_issue', true),
            'goal_monthly'     => get_user_meta($user_id, 'report_goal_monthly', true),
            'focus_numbers'    => get_user_meta($user_id, 'report_focus_numbers', true),
            'current_state'    => get_user_meta($user_id, 'report_current_state', true),
            'goal_main'        => get_user_meta($user_id, 'report_goal_main', true),
            'additional_notes'  => get_user_meta($user_id, 'report_additional_notes', true),
            'output_mode'       => get_user_meta($user_id, 'report_output_mode', true) ?: 'normal',
            'exclude_foreign'   => get_user_meta($user_id, 'report_exclude_foreign', true) === '1',
            // 業種詳細・成長ステージ・CV定義
            'industry_subcategory'   => $client['industry_subcategory'] ?? [],
            'industry_detail'        => $client['industry_detail'] ?? '',
            'stage'                  => $client['stage'] ?? '',
            'main_conversions'       => $client['main_conversions'] ?? '',
            // ペルソナ情報（全フィールド）
            'persona_one_liner'        => $client['persona_one_liner'] ?? '',
            'persona_detail_text'      => $client['persona_detail_text'] ?? '',
            'persona_age_ranges'       => $client['persona_age_ranges'] ?? [],
            'persona_genders'          => $client['persona_genders'] ?? [],
            'persona_attributes'       => $client['persona_attributes'] ?? [],
            'persona_decision_factors' => $client['persona_decision_factors'] ?? [],
            'persona_reference_urls'   => $client['persona_reference_urls'] ?? [],
        ];
    }

    /**
     * 今月のレポート生成回数を取得
     */
    public function get_generation_count(WP_REST_Request $request): WP_REST_Response {
        $user_id = get_current_user_id();
        
        // 前月の年月を取得（レポートは前月分として保存されるため）
        $tz = wp_timezone();
        $now = new DateTime('now', $tz);
        $prev_month = new DateTime('first day of last month', $tz);
        $year_month = $prev_month->format('Y-m');
        
        error_log("[GCREV] get_generation_count: user_id={$user_id}, year_month={$year_month}");
        
        // 前月生成されたレポート数を取得
        $args = [
            'post_type'      => 'gcrev_report',
            'post_status'    => 'publish',
            'author'         => $user_id,
            'meta_query'     => [
                [
                    'key'     => '_gcrev_year_month',
                    'value'   => $year_month,
                    'compare' => '='
                ]
            ],
            'posts_per_page' => -1,
            'fields'         => 'ids'
        ];
        
        $query = new WP_Query($args);
        $current_count = $query->found_posts;
        
        error_log("[GCREV] get_generation_count: found {$current_count} reports for year_month={$year_month}");
        
        // 上限（プラン別に変更可能）
        $max_count = 10;
        $remaining = max(0, $max_count - $current_count);
        
        return new WP_REST_Response([
            'success' => true,
            'data' => [
                'current_count' => $current_count,
                'max_count'     => $max_count,
                'remaining'     => $remaining
            ]
        ], 200);
    }
    // =========================================================
    // レポート生成（Multi-pass）
    // =========================================================
    public function generate_report(WP_REST_Request $request): WP_REST_Response {
        @set_time_limit( 300 );

        $user_id = get_current_user_id();
        $params  = $request->get_json_params();

        $prev_data   = $params['previous_month'] ?? null;
        $two_data    = $params['two_months_ago'] ?? null;
        $year_month  = $params['year_month']     ?? null;

        // 当月以降のレポート生成を禁止
        if ( $year_month ) {
            $now_ym = ( new DateTimeImmutable( 'now', wp_timezone() ) )->format( 'Y-m' );
            if ( $year_month >= $now_ym ) {
                return new WP_REST_Response([
                    'success' => false,
                    'message' => '当月のレポートは生成できません。月次レポートは確定済みの前月以前が対象です。',
                ], 400);
            }
        }

        if (!is_array($prev_data) || !is_array($two_data)) {
            return new WP_REST_Response([
                'success' => false,
                'message' => 'リクエストデータが不正です',
            ], 400);
        }

        // クライアント設定 + 月次設定をサーバー側で統合構築
        $client_info = $this->build_client_info_for_report($user_id);

        // 海外アクセス除外 + 解析対象/除外URL条件 を GA4 + GSC に適用してから
        // 月次レポートのデータを取り直す。どちらか片方だけでも有効なら再取得する。
        $exclude_foreign = ! empty( $client_info['exclude_foreign'] );
        $inc = get_user_meta( $user_id, '_gcrev_include_paths', true );
        $exc = get_user_meta( $user_id, '_gcrev_exclude_paths', true );
        $inc = is_array( $inc ) ? $inc : [];
        $exc = is_array( $exc ) ? $exc : [];
        $has_path_filter = ! empty( $inc ) || ! empty( $exc );

        $report_filter_set = $exclude_foreign;        // restore_country_filter に渡すフラグ
        $report_path_filters_applied = false;

        if ( $exclude_foreign || $has_path_filter ) {
            try {
                $config = $this->config->get_user_config( $user_id );

                if ( $exclude_foreign ) {
                    $this->ga4->set_country_filter( 'Japan' );
                }

                if ( $has_path_filter ) {
                    $this->ga4->set_include_paths_filter( $inc );
                    $this->ga4->set_exclude_paths_filter( $exc );
                    $this->gsc->set_include_paths_filter( $inc );
                    $this->gsc->set_exclude_paths_filter( $exc );
                    $this->path_filters_set = true; // restore_country_filter() で解除されるよう状態同期
                    $report_path_filters_applied = true;
                }

                $prev_data = $this->fetch_dashboard_data_internal( $config, 'previousMonth' );
                $two_data  = $this->fetch_dashboard_data_internal( $config, 'twoMonthsAgo' );
            } catch ( \Throwable $e ) {
                if ( $exclude_foreign ) {
                    $this->ga4->set_country_filter( null );
                }
                if ( $report_path_filters_applied ) {
                    $this->ga4->clear_include_paths_filter();
                    $this->ga4->set_page_path_filter( null );
                    $this->gsc->clear_path_filters();
                    $this->path_filters_set = false;
                    $report_path_filters_applied = false;
                }
                error_log( '[GCREV] generate_report: filter refetch failed: ' . $e->getMessage() );
                $report_filter_set = false;
            }
        }

        try {
            error_log("[GCREV] Generating new report for user_id={$user_id}");

            // ターゲットエリア（都道府県）の判定 — クライアント設定から取得
            $client_settings = gcrev_get_client_settings($user_id);
            $target_area = gcrev_detect_area_from_client_settings($client_settings);

            // -------------------------------------------------
            // 追加仕様：Key events 取得（お問い合わせ / 資料DL 等）
            // ※ページ側の構造は一切変更せず、レポートHTMLだけで反映
            // -------------------------------------------------
            $config = $this->config->get_user_config($user_id);
            $ga4_id = $config['ga4_id'];

            $prev_start = (string)($prev_data['current_period']['start'] ?? '');
            $prev_end   = (string)($prev_data['current_period']['end']   ?? '');
            $two_start  = (string)($two_data['current_period']['start']  ?? '');
            $two_end    = (string)($two_data['current_period']['end']    ?? '');

            $prev_key_events = ($prev_start && $prev_end) ? $this->ga4->fetch_ga4_key_events($ga4_id, $prev_start, $prev_end) : [];
            $two_key_events  = ($two_start  && $two_end)  ? $this->ga4->fetch_ga4_key_events($ga4_id, $two_start,  $two_end)  : [];

            $selected_events = $this->ga4->select_report_key_events($prev_key_events, $two_key_events);
            // ['contact' => ['name'=>..., 'label'=>...], 'download' => [...], 'others'=>[]]
            // -------------------------------------------------
            // 追加：実質CV判定 → client_info に注入（AIレポート生成で使用）
            // -------------------------------------------------
            $report_year_month = $year_month;
            if (empty($report_year_month) && $prev_start) {
                $report_year_month = substr($prev_start, 0, 7);
            }
            if (!empty($report_year_month)) {
                $eff = $this->get_effective_cv_monthly($report_year_month, $user_id);
                $client_info['effective_cv'] = [
                    'source'     => $eff['source'],
                    'cv'         => $eff['total'],
                    'has_actual' => ($eff['source'] !== 'ga4'),
                    'detail'     => $eff['breakdown_manual'] ?? [],
                    'components' => $eff['components'],
                    'daily'      => $eff['daily'],
                ];
                error_log("[GCREV] generate_report: effective_cv source={$eff['source']}, total={$eff['total']}");
            }

            // ページ改善分析データ取得 → client_info に注入
            $pi = $this->get_page_improvement_summary( $user_id, [ 'limit' => 5, 'full_summary' => true ] );
            if ( ! empty( $pi['pages'] ) ) {
                $client_info['page_insights'] = $this->condense_page_insights_for_report( $pi );
            }

            // セクション単位で "文章部" を生成（プロバイダ自動選択: ChatGPT or Gemini）
            $sections_html = $this->generator->generate_report($prev_data, $two_data, $client_info, $target_area);

            // 最終HTML：sample_report.html のレイアウトに合わせて組み立て
            $report_html = $this->generator->build_sample_layout_report_html(
                $prev_data,
                $two_data,
                $client_info,
                $sections_html,
                $target_area,
                $selected_events,
                $prev_key_events,
                $two_key_events
            );


            // === 初心者向けモード：全文リライト（Markdown出力） ===
            $beginner_markdown = '';
            $is_easy_mode = (($client_info['output_mode'] ?? 'normal') === 'easy');
            if ($is_easy_mode) {
                $rw_year_month = $year_month;
                if (empty($rw_year_month) && $prev_start) {
                    $rw_year_month = substr($prev_start, 0, 7);
                }
                if (!empty($rw_year_month)) {
                    $beginner_markdown = $this->generator->rewrite_report_for_beginner(
                        $sections_html,
                        $target_area,
                        $user_id,
                        $rw_year_month
                    );
                }
                if ($beginner_markdown !== '') {
                    error_log("[GCREV] generate_report: beginner_markdown generated, length=" . mb_strlen($beginner_markdown));
                }
            }

            // === 手動生成時も履歴保存 ===
            $highlights = $this->highlights_mod->extract_highlights_from_html($report_html, $user_id);
            $saved_post_id = $this->repo->save_report_to_history($user_id, $report_html, $client_info, 'manual', $year_month, $highlights, $beginner_markdown);

            // === AI生成メタ情報保存 ===
            if ( $saved_post_id > 0 ) {
                $ai_meta = $this->generator->get_last_ai_meta();
                if ( ! empty( $ai_meta ) ) {
                    update_post_meta( $saved_post_id, '_gcrev_report_ai_meta', wp_json_encode( $ai_meta, JSON_UNESCAPED_UNICODE ) );
                }
            }

            // === KPIスナップショット保存 ===
            if ( $saved_post_id > 0 ) {
                $this->save_kpi_snapshot_for_report( $saved_post_id, $prev_data, $user_id, $year_month );
            }

            // === インフォグラフィックJSON生成・保存 ===
            try {
                $infographic = $this->generate_infographic_json($prev_data, $two_data, $client_info, $user_id);
                if ($infographic) {
                    // year_month が 'YYYY-MM' 形式で来る場合をパース
                    $ig_year  = $year_month ? (int)substr($year_month, 0, 4) : 0;
                    $ig_month = $year_month ? (int)substr($year_month, 5, 2) : 0;
                    if ($ig_year > 0 && $ig_month > 0) {
                        $this->save_monthly_infographic($ig_year, $ig_month, $user_id, $infographic);
                        error_log("[GCREV] generate_report: Infographic saved for user_id={$user_id}, {$year_month}");
                    } else {
                        // year_month不明の場合は前月を使用
                        $tz_ig = wp_timezone();
                        $prev_dt = new DateTimeImmutable('first day of last month', $tz_ig);
                        $this->save_monthly_infographic((int)$prev_dt->format('Y'), (int)$prev_dt->format('n'), $user_id, $infographic);
                        error_log("[GCREV] generate_report: Infographic saved (fallback prev month) for user_id={$user_id}");
                    }
                }
            } catch (\Exception $ig_e) {
                error_log("[GCREV] generate_report: Infographic error: " . $ig_e->getMessage());
            }

            $response_data = [
                'success'     => true,
                'report_html' => $report_html,
            ];
            if ($beginner_markdown !== '') {
                $response_data['beginner_markdown'] = $beginner_markdown;
            }

            return new WP_REST_Response($response_data, 200);

        } catch (\Exception $e) {
            error_log("[GCREV] Report generation ERROR for user_id={$user_id}: " . $e->getMessage());
            return new WP_REST_Response([
                'success' => false,
                'message' => $e->getMessage(),
            ], 500);
        } finally {
            $this->restore_country_filter( $report_filter_set );
        }
    }

    /**
     * REST: 当月の最新レポート取得
     */
    public function get_current_report(WP_REST_Request $request): WP_REST_Response {

        $user_id = get_current_user_id();
        $tz = wp_timezone();
        $now = new DateTimeImmutable('now', $tz);
        $year_month = $now->format('Y-m');

        $args = [
            'post_type'      => 'gcrev_report',
            'posts_per_page' => 1,
            'meta_query'     => [
                [
                    'key'   => '_gcrev_user_id',
                    'value' => $user_id,
                ],
                [
                    'key'   => '_gcrev_year_month',
                    'value' => $year_month,
                ],
                [
                    'key'   => '_gcrev_is_current',
                    'value' => 1,
                ],
            ],
        ];

        $posts = get_posts($args);

        if (empty($posts)) {
            return new WP_REST_Response([
                'success' => true,
                'report'  => null,
            ], 200);
        }

        $post = $posts[0];
        $report = $this->repo->format_report_data($post);

        return new WP_REST_Response([
            'success' => true,
            'report'  => $report,
        ], 200);
    }

    /**
     * REST: レポート履歴一覧取得（最新12件）
     */
    public function get_report_history(WP_REST_Request $request): WP_REST_Response {

        $user_id = get_current_user_id();

        $args = [
            'post_type'      => 'gcrev_report',
            'posts_per_page' => 12,
            'orderby'        => 'meta_value',
            'meta_key'       => '_gcrev_created_at',
            'order'          => 'DESC',
            'meta_query'     => [
                [
                    'key'   => '_gcrev_user_id',
                    'value' => $user_id,
                ],
            ],
        ];

        $posts = get_posts($args);

        $reports = array_map([$this->repo, 'format_report_data'], $posts);

        return new WP_REST_Response([
            'success' => true,
            'reports' => $reports,
        ], 200);
    }

    /**
     * REST: 特定レポート取得
     */
    public function get_report_by_id(WP_REST_Request $request): WP_REST_Response {

        $user_id   = get_current_user_id();
        $report_id = (int) $request->get_param('report_id');

        $post = get_post($report_id);

        if (!$post || $post->post_type !== 'gcrev_report') {
            return new WP_REST_Response([
                'success' => false,
                'message' => 'レポートが見つかりません',
            ], 404);
        }

        // 権限チェック：本人のレポートのみ
        $owner_id = (int) get_post_meta($post->ID, '_gcrev_user_id', true);
        if ($owner_id !== $user_id) {
            return new WP_REST_Response([
                'success' => false,
                'message' => 'アクセス権限がありません',
            ], 403);
        }

        $report = $this->repo->format_report_data($post);

        return new WP_REST_Response([
            'success' => true,
            'report'  => $report,
        ], 200);
    }

    /**
     * === Cronから呼ばれる：毎月1日に全ユーザーの当月ドラフトを自動生成 ===
     * 
     * 注意：実際は毎日Cronを動かし、日付チェックで1日のみ実行する設計
     */
    /** Transientロック: 重複実行防止 */
    private const LOCK_REPORT_GEN      = 'gcrev_lock_report_gen';
    private const LOCK_REPORT_FINALIZE = 'gcrev_lock_report_finalize';
    private const LOCK_PREFETCH        = 'gcrev_lock_prefetch';
    private const LOCK_TTL             = 7200; // 2時間（チャンク処理の全完了を待つため）
    private const STALE_LOCK_THRESHOLD = 1800; // 30分: ハートビート更新がない場合に stale lock と判定

    /** レポート生成チャンクサイズ（重い処理なのでプリフェッチより少なく） */
    public const REPORT_CHUNK_LIMIT = 3;

    /**
     * ロックを取得する（タイムスタンプ付き heartbeat 方式）
     *
     * ロック値に現在のタイムスタンプを保存し、stale lock 検出に使用する。
     */
    private function acquire_lock( string $lock_key ): bool {
        $existing = get_transient( $lock_key );
        if ( $existing !== false ) {
            // stale lock チェック: 前回の heartbeat から STALE_LOCK_THRESHOLD 秒以上経過していたら自動解除
            $lock_time = is_numeric( $existing ) && (int) $existing > 1000000000 ? (int) $existing : 0;
            if ( $lock_time > 0 && ( time() - $lock_time ) > self::STALE_LOCK_THRESHOLD ) {
                $this->prefetch_log( "[LOCK] Stale lock detected: key={$lock_key}, locked_at=" . date( 'Y-m-d H:i:s', $lock_time ) . ", age=" . ( time() - $lock_time ) . "s — auto-releasing" );
                delete_transient( $lock_key );
                // stale lock の Cron Logger 記録
                if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                    // 前回の log_id があれば finish させる
                    $log_id_keys = [
                        'gcrev_lock_prefetch'         => 'gcrev_current_prefetch_log_id',
                        'gcrev_lock_monthly_prefetch'  => 'gcrev_current_monthly_prefetch_log_id',
                    ];
                    foreach ( $log_id_keys as $lk => $lid_key ) {
                        if ( $lock_key === $lk ) {
                            $old_log_id = (int) get_transient( $lid_key );
                            if ( $old_log_id > 0 ) {
                                Gcrev_Cron_Logger::finish( $old_log_id, 'stale_lock_released' );
                                delete_transient( $lid_key );
                            }
                        }
                    }
                    // スロット版のlog_id解放
                    if ( preg_match( '/slot_(\d+)$/', $lock_key, $m ) ) {
                        $slot_num = $m[1];
                        foreach ( [ "gcrev_current_prefetch_slot_{$slot_num}_log_id", "gcrev_current_monthly_prefetch_slot_{$slot_num}_log_id" ] as $lid_key ) {
                            $old_log_id = (int) get_transient( $lid_key );
                            if ( $old_log_id > 0 ) {
                                Gcrev_Cron_Logger::finish( $old_log_id, 'stale_lock_released' );
                                delete_transient( $lid_key );
                            }
                        }
                    }
                }
            } else {
                return false; // 有効なロックが存在 → 取得失敗
            }
        }
        set_transient( $lock_key, time(), self::LOCK_TTL );
        return true;
    }

    /**
     * ロックの heartbeat を更新する（チャンク処理ごとに呼ぶ）
     */
    private function heartbeat_lock( string $lock_key ): void {
        set_transient( $lock_key, time(), self::LOCK_TTL );
    }

    /**
     * ロックを解放する
     */
    private function release_lock( string $lock_key ): void {
        delete_transient( $lock_key );
    }

    /**
     * 指定ロックキーが stale かどうかを判定する（管理画面から使用）
     */
    public static function is_lock_stale( string $lock_key ): bool {
        $val = get_transient( $lock_key );
        if ( $val === false ) {
            return false;
        }
        $lock_time = is_numeric( $val ) && (int) $val > 1000000000 ? (int) $val : 0;
        if ( $lock_time === 0 ) {
            // 旧形式（値が 1）の場合は stale と見なす
            return true;
        }
        return ( time() - $lock_time ) > self::STALE_LOCK_THRESHOLD;
    }

    /**
     * 指定ロックキーのロック開始時刻を取得する（管理画面から使用）
     */
    public static function get_lock_time( string $lock_key ): ?int {
        $val = get_transient( $lock_key );
        if ( $val === false ) {
            return null;
        }
        $lock_time = is_numeric( $val ) && (int) $val > 1000000000 ? (int) $val : null;
        return $lock_time;
    }

    /**
     * プリフェッチ用デバッグログ出力ヘルパー
     *
     * KUSANAGI 環境で error_log() が効かない問題に対応し、
     * /tmp/gcrev_cron_debug.log に統一出力する。
     */
    private function prefetch_log( string $message ): void {
        file_put_contents(
            '/tmp/gcrev_cron_debug.log',
            date( 'Y-m-d H:i:s' ) . ' ' . $message . "\n",
            FILE_APPEND
        );
    }

    /**
     * 指定ファイルへのプリフェッチログ出力（スロット版用）
     */
    private function prefetch_log_file( string $file, string $message ): void {
        file_put_contents(
            $file,
            date( 'Y-m-d H:i:s' ) . ' [PREFETCH] ' . $message . "\n",
            FILE_APPEND
        );
    }

    /**
     * === Cronから呼ばれる：毎月1日にチャンク生成を起動 ===
     *
     * 全ユーザーを直列処理せず、REPORT_CHUNK_LIMIT ずつ
     * 自己チェーンで分割実行する（prefetch_chunk と同パターン）。
     */
    public function auto_generate_monthly_reports(): void {

        // ─── 重複実行防止ロック ───
        if ( get_transient( self::LOCK_REPORT_GEN ) ) {
            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " auto_generate: LOCKED, skipping duplicate run\n", FILE_APPEND );
            if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                $locked_id = Gcrev_Cron_Logger::start( 'report_generate', [ 'note' => 'locked' ] );
                Gcrev_Cron_Logger::finish( $locked_id, 'locked' );
            }
            return;
        }
        set_transient( self::LOCK_REPORT_GEN, time(), self::LOCK_TTL );

        $tz  = wp_timezone();
        $now = new DateTimeImmutable( 'now', $tz );

        // 前月の年月を取得（レポート対象）
        $prev_dt    = $now->modify( 'first day of last month' );
        $year_month = $prev_dt->format( 'Y-m' );

        // Cron Logger: ジョブ開始
        $log_id = 0;
        if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
            $log_id = Gcrev_Cron_Logger::start( 'report_generate', [
                'chunk_limit' => self::REPORT_CHUNK_LIMIT,
                'year_month'  => $year_month,
                'mode'        => 'queue',
            ] );
            set_transient( 'gcrev_current_report_gen_log_id', $log_id, self::LOCK_TTL );
        }

        file_put_contents( '/tmp/gcrev_report_debug.log',
            date( 'Y-m-d H:i:s' ) . " auto_generate: START on " . $now->format( 'Y-m-d' ) . " — year_month={$year_month}, job_id={$log_id}\n", FILE_APPEND );

        // ─── キューテーブルに全対象ユーザーを登録 ───
        if ( class_exists( 'Gcrev_Report_Queue' ) && $log_id > 0 ) {
            $enqueued = Gcrev_Report_Queue::enqueue_all_users(
                $log_id,
                $year_month,
                [ $this, 'build_client_info_for_report' ]
            );

            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " auto_generate: Enqueued {$enqueued} users for {$year_month}\n", FILE_APPEND );

            // 最初のチャンクをスケジュール（10秒後）
            wp_schedule_single_event(
                time() + 10,
                'gcrev_monthly_report_generate_chunk_event',
                [ $log_id, self::REPORT_CHUNK_LIMIT ]
            );
        } else {
            // Queue クラスが未ロードまたは job_id 取得失敗 → ロック解放
            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " auto_generate: ERROR — Queue class not available or job_id=0\n", FILE_APPEND );
            delete_transient( self::LOCK_REPORT_GEN );
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::finish( $log_id, 'error', 'Queue class not available' );
                delete_transient( 'gcrev_current_report_gen_log_id' );
            }
        }
    }

    /**
     * レポート生成チャンク処理（キューベース）
     *
     * キューテーブルから pending アイテムを取得し、レポートを生成する。
     * 残りキューがあれば次のチャンクを自己スケジュール。
     *
     * @param int $job_id Cron Logger のジョブID（= キューの job_id）
     * @param int $limit  チャンクサイズ
     */
    public function report_generate_chunk( int $job_id, int $limit ): void {

        // Cron Logger: log_id を取得（引数の job_id をそのまま使う）
        $log_id = $job_id;

        file_put_contents( '/tmp/gcrev_report_debug.log',
            date( 'Y-m-d H:i:s' ) . " report_generate_chunk START: job_id={$job_id}, limit={$limit}\n", FILE_APPEND );

        $tz  = wp_timezone();
        $now = new DateTimeImmutable( 'now', $tz );

        // ─── ストール復旧: processing のまま 30分超のアイテムを pending に戻す ───
        if ( class_exists( 'Gcrev_Report_Queue' ) ) {
            $recovered = Gcrev_Report_Queue::recover_stale_items( $job_id );
            if ( $recovered > 0 ) {
                file_put_contents( '/tmp/gcrev_report_debug.log',
                    date( 'Y-m-d H:i:s' ) . " report_generate_chunk: Recovered {$recovered} stale items\n", FILE_APPEND );
            }
        }

        // ─── キューから次のバッチを取得 ───
        if ( ! class_exists( 'Gcrev_Report_Queue' ) ) {
            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " report_generate_chunk: ERROR — Queue class not available\n", FILE_APPEND );
            delete_transient( self::LOCK_REPORT_GEN );
            return;
        }

        $items = Gcrev_Report_Queue::claim_next( $job_id, $limit );

        if ( empty( $items ) ) {
            // 残りアイテムなし → 完了
            delete_transient( self::LOCK_REPORT_GEN );
            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " report_generate_chunk: No more items for job_id={$job_id}. DONE.\n", FILE_APPEND );
            if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( 'gcrev_current_report_gen_log_id' );
            }
            return;
        }

        foreach ( $items as $item ) {
            $queue_id   = (int) $item->id;
            $user_id    = (int) $item->user_id;
            $year_month = $item->year_month;

            // スナップショットからクライアント情報を復元
            $client_info = ! empty( $item->client_info_snapshot )
                ? json_decode( $item->client_info_snapshot, true )
                : [];

            if ( empty( $client_info ) ) {
                Gcrev_Report_Queue::mark_skipped( $queue_id, 'Empty client_info snapshot' );
                if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', 'Empty client_info snapshot' );
                }
                continue;
            }

            // 当月レポートが既に存在するかチェック（手動生成されている可能性）
            $existing = $this->repo->get_reports_by_month( $user_id, $year_month );
            if ( ! empty( $existing ) ) {
                Gcrev_Report_Queue::mark_skipped( $queue_id, 'Report already exists' );
                if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', 'Report already exists' );
                }
                continue;
            }

            // GA4プロパティ設定チェック
            $prev2_check = $this->has_prev2_data( $user_id );
            if ( ! $prev2_check['available'] ) {
                $reason = 'GA4 not ready: ' . ( $prev2_check['reason'] ?? '' );
                Gcrev_Report_Queue::mark_skipped( $queue_id, $reason );
                if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', $reason );
                }
                continue;
            }

            $exclude_foreign_auto    = false;
            $path_filters_set_auto   = false;

            try {
                // 前月・前々月データ取得
                $config = $this->config->get_user_config( $user_id );

                // 海外アクセス除外フィルタ（CV取得まで維持、finally で解除）
                $exclude_foreign_auto = ( $client_info['exclude_foreign'] ?? false );
                if ( $exclude_foreign_auto ) {
                    $this->ga4->set_country_filter( 'Japan' );
                }

                // 解析対象/除外URL条件を GA4 + GSC に適用してから取得する。
                // これにより /media/ 等の除外配下が Cron 月次レポートにも混入しない。
                $inc_auto = get_user_meta( $user_id, '_gcrev_include_paths', true );
                $exc_auto = get_user_meta( $user_id, '_gcrev_exclude_paths', true );
                $inc_auto = is_array( $inc_auto ) ? $inc_auto : [];
                $exc_auto = is_array( $exc_auto ) ? $exc_auto : [];
                if ( ! empty( $inc_auto ) || ! empty( $exc_auto ) ) {
                    $this->ga4->set_include_paths_filter( $inc_auto );
                    $this->ga4->set_exclude_paths_filter( $exc_auto );
                    $this->gsc->set_include_paths_filter( $inc_auto );
                    $this->gsc->set_exclude_paths_filter( $exc_auto );
                    $path_filters_set_auto = true;
                }

                $prev_data = $this->fetch_dashboard_data_internal( $config, 'previousMonth' );
                $two_data  = $this->fetch_dashboard_data_internal( $config, 'twoMonthsAgo' );

                // 実質CV注入
                $auto_ym  = ( new DateTimeImmutable( 'first day of last month', $tz ) )->format( 'Y-m' );
                $eff_auto = $this->get_effective_cv_monthly( $auto_ym, $user_id );
                $client_info['effective_cv'] = [
                    'source'     => $eff_auto['source'],
                    'cv'         => $eff_auto['total'],
                    'has_actual' => ( $eff_auto['source'] !== 'ga4' ),
                    'detail'     => $eff_auto['breakdown_manual'] ?? [],
                    'components' => $eff_auto['components'],
                ];

                // ページ改善分析データ取得 → client_info に注入
                $pi_auto = $this->get_page_improvement_summary( $user_id, [ 'limit' => 5, 'full_summary' => true ] );
                if ( ! empty( $pi_auto['pages'] ) ) {
                    $client_info['page_insights'] = $this->condense_page_insights_for_report( $pi_auto );
                }

                // ターゲットエリア判定（クライアント設定から）
                $auto_client_settings = gcrev_get_client_settings( $user_id );
                $auto_target_area     = gcrev_detect_area_from_client_settings( $auto_client_settings );

                $report_html = $this->generator->generate_report( $prev_data, $two_data, $client_info, $auto_target_area );

                // === 初心者向けモード：全文リライト（Markdown出力） ===
                $auto_beginner_md = '';
                if ( ( $client_info['output_mode'] ?? 'normal' ) === 'easy' ) {
                    $auto_beginner_md = $this->generator->rewrite_report_for_beginner(
                        $report_html,
                        null,
                        $user_id,
                        $auto_ym
                    );
                }

                // 保存（source=auto、スナップショットの client_info を使用）
                $highlights    = $this->highlights_mod->extract_highlights_from_html( $report_html, $user_id );
                $saved_post_id = $this->repo->save_report_to_history( $user_id, $report_html, $client_info, 'auto', null, $highlights, $auto_beginner_md );

                // === AI生成メタ情報保存 ===
                if ( $saved_post_id > 0 ) {
                    $ai_meta = $this->generator->get_last_ai_meta();
                    if ( ! empty( $ai_meta ) ) {
                        update_post_meta( $saved_post_id, '_gcrev_report_ai_meta', wp_json_encode( $ai_meta, JSON_UNESCAPED_UNICODE ) );
                    }
                }

                // === KPIスナップショット保存 ===
                if ( $saved_post_id > 0 ) {
                    $this->save_kpi_snapshot_for_report( $saved_post_id, $prev_data, $user_id, $auto_ym );
                }

                // === インフォグラフィックJSON生成・保存 ===
                try {
                    $infographic = $this->generate_infographic_json( $prev_data, $two_data, $client_info, $user_id );
                    if ( $infographic ) {
                        $prev_dt  = new DateTimeImmutable( 'first day of last month', $tz );
                        $ig_year  = (int) $prev_dt->format( 'Y' );
                        $ig_month = (int) $prev_dt->format( 'n' );
                        $this->save_monthly_infographic( $ig_year, $ig_month, $user_id, $infographic );
                    }
                } catch ( \Exception $ig_e ) {
                    file_put_contents( '/tmp/gcrev_report_debug.log',
                        date( 'Y-m-d H:i:s' ) . " auto_generate: Infographic error user_id={$user_id}: " . $ig_e->getMessage() . "\n", FILE_APPEND );
                }

                // ─── 成功 ───
                Gcrev_Report_Queue::mark_success( $queue_id );
                file_put_contents( '/tmp/gcrev_report_debug.log',
                    date( 'Y-m-d H:i:s' ) . " auto_generate: SUCCESS user_id={$user_id}, year_month={$year_month}\n", FILE_APPEND );
                if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'success' );
                }

            } catch ( \Exception $e ) {
                // ─── 失敗 ───
                Gcrev_Report_Queue::mark_failed( $queue_id, $e->getMessage() );
                file_put_contents( '/tmp/gcrev_report_debug.log',
                    date( 'Y-m-d H:i:s' ) . " auto_generate: ERROR user_id={$user_id}: " . $e->getMessage() . "\n", FILE_APPEND );
                if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'error', $e->getMessage() );
                }
            } finally {
                // 海外アクセス除外フィルタ解除（次ユーザーへの影響を防止）
                if ( $exclude_foreign_auto ) {
                    $this->ga4->set_country_filter( null );
                }
                // 解析対象/除外URL条件フィルタ解除（次ユーザーへの影響を防止）
                if ( $path_filters_set_auto ) {
                    $this->ga4->clear_include_paths_filter();
                    $this->ga4->set_page_path_filter( null );
                    $this->gsc->clear_path_filters();
                }
            }
        }

        // ─── 次チャンクのスケジュール ───
        if ( Gcrev_Report_Queue::has_pending_or_processing( $job_id ) ) {
            wp_schedule_single_event(
                time() + 10,
                'gcrev_monthly_report_generate_chunk_event',
                [ $job_id, $limit ]
            );
            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " report_generate_chunk: Scheduled next chunk for job_id={$job_id}\n", FILE_APPEND );
        } else {
            delete_transient( self::LOCK_REPORT_GEN );
            file_put_contents( '/tmp/gcrev_report_debug.log',
                date( 'Y-m-d H:i:s' ) . " report_generate_chunk: All items processed for job_id={$job_id}. DONE.\n", FILE_APPEND );
            if ( $log_id > 0 && class_exists( 'Gcrev_Cron_Logger' ) ) {
                Gcrev_Cron_Logger::finish( $log_id, 'success' );
                delete_transient( 'gcrev_current_report_gen_log_id' );
            }
        }
    }

    /**
     * === Cronから呼ばれる：月末に未確定レポートを自動確定 ===
     *
     * 注意：実際は毎日Cronを動かし、月末かどうかチェックして実行
     */
    public function auto_finalize_monthly_reports(): void {

        // ─── 重複実行防止ロック ───
        if ( get_transient( self::LOCK_REPORT_FINALIZE ) ) {
            error_log( '[GCREV] auto_finalize: LOCKED, skipping duplicate run' );
            if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
                $locked_id = Gcrev_Cron_Logger::start( 'report_finalize', [ 'note' => 'locked' ] );
                Gcrev_Cron_Logger::finish( $locked_id, 'locked' );
            }
            return;
        }
        set_transient( self::LOCK_REPORT_FINALIZE, 1, self::LOCK_TTL );

        $tz = wp_timezone();
        $now = new DateTimeImmutable('now', $tz);

        // 月末判定（翌日が1日かどうか）
        $tomorrow = $now->add(new DateInterval('P1D'));
        if ((int)$tomorrow->format('d') !== 1) {
            error_log("[GCREV] auto_finalize: Not end of month, skipping.");
            delete_transient( self::LOCK_REPORT_FINALIZE );
            return;
        }

        // Cron Logger: ジョブ開始
        $log_id = 0;
        if ( class_exists( 'Gcrev_Cron_Logger' ) ) {
            $log_id = Gcrev_Cron_Logger::start( 'report_finalize' );
        }

        error_log("[GCREV] auto_finalize_monthly_reports: START on " . $now->format('Y-m-d'));

        // auto_generate は毎月1日に「前月分」レポートを draft で生成する。
        // 例: 3月1日に2月分を生成 → 3月末に2月分を確定。
        // したがって finalize 対象は「前月」のレポート。
        $prev = $now->modify('first day of last month');
        $year_month = $prev->format('Y-m');

        // 全ユーザー取得
        $users = get_users(['fields' => ['ID']]);

        foreach ($users as $u) {
            $user_id = (int) $u->ID;

            // 当月の最新レポート（is_current=1）取得
            $args = [
                'post_type'      => 'gcrev_report',
                'posts_per_page' => 1,
                'meta_query'     => [
                    [
                        'key'   => '_gcrev_user_id',
                        'value' => $user_id,
                    ],
                    [
                        'key'   => '_gcrev_year_month',
                        'value' => $year_month,
                    ],
                    [
                        'key'   => '_gcrev_is_current',
                        'value' => 1,
                    ],
                ],
            ];

            $posts = get_posts($args);
            if (empty($posts)) {
                error_log("[GCREV] auto_finalize: user_id={$user_id} has no current report for {$year_month}, skipping.");
                if ( $log_id > 0 ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', 'No current report' );
                }
                continue;
            }

            $post = $posts[0];
            $state = get_post_meta($post->ID, '_gcrev_report_state', true);

            // 既にfinalなら何もしない
            if ($state === 'final') {
                error_log("[GCREV] auto_finalize: user_id={$user_id} report already final, skipping.");
                if ( $log_id > 0 ) {
                    Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'skip', 'Already final' );
                }
                continue;
            }

            // 確定処理
            update_post_meta($post->ID, '_gcrev_report_state', 'final');
            update_post_meta($post->ID, '_gcrev_finalized_at', $now->format('Y-m-d H:i:s'));

            error_log("[GCREV] auto_finalize: SUCCESS user_id={$user_id}, post_id={$post->ID}, year_month={$year_month}");
            if ( $log_id > 0 ) {
                Gcrev_Cron_Logger::log_user( $log_id, $user_id, 'success' );
            }
        }

        delete_transient( self::LOCK_REPORT_FINALIZE );
        error_log("[GCREV] auto_finalize_monthly_reports: DONE");

        // Cron Logger: ジョブ完了
        if ( $log_id > 0 ) {
            Gcrev_Cron_Logger::finish( $log_id, 'success' );
        }
    }
    // =========================================================
    // v2ダッシュボード統合用メソッド（2881行目の直後に追加）
    // =========================================================

    /**
     * v2ダッシュボード用KPI取得
     * 既存のget_dashboard_dataを活用
     * 
     * @param string $period 期間: last30, prev-month, prev-prev-month
     * @param int|null $user_id ユーザーID
     * @return array KPIデータ
     */
    /**
     * v2ダッシュボード用KPI取得
     *
     * [CACHE_FIRST] cache_first=1 の場合（last180/last365 想定）:
     *   1) transient を最初にチェック → あれば即 return（APIコール完全スキップ）
     *   2) 無い場合のみ API 取得 → 取得後 transient に保存 → return
     *   → キャッシュがあるのに API に行くルートは完全に排除される
     */
    public function get_dashboard_kpi(string $period = 'prev-month', ?int $user_id = null, int $cache_first = 0): array {
        if (!$user_id) {
            $user_id = get_current_user_id();
        }

        // 海外アクセス除外フィルタ（inject_effective_cv_into_kpi まで維持）
        $filter_set = $this->maybe_set_country_filter( $user_id );

        try {

        // 期間変換
        $range_map = [
            'last30'         => 'last30',
            'last90'         => 'last90',
            'last180'        => 'last180',
            'last365'        => 'last365',
            'prev-month'     => 'previousMonth',
            'prev-prev-month'=> 'twoMonthsAgo'
        ];

        $range = $range_map[$period] ?? 'previousMonth';

        // --- [CACHE_FIRST] 長期間の場合：明示的にキャッシュ優先パスを通る ---
        // last90/last180/last365 は自動的に cache_first=1 扱いにする（JS側が付け忘れても安全）
        if ($cache_first || in_array($period, ['last90', 'last180', 'last365'], true)) {
            $cache_key_debug = $this->cache_key_dashboard($user_id, $range);
            $cached = $this->dashboard_cache_get($user_id, $range);
            if ($cached !== null) {
                $cp = $cached['current_period'] ?? [];
                file_put_contents('/tmp/gcrev_dash_debug.log',
                    date('Y-m-d H:i:s') . " [KPI] CACHE HIT period={$period}, range={$range}, key={$cache_key_debug}, dates=" . ($cp['start'] ?? '?') . "~" . ($cp['end'] ?? '?') . "\n",
                    FILE_APPEND
                );
                $cached = $this->inject_effective_cv_into_kpi($cached, $period, $user_id);
                return $cached;
            }
            file_put_contents('/tmp/gcrev_dash_debug.log',
                date('Y-m-d H:i:s') . " [KPI] CACHE MISS period={$period}, range={$range}, key={$cache_key_debug}\n",
                FILE_APPEND
            );
        }

        // cache_first 明示指定でキャッシュが空 → stale (TTL切れだが option_value が残っている) を試す
        // それでも空なら空配列を返してJS非同期に委任
        // （以前は last30/prev-month を同期取得していたが、15-18本のAPI呼び出しで
        //   ページ表示が8-15秒ブロックされるため、全期間をJS非同期に統一）
        if ( $cache_first ) {
            $stale = $this->get_stale_dashboard_cache( $user_id, $range );
            if ( $stale !== null ) {
                file_put_contents('/tmp/gcrev_dash_debug.log',
                    date('Y-m-d H:i:s') . " [KPI] STALE HIT period={$period}, range={$range}, user={$user_id}\n",
                    FILE_APPEND
                );
                $stale['_stale'] = true;
                $stale = $this->inject_effective_cv_into_kpi( $stale, $period, $user_id );
                return $stale;
            }
            file_put_contents('/tmp/gcrev_dash_debug.log',
                date('Y-m-d H:i:s') . " [cache_first] Cache miss (no stale) for user={$user_id}, period={$period} — delegating to JS async\n",
                FILE_APPEND
            );
            return [];
        }

        // 既存メソッドでデータ取得（WP_REST_Requestをモック）
        // ※ get_dashboard_data 内部にもキャッシュチェックがあるが、
        //    上の [CACHE_FIRST] ブロックで先にチェック済みなので
        //    ここに到達 = キャッシュ無し確定。二重チェックは安全側に倒す。
        $request = new WP_REST_Request('GET', '/gcrev_insights/v1/dashboard');
        $request->set_param('range', $range);

        $response = $this->get_dashboard_data($request);

        if ($response instanceof WP_REST_Response) {
            $data = $response->get_data();
            $result = $data['data'] ?? [];

            // [CACHE_FIRST] フォールバック取得時：長期間は追加でキャッシュ保存を保証
            if (in_array($period, ['last180', 'last365'], true) && !empty($result)) {
                $this->dashboard_cache_set($user_id, $range, $result);
            }

            $result = $this->inject_effective_cv_into_kpi($result, $period, $user_id);
            return $result;
        }
        return [];

        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    /**
     * 任意の日付範囲でKPIデータを取得する（月次レポートの過去閲覧時に使用）
     *
     * @param string $start_date 開始日 (Y-m-d)
     * @param string $end_date   終了日 (Y-m-d)
     * @param int    $user_id    ユーザーID
     * @return array KPIデータ
     */
    public function get_dashboard_kpi_by_dates( string $start_date, string $end_date, int $user_id, ?string $cache_scope = null ): array {
        // --- Transient キャッシュ（12+ API呼び出しを回避）---
        $exclude_foreign = get_user_meta( $user_id, 'report_exclude_foreign', true );
        $filter_suffix   = $exclude_foreign ? '_filtered' : '';
        // 解析対象/除外URL条件があればキャッシュキーを差別化（条件内容のハッシュ）
        if ( class_exists( 'Gcrev_Path_Filter' ) ) {
            $filter_suffix .= Gcrev_Path_Filter::cache_suffix( $user_id );
        }
        if ( $cache_scope !== null && $cache_scope !== '' ) {
            // period ベースの安定キー。日付が毎日スライドしても同じキーを使う
            // → cron が書いたキャッシュを翌日 cron までヒットできる
            $cache_key = "gcrev_dash_bydate_{$user_id}_{$cache_scope}{$filter_suffix}";
        } else {
            // 任意日付（レポート過去閲覧など）— 日付ベースキーで区別
            // v2: ga4_phone_tap フィールド追加に伴いキャッシュキーを更新
            $cache_key = "gcrev_dash_bydate_v2_{$user_id}_{$start_date}_{$end_date}{$filter_suffix}";
        }
        $cached = get_transient( $cache_key );
        if ( $cached !== false && is_array( $cached ) ) {
            return $cached;
        }

        $config = $this->config->get_user_config( $user_id );

        $ga4_id  = $config['ga4_id'];
        $gsc_url = $config['gsc_url'];
        $site_url = $config['site_url'] ?? '';

        // 海外アクセス除外フィルタ
        $filter_set = $this->maybe_set_country_filter( $user_id );

        try {

        // 比較期間（同日数の直前期間）
        $comparison = $this->dates->get_comparison_range( $start_date, $end_date );

        // GA4 データ取得
        $ga4_pages   = $this->ga4->fetch_ga4_data( $ga4_id, $start_date, $end_date, $site_url );
        $ga4_summary = $this->ga4->fetch_ga4_summary( $ga4_id, $start_date, $end_date );
        $ga4_prev    = $this->ga4->fetch_ga4_summary( $ga4_id, $comparison['start'], $comparison['end'] );
        $daily       = $this->ga4->fetch_ga4_daily_series( $ga4_id, $start_date, $end_date );

        $devices    = $this->ga4->fetch_ga4_breakdown( $ga4_id, $start_date, $end_date, 'deviceCategory', 'sessions' );
        $medium     = $this->ga4->fetch_ga4_breakdown( $ga4_id, $start_date, $end_date, 'sessionMedium', 'sessions' );
        $geo_region = $this->ga4->fetch_ga4_breakdown( $ga4_id, $start_date, $end_date, 'region', 'sessions' );
        $age        = $this->ga4->fetch_ga4_age_breakdown( $ga4_id, $start_date, $end_date );

        $gsc_data = $this->gsc->fetch_gsc_data( $gsc_url, $start_date, $end_date );
        $trends   = $this->build_trends( $ga4_summary, $ga4_prev );

        // 流入元分析データ
        $source_analysis = [ 'channels_summary' => [], 'sources_detail' => [], 'channels_daily_series' => [] ];
        try {
            $source_current  = $this->ga4->fetch_source_data_from_ga4( $ga4_id, $start_date, $end_date );
            $source_previous = $this->ga4->fetch_source_data_from_ga4( $ga4_id, $comparison['start'], $comparison['end'] );
            $source_analysis = $this->format_source_analysis_data( $source_current, $source_previous );
        } catch ( \Exception $e ) {
            error_log( '[GCREV] get_dashboard_kpi_by_dates source error: ' . $e->getMessage() );
        }

        $result = [
            'current_period' => [
                'start' => $start_date,
                'end'   => $end_date,
            ],
            'comparison_period' => [
                'start' => $comparison['start'],
                'end'   => $comparison['end'],
            ],

            'pageViews'      => $ga4_summary['pageViews'],
            'sessions'       => $ga4_summary['sessions'],
            'users'          => $ga4_summary['users'],
            'newUsers'       => $ga4_summary['newUsers'],
            'returningUsers' => $ga4_summary['returningUsers'],
            'avgDuration'    => $ga4_summary['avgDuration'],
            'conversions'    => $ga4_summary['conversions'] ?? '0',

            'trends'  => $trends,
            'daily'   => $daily,
            'devices' => $devices,
            'medium'  => $medium,
            'geo_region' => $geo_region,
            'age'     => $age,
            'pages'   => $ga4_pages['pages'] ?? [],
            'keywords' => $gsc_data['keywords'] ?? [],

            'channels_summary'      => $source_analysis['channels_summary'] ?? [],
            'sources_detail'        => $source_analysis['sources_detail'] ?? [],
            'channels_daily_series' => $source_analysis['channels_daily_series'] ?? [],
        ];

        // 実質CVの注入（CV設定を反映）
        $tz = wp_timezone();
        $start_dt = new \DateTimeImmutable( $start_date, $tz );
        $end_dt   = new \DateTimeImmutable( $end_date, $tz );
        $is_full_month = ( $start_dt->format('d') === '01' && $end_dt->format('Y-m-d') === $end_dt->format('Y-m-t') );

        if ( $is_full_month ) {
            $year_month = $start_dt->format('Y-m');
            $effective  = $this->get_effective_cv_monthly( $year_month, $user_id );
        } else {
            $effective = $this->get_effective_cv_for_range( $start_date, $end_date, $user_id );
        }

        $result['conversions']    = (string) $effective['total'];
        $result['cv_source']      = $effective['source'];
        $result['cv_detail']      = $effective['breakdown_manual'] ?? [];
        $result['ga4_cv']         = $effective['components']['ga4_total'];
        $result['ga4_phone_tap']  = (int) ( $effective['components']['phone_tap_total'] ?? 0 );
        $result['effective_cv']   = $effective;

        // CV 増減（完全月の場合のみ前月比を計算）
        if ( $is_full_month ) {
            $comp_ym = $start_dt->modify( 'first day of last month' )->format('Y-m');
            $comp_effective = $this->get_effective_cv_monthly( $comp_ym, $user_id );
            $cur = (float) $effective['total'];
            $prv = (float) $comp_effective['total'];

            if ( abs( $prv ) < 0.0001 ) {
                $cv_trend = ( abs( $cur ) < 0.0001 )
                    ? [ 'value' => 0, 'text' => '±0.0%', 'color' => '#666' ]
                    : [ 'value' => 100, 'text' => '+∞', 'color' => '#3b82f6' ];
            } else {
                $val  = ( ( $cur - $prv ) / $prv ) * 100.0;
                $text = ( $val > 0 ? '+' : '' ) . number_format( $val, 1 ) . '%';
                $color = $val > 0 ? '#3b82f6' : ( $val < 0 ? '#ef4444' : '#666' );
                $cv_trend = [ 'value' => $val, 'text' => $text, 'color' => $color ];
            }
            if ( ! isset( $result['trends'] ) ) {
                $result['trends'] = [];
            }
            $result['trends']['conversions'] = $cv_trend;
        }

        // キャッシュ保存（7日。cron が毎日更新する前提の余裕枠）
        set_transient( $cache_key, $result, self::DASHBOARD_CACHE_TTL );

        return $result;

        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    /**
     * KPIレスポンスに実質CVデータを注入する
     * 月単位期間（prev-month等）は get_effective_cv_monthly、
     * 日付レンジ期間（last30等）は get_effective_cv_for_range で取得
     */
    private function inject_effective_cv_into_kpi(array $data, string $period, int $user_id): array {
        $year_month = $this->period_to_year_month($period);

        if ($year_month !== null) {
            // 月単位期間（prev-month 等）→ 従来通り月単位で取得
            $effective = $this->get_effective_cv_monthly($year_month, $user_id);
        } else {
            // 日付レンジ期間（last30, last90 等）→ current_period から日付レンジで取得
            $cp = $data['current_period'] ?? [];
            $start = $cp['start'] ?? '';
            $end   = $cp['end']   ?? '';
            if ($start === '' || $end === '') {
                return $data;
            }
            $effective = $this->get_effective_cv_for_range($start, $end, $user_id);
        }

        $data['conversions']    = (string)$effective['total'];
        $data['cv_source']      = $effective['source']; // 'hybrid' | 'ga4'
        $data['cv_detail']      = $effective['breakdown_manual'] ?? [];
        $data['ga4_cv']         = $effective['components']['ga4_total'];
        $data['ga4_phone_tap']  = (int) ( $effective['components']['phone_tap_total'] ?? 0 );
        $data['effective_cv']   = $effective; // 全データ（テンプレート・スコア計算で利用）

        // 表示ラベル別内訳（ダッシュボードカード・グラフの凡例用）
        // ゴール関連設定で指定した「表示ラベル」ごとにカウントをまとめる
        $breakdown_items = [];
        foreach ($effective['breakdown_by_label'] ?? [] as $key => $item) {
            $cnt = (int) ($item['count'] ?? 0);
            if ($cnt <= 0) continue;
            $label = (string) ($item['label'] ?? $key);
            // 同じ表示ラベルを持つイベントは合算（例: phone_click と 電話タップ の両方にラベル '電話タップ' が付いている場合）
            if (isset($breakdown_items[$label])) {
                $breakdown_items[$label]['count'] += $cnt;
            } else {
                $breakdown_items[$label] = [
                    'label'  => $label,
                    'count'  => $cnt,
                    'source' => (string) ($item['source'] ?? 'ga4'),
                ];
            }
        }
        // count 降順に並び替え → 配列化
        usort($breakdown_items, function ($a, $b) { return $b['count'] <=> $a['count']; });
        $data['cv_breakdown_items'] = array_values($breakdown_items);

        // --- CV増減（trends.conversions）も実質CVベースで再計算 ---
        $comp_period = ($period === 'prev-month' || $period === 'previousMonth')
            ? 'prev-prev-month'
            : null;
        $comp_ym = $comp_period ? $this->period_to_year_month($comp_period) : null;

        if ($comp_ym !== null) {
            $comp_effective = $this->get_effective_cv_monthly($comp_ym, $user_id);
            $cur = (float)$effective['total'];
            $prv = (float)$comp_effective['total'];

            if (abs($prv) < 0.0001) {
                $trend = (abs($cur) < 0.0001)
                    ? ['value' => 0, 'text' => '±0.0%', 'color' => '#666']
                    : ['value' => 100, 'text' => '+∞', 'color' => '#3b82f6'];
            } else {
                $val  = (($cur - $prv) / $prv) * 100.0;
                $text = ($val > 0 ? '+' : '') . number_format($val, 1) . '%';
                $color = $val > 0 ? '#3b82f6' : ($val < 0 ? '#ef4444' : '#666');
                $trend = ['value' => $val, 'text' => $text, 'color' => $color];
            }

            if (!isset($data['trends'])) {
                $data['trends'] = [];
            }
            $data['trends']['conversions'] = $trend;
        }

        return $data;
    }

    /**
     * 月次レポート取得（v2ダッシュボード用）
     * HTMLからテキスト抽出版
     * 
     * @param int $year 年
     * @param int $month 月
     * @param int|null $user_id ユーザーID
     * @return array|null レポートデータ
     */
    public function get_monthly_ai_report(int $year, int $month, ?int $user_id = null): ?array {
        return $this->report_service->get_monthly_ai_report($year, $month, $user_id);
    }


    /**
     * 月次レポート手動生成（v2ダッシュボード用）
     * 
     * @param int|null $user_id ユーザーID
     * @param int|null $year 年
     * @param int|null $month 月
     * @return array 生成結果
     */
    public function generate_monthly_report_manual(?int $user_id = null, ?int $year = null, ?int $month = null): array {
        if (!$user_id) {
            $user_id = get_current_user_id();
        }

        // デフォルトは前月
        $tz = wp_timezone();
        if (!$year || !$month) {
            $prev = new DateTimeImmutable('first day of last month', $tz);
            $year = intval($prev->format('Y'));
            $month = intval($prev->format('n'));
        }

        // 当月以降のレポート生成を禁止（月次レポートは確定済みの前月以前のみ）
        $now_ym  = (new DateTimeImmutable('now', $tz))->format('Y-m');
        $year_month = sprintf('%04d-%02d', $year, $month);
        if ($year_month >= $now_ym) {
            error_log("[GCREV] generate_monthly_report_manual: BLOCKED — {$year_month} is current or future month");
            return [
                'success' => false,
                'message' => '当月のレポートは生成できません。月次レポートは確定済みの前月以前が対象です。',
            ];
        }

        error_log("[GCREV] generate_monthly_report_manual: user_id={$user_id}, year_month={$year_month}");

        // 既存レポート数確認
        $args = [
            'post_type'      => 'gcrev_report',
            'posts_per_page' => -1,
            'post_status'    => 'publish',
            'meta_query'     => [
                'relation' => 'AND',
                [
                    'key'   => '_gcrev_user_id',
                    'value' => $user_id,
                ],
                [
                    'key'   => '_gcrev_year_month',
                    'value' => $year_month,
                ],
            ],
        ];

        $existing = get_posts($args);
        $current_version = count($existing);

        // 10回上限チェック
        if ($current_version >= 10) {
            return [
                'success' => false,
                'message' => 'このレポートは生成上限（10回）に達しています'
            ];
        }

        // クライアント情報取得（クライアント設定 + 月次設定を統合）
        $client_info = $this->build_client_info_for_report($user_id);

        if (empty($client_info['site_url'])) {
            return [
                'success' => false,
                'message' => 'クライアント設定のサイトURLが未設定です'
            ];
        }

        // -------------------------------------------------
        // GA4プロパティ設定チェック
        // -------------------------------------------------
        $prev2_check = $this->has_prev2_data($user_id);
        if (!$prev2_check['available']) {
            error_log("[GCREV] generate_monthly_report_manual: GA4_NOT_READY for user_id={$user_id}: " . ($prev2_check['reason'] ?? ''));
            return [
                'success' => false,
                'code'    => 'NO_PREV2_DATA',
                'message' => $prev2_check['reason'] ?? 'GA4プロパティの設定を確認してください。',
            ];
        }

        // 海外アクセス除外 + 解析対象/除外URL条件を GA4 + GSC の両方に適用してから
        // 月次レポートのデータを取得する。これにより /media/ 等の除外配下が
        // レポートの KPI / キーワード / ページ集計に混入しないようにする。
        $exclude_foreign_manual = !empty($client_info['exclude_foreign']);
        $inc_manual = get_user_meta( $user_id, '_gcrev_include_paths', true );
        $exc_manual = get_user_meta( $user_id, '_gcrev_exclude_paths', true );
        $inc_manual = is_array( $inc_manual ) ? $inc_manual : [];
        $exc_manual = is_array( $exc_manual ) ? $exc_manual : [];
        $has_path_filter_manual = ! empty( $inc_manual ) || ! empty( $exc_manual );
        $path_filters_set_manual = false;

        try {
            // 既存のgenerate_reportロジックを呼び出し
            $config = $this->config->get_user_config($user_id);

            if ($exclude_foreign_manual) {
                $this->ga4->set_country_filter('Japan');
            }
            if ( $has_path_filter_manual ) {
                $this->ga4->set_include_paths_filter( $inc_manual );
                $this->ga4->set_exclude_paths_filter( $exc_manual );
                $this->gsc->set_include_paths_filter( $inc_manual );
                $this->gsc->set_exclude_paths_filter( $exc_manual );
                $path_filters_set_manual = true;
            }

            // 前月・前々月データ取得
            $prev_data = $this->fetch_dashboard_data_internal($config, 'previousMonth');
            $two_data = $this->fetch_dashboard_data_internal($config, 'twoMonthsAgo');

            // ターゲットエリア判定（クライアント設定から）
            $manual_client_settings = gcrev_get_client_settings($user_id);
            $target_area = gcrev_detect_area_from_client_settings($manual_client_settings);

            // -------------------------------------------------
            // 追加：実質CV判定 → client_info に注入（AIレポート生成で使用）
            // -------------------------------------------------
            if (!empty($year_month)) {
                $eff = $this->get_effective_cv_monthly($year_month, $user_id);
                $client_info['effective_cv'] = [
                    'source'     => $eff['source'],
                    'cv'         => $eff['total'],
                    'has_actual' => ($eff['source'] !== 'ga4'),
                    'detail'     => $eff['breakdown_manual'] ?? [],
                    'components' => $eff['components'],
                    'daily'      => $eff['daily'],
                ];
                error_log("[GCREV] generate_monthly_report_manual: effective_cv source={$eff['source']}, total={$eff['total']}");
            }

            // ページ改善分析データ取得 → client_info に注入
            $pi = $this->get_page_improvement_summary( $user_id, [ 'limit' => 5, 'full_summary' => true ] );
            if ( ! empty( $pi['pages'] ) ) {
                $client_info['page_insights'] = $this->condense_page_insights_for_report( $pi );
            }

            // レポートHTML生成（プロバイダ自動選択: ChatGPT or Gemini）
            $sections_html = $this->generator->generate_report($prev_data, $two_data, $client_info, $target_area);

            // Key events取得
            $ga4_id = $config['ga4_id'];
            $prev_start = (string)($prev_data['current_period']['start'] ?? '');
            $prev_end = (string)($prev_data['current_period']['end'] ?? '');
            $two_start = (string)($two_data['current_period']['start'] ?? '');
            $two_end = (string)($two_data['current_period']['end'] ?? '');

            $prev_key_events = ($prev_start && $prev_end) ? $this->ga4->fetch_ga4_key_events($ga4_id, $prev_start, $prev_end) : [];
            $two_key_events = ($two_start && $two_end) ? $this->ga4->fetch_ga4_key_events($ga4_id, $two_start, $two_end) : [];
            $selected_events = $this->ga4->select_report_key_events($prev_key_events, $two_key_events);

            // 最終HTML組み立て
            $report_html = $this->generator->build_sample_layout_report_html(
                $prev_data,
                $two_data,
                $client_info,
                $sections_html,
                $target_area,
                $selected_events,
                $prev_key_events,
                $two_key_events
            );

            // === 初心者向けモード：全文リライト（Markdown出力） ===
            $beginner_markdown2 = '';
            if (($client_info['output_mode'] ?? 'normal') === 'easy' && !empty($year_month)) {
                $beginner_markdown2 = $this->generator->rewrite_report_for_beginner(
                    $sections_html,
                    $target_area,
                    $user_id,
                    $year_month
                );
            }

            // 履歴保存
            $highlights = $this->highlights_mod->extract_highlights_from_html($report_html, $user_id);
            $saved_post_id = $this->repo->save_report_to_history($user_id, $report_html, $client_info, 'manual', $year_month, $highlights, $beginner_markdown2);

            // === AI生成メタ情報保存 ===
            if ( $saved_post_id > 0 ) {
                $ai_meta = $this->generator->get_last_ai_meta();
                if ( ! empty( $ai_meta ) ) {
                    update_post_meta( $saved_post_id, '_gcrev_report_ai_meta', wp_json_encode( $ai_meta, JSON_UNESCAPED_UNICODE ) );
                }
            }

            // === KPIスナップショット保存 ===
            if ( $saved_post_id > 0 ) {
                $this->save_kpi_snapshot_for_report( $saved_post_id, $prev_data, $user_id, $year_month );
            }

            // === インフォグラフィックJSON生成・保存 ===
            try {
                $infographic = $this->generate_infographic_json($prev_data, $two_data, $client_info, $user_id);
                if ($infographic) {
                    $this->save_monthly_infographic($year, $month, $user_id, $infographic);
                    error_log("[GCREV] generate_monthly_report_manual: Infographic saved for user_id={$user_id}, {$year}-{$month}");
                } else {
                    error_log("[GCREV] generate_monthly_report_manual: Infographic generation returned null for user_id={$user_id}");
                }
            } catch (\Exception $ig_e) {
                // インフォグラフィック失敗はレポート本体には影響させない
                error_log("[GCREV] generate_monthly_report_manual: Infographic error: " . $ig_e->getMessage());
            }

            $result = [
                'success' => true,
                'message' => 'レポートを生成しました',
                'version' => $current_version + 1,
            ];
            if ($beginner_markdown2 !== '') {
                $result['beginner_markdown'] = $beginner_markdown2;
            }

            return $result;

        } catch (\Exception $e) {
            file_put_contents('/tmp/gcrev_report_debug.log',
                date('Y-m-d H:i:s') . " generate_monthly_report_manual ERROR: " . $e->getMessage() . "\n" . $e->getTraceAsString() . "\n",
                FILE_APPEND
            );
            return [
                'success' => false,
                'message' => 'レポートの生成に失敗しました: ' . $e->getMessage()
            ];
        } finally {
            // 海外アクセス除外フィルタ解除
            if ( $exclude_foreign_manual ) {
                $this->ga4->set_country_filter( null );
            }
            // 解析対象/除外URL条件フィルタ解除
            if ( $path_filters_set_manual ) {
                $this->ga4->clear_include_paths_filter();
                $this->ga4->set_page_path_filter( null );
                $this->gsc->clear_path_filters();
            }
        }
    }

    /**
     * REST: v2ダッシュボード用KPI取得
     */
    public function rest_get_dashboard_kpi(WP_REST_Request $request): WP_REST_Response {
        $period      = $request->get_param('period') ?? 'prev-month';
        $cache_first = $request->get_param('cache_first') ?? '0';
        $start_date  = $request->get_param('start_date');
        $end_date    = $request->get_param('end_date');
        $user_id     = get_current_user_id();

        // 海外アクセス除外フィルタ
        $filter_set = $this->maybe_set_country_filter( $user_id );

        try {
            // start_date / end_date が指定されている場合は日付範囲で取得
            if ( $start_date && $end_date ) {
                $kpi_data = $this->get_dashboard_kpi_by_dates( $start_date, $end_date, $user_id );
            } else {
                $kpi_data = $this->get_dashboard_kpi($period, $user_id, (int)$cache_first);
            }

            return new WP_REST_Response([
                'success' => true,
                'data'    => $kpi_data,
            ], 200);

        } catch (\Exception $e) {
            file_put_contents( '/tmp/gcrev_dash_debug.log',
                date( 'Y-m-d H:i:s' ) . " [REST /kpi] ERROR user={$user_id}, period={$period}: " . mb_substr( $e->getMessage(), 0, 300 ) . "\n",
                FILE_APPEND
            );

            // stale データのフォールバック
            $range_map = [
                'last30' => 'last30', 'last90' => 'last90', 'last180' => 'last180', 'last365' => 'last365',
                'prev-month' => 'previousMonth', 'prev-prev-month' => 'twoMonthsAgo',
            ];
            $fallback_range = $range_map[ $period ] ?? 'previousMonth';
            $stale_data = $this->get_stale_dashboard_cache( $user_id, $fallback_range );
            if ( $stale_data ) {
                return new WP_REST_Response([
                    'success' => true,
                    'data'    => $stale_data,
                    'stale'   => true,
                    'message' => '最新データの取得に失敗したため、前回のデータを表示しています。',
                ], 200);
            }

            return new WP_REST_Response([
                'success' => false,
                'message' => $e->getMessage(),
            ], 500);
        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    /**
     * REST: 年次レポートデータ取得
     * GET gcrev/v1/annual-report?year=YYYY
     */
    public function rest_get_annual_report( \WP_REST_Request $request ): \WP_REST_Response {
        $year    = (int) $request->get_param( 'year' );
        $user_id = get_current_user_id();
        $is_current_year = ( $year === (int) date( 'Y' ) );
        $force_refresh   = $request->get_param( 'refresh' ) === '1';

        // --- キャッシュ戦略 ---
        // 過去年: user meta に永続保存（確定データ、再取得不要）
        // 今年 : Transient 24h（まだデータが増えるため定期更新）
        // refresh=1: キャッシュを無視して再取得
        $meta_key = "gcrev_annual_snapshot_{$year}";

        if ( $force_refresh ) {
            delete_user_meta( $user_id, $meta_key );
        }

        // AI総括プロンプトのバージョン — プロンプト変更時にインクリメントする
        $ai_prompt_version = 2;

        if ( ! $is_current_year && ! $force_refresh ) {
            $saved = get_user_meta( $user_id, $meta_key, true );
            if ( ! empty( $saved ) && is_array( $saved ) ) {
                // AI総括が未生成、またはプロンプトバージョンが古い場合は再生成
                $saved_version = $saved['ai_summary_version'] ?? 0;
                if ( empty( $saved['ai_summary'] ) || $saved_version < $ai_prompt_version ) {
                    try {
                        $client_settings = function_exists( 'gcrev_get_client_settings' )
                            ? gcrev_get_client_settings( $user_id ) : [];
                        $business_name   = function_exists( 'gcrev_get_business_name' )
                            ? gcrev_get_business_name( $user_id ) : '';
                        $ai = $this->generate_annual_ai_summary(
                            $year, $saved['kpi'] ?? [], $saved['kpi_prev'] ?? $saved['kpi'] ?? [],
                            $saved['trends'] ?? [], $saved['monthly'] ?? [],
                            $saved['channels_summary'] ?? [], $saved['keywords'] ?? [], $saved['pages'] ?? [],
                            $client_settings, $business_name
                        );
                        if ( ! empty( $ai ) ) {
                            $saved['ai_summary']         = $ai;
                            $saved['ai_summary_version'] = $ai_prompt_version;
                            update_user_meta( $user_id, $meta_key, $saved );
                        }
                    } catch ( \Throwable $e ) {
                        file_put_contents( '/tmp/gcrev_annual_debug.log',
                            date( 'Y-m-d H:i:s' ) . " AI backfill error: " . $e->getMessage() . "\n", FILE_APPEND );
                    }
                }
                return new \WP_REST_Response( [ 'success' => true, 'data' => $saved ], 200 );
            }
        } else {
            $exclude_foreign = get_user_meta( $user_id, 'report_exclude_foreign', true );
            $filter_suffix   = $exclude_foreign ? '_filtered' : '';
            // 解析対象/除外URL条件があればキャッシュキーを差別化
            if ( class_exists( 'Gcrev_Path_Filter' ) ) {
                $filter_suffix .= Gcrev_Path_Filter::cache_suffix( $user_id );
            }
            $transient_key   = "gcrev_annual_{$user_id}_{$year}{$filter_suffix}";
            $cached          = get_transient( $transient_key );
            $cached_version  = is_array( $cached ) ? ( $cached['ai_summary_version'] ?? 0 ) : 0;
            if ( $cached !== false && is_array( $cached ) && $cached_version >= $ai_prompt_version ) {
                return new \WP_REST_Response( [ 'success' => true, 'data' => $cached ], 200 );
            }
        }

        $filter_set = $this->maybe_set_country_filter( $user_id );

        try {
            $config   = $this->config->get_user_config( $user_id );
            $ga4_id   = $config['ga4_id'];
            $gsc_url  = $config['gsc_url'];
            $site_url = $config['site_url'] ?? '';

            if ( empty( $ga4_id ) ) {
                return new \WP_REST_Response( [
                    'success' => false,
                    'code'    => 'NO_GA4',
                    'message' => 'GA4プロパティが設定されていません。クライアント設定でGA4連携を完了してください。',
                ], 200 );
            }

            $start = "{$year}-01-01";
            $end   = "{$year}-12-31";

            // 対象年が未来、または現在年で1月より前のデータしかない場合はチェック
            $current_year = (int) date( 'Y' );
            if ( $year > $current_year ) {
                return new \WP_REST_Response( [
                    'success' => false,
                    'code'    => 'FUTURE_YEAR',
                    'message' => "{$year}年のデータはまだありません。",
                ], 200 );
            }

            $prev_year  = $year - 1;
            $prev_start = "{$prev_year}-01-01";
            $prev_end   = "{$prev_year}-12-31";

            // 年間KPIサマリー
            $kpi      = $this->ga4->fetch_ga4_summary( $ga4_id, $start, $end );
            $kpi_prev = $this->ga4->fetch_ga4_summary( $ga4_id, $prev_start, $prev_end );
            $trends   = $this->build_trends( $kpi, $kpi_prev );

            // 月別推移
            $monthly      = $this->ga4->fetch_ga4_monthly_series( $ga4_id, $start, $end );
            $monthly_prev = $this->ga4->fetch_ga4_monthly_series( $ga4_id, $prev_start, $prev_end );

            // ページランキング
            $ga4_pages = $this->ga4->fetch_ga4_data( $ga4_id, $start, $end, $site_url );
            $pages     = array_slice( $ga4_pages['pages'] ?? [], 0, 20 );

            // 流入元
            $channels_summary = [];
            try {
                $source_data = $this->ga4->fetch_source_data_from_ga4( $ga4_id, $start, $end );
                $channels_summary = $source_data['channels'] ?? [];
                $total_sess = 0;
                foreach ( $channels_summary as $ch ) {
                    $total_sess += (int) ( $ch['sessions'] ?? 0 );
                }
                if ( $total_sess > 0 ) {
                    foreach ( $channels_summary as &$ch ) {
                        $ch['percentage'] = round( ( (int) $ch['sessions'] / $total_sess ) * 100, 1 );
                    }
                    unset( $ch );
                }
            } catch ( \Exception $e ) {
                file_put_contents( '/tmp/gcrev_annual_debug.log',
                    date( 'Y-m-d H:i:s' ) . " source error: " . $e->getMessage() . "\n", FILE_APPEND );
            }

            // キーワード
            $gsc_data = [];
            try {
                $gsc_data = $this->gsc->fetch_gsc_data( $gsc_url, $start, $end );
            } catch ( \Exception $e ) {
                file_put_contents( '/tmp/gcrev_annual_debug.log',
                    date( 'Y-m-d H:i:s' ) . " gsc error: " . $e->getMessage() . "\n", FILE_APPEND );
            }
            $keywords = array_slice( $gsc_data['keywords'] ?? [], 0, 20 );

            // --- AI年間総括コメント生成 ---
            $ai_summary = null;
            try {
                $client_settings = function_exists( 'gcrev_get_client_settings' )
                    ? gcrev_get_client_settings( $user_id ) : [];
                $business_name   = function_exists( 'gcrev_get_business_name' )
                    ? gcrev_get_business_name( $user_id ) : '';

                $ai_summary = $this->generate_annual_ai_summary(
                    $year, $kpi, $kpi_prev, $trends, $monthly, $channels_summary, $keywords, $pages,
                    $client_settings, $business_name
                );
            } catch ( \Throwable $e ) {
                file_put_contents( '/tmp/gcrev_annual_debug.log',
                    date( 'Y-m-d H:i:s' ) . " AI summary error: " . $e->getMessage() . "\n", FILE_APPEND );
            }

            $result = [
                'year'             => $year,
                'period'           => [ 'start' => $start, 'end' => $end ],
                'prev_year'        => [ 'start' => $prev_start, 'end' => $prev_end ],
                'kpi'              => $kpi,
                'kpi_prev'         => $kpi_prev,
                'trends'           => $trends,
                'monthly'          => $monthly,
                'monthly_prev'     => $monthly_prev,
                'pages'            => $pages,
                'channels_summary' => $channels_summary,
                'keywords'         => $keywords,
                'ai_summary'         => $ai_summary,
                'ai_summary_version' => $ai_prompt_version,
                'snapshot_saved_at'  => ( new \DateTimeImmutable( 'now', wp_timezone() ) )->format( 'Y-m-d H:i:s' ),
            ];

            // --- 保存 ---
            if ( ! $is_current_year ) {
                // 過去年: user meta に永続保存（確定スナップショット）
                update_user_meta( $user_id, $meta_key, $result );
            } else {
                // 今年: Transient 24h
                $exclude_foreign = get_user_meta( $user_id, 'report_exclude_foreign', true );
                $filter_suffix   = $exclude_foreign ? '_filtered' : '';
                if ( class_exists( 'Gcrev_Path_Filter' ) ) {
                    $filter_suffix .= Gcrev_Path_Filter::cache_suffix( $user_id );
                }
                $transient_key   = "gcrev_annual_{$user_id}_{$year}{$filter_suffix}";
                set_transient( $transient_key, $result, 24 * HOUR_IN_SECONDS );
            }

            return new \WP_REST_Response( [ 'success' => true, 'data' => $result ], 200 );

        } catch ( \Exception $e ) {
            file_put_contents( '/tmp/gcrev_annual_debug.log',
                date( 'Y-m-d H:i:s' ) . " API ERROR: " . $e->getMessage() . "\n", FILE_APPEND );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => $e->getMessage(),
            ], 500 );
        } finally {
            $this->restore_country_filter( $filter_set );
        }
    }

    /**
     * AI年間総括コメントを生成する
     */
    private function generate_annual_ai_summary(
        int $year, array $kpi, array $kpi_prev, array $trends, array $monthly,
        array $channels, array $keywords, array $pages,
        array $client_settings, string $business_name
    ): ?string {

        // クライアント情報をプロンプトに含める
        $client_context = '';
        if ( ! empty( $business_name ) ) {
            $client_context .= "事業者名: {$business_name}\n";
        }
        if ( ! empty( $client_settings['site_url'] ) ) {
            $client_context .= "サイトURL: {$client_settings['site_url']}\n";
        }
        if ( ! empty( $client_settings['industry'] ) ) {
            $client_context .= "業種: {$client_settings['industry']}\n";
        }
        if ( ! empty( $client_settings['business_type'] ) ) {
            $client_context .= "業態: " . gcrev_business_type_labels( $client_settings['business_type'] ) . "\n";
        }
        $area_label = function_exists( 'gcrev_get_client_area_label' )
            ? gcrev_get_client_area_label( $client_settings ) : '';
        if ( ! empty( $area_label ) ) {
            $client_context .= "対象エリア: {$area_label}\n";
        }

        // KPIサマリーテキスト
        $kpi_text = "【{$year}年 年間実績】\n";
        $kpi_text .= "  ページビュー: {$kpi['pageViews']}（前年: {$kpi_prev['pageViews']}）\n";
        $kpi_text .= "  セッション: {$kpi['sessions']}（前年: {$kpi_prev['sessions']}）\n";
        $kpi_text .= "  ユーザー数: {$kpi['users']}（前年: {$kpi_prev['users']}）\n";
        $kpi_text .= "  新規ユーザー: {$kpi['newUsers']}（前年: {$kpi_prev['newUsers']}）\n";
        $kpi_text .= "  ゴール数: {$kpi['conversions']}（前年: {$kpi_prev['conversions']}）\n";

        // トレンドテキスト
        $trend_text = "【前年比】\n";
        foreach ( $trends as $key => $t ) {
            if ( isset( $t['text'] ) ) {
                $labels = [
                    'pageViews' => 'ページビュー', 'sessions' => 'セッション',
                    'users' => 'ユーザー', 'newUsers' => '新規ユーザー',
                    'returningUsers' => 'リピーター', 'avgDuration' => '平均滞在時間',
                    'conversions' => 'ゴール数',
                ];
                $label = $labels[ $key ] ?? $key;
                $trend_text .= "  {$label}: {$t['text']}\n";
            }
        }

        // 月別推移テキスト（要約）
        $monthly_text = "【月別セッション推移】\n";
        $labels = $monthly['labels'] ?? [];
        $sess_arr = $monthly['sessions'] ?? [];
        for ( $i = 0; $i < count( $labels ); $i++ ) {
            $m = (int) substr( (string) ( $labels[ $i ] ?? '' ), 5, 2 );
            $monthly_text .= "  {$m}月: " . number_format( $sess_arr[ $i ] ?? 0 ) . "\n";
        }

        // 流入元TOP5
        $ch_text = "【流入元TOP5】\n";
        $top_channels = array_slice( $channels, 0, 5 );
        foreach ( $top_channels as $ch ) {
            $pct = isset( $ch['percentage'] ) ? number_format( $ch['percentage'], 1 ) . '%' : '-';
            $ch_text .= "  {$ch['channel']}: {$pct}\n";
        }

        // キーワードTOP5
        $kw_text = "【検索キーワードTOP5】\n";
        $top_kw = array_slice( $keywords, 0, 5 );
        foreach ( $top_kw as $kw ) {
            $kw_text .= "  {$kw['query']}: クリック{$kw['clicks']}回, 表示{$kw['impressions']}回\n";
        }

        // 人気ページTOP5
        $pg_text = "【人気ページTOP5】\n";
        $top_pages = array_slice( $pages, 0, 5 );
        foreach ( $top_pages as $p ) {
            $title = $p['title'] ?? $p['page'] ?? '-';
            $pg_text .= "  {$title}: {$p['pageViews']}PV\n";
        }

        $prompt = <<<PROMPT
あなたはウェブサイト運営のレポートを書く専門家です。
以下のアクセスデータをもとに、{$year}年の年間総括を書いてください。

【読み手】サイト管理者・運営担当者（一般ユーザーではない）

{$client_context}
{$kpi_text}
{$trend_text}
{$monthly_text}
{$ch_text}
{$kw_text}
{$pg_text}

以下4点を■見出し付きで書いてください（合計400〜600文字）。

■この1年の成果
- 主要KPI（セッション・ユーザー数・PV・ゴール数）の前年比を数字付きで報告する
- 「今年はセッション数がXX件で、前年比XX%増加しました」のように書く
- 全体傾向を1〜2文で端的にまとめる

■特に伸びたポイント
- 伸びた指標・流入元・キーワード・ページを具体的に挙げる
- 「セッション数がXX%増加しました」「〇〇というキーワードからの流入が多く見られました」のように事実ベースで短く書く
- 1項目につき1〜2文。長い説明や背景の推測は不要

■課題
- 弱い指標を具体的に指摘する（例: 「新規ユーザー数が前年比XX%減少しています」）
- 「課題があります」だけで終わらず、何がどう弱いのかを明確にする
- 流入元の偏り、新規獲得の弱さ、特定指標の低下など、データから読み取れる問題点を挙げる

■来年の改善ポイント
- 管理者が次に取れるアクションを提案する
- 「〜を強化するとよいです」「〜の見直しが必要です」「〜の施策を検討してください」のように書く
- 「〜していきます」「〜してまいります」のような宣言文は使わない
- 2〜4項目を箇条書き的に端的に

【文章ルール — 厳守】
- 感謝・語りかけ・情緒的な表現は絶対に使わない
  NG例: 「ご利用ありがとうございます」「引き続き多くの方に訪れていただけました」「前向きに取り組んでまいります」「皆さんに」
- 「〜しました」「〜が見られます」「〜が必要です」のような客観的な報告文で統一する
- 主語は省略するか「当サイト」とする。「私たち」「皆さん」は使わない
- 1文は短く。回りくどい表現や修飾を避ける
- 専門用語は避け、やさしい日本語で簡潔に
- マークダウンは使わず、プレーンテキストで出力する
PROMPT;

        if ( ! $this->ai ) {
            file_put_contents( '/tmp/gcrev_annual_debug.log',
                date( 'Y-m-d H:i:s' ) . " AI summary: ERROR - ai client is null\n", FILE_APPEND );
            return null;
        }

        file_put_contents( '/tmp/gcrev_annual_debug.log',
            date( 'Y-m-d H:i:s' ) . " AI summary: calling Gemini, prompt_len=" . strlen( $prompt ) . "\n", FILE_APPEND );

        $raw = $this->ai->call_gemini_api( $prompt, [
            'temperature'     => 0.7,
            'maxOutputTokens' => 4096,
        ] );

        file_put_contents( '/tmp/gcrev_annual_debug.log',
            date( 'Y-m-d H:i:s' ) . " AI summary: response_len=" . strlen( $raw ?? '' ) . ", empty=" . ( empty( $raw ) ? 'yes' : 'no' ) . "\n", FILE_APPEND );

        if ( empty( $raw ) ) {
            return null;
        }

        return trim( $raw );
    }

    /**
     * REST: ダッシュボードスコア計算（JS非同期取得後にサーバー側で統一スコアを計算）
     * curr/prev の4指標を受け取り、calc_monthly_health_score で計算して返す。
     * 結果は KPI transient にも保存し、次回リロード時のスコア安定化に利用。
     */
    public function rest_calc_dashboard_score( WP_REST_Request $request ): WP_REST_Response {
        $user_id = get_current_user_id();
        $curr_raw = $request->get_param('curr');
        $prev_raw = $request->get_param('prev');

        if ( ! is_array( $curr_raw ) || ! is_array( $prev_raw ) ) {
            return new WP_REST_Response([ 'success' => false, 'message' => 'Invalid params' ], 400);
        }

        $keys = ['traffic', 'cv', 'gsc', 'meo'];
        $curr = [];
        $prev = [];
        foreach ( $keys as $k ) {
            $curr[ $k ] = (int)( $curr_raw[ $k ] ?? 0 );
            $prev[ $k ] = (int)( $prev_raw[ $k ] ?? 0 );
        }

        $health = $this->calc_monthly_health_score( $curr, $prev, [], $user_id );

        // KPI transient にスコアを保存（次回リロード時にPHP側で即復元）
        $exclude_foreign = get_user_meta( $user_id, 'report_exclude_foreign', true );
        $filter_suffix   = $exclude_foreign ? '_jp' : '';
        if ( class_exists( 'Gcrev_Path_Filter' ) && Gcrev_Path_Filter::has_filters( $user_id ) ) {
            $filter_suffix .= '_ex';
        }
        $cache_key       = "gcrev_dash_{$user_id}_last30{$filter_suffix}";
        $kpi_cached      = get_transient( $cache_key );
        if ( $kpi_cached !== false && is_array( $kpi_cached ) ) {
            $kpi_cached['_cached_score'] = [
                'score'      => $health['score'],
                'status'     => $health['status'],
                'breakdown'  => $health['breakdown'],
                'components' => $health['components'],
            ];
            set_transient( $cache_key, $kpi_cached, self::DASHBOARD_CACHE_TTL );
        }

        return new WP_REST_Response([
            'success'    => true,
            'score'      => $health['score'],
            'status'     => $health['status'],
            'components' => $health['components'] ?? null,
        ], 200);
    }

    /**
     * REST: v2ダッシュボード用レポート手動生成
     */
    public function rest_generate_report_manual(WP_REST_Request $request): WP_REST_Response {
        @set_time_limit( 300 );

        $year = $request->get_param('year');
        $month = $request->get_param('month');
        $user_id = get_current_user_id();

        file_put_contents('/tmp/gcrev_report_debug.log',
            date('Y-m-d H:i:s') . " REST generate_report_manual START: user_id={$user_id}, year={$year}, month={$month}\n",
            FILE_APPEND
        );

        // PHP Fatal Error をキャッチして JSON レスポンスを返すためのシャットダウンハンドラ
        register_shutdown_function(function () {
            $error = error_get_last();
            if ($error && in_array($error['type'], [E_ERROR, E_PARSE, E_CORE_ERROR, E_COMPILE_ERROR], true)) {
                file_put_contents('/tmp/gcrev_report_debug.log',
                    date('Y-m-d H:i:s') . " FATAL ERROR: {$error['message']} in {$error['file']}:{$error['line']}\n",
                    FILE_APPEND
                );
                // 出力バッファをクリアして JSON エラーレスポンスを返す
                if (ob_get_level()) {
                    ob_end_clean();
                }
                header('Content-Type: application/json; charset=utf-8');
                http_response_code(500);
                echo wp_json_encode([
                    'success' => false,
                    'message' => 'サーバーで致命的なエラーが発生しました。管理者にお問い合わせください。',
                ], JSON_UNESCAPED_UNICODE);
                exit;
            }
        });

        try {
            $result = $this->generate_monthly_report_manual($user_id, $year, $month);

            if ($result['success']) {
                return new WP_REST_Response($result, 200);
            } else {
                return new WP_REST_Response($result, 400);
            }

        } catch (\Throwable $e) {
            file_put_contents('/tmp/gcrev_report_debug.log',
                date('Y-m-d H:i:s') . " REST generate_report_manual ERROR: " . $e->getMessage() . "\n" . $e->getTraceAsString() . "\n",
                FILE_APPEND
            );
            return new WP_REST_Response([
                'success' => false,
                'message' => $e->getMessage(),
            ], 500);
        }
    }

    /**
     * REST: 前々月データ存在チェック
