    // SEO対策
    // =========================================================

    /**
     * SEO診断結果を取得
     */
    public function rest_get_seo_report( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id = get_current_user_id();
        if ( current_user_can( 'manage_options' ) && $request->get_param( 'user_id' ) ) {
            $user_id = absint( $request->get_param( 'user_id' ) );
        }

        try {
            $checker = new Gcrev_SEO_Checker();
            $data    = $checker->get_diagnosis( $user_id );
            if ( ! $data ) {
                return new \WP_REST_Response( [
                    'success' => true,
                    'data'    => null,
                    'message' => 'まだ診断が実行されていません。',
                ] );
            }
            return new \WP_REST_Response( [ 'success' => true, 'data' => $data ] );
        } catch ( \Throwable $e ) {
            error_log( '[GCREV][SEO] get_report error: ' . $e->getMessage() );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => 'データ取得中にエラーが発生しました。',
            ], 500 );
        }
    }

    /**
     * SEO診断を実行
     */
    public function rest_run_seo_diagnosis( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id = get_current_user_id();
        if ( current_user_can( 'manage_options' ) && $request->get_param( 'user_id' ) ) {
            $user_id = absint( $request->get_param( 'user_id' ) );
        }

        // レート制限（テスト中のため一時無効化）
        $lock_key = 'gcrev_seo_diag_lock_' . $user_id;
        delete_transient( $lock_key ); // 既存ロック解除
        // if ( get_transient( $lock_key ) ) {
        //     return new \WP_REST_Response( [
        //         'success' => false,
        //         'message' => 'SEO診断は1時間に1回のみ実行できます。しばらくお待ちください。',
        //     ], 429 );
        // }
        // set_transient( $lock_key, 1, HOUR_IN_SECONDS );

        // タイムアウト延長（クロールに時間がかかるため）
        @set_time_limit( 180 );

        try {
            $checker = new Gcrev_SEO_Checker( $this->ai );
            $run_data = $checker->run_diagnosis( $user_id );
            // 比較データ付きで返す
            $result = $checker->get_diagnosis( $user_id );
            // get_diagnosis が null の場合は run_diagnosis の結果を直接返す
            if ( ! $result ) {
                $run_data['comparison']   = null;
                $run_data['historyCount'] = 0;
                $result = $run_data;
            }
            return new \WP_REST_Response( [ 'success' => true, 'data' => $result ] );
        } catch ( \Throwable $e ) {
            // delete_transient( $lock_key );
            error_log( '[GCREV][SEO] run_diagnosis error: ' . $e->getMessage() );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => '診断中にエラーが発生しました: ' . esc_html( $e->getMessage() ),
            ], 500 );
        }
    }

    /**
     * SEOキーワード調査を実行
     *
     * 一般ユーザー: 自分自身のデータのみ
     * 管理者: user_id パラメータで任意ユーザーを指定可能
     */
    public function rest_seo_keyword_research( \WP_REST_Request $request ): \WP_REST_Response {
        $current_uid = get_current_user_id();
        $user_id     = absint( $request->get_param( 'user_id' ) );

        // 管理者以外は自分のIDのみ
        if ( ! current_user_can( 'manage_options' ) ) {
            $user_id = $current_uid;
        }

        if ( $user_id < 1 || ! get_userdata( $user_id ) ) {
            return new \WP_REST_Response( [
                'success' => false,
                'error'   => '有効なクライアントを選択してください。',
            ], 400 );
        }

        if ( ! $this->keyword_research ) {
            return new \WP_REST_Response( [
                'success' => false,
                'error'   => 'キーワード調査サービスが初期化されていません。',
            ], 500 );
        }

        // シードキーワード
        $seed_raw = sanitize_textarea_field( wp_unslash( $request->get_param( 'seed_keywords' ) ?? '' ) );
        $seeds = [];
        if ( $seed_raw !== '' ) {
            $seeds = array_values( array_filter(
                array_map( 'trim', preg_split( '/[,\n\r]+/', $seed_raw ) ),
                function( $s ) { return $s !== ''; }
            ) );
        }

        $enable_competitor = (bool) $request->get_param( 'enable_competitor' );

        @set_time_limit( 300 );

        try {
            $result = $this->keyword_research->research( $user_id, $seeds, $enable_competitor );
            return new \WP_REST_Response( $result );
        } catch ( \Throwable $e ) {
            file_put_contents( '/tmp/gcrev_seo_debug.log',
                date( 'Y-m-d H:i:s' ) . " REST keyword-research error: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response( [
                'success' => false,
                'error'   => 'キーワード調査中にエラーが発生しました: ' . $e->getMessage(),
            ], 500 );
        }
    }

    /**
     * キーワード調査の最新結果を取得
     */
    public function rest_seo_keyword_research_latest( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id = get_current_user_id();

        if ( ! $this->keyword_research ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => 'no_service' ], 500 );
        }

        $result = $this->keyword_research->get_latest_result( $user_id );
        if ( $result === null ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => 'no_data' ] );
        }

        return new \WP_REST_Response( $result );
    }

    // =========================================================
    // Google Ads API 疎通確認
    // =========================================================

    /**
     * Google Ads API 接続テスト
     */
    public function rest_google_ads_test_connection( \WP_REST_Request $request ): \WP_REST_Response {
        // 設定チェック
        if ( ! class_exists( 'Gcrev_Google_Ads_Client' ) ) {
            return new \WP_REST_Response( [
                'success' => false,
                'error'   => 'Google Ads クライアントクラスが読み込まれていません。',
            ], 500 );
        }

        if ( ! Gcrev_Google_Ads_Client::is_configured() ) {
            $missing = Gcrev_Google_Ads_Client::get_missing_config();
            return new \WP_REST_Response( [
                'success' => false,
                'error'   => 'Google Ads API の認証情報が未設定です。',
                'missing' => $missing,
            ], 400 );
        }

        $client = $this->google_ads ?? new Gcrev_Google_Ads_Client();

        try {
            $result = $client->test_connection();
            $status = $result['success'] ? 200 : 500;
            return new \WP_REST_Response( $result, $status );
        } catch ( \Throwable $e ) {
            file_put_contents( '/tmp/gcrev_google_ads_debug.log',
                date( 'Y-m-d H:i:s' ) . " REST test_connection error: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response( [
                'success' => false,
                'error'   => 'Google Ads API 疎通テスト中にエラーが発生しました: ' . $e->getMessage(),
            ], 500 );
        }
    }

