    public function rest_wp_publish_test( \WP_REST_Request $request ): \WP_REST_Response {
        require_once __DIR__ . '/gcrev-api/modules/class-wp-publish-client.php';
        $user_id = absint( $request->get_param( 'user_id' ) );
        if ( $user_id <= 0 ) { return new \WP_REST_Response( [ 'success' => false, 'error' => 'ユーザーIDが必要です' ] ); }
        $settings = Gcrev_WP_Publish_Client::get_settings( $user_id );
        if ( ! $settings['site_url'] || ! $settings['username'] || ! $settings['app_password'] ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => '接続情報が不足しています' ] );
        }
        $client = new Gcrev_WP_Publish_Client();
        $result = $client->test_connection( $settings['site_url'], $settings['username'], $settings['app_password'] );
        return new \WP_REST_Response( $result );
    }

    public function rest_wp_publish_categories( \WP_REST_Request $request ): \WP_REST_Response {
        require_once __DIR__ . '/gcrev-api/modules/class-wp-publish-client.php';
        $user_id  = get_current_user_id();
        $settings = Gcrev_WP_Publish_Client::get_settings( $user_id );
        if ( ! $settings['enabled'] || $settings['site_url'] === '' || $settings['username'] === '' || $settings['app_password'] === '' ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => 'WordPress連携が設定されていません。' ] );
        }
        $client = new Gcrev_WP_Publish_Client();
        $result = $client->get_categories( $settings['site_url'], $settings['username'], $settings['app_password'] );
        return new \WP_REST_Response( $result );
    }

    public function rest_writing_check_similarity( \WP_REST_Request $request ): \WP_REST_Response {
        if ( ! $this->writing_service ) { return new \WP_REST_Response( [ 'success' => false, 'error' => 'Writing service not available' ], 500 ); }
        $keyword = sanitize_text_field( $request->get_json_params()['keyword'] ?? '' );
        if ( $keyword === '' ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => 'キーワードを入力してください。' ], 400 );
        }
        try {
            $result = $this->writing_service->check_similarity( get_current_user_id(), $keyword );
