     * GET /writing/auto-article/history — 自動記事生成履歴
     */
    public function rest_auto_article_history( \WP_REST_Request $request ): \WP_REST_Response {
        require_once __DIR__ . '/gcrev-api/utils/class-auto-article-queue.php';

        $limit   = min( 100, max( 1, (int) ( $request->get_param( 'limit' ) ?: 50 ) ) );
        $history = Gcrev_Auto_Article_Queue::get_user_history( get_current_user_id(), $limit );

        $items = array_map( function ( $row ) {
            return [
                'id'               => (int) $row->id,
                'keyword'          => $row->keyword,
                'final_keyword'    => $row->final_keyword,
                'keyword_group'    => $row->keyword_group,
                'priority_score'   => (float) $row->priority_score,
                'status'           => $row->status,
                'article_id'       => $row->article_id ? (int) $row->article_id : null,
                'wp_draft_id'      => $row->wp_draft_id ? (int) $row->wp_draft_id : null,
                'quality_score'    => $row->quality_score !== null ? (float) $row->quality_score : null,
                'quality_feedback' => $row->quality_feedback ?: null,
                'error_message'    => $row->error_message ?: null,
                'angle_json'       => $row->angle_json ? json_decode( $row->angle_json, true ) : null,
                'created_at'       => $row->created_at,
                'finished_at'      => $row->finished_at,
            ];
        }, $history );

        return new \WP_REST_Response( [ 'success' => true, 'history' => $items ] );
    }

    /**
     * POST /writing/auto-article/trigger — 手動で即時記事生成をトリガー
     */
    public function rest_auto_article_trigger( \WP_REST_Request $request ): \WP_REST_Response {
        $service = $this->get_auto_article_service();
        if ( ! $service ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => 'Service not available' ], 500 );
        }

        $keyword = sanitize_text_field( $request->get_json_params()['keyword'] ?? '' );

        try {
            $result = $service->trigger_single( get_current_user_id(), $keyword );
            return new \WP_REST_Response( $result );
        } catch ( \Throwable $e ) {
            return new \WP_REST_Response( [ 'success' => false, 'error' => $e->getMessage() ], 500 );
        }
    }

    // =========================================================
    // 口コミ投稿支援
    // =========================================================

    /**
     * リバースプロキシ（KUSANAGI/nginx）を考慮した実クライアントIP取得
     */
    private function get_client_ip(): string {
        // X-Forwarded-For: 複数IPがカンマ区切りの場合、最初（=元のクライアント）を使用
        if ( ! empty( $_SERVER['HTTP_X_FORWARDED_FOR'] ) ) {
            $ips = explode( ',', $_SERVER['HTTP_X_FORWARDED_FOR'] );
            $ip  = trim( $ips[0] );
            if ( filter_var( $ip, FILTER_VALIDATE_IP ) ) {
                return $ip;
            }
        }
        // X-Real-IP（nginx proxy_set_header X-Real-IP）
        if ( ! empty( $_SERVER['HTTP_X_REAL_IP'] ) ) {
            $ip = trim( $_SERVER['HTTP_X_REAL_IP'] );
            if ( filter_var( $ip, FILTER_VALIDATE_IP ) ) {
                return $ip;
            }
        }
        return sanitize_text_field( $_SERVER['REMOTE_ADDR'] ?? 'unknown' );
    }

    /**
     * レートリミットチェック（公開エンドポイント保護）
     * permission_callback では常に true を返し、コールバック内でチェックする
     */
    public function check_review_rate_limit(\WP_REST_Request $request): bool {
        return true;
    }

    /**
     * レートリミットを実行し、超過時は WP_REST_Response を返す
     * 1時間あたり30回/IPに制限
     *
     * @return \WP_REST_Response|null  超過時はレスポンス、OK時は null
     */
    private function enforce_review_rate_limit(): ?\WP_REST_Response {
        $ip    = $this->get_client_ip();
        $key   = 'gcrev_review_rate_' . md5( $ip );
        $count = (int) get_transient( $key );
        if ( $count >= 30 ) {
            file_put_contents('/tmp/gcrev_review_debug.log',
                date('Y-m-d H:i:s') . " RATE LIMIT exceeded: ip={$ip}, count={$count}\n",
                FILE_APPEND
            );
            return new \WP_REST_Response([
                'success' => false,
                'message' => 'しばらく時間をおいてから再度お試しください。（1時間あたりの利用回数上限に達しました）',
            ], 429);
        }
        set_transient( $key, $count + 1, HOUR_IN_SECONDS );
        return null;
    }

    /**
     * 口コミ参考文を生成する（公開エンドポイント）
     *
     * POST gcrev/v1/review/generate
     * Body（トークン方式）: { survey_token, answers: [{question_id, question, answer}] }
     * Body（レガシー方式）: { answers: [{question, answer}], user_id: int }
     */
    public function rest_generate_review(\WP_REST_Request $request): \WP_REST_Response {
        // レートリミットチェック（超過時は日本語メッセージ付き 429 を返す）
        $rate_error = $this->enforce_review_rate_limit();
        if ( $rate_error ) {
            return $rate_error;
        }

        try {
            file_put_contents('/tmp/gcrev_review_debug.log',
                date('Y-m-d H:i:s') . " rest_generate_review called, ip=" . $this->get_client_ip() . "\n",
                FILE_APPEND
            );
            global $wpdb;
            $params       = $request->get_json_params();
            $answers      = $params['answers'] ?? [];
            $survey_token = sanitize_text_field($params['survey_token'] ?? '');
            $user_id      = absint($params['user_id'] ?? 0);

            if (empty($answers) || !is_array($answers)) {
                return new \WP_REST_Response([
                    'success' => false,
                    'message' => '回答データが不足しています。',
                ], 400);
            }

            // トークン方式: DBからアンケート情報を取得
            $survey_id      = 0;
            $survey_user_id = 0;
            $business_name  = '';

            if (!empty($survey_token)) {
                $t_surveys = $wpdb->prefix . 'gcrev_surveys';
                $survey = $wpdb->get_row($wpdb->prepare(
                    "SELECT * FROM {$t_surveys} WHERE token = %s AND status = 'published'",
                    $survey_token
                ));
                if (!$survey) {
                    return new \WP_REST_Response([
                        'success' => false,
                        'message' => 'アンケートが見つかりません。',
                    ], 404);
                }
                // お試し期限切れチェック
                if ( function_exists( 'gcrev_is_trial_expired' ) && gcrev_is_trial_expired( (int) $survey->user_id ) ) {
                    return new \WP_REST_Response([
                        'success' => false,
                        'message' => 'このアンケートは現在ご利用いただけません。',
                    ], 403);
                }
                $survey_id      = (int) $survey->id;
                $survey_user_id = (int) $survey->user_id;
                $user_id        = $survey_user_id;
                $business_name  = function_exists('gcrev_get_business_name')
                    ? gcrev_get_business_name($survey_user_id)
                    : (get_user_meta($survey_user_id, 'gcrev_business_name', true) ?: '');
            } elseif ($user_id > 0) {
                // レガシー方式
                $business_name = function_exists('gcrev_get_business_name')
                    ? gcrev_get_business_name($user_id)
                    : (get_user_meta($user_id, 'gcrev_business_name', true) ?: '');
            }

            // 回答をプロンプト用テキストに整形
            $answer_text = $this->format_review_answers($answers);
            if (empty($answer_text)) {
                return new \WP_REST_Response([
                    'success' => false,
                    'message' => '有効な回答がありません。入力内容をご確認ください。',
                ], 400);
            }

            // 再生成フラグ
            $is_regenerate = ! empty($params['regenerate']);
            $existing_response_id = absint($params['response_id'] ?? 0);

            // AIプロンプト構築 → Gemini API 呼び出し（口コミ用に高 temperature）
            $ai_keywords     = (isset($survey) && property_exists($survey, 'ai_keywords') && !empty($survey->ai_keywords)) ? (string) $survey->ai_keywords : '';
            $ai_extra_prompt = (isset($survey) && property_exists($survey, 'ai_extra_prompt') && !empty($survey->ai_extra_prompt)) ? (string) $survey->ai_extra_prompt : '';
            $ai_reference_reviews = [];
            if (isset($survey) && property_exists($survey, 'ai_reference_reviews') && !empty($survey->ai_reference_reviews)) {
                $decoded_refs = json_decode((string) $survey->ai_reference_reviews, true);
                if (is_array($decoded_refs)) { $ai_reference_reviews = $decoded_refs; }
            }
            // 業種・サービス内容・ターゲット・強み・口コミ重点を解決
            // アンケートに保存された ai_generation_context（モーダルで入力した値）を優先、
            // 空欄フィールドのみクライアント設定でフォールバック補完する
            $_resolve_survey_id = (int) ( $survey_id ?? 0 );
            $_resolve_user_id   = (int) ( $survey_user_id ?? $user_id ?? 0 );
            $client_info = $this->resolve_review_generation_context( $_resolve_survey_id, $_resolve_user_id );
            $prompt       = $this->build_review_prompt($answer_text, $business_name, $ai_keywords, $ai_extra_prompt, $ai_reference_reviews, $client_info);
            file_put_contents('/tmp/gcrev_review_debug.log',
                date('Y-m-d H:i:s') . " calling gemini API, prompt_len=" . strlen($prompt) . ", is_regenerate=" . ($is_regenerate ? 'yes' : 'no') . "\n",
                FILE_APPEND
            );
            // 生成＋禁止フレーズ検出＋自動再生成（最大2回試行）
            // 店舗名が本文に混入した場合も禁止扱いで再生成される
            $parsed = $this->generate_review_with_retry( $prompt, (string) $business_name );
            if ($parsed === null) {
                file_put_contents('/tmp/gcrev_review_debug.log',
                    date('Y-m-d H:i:s') . " JSON parse failed (after retry)\n",
                    FILE_APPEND
                );
                return new \WP_REST_Response([
                    'success' => false,
                    'message' => '口コミ案の作成に失敗しました。もう一度お試しください。',
                ], 500);
            }

            // 回答をDBに保存（トークン方式の場合のみ）
            $response_id = 0;
            $version     = 1;
            if ($survey_id > 0) {
                if ($is_regenerate && $existing_response_id > 0) {
                    // 再生成: 既存 response_id に新バージョンの AI 生成文を追加
                    $version = $this->save_regenerated_review($wpdb, $existing_response_id, $survey_id, $survey_user_id, $parsed);
                    $response_id = $existing_response_id;
                } else {
                    // 初回生成: 新規 response 作成
                    $extra = [
                        'respondent_name' => sanitize_text_field($params['respondent_name'] ?? ''),
                        'consent_ai'      => ! empty($params['consent_ai']),
                        'consent_review'  => ! empty($params['consent_review']),
                    ];
                    $response_id = $this->save_survey_response($wpdb, $survey_id, $survey_user_id, $answers, $parsed, $extra);
                }
            }

            return new \WP_REST_Response([
                'success'       => true,
                // 後方互換のため short_review も空文字で返す（フロント側が参照している可能性）
                'short_review'  => '',
                'normal_review' => $parsed['normal_review'],
                'review'        => $parsed['normal_review'],
                'response_id'   => $response_id,
                'version'       => $version,
            ], 200);

        } catch (\Throwable $e) {
            file_put_contents('/tmp/gcrev_review_debug.log',
                date('Y-m-d H:i:s') . " review generate error: " . $e->getMessage()
                . "\n  File: " . $e->getFile() . ':' . $e->getLine()
                . "\n  Trace: " . substr($e->getTraceAsString(), 0, 800) . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response([
                'success' => false,
                'message' => '口コミ案の作成に失敗しました。少し時間をおいてもう一度お試しください。',
            ], 500);
        }
    }

    /**
     * アンケート回答をDBに保存
     */
    private function save_survey_response(\wpdb $wpdb, int $survey_id, int $user_id, array $answers, array $parsed, array $extra = []): int {
        $t_responses = $wpdb->prefix . 'gcrev_survey_responses';
        $t_answers   = $wpdb->prefix . 'gcrev_survey_response_answers';
        $t_ai_gen    = $wpdb->prefix . 'gcrev_survey_ai_generations';
        $now         = current_time('mysql');

        $wpdb->insert($t_responses, [
            'survey_id'       => $survey_id,
            'user_id'         => $user_id,
            'respondent_name' => sanitize_text_field($extra['respondent_name'] ?? ''),
            'short_review'    => '',
            'normal_review'   => (string) ($parsed['normal_review'] ?? ''),
            'status'          => 'new',
            'consent_ai'      => ! empty($extra['consent_ai']) ? 1 : 0,
            'consent_review'  => ! empty($extra['consent_review']) ? 1 : 0,
            'created_at'      => $now,
        ], ['%d', '%d', '%s', '%s', '%s', '%s', '%d', '%d', '%s']);

        $response_id = (int) $wpdb->insert_id;
        if ($response_id <= 0) return 0;

        foreach ($answers as $item) {
            $question_id = absint($item['question_id'] ?? 0);
            $answer      = $item['answer'] ?? '';

            $answer_json = is_array($answer)
                ? wp_json_encode($answer, JSON_UNESCAPED_UNICODE)
                : sanitize_textarea_field($answer);

            $wpdb->insert($t_answers, [
                'response_id' => $response_id,
                'question_id' => $question_id,
                'answer'      => $answer_json,
            ], ['%d', '%d', '%s']);
        }

        // AI生成文を ai_generations テーブルにも保存（2026年4月以降は 'normal' 1本のみ）
        if ( ! empty($parsed['normal_review']) ) {
            $wpdb->insert($t_ai_gen, [
                'response_id'    => $response_id,
                'survey_id'      => $survey_id,
                'user_id'        => $user_id,
                'generated_text' => $parsed['normal_review'],
                'review_type'    => 'normal',
                'version'        => 1,
                'status'         => 'generated',
                'created_at'     => $now,
            ], ['%d', '%d', '%d', '%s', '%s', '%d', '%s', '%s']);
        }

        return $response_id;
    }

    /**
     * 再生成時のAI生成文を保存（既存 response_id に新バージョンを追加）。
     * 2026年4月以降は口コミを1本のみ生成する方針のため、review_type='normal' に統一。
     */
    private function save_regenerated_review(\wpdb $wpdb, int $response_id, int $survey_id, int $user_id, array $parsed): int {
        $t_ai_gen = $wpdb->prefix . 'gcrev_survey_ai_generations';
        $now      = current_time('mysql');

        $text = (string) ($parsed['normal_review'] ?? '');
        if ($text === '') { return 1; }

        $max_ver = (int) $wpdb->get_var($wpdb->prepare(
            "SELECT COALESCE(MAX(version), 0) FROM {$t_ai_gen} WHERE response_id = %d AND review_type = %s",
            $response_id, 'normal'
        ));
        $version = $max_ver + 1;

        $wpdb->insert($t_ai_gen, [
            'response_id'    => $response_id,
            'survey_id'      => $survey_id,
            'user_id'        => $user_id,
            'generated_text' => $text,
            'review_type'    => 'normal',
            'version'        => $version,
            'status'         => 'generated',
            'created_at'     => $now,
        ], ['%d', '%d', '%d', '%s', '%s', '%d', '%s', '%s']);

        // responses テーブル: normal_review のみ更新、short_review は空にする
        $t_resp = $wpdb->prefix . 'gcrev_survey_responses';
        $wpdb->update(
            $t_resp,
            ['short_review' => '', 'normal_review' => $text],
            ['id' => $response_id],
            ['%s', '%s'],
            ['%d']
        );

        return $version;
    }

    /**
     * アンケート回答をプロンプト用テキストに整形
     */
    private function format_review_answers(array $answers): string {
        $lines = [];
        foreach ($answers as $item) {
            $question = sanitize_text_field($item['question'] ?? '');
            $answer   = $item['answer'] ?? '';

            if (empty($question)) continue;

            if (is_array($answer)) {
                $answer = array_map('sanitize_text_field', $answer);
                $answer = array_filter($answer);
                if (empty($answer)) continue;
                $lines[] = "【{$question}】\n" . implode('、', $answer);
            } else {
                $answer = sanitize_textarea_field($answer);
                if (trim($answer) === '') continue;
                $lines[] = "【{$question}】\n{$answer}";
            }
        }
        return implode("\n\n", $lines);
    }

    /**
     * 口コミ生成用AIプロンプトを構築
     */
    /**
     * AI 典型句（禁止フレーズ）のブラックリスト。
     * これが含まれる口コミが生成された場合は自動で1回だけ再生成する。
     * リストは正規表現ではなく部分一致（mb_strpos）で判定する。
     */
    private const REVIEW_FORBIDDEN_PATTERNS = [
        '自信を持っておすすめ',
        '自信を持ってお勧め',
        '絶対おすすめ',
        '感謝の気持ちでいっぱい',
        '感謝しかありません',
        '感謝しかない',
        '一人ひとりに寄り添',
        '寄り添う姿勢',
        '心から感謝',
        '期待以上',
        '想像以上',
        '大きな強み',
        '大きな安心感',
        '親身に接して',
        '親身になって',
        '丁寧に対応していただき',
        '柔軟に対応していただき',
        '迅速に対応していただき',
        '本当に頼んでよかった',
        '本当によかったです',
        '最初は不安でしたが',
        '初めてで不安でしたが',
        '大変満足しています',
        '大変満足でした',
        // 追加（AIっぽい過剰表現）
        '感動しました',
        '感動的',
        '感動を覚え',
        '強くおすすめ',
        '強くお勧め',
        '強く推薦',
        '言葉がぴったり',
        '言葉がぴったりな',
        // 過去のプロンプト内例文から AI が頻繁にコピーしてくるフレーズの短縮形
        // （語尾や助詞を少し変えた派生も広く検知するため、できるだけ短い核部分だけを指定）
        '気張らず行ける',
        '思い出す場所の一つ',
        '良い意味で予想を裏切られた',
        '予想を裏切られた感じ',
        '選んで正解でした',
        'なんとなく、いい時間',
        'いい時間だったな',
        'ありがたく存じ',
        '人によるかもしれません',
        '悪くなかった、というのが',
        // サービス利用文脈に合わない「通う」「通院」系のフレーズ
        // （コンサル・EC・プロダクト等では不自然。医療・美容サロン等で自然な場合は回答内にその旨があるので許容されるはず）
        'しばらく通ってみようかな',
        'しばらく通ってみよう',
        // 末尾の「また〜」系の繰り返しが目立つ場合のみ検知
        // （自然な出現は許容したいので、連続3パターン中で頻出する場合のみ再生成扱い）
    ];

    /**
     * 締めの「また〜」系パターン。
     * REVIEW_FORBIDDEN_PATTERNS には入れず（自然な表現のため）、
     * 連続でこの系統が出たら変化を促す目的のみに使う。現状は参考リスト。
     */
    private const REVIEW_ENDING_OVERUSED_PATTERNS = [
        'また利用すると思います',
        'またお願いしたいと思います',
        'また利用させていただきたい',
        'また機会があればお願い',
        'また利用したいと思います',
        'また利用する気持ちです',
    ];

    /**
     * テキスト中に含まれる禁止フレーズを列挙する。
     *
     * @return array<int,string>
     */
    private function detect_forbidden_phrases( string $text ): array {
        $found = [];
        foreach ( self::REVIEW_FORBIDDEN_PATTERNS as $p ) {
            if ( mb_strpos( $text, $p ) !== false ) {
                $found[] = $p;
            }
        }
        return $found;
    }

    /**
     * 口コミ生成を禁止フレーズ検出付きで実行する。
     * 検出された場合は1回だけ再生成（合計2回試行）する。
     * 2回目でも禁止フレーズが残っていればログに警告を出して最後の結果を返す。
     *
     * @return array|null parse_review_response の戻り値（失敗時 null）
     */
    /**
     * 動的な禁止フレーズ検出（静的パターン + 店舗名）。
     *
     * @param string $text
     * @param string $business_name 店舗・サービス名（空でなければ本文中に含まれていないかチェック）
     * @return array<int,string>
     */
    private function detect_forbidden_phrases_dynamic( string $text, string $business_name = '' ): array {
        $found = $this->detect_forbidden_phrases( $text );

        // 店舗名の直接記載を検知
        $bn = trim( $business_name );
        if ( $bn !== '' ) {
            // 末尾の「様/さん」等を除去したコア名も検知対象
            $bn_core = preg_replace( '/(様|さん|御中|殿)$/u', '', $bn );
            $candidates = array_unique( array_filter( [ $bn, $bn_core ] ) );
            foreach ( $candidates as $cand ) {
                if ( mb_strlen( $cand ) >= 2 && mb_strpos( $text, $cand ) !== false ) {
                    $found[] = '店舗名「' . $cand . '」';
                }
            }
        }

        return $found;
    }

    private function generate_review_with_retry( string $prompt, string $business_name = '' ): ?array {
        // 1回目
        $raw = $this->call_review_generation_api( $prompt );
        $parsed = $this->parse_review_response( $raw );
        if ( $parsed === null ) {
            return null;
        }

        $text = (string) ( $parsed['normal_review'] ?? '' );
        $found = $this->detect_forbidden_phrases_dynamic( $text, $business_name );
        if ( empty( $found ) ) {
            return $parsed;
        }

        // 禁止フレーズ検出 → 再生成
        file_put_contents(
            '/tmp/gcrev_review_debug.log',
            date( 'Y-m-d H:i:s' ) . ' [review-gen] forbidden detected: ' . implode( ', ', $found ) . ' — retrying' . "\n",
            FILE_APPEND
        );

        $retry_prompt = $prompt
            . "\n\n---\n\n# 【重要・再生成指示】\n"
            . "直前の出力には以下の**絶対使用禁止フレーズ**が含まれていました:\n"
            . "- " . implode( "\n- ", $found ) . "\n\n"
            . "**これらのフレーズ及び類似の言い換え（例: 「感謝しかありません」「自信を持って紹介したい」など）は一切使わずに、別の自然な表現で書き直してください。**\n"
            . "店舗名・会社名が検知された場合は、それを「こちら」「このお店」「この医院」等の代名詞に置き換えて再生成してください。\n"
            . "参考口コミサンプルに含まれる自然な言い回しを優先して真似してください。";

        $raw2 = $this->call_review_generation_api( $retry_prompt );
        $parsed2 = $this->parse_review_response( $raw2 );
        if ( $parsed2 === null ) {
            // 再生成失敗 → 最初の結果を返す
            return $parsed;
        }

        $text2 = (string) ( $parsed2['normal_review'] ?? '' );
        $found2 = $this->detect_forbidden_phrases_dynamic( $text2, $business_name );
        file_put_contents(
            '/tmp/gcrev_review_debug.log',
            date( 'Y-m-d H:i:s' ) . ( empty( $found2 )
                ? ' [review-gen] retry clean ✓'
                : ' [review-gen] retry still has: ' . implode( ', ', $found2 ) )
            . "\n",
            FILE_APPEND
        );
        return $parsed2;
    }

    /**
     * 口コミ生成を OpenAI 優先・Gemini フォールバックで実行する共通ヘルパー。
     *
     * OpenAI API キーが設定されていれば OpenAI (gpt-4.1 + JSON mode) を優先し、
     * キー未設定・API エラー・レートリミット等で失敗した場合は Gemini にフォールバック。
     *
     * @param string $prompt build_review_prompt() の戻り値
     * @return string 生の応答テキスト（JSON 文字列）
     * @throws \Exception 両プロバイダとも失敗した場合
     */
    private function call_review_generation_api( string $prompt ): string {
        $openai_key = $this->config->get_openai_api_key();

        // OpenAI を優先
        if ( $openai_key !== '' && class_exists( 'Gcrev_OpenAI_Client' ) ) {
            try {
                $client = new \Gcrev_OpenAI_Client( $this->config );
                $system = 'あなたは実際にサービスを利用した顧客の立場で、Google口コミの下書きを作成するプロのライターです。'
                    . '与えられた指示・参考口コミ・禁止事項を厳密に守り、自然で現実的な1本の口コミを JSON 形式で返してください。';
                $result = $client->call_chat_api( $system, $prompt, [
                    'model'       => 'gpt-4.1',
                    'temperature' => 0.75,
                    'max_tokens'  => 2048,
                ] );
                if ( ! empty( $result['text'] ) && is_string( $result['text'] ) ) {
                    file_put_contents( '/tmp/gcrev_review_debug.log',
                        date( 'Y-m-d H:i:s' ) . ' [review-gen] OpenAI gpt-4.1 success tokens=' . (int) ( $result['prompt_tokens'] ?? 0 ) . '/' . (int) ( $result['completion_tokens'] ?? 0 ) . "\n",
                        FILE_APPEND
                    );
                    return (string) $result['text'];
                }
            } catch ( \Throwable $e ) {
                file_put_contents( '/tmp/gcrev_review_debug.log',
                    date( 'Y-m-d H:i:s' ) . ' [review-gen] OpenAI failed, fallback to Gemini: ' . $e->getMessage() . "\n",
                    FILE_APPEND
                );
                // Fall through to Gemini
            }
        }

        // Gemini フォールバック
        $raw = $this->ai->call_gemini_api( $prompt, [
            'temperature'     => 0.75,
            'topP'            => 0.9,
            'maxOutputTokens' => 4096,
        ] );
        file_put_contents( '/tmp/gcrev_review_debug.log',
            date( 'Y-m-d H:i:s' ) . ' [review-gen] Gemini used (len=' . strlen( (string) $raw ) . ")\n",
            FILE_APPEND
        );
        return (string) $raw;
    }

