    /**
     * 口コミ生成に使う「業種 / サービス内容 / ターゲット / 強み / 口コミで引き出したい内容」を解決する。
     *
     * 優先順位:
     *   1. アンケートに保存された ai_generation_context（モーダルで入力した値）
     *      → 一度でも生成したアンケートは、以降クライアント設定変更の影響を受けず固定される
     *   2. クライアント設定（gcrev_get_client_settings）
     *
     * 戻り値キーは build_review_prompt() が期待する $client_info と互換の形で返す:
     *   - industry
     *   - service_description
     *   - strengths
     *   - persona_one_liner (= target)
     *   - review_emphasis
     *
     * @param int $survey_id
     * @param int $user_id  アンケート所有者の user_id（client_info のフォールバック取得に使用）
     * @return array
     */
    private function resolve_review_generation_context( int $survey_id, int $user_id ): array {
        global $wpdb;

        // 1) アンケートに保存された ai_generation_context を読む
        $saved = [
            'industry'            => '',
            'service_description' => '',
            'target'              => '',
            'strengths'           => '',
            'review_emphasis'     => '',
        ];
        if ( $survey_id > 0 ) {
            $t_surveys = $wpdb->prefix . 'gcrev_surveys';
            $row = $wpdb->get_var( $wpdb->prepare(
                "SELECT ai_generation_context FROM {$t_surveys} WHERE id = %d",
                $survey_id
            ) );
            if ( ! empty( $row ) ) {
                $decoded = json_decode( (string) $row, true );
                if ( is_array( $decoded ) ) {
                    foreach ( array_keys( $saved ) as $k ) {
                        if ( isset( $decoded[ $k ] ) && is_string( $decoded[ $k ] ) ) {
                            $saved[ $k ] = trim( $decoded[ $k ] );
                        }
                    }
                }
            }
        }

        // 2) クライアント設定を取得（フォールバックおよび不足分の補完用）
        $client = ( $user_id > 0 && function_exists( 'gcrev_get_client_settings' ) )
            ? gcrev_get_client_settings( $user_id )
            : [];

        $client_industry = trim( (string) ( $client['industry'] ?? ( $client['industry_detail'] ?? '' ) ) );
        $client_service  = trim( (string) ( $client['service_description'] ?? '' ) );
        $client_strong   = trim( (string) ( $client['strengths'] ?? '' ) );
        $client_target   = trim( (string) ( $client['persona_one_liner'] ?? '' ) );
        $client_emph     = trim( (string) ( $client['review_emphasis'] ?? '' ) );

        // 3) 保存値を優先、空のフィールドのみクライアント設定で補完
        $industry        = $saved['industry']            !== '' ? $saved['industry']            : $client_industry;
        $service         = $saved['service_description'] !== '' ? $saved['service_description'] : $client_service;
        $target          = $saved['target']              !== '' ? $saved['target']              : $client_target;
        $strengths       = $saved['strengths']           !== '' ? $saved['strengths']           : $client_strong;
        $review_emphasis = $saved['review_emphasis']     !== '' ? $saved['review_emphasis']     : $client_emph;

        // どのソースが使われたかログに残す（業種ズレ等のトラブル調査用）
        $sources = [
            'industry'            => $saved['industry']            !== '' ? 'survey' : ( $client_industry !== '' ? 'client' : 'none' ),
            'service_description' => $saved['service_description'] !== '' ? 'survey' : ( $client_service  !== '' ? 'client' : 'none' ),
            'target'              => $saved['target']              !== '' ? 'survey' : ( $client_target   !== '' ? 'client' : 'none' ),
            'strengths'           => $saved['strengths']           !== '' ? 'survey' : ( $client_strong   !== '' ? 'client' : 'none' ),
            'review_emphasis'     => $saved['review_emphasis']     !== '' ? 'survey' : ( $client_emph     !== '' ? 'client' : 'none' ),
        ];
        file_put_contents( '/tmp/gcrev_review_debug.log',
            date( 'Y-m-d H:i:s' )
                . ' [review-gen] context resolved: survey_id=' . $survey_id
                . ' industry="' . mb_substr( $industry, 0, 40 ) . '" (src=' . $sources['industry'] . ')'
                . ' / service="' . mb_substr( $service, 0, 40 ) . '" (src=' . $sources['service_description'] . ')'
                . ' / target_src=' . $sources['target']
                . ' / strengths_src=' . $sources['strengths']
                . ' / emphasis_src=' . $sources['review_emphasis']
                . "\n",
            FILE_APPEND
        );

        // build_review_prompt() の $client_info と互換な形状で返す
        return [
            'industry'            => $industry,
            'service_description' => $service,
            'strengths'           => $strengths,
            'persona_one_liner'   => $target,
            'review_emphasis'     => $review_emphasis,
        ];
    }

    /**
     * 参考口コミ文中の「他店舗の固有名詞」をマスクする。
     *
     * 参考口コミには過去に他のクライアント向けに書かれたサンプルが混在することがあり、
     * その中の会社名・屋号が AI 応答に紛れ込む事例が確認された（例: 株式会社◯◯）。
     * 生成時に引用されないよう、会社名系の固有名詞を `[他店名]` に置換する。
     *
     * - 現在のクライアントの $business_name は対象外（そのまま残す）
     * - 置換対象: 株式会社〜 / 〜株式会社 / 有限会社〜 / 〜有限会社 / 合同会社〜 / 〜合同会社
     *
     * @param string $text        参考口コミ1件分のテキスト
     * @param string $keep_name  現在のクライアントの店舗・サービス名（これは置換しない）
     * @return string
     */
    private function mask_reference_proper_nouns( string $text, string $keep_name = '' ): string {
        if ( $text === '' ) { return $text; }

        $patterns = [
            // 「株式会社〜」「有限会社〜」「合同会社〜」（後続名称2〜20文字）
            '/(株式会社|有限会社|合同会社)[ 　]?[\p{L}\p{N}ー・]{1,20}/u',
            // 「〜株式会社」「〜有限会社」「〜合同会社」（前置名称2〜20文字）
            '/[\p{L}\p{N}ー・]{1,20}[ 　]?(株式会社|有限会社|合同会社)/u',
        ];

        $masked = $text;
        foreach ( $patterns as $pat ) {
            $masked = preg_replace_callback( $pat, function ( $m ) use ( $keep_name ) {
                $hit = $m[0];
                // 現在のクライアント名を含む場合はそのまま
                if ( $keep_name !== '' && mb_strpos( $hit, $keep_name ) !== false ) {
                    return $hit;
                }
                return '[他店名]';
            }, $masked );
        }

        return $masked;
    }

    private function build_review_prompt(
        string $answer_text,
        string $business_name = '',
        string $ai_keywords = '',
        string $ai_extra_prompt = '',
        array $ai_reference_reviews = [],
        array $client_info = []
    ): string {
        // 前提情報ブロック（業種・サービス内容・ターゲット・強み・口コミで引き出したい内容）
        // ※ 呼び出し側で resolve_review_generation_context() を通すと、
        //    アンケートに保存された ai_generation_context が優先される（クライアント設定の変更に引きずられない）
        $industry            = trim( (string) ( $client_info['industry'] ?? ( $client_info['industry_detail'] ?? '' ) ) );
        $service_description = trim( (string) ( $client_info['service_description'] ?? '' ) );
        $strengths           = trim( (string) ( $client_info['strengths']           ?? '' ) );
        $target              = trim( (string) ( $client_info['persona_one_liner']   ?? '' ) );
        $review_emphasis     = trim( (string) ( $client_info['review_emphasis']     ?? '' ) );

        // 店舗・サービス名は前提としては渡さない（AI が本文に書き込んでしまう事例が多発したため）
        // 業種・サービス内容等の文脈情報のみを前提として渡し、固有名詞は「このお店」「こちら」で受けさせる
        $premise_lines = [];
        if ( $industry !== '' )           { $premise_lines[] = '* 業種：' . $industry; }
        if ( $service_description !== '' ){ $premise_lines[] = '* サービス内容：' . $service_description; }
        if ( $target !== '' )             { $premise_lines[] = '* ターゲット：' . $target; }
        if ( $strengths !== '' )          { $premise_lines[] = '* 特徴・強み：' . str_replace("\n", ' / ', $strengths); }
        $premise_part = empty( $premise_lines ) ? '' : ( implode( "\n", $premise_lines ) . "\n" );

        // 「口コミで引き出したい内容」は前提情報ブロックではなく、ヒントとして別セクションに出す
        $emphasis_part = '';
        if ( $review_emphasis !== '' ) {
            $emphasis_normalized = str_replace("\n", ' / ', $review_emphasis);
            $emphasis_part = "\n## 【口コミで特に触れてほしい観点（ヒント）】\n"
                . "以下はクライアントが「口コミで引き出したい」と考えている観点です。\n"
                . "アンケート回答の中に関連する記述があれば、その部分を優先的に本文に織り込んでください。\n"
                . "**ただし、回答に書いていないことを創作してまで触れる必要はありません**（必須ではなくヒント）。\n"
                . "- " . $emphasis_normalized . "\n";
        }

        // 業種の強制アンカリング - 業種と矛盾する業界語彙の混入を防ぐ
        $industry_anchor_part = '';
        if ( $industry !== '' ) {
            $industry_anchor_part = "\n## 【業種アンカリング（厳守）】\n"
                . "このアンケートの業種は **「{$industry}」** です。\n"
                . "生成する口コミは必ずこの業種の文脈・語彙・体験に沿うこと。\n"
                . "- 「{$industry}」と明らかに矛盾する業界の用語は**絶対に使わない**\n"
                . "- アンケート回答内に業種と関係の薄い言及があっても、**業種の文脈に解釈し直して自然に書く**こと（無理なら触れない）\n"
                . "- 業種が医療・福祉系であれば、患者・診察・治療・スタッフ・医師・助産師など医療文脈の語彙のみを使う\n"
                . "- 業種が飲食なら、料理・味・接客・来店体験など飲食文脈の語彙のみを使う\n"
                . "- サービス内容「{$service_description}」とも整合的に書くこと\n"
                . "\n### 【動詞・名詞の業種適合】\n"
                . "利用形態に合わない動詞・名詞は使わないこと:\n"
                . "- 「通う／通院」は**定期的に物理的に訪れる業種のみ**（医療・美容・習い事等）で使う。\n"
                . "  コンサル・ITサービス・ECサイト・ツール等では使わず、代わりに「使う」「お願いする」「導入する」「続ける」「活用する」等にする。\n"
                . "- 「来店」「店内」「受付」は実店舗を持つ業種のみで使う。\n"
                . "- サービスの継続意向を示す時は、業種に合う自然な動詞を選ぶこと。\n";
        }

        // === 毎回ランダム化する要素（書き出し・ペルソナ・長さ・締め方） ===
        // 乱数シードは指定せず、生成ごとに真の乱数にする
        $opening = self::REVIEW_OPENING_PATTERNS[ array_rand( self::REVIEW_OPENING_PATTERNS ) ];
        $persona = self::REVIEW_PERSONA_PATTERNS[ array_rand( self::REVIEW_PERSONA_PATTERNS ) ];
        $length  = self::REVIEW_LENGTH_PATTERNS [ array_rand( self::REVIEW_LENGTH_PATTERNS ) ];
        $ending  = self::REVIEW_ENDING_PATTERNS [ array_rand( self::REVIEW_ENDING_PATTERNS ) ];

        // デバッグログ: 今回選ばれたパターンを記録
        file_put_contents( '/tmp/gcrev_review_debug.log',
            date( 'Y-m-d H:i:s' ) . ' [review-gen] randomized: open=' . mb_substr( $opening, 0, 30 )
                . ' / persona=' . mb_substr( $persona, 0, 30 )
                . ' / length=' . $length['range']
                . ' / ending=' . mb_substr( $ending, 0, 30 ) . "\n",
            FILE_APPEND
        );

        $randomized_block = "## 【今回だけの生成指定（毎回変わります・必ず守る）】\n\n"
            . "この指定は生成ごとにランダムに変わります。**前回と似た書き方にしないこと**が最優先です。\n\n"
            . "- **書き出しの方向性**: {$opening}\n"
            . "- **語り手の性格・テイスト**: {$persona}\n"
            . "- **文章量**: {$length['range']}（{$length['guide']}）\n"
            . "- **締め方の方向性**: {$ending}\n\n"
            . "※ 上記は**構造の説明**です。そこに書かれた単語・語句を本文にそのまま使わないこと。\n"
            . "  方向性だけを受け取り、**使う言葉・語順・語尾は自分で選び直す**こと。\n"
            . "※ 特定の語尾（「また利用したい」「〜な気持ちです」等）に固執しないこと。\n";

        // キーワード指示
        $keywords_part = '';
        if (!empty($ai_keywords)) {
            $kw_list = array_filter(array_map('trim', explode("\n", $ai_keywords)));
            if (!empty($kw_list)) {
                $keywords_part = "\n## 【含めたいキーワード】\n以下をできるだけ自然な形で文中に含めてください（無理に全部は不要）:\n- " . implode("\n- ", $kw_list) . "\n";
            }
        }

        // 追加プロンプト（管理画面で設定された追加指示）
        $extra_part = '';
        if (!empty($ai_extra_prompt)) {
            $extra_part = "\n## 【追加指示】\n{$ai_extra_prompt}\n";
        }

        // 参考口コミ（few-shot）: active=true のみ抽出
        $ref_part = '';
        if (!empty($ai_reference_reviews) && is_array($ai_reference_reviews)) {
            $lines = [];
            $idx = 0;
            foreach ($ai_reference_reviews as $item) {
                $text = '';
                $active = true;
                if (is_string($item)) {
                    $text = $item;
                } elseif (is_array($item)) {
                    $text   = isset($item['text']) ? (string) $item['text'] : '';
                    $active = ! empty($item['active']);
                } else {
                    continue;
                }
                if (! $active) continue;
                $text = trim($text);
                if ($text === '') continue;
                // 参考口コミに混入している「他店舗の会社名」をマスク（現クライアント名は残す）
                $text = $this->mask_reference_proper_nouns( $text, $business_name );
                $idx++;
                $lines[] = sprintf('【例%d】%s', $idx, $text);
                if ($idx >= 10) break;
            }
            if (!empty($lines)) {
                $ref_part = "\n## 【参考】語彙・雰囲気の参考資料（強制ではない）\n"
                    . "下記は実際のユーザーが書いた口コミです。**単語選びや感情の温度感の雰囲気を参考にする程度**で構いません。\n"
                    . "ただし以下の点は**参考にしない**でください:\n"
                    . "- 書き出し（最初の1文）は参考口コミと被らないこと\n"
                    . "- 構成の順番は参考口コミに引きずられないこと\n"
                    . "- 締めの言い回しは参考口コミと被らないこと\n"
                    . "- 文章量は参考口コミに関係なく、後述の「今回の指定」に従うこと\n\n"
                    . "**引用禁止**: 参考口コミ内の固有名詞・具体的な数値・個別エピソード（これらは今回のアンケート回答のみから使う）\n"
                    . "**`[他店名]` は別店舗の会社名をマスクした印です。絶対にそのまま出力に残さない／別の店舗名を当てはめて復元しないこと。**\n\n"
                    . "--- 参考口コミ ここから ---\n"
                    . implode("\n\n", $lines) . "\n"
                    . "--- 参考口コミ ここまで ---\n";
            }
        }

        return <<<PROMPT
あなたは実際にサービスを利用した一般ユーザーとして、自然な口コミ文を作成してください。
広告ではなく、リアルな体験ベースの感想を書くことを最優先とします。

---

## 【前提情報】

{$premise_part}
---

## 【アンケート回答（事実のソース）】

以下はユーザーが実際に答えたアンケートです。**書く口コミ文の事実はこの回答のみから使ってください**。
書いていない数字・出来事は絶対に創作しないこと。（ただし、回答内で言及されている固有名詞（担当者名・会社名等）はそのまま使って構いません。）

{$answer_text}
{$ref_part}
---

## 【最重要ルール】

* **毎回同じ構成・同じ語尾・同じ結びで書かないこと（最優先）**
* 上部の「今回だけの生成指定」に従い、書き出し・語り手・長さ・締め方をそれに合わせる
* 人間らしい「揺らぎ・迷い・感情」を含める
* 完璧に褒めすぎない（軽い不満や違和感も自然に含めてよい）
* 宣伝文のような文章にしない

---

## 【内容ルール】

以下を自然に含める（全部ではなくバランス良く、長さ指定に応じて取捨選択）:

* 利用前の気持ち（任意）
* 実際に体験したこと
* 感情の変化
* 印象に残ったポイント

---

## 【具体性ルール（必須）】

以下のような「リアルな細かい要素」を **必ず1つ以上** 入れる:

* 接客の雰囲気・話し方
* 店内や施設の空気感
* 待ち時間や流れ
* 使いやすさ・導線
* 小さな気配り

**「良かった」「丁寧だった」だけで終わらせない**。

---

## 【揺らぎルール】

以下を自然に織り込む:

* 「正直」「なんとなく」「少し」「どちらかというと」「〜気がする」などの曖昧・揺らぎ表現
* 小さなマイナス要素や気になった点（任意、あってよい）
* 迷いや比較・自問自答

---

## 【禁止事項】

**以下は絶対に使用禁止**:

* 定型文・決まり文句:
  - 「大変満足しています」「大変満足でした」
  - 「自信を持っておすすめ」「自信を持ってお勧め」「絶対おすすめ」
  - 「心から感謝」「感謝の気持ちでいっぱい」「感謝しかありません」
  - 「本当に頼んでよかった」「本当によかったです」
* AI 頻用の典型句:
  - 「一人ひとりに寄り添う」「寄り添う姿勢」
  - 「期待以上」「想像以上」
  - 「大きな強み」「大きな安心感」
  - 「親身に接してくださり」「親身になって」
  - 「丁寧に対応していただき」「柔軟に対応していただき」「迅速に対応していただき」
  - 「感動しました」「感動的」「感動を覚え」
  - 「強くおすすめ」「強くお勧め」「強く推薦」
  - 「言葉がぴったり」
* **締めでの「また利用する」「またお願いしたい」の連発** — 上の「締め方パターン」に従い、毎回違う締めにする
* テンプレ導入「最初は不安でしたが」「初めてで不安でしたが」
* 過度に整った・宣伝色の強い断定表現
* 星評価（★）
* アンケート回答にない事実・数字の創作
* 固有名詞の誤用:
  - 参考口コミ内の `[他店名]` をそのまま出力に残すこと
  - 参考口コミに出てくる他店舗の会社名・屋号を今回の口コミに混ぜること
  - アンケートに書かれていない会社名・人物名・ブランド名を創作すること
  - **店舗名・会社名・屋号を口コミ本文内に直接書くこと**
    （例: 「◯◯クリニックさんに行きました」「株式会社◯◯さんで〜」等は全て禁止）
    Google の口コミではほとんどのユーザーは店名を本文に書かない。
    店舗を指す場合は「こちら」「このお店」「この医院」等の代名詞で受けること。
* **プロンプト内の構造説明のコピー禁止（非常に重要）**:
  - 書き出し／ペルソナ／締め方等のパターンは**構造の説明**であり、**テンプレ文ではない**。
  - パターン説明に含まれる語句（例: 「気張らず」「思い出す場所」「予想を裏切られた」等）を
    口コミ本文にそのまま使ってはならない。
  - パターンが示す**方向性・雰囲気だけを取り入れ**、使う単語・語順・語尾は**完全に自分で選び直す**こと。
  - 同じ雰囲気でも、業種・サービスの文脈に合った具体的な描写に置き換える
    （例: コンサル系で「通う」は不自然 → 「使う」「お願いする」「続けてみる」等に）。

---

## 【語彙の偏り禁止】

以下の語は**1本の口コミの中で2回以上使わないこと**（1回までならOK、ゼロでもよい）:

* 「清潔感」
* 「落ち着いた雰囲気」
* 「アットホーム」
* 「温かい雰囲気」
* 「居心地の良い」

また、**複数の口コミを通じてこれらの語ばかりが繰り返される状態**を避けるため、
同じ意味合いは別の表現で言い換える（例: 「清潔感」→「きれいに保たれていて気持ちよかった」「ほこりっぽくない」等）。
「雰囲気」系の表現に頼りすぎず、**具体的な情景・動作・音・光景**を短くても一つ入れること。

---

## 【語り口】

* 一人称（私）が基本
* 日常会話に近い自然な日本語
* 文の長さに変化をつける
* 参考口コミサンプルがある場合はその語尾配合に寄せるが、**同じ語尾の連続使用は避ける**
* 上の「語り手の性格・テイスト」指定に従って、言葉遣いや感情の濃さを調整する

---

## 【文章量】

下記「今回だけの生成指定」の **文章量** に従うこと。指定範囲内に収め、短い指定なら思い切って削る、長い指定なら情景や感情をしっかり展開する。

---
{$industry_anchor_part}{$emphasis_part}{$keywords_part}{$extra_part}
{$randomized_block}
---

## 【最終確認】

出力する前に、以下を自己チェックしてください:

1. **書き出しが上記「書き出しパターン」の指定どおりか？** 参考口コミとは被っていないか？
2. **文字数が上記「文章量」の指定内か？** 指定より長すぎ・短すぎていないか？
3. **語り手が上記「語り手の性格・テイスト」の指定どおりか？** 別の性格の口調になっていないか？
4. **締めが上記「締め方のパターン」の指定どおりか？** 「また利用したい」「またお願いしたい」系で終わっていないか？

**これらの指定に従わない場合、出力は失敗扱いとなります。** 毎回このブロックの指定は異なります。前回と違う書き方になっているか必ず確認してください。

---

## 出力形式

以下の JSON 形式のみを出力してください。説明文・マークダウン・コードフェンスは不要です。
改行が必要な場合は値内で \\n を使ってください（段落区切りは \\n\\n）。

{
  "review": "ここに口コミ本文"
}
PROMPT;
    }

    /**
     * AI応答からJSONをパース。
     * 新スキーマ { review } が主、旧スキーマ { short_review, normal_review } も後方互換で受理する。
     * 戻り値は常に { normal_review } 1件のみ（DB 保存の統一のため）。
     */
    private function parse_review_response(string $raw): ?array {
        // マークダウンのコードブロックを除去
        $cleaned = preg_replace('/```(?:json)?\s*/i', '', $raw);
        $cleaned = preg_replace('/```\s*/', '', $cleaned);
        $cleaned = trim($cleaned);

        $parsed = json_decode($cleaned, true);
        if (!is_array($parsed)) {
            // フォールバック: JSON ブロックっぽい部分を抜き出す
            if (preg_match('/\{[\s\S]*\}/', $raw, $m)) {
                $parsed = json_decode($m[0], true);
            }
        }

        if (!is_array($parsed)) {
            return null;
        }

        // 新スキーマ優先
        $text = '';
        if (!empty($parsed['review']) && is_string($parsed['review'])) {
            $text = $parsed['review'];
        } elseif (!empty($parsed['normal_review']) && is_string($parsed['normal_review'])) {
            $text = $parsed['normal_review'];
        } elseif (!empty($parsed['short_review']) && is_string($parsed['short_review'])) {
            $text = $parsed['short_review'];
        }

        $text = trim($text);
        if ($text === '') {
            return null;
        }

        // sanitize_textarea_field は改行を保持する (\n / \r\n) ので OK
        return [
            'normal_review' => sanitize_textarea_field($text),
        ];
    }

    // =========================================================
    // アンケート管理 REST API コールバック
    // =========================================================

    private const SURVEY_LIMIT = 3;
    private const SURVEY_QUESTION_LIMIT = 60; // 1アンケートあたりの質問件数上限

    /**
     * アンケートへのアクセス権チェック
     */
    private function can_access_survey(int $survey_id, int $user_id): bool {
        if ($survey_id <= 0) return false;
        if (current_user_can('manage_options')) return true;
        global $wpdb;
        $owner = (int) $wpdb->get_var($wpdb->prepare(
            "SELECT user_id FROM {$wpdb->prefix}gcrev_surveys WHERE id = %d",
            $survey_id
        ));
        return $owner === $user_id;
    }

    /**
     * GET survey/list — 自分のアンケート一覧
     */
    public function rest_survey_list(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $user_id  = get_current_user_id();
        $is_admin = current_user_can('manage_options');
        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';
        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';

        // アンケート一覧は「自分が作成したもののみ」を表示する。
        // 管理者権限を持っていても他ユーザーが作成したアンケートは本画面に混ざらないようにする。
        $surveys = $wpdb->get_results( $wpdb->prepare(
            "SELECT s.*,
                    (SELECT COUNT(*) FROM {$t_questions} q WHERE q.survey_id = s.id AND q.is_active = 1) AS question_count
             FROM {$t_surveys} s
             WHERE s.user_id = %d
             ORDER BY s.updated_at DESC",
            $user_id
        ) );

        $form_url = home_url('/review-form/');
        $items = [];
        foreach ($surveys as $s) {
            $items[] = [
                'id'             => (int) $s->id,
                'title'          => $s->title,
                'status'         => $s->status,
                'question_count' => (int) $s->question_count,
                'token'          => $s->token,
                'public_url'     => $s->status === 'published' ? $form_url . '?t=' . $s->token : '',
                'updated_at'     => $s->updated_at,
                'user_id'        => (int) $s->user_id,
            ];
        }

        $count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$t_surveys} WHERE user_id = %d",
            $user_id
        ) );

        return new \WP_REST_Response([
            'surveys'  => $items,
            'count'    => $count,
            'limit'    => self::SURVEY_LIMIT,
            'is_admin' => $is_admin,
        ], 200);
    }

    /**
     * GET survey/detail — アンケート詳細 + 質問一覧
     */
    public function rest_survey_detail(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $survey_id = absint($request->get_param('id'));
        $user_id   = get_current_user_id();

        if (!$this->can_access_survey($survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';
        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';

        $survey = $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$t_surveys} WHERE id = %d", $survey_id
        ));
        if (!$survey) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アンケートが見つかりません。'], 404);
        }

        $questions = $wpdb->get_results($wpdb->prepare(
            "SELECT * FROM {$t_questions} WHERE survey_id = %d ORDER BY sort_order ASC, id ASC",
            $survey_id
        ));

        $q_items = [];
        foreach ($questions as $q) {
            $opts = [];
            if (!empty($q->options)) {
                $decoded = json_decode($q->options, true);
                if (is_array($decoded)) $opts = $decoded;
            }
            $q_items[] = [
                'id'          => (int) $q->id,
                'type'        => $q->type,
                'label'       => $q->label,
                'description' => $q->description,
                'placeholder' => $q->placeholder,
                'options'     => $opts,
                'required'    => (bool) $q->required,
                'sort_order'  => (int) $q->sort_order,
                'is_active'   => (bool) $q->is_active,
                'category'    => $q->category ?? '',
                'is_fixed'    => !empty($q->is_fixed),
            ];
        }

        // 参考口コミサンプル: [{ text, active }] の配列として返す
        // 旧形式 (string[]) は active=true 扱いで受理（後方互換）
        $ref_reviews = [];
        if (!empty($survey->ai_reference_reviews ?? '')) {
            $decoded = json_decode((string) $survey->ai_reference_reviews, true);
            if (is_array($decoded)) {
                foreach ($decoded as $item) {
                    if (is_string($item)) {
                        $text = trim($item);
                        if ($text === '') continue;
                        $ref_reviews[] = [ 'text' => $text, 'active' => true ];
                    } elseif (is_array($item)) {
                        $text = isset($item['text']) ? trim((string) $item['text']) : '';
                        if ($text === '') continue;
                        $active = ! empty($item['active']);
                        $ref_reviews[] = [ 'text' => $text, 'active' => $active ];
                    }
                    if (count($ref_reviews) >= 10) break;
                }
            }
        }

        // AI 30問生成の前回入力（業種・サービス内容・ターゲット・強み・口コミ重点）
        // 一度入力した内容はこのアンケートに紐づいて固定され、クライアント設定の変更に引きずられない
        $ai_gen_ctx = [];
        if ( ! empty( $survey->ai_generation_context ?? '' ) ) {
            $decoded = json_decode( (string) $survey->ai_generation_context, true );
            if ( is_array( $decoded ) ) {
                $ai_gen_ctx = [
                    'industry'            => (string) ( $decoded['industry']            ?? '' ),
                    'service_description' => (string) ( $decoded['service_description'] ?? '' ),
                    'target'              => (string) ( $decoded['target']              ?? '' ),
                    'strengths'           => (string) ( $decoded['strengths']           ?? '' ),
                    'review_emphasis'     => (string) ( $decoded['review_emphasis']     ?? '' ),
                ];
            }
        }

        $form_url = home_url('/review-form/');
        return new \WP_REST_Response([
            'survey' => [
                'id'                     => (int) $survey->id,
                'title'                  => $survey->title,
                'description'            => $survey->description,
                'google_review_url'      => $survey->google_review_url,
                'status'                 => $survey->status,
                'token'                  => $survey->token,
                'ai_keywords'            => $survey->ai_keywords ?? '',
                'ai_extra_prompt'        => $survey->ai_extra_prompt ?? '',
                'ai_reference_reviews'   => $ref_reviews,
                'ai_generation_context'  => $ai_gen_ctx,
                'created_at'             => $survey->created_at,
                'updated_at'             => $survey->updated_at,
            ],
            'questions'  => $q_items,
            'public_url' => $survey->status === 'published' ? $form_url . '?t=' . $survey->token : '',
        ], 200);
    }

    /**
     * POST survey/save — アンケート作成/更新
     */
    public function rest_survey_save(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params  = $request->get_json_params();
        $user_id = get_current_user_id();
        $id      = absint($params['id'] ?? 0);

        $title             = sanitize_text_field($params['title'] ?? '');
        $description       = sanitize_textarea_field($params['description'] ?? '');
        $google_review_url = esc_url_raw($params['google_review_url'] ?? '');
        $status            = sanitize_text_field($params['status'] ?? 'draft');
        $ai_keywords       = isset($params['ai_keywords']) ? sanitize_textarea_field($params['ai_keywords']) : null;
        $ai_extra_prompt   = isset($params['ai_extra_prompt']) ? sanitize_textarea_field($params['ai_extra_prompt']) : null;

        // 参考口コミサンプル: 最大10件、各600字まで
        // 形式: [{ text: string, active: bool }]（旧形式 string[] は active=true で受理）
        $ai_reference_reviews_json = null;
        if (array_key_exists('ai_reference_reviews', $params)) {
            $raw = $params['ai_reference_reviews'];
            $clean = [];
            if (is_array($raw)) {
                foreach ($raw as $item) {
                    $text   = '';
                    $active = true;
                    if (is_string($item)) {
                        $text = $item;
                    } elseif (is_array($item)) {
                        $text   = isset($item['text']) ? (string) $item['text'] : '';
                        $active = ! empty($item['active']);
                    } else {
                        continue;
                    }
                    $text = sanitize_textarea_field($text);
                    $text = trim($text);
                    if ($text === '') continue;
                    if (mb_strlen($text) > 600) {
                        $text = mb_substr($text, 0, 600);
                    }
                    $clean[] = [ 'text' => $text, 'active' => (bool) $active ];
                    if (count($clean) >= 10) break;
                }
            }
            $ai_reference_reviews_json = wp_json_encode($clean, JSON_UNESCAPED_UNICODE);
        }

        if (empty($title)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'タイトルは必須です。'], 400);
        }
        if (!in_array($status, ['draft', 'published'], true)) {
            $status = 'draft';
        }

        $t_surveys = $wpdb->prefix . 'gcrev_surveys';
        $now = current_time('mysql');

        if ($id > 0) {
            // 更新
            if (!$this->can_access_survey($id, $user_id)) {
                return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
            }
            $update_data = [
                'title'             => $title,
                'description'       => $description,
                'google_review_url' => $google_review_url,
                'status'            => $status,
                'updated_at'        => $now,
            ];
            $update_fmt = ['%s', '%s', '%s', '%s', '%s'];
            if ($ai_keywords !== null) {
                $update_data['ai_keywords'] = $ai_keywords;
                $update_fmt[] = '%s';
            }
            if ($ai_extra_prompt !== null) {
                $update_data['ai_extra_prompt'] = $ai_extra_prompt;
                $update_fmt[] = '%s';
            }
            if ($ai_reference_reviews_json !== null) {
                $update_data['ai_reference_reviews'] = $ai_reference_reviews_json;
                $update_fmt[] = '%s';
            }
            $wpdb->update($t_surveys, $update_data, ['id' => $id], $update_fmt, ['%d']);
        } else {
            // 新規作成 — 上限チェック
            $count = (int) $wpdb->get_var($wpdb->prepare(
                "SELECT COUNT(*) FROM {$t_surveys} WHERE user_id = %d", $user_id
            ));
            if ($count >= self::SURVEY_LIMIT) {
                return new \WP_REST_Response([
                    'success' => false,
                    'message' => 'アンケートは最大' . self::SURVEY_LIMIT . '件まで作成できます。',
                    'count'   => $count,
                    'limit'   => self::SURVEY_LIMIT,
                ], 400);
            }

            $token = wp_generate_password(32, false);
            $wpdb->insert($t_surveys, [
                'user_id'              => $user_id,
                'title'                => $title,
                'description'          => $description,
                'google_review_url'    => $google_review_url,
                'token'                => $token,
                'status'               => $status,
                'ai_keywords'          => $ai_keywords ?? '',
                'ai_extra_prompt'      => $ai_extra_prompt ?? '',
                'ai_reference_reviews' => $ai_reference_reviews_json ?? '',
                'created_at'           => $now,
                'updated_at'           => $now,
            ], ['%d', '%s', '%s', '%s', '%s', '%s', '%s', '%s', '%s', '%s', '%s']);
            $id = (int) $wpdb->insert_id;
        }

        return new \WP_REST_Response([
            'success'   => true,
            'survey_id' => $id,
        ], 200);
    }

    /**
     * POST survey/delete — アンケート削除
     */
    public function rest_survey_delete(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params    = $request->get_json_params();
        $survey_id = absint($params['id'] ?? 0);
        $user_id   = get_current_user_id();

        if (!$this->can_access_survey($survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';
        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $t_responses = $wpdb->prefix . 'gcrev_survey_responses';
        $t_answers   = $wpdb->prefix . 'gcrev_survey_response_answers';
        $t_ai_gen    = $wpdb->prefix . 'gcrev_survey_ai_generations';

        // カスケード削除: 回答 → 回答詳細 + AI生成文
        $response_ids = $wpdb->get_col($wpdb->prepare(
            "SELECT id FROM {$t_responses} WHERE survey_id = %d", $survey_id
        ));
        if ( ! empty($response_ids) ) {
            $placeholders = implode(',', array_fill(0, count($response_ids), '%d'));
            $wpdb->query($wpdb->prepare(
                "DELETE FROM {$t_answers} WHERE response_id IN ({$placeholders})",
                ...$response_ids
            ));
        }
        $wpdb->delete($t_ai_gen, ['survey_id' => $survey_id], ['%d']);
        $wpdb->delete($t_responses, ['survey_id' => $survey_id], ['%d']);
        $wpdb->delete($t_questions, ['survey_id' => $survey_id], ['%d']);
        $wpdb->delete($t_surveys, ['id' => $survey_id], ['%d']);

        return new \WP_REST_Response(['success' => true], 200);
    }

    /**
     * POST survey/question/save — 質問追加/更新
     */
    public function rest_survey_question_save(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params    = $request->get_json_params();
        $survey_id = absint($params['survey_id'] ?? 0);
        $q_id      = absint($params['id'] ?? 0);
        $user_id   = get_current_user_id();

        if (!$this->can_access_survey($survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $label = sanitize_text_field($params['label'] ?? '');
        if (empty($label)) {
            return new \WP_REST_Response(['success' => false, 'message' => '質問文は必須です。'], 400);
        }

        $type        = sanitize_text_field($params['type'] ?? 'textarea');
        $valid_types = ['textarea', 'radio', 'checkbox', 'text', 'select'];
        if (!in_array($type, $valid_types, true)) {
            $type = 'textarea';
        }

        $description = sanitize_text_field($params['description'] ?? '');
        $placeholder = sanitize_text_field($params['placeholder'] ?? '');
        $required    = !empty($params['required']) ? 1 : 0;
        $sort_order  = absint($params['sort_order'] ?? 0);
        $is_active   = isset($params['is_active']) ? (int) (bool) $params['is_active'] : 1;

        // options処理
        $options_raw = $params['options'] ?? [];
        if (is_array($options_raw)) {
            $options_raw = array_map('sanitize_text_field', $options_raw);
            $options_raw = array_values(array_filter($options_raw, function($v) { return $v !== ''; }));
        } else {
            $options_raw = [];
        }
        $options_json = !empty($options_raw) ? wp_json_encode($options_raw, JSON_UNESCAPED_UNICODE) : '';

        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';

        // 新規追加の場合のみ上限チェック（既存質問の編集時はチェック不要）
        if ($q_id <= 0) {
            $existing_count = (int) $wpdb->get_var($wpdb->prepare(
                "SELECT COUNT(*) FROM {$t_questions} WHERE survey_id = %d",
                $survey_id
            ));
            if ($existing_count >= self::SURVEY_QUESTION_LIMIT) {
                return new \WP_REST_Response([
                    'success' => false,
                    'message' => sprintf(
                        '質問は1アンケートあたり最大%d件までです（現在 %d 件）。不要な質問を削除してから追加してください。',
                        self::SURVEY_QUESTION_LIMIT, $existing_count
                    ),
                    'limit' => self::SURVEY_QUESTION_LIMIT,
                    'count' => $existing_count,
                ], 400);
            }
        }

        $category = sanitize_text_field($params['category'] ?? '');
        if (mb_strlen($category) > 32) { $category = mb_substr($category, 0, 32); }
        $is_fixed = !empty($params['is_fixed']) ? 1 : 0;

        $data = [
            'survey_id'   => $survey_id,
            'type'        => $type,
            'label'       => $label,
            'description' => $description,
            'placeholder' => $placeholder,
            'options'     => $options_json,
            'required'    => $required,
            'sort_order'  => $sort_order,
            'is_active'   => $is_active,
            'category'    => $category,
            'is_fixed'    => $is_fixed,
        ];
        $format = ['%d', '%s', '%s', '%s', '%s', '%s', '%d', '%d', '%d', '%s', '%d'];

        if ($q_id > 0) {
            $wpdb->update($t_questions, $data, ['id' => $q_id, 'survey_id' => $survey_id], $format, ['%d', '%d']);
        } else {
            $wpdb->insert($t_questions, $data, $format);
            $q_id = (int) $wpdb->insert_id;
        }

        // survey の updated_at を更新
        $wpdb->update($t_surveys, ['updated_at' => current_time('mysql')], ['id' => $survey_id], ['%s'], ['%d']);

        return new \WP_REST_Response([
            'success'     => true,
            'question_id' => $q_id,
        ], 200);
    }

    /**
     * POST survey/ai-generate-questions — クライアント情報をもとに AI で 30 問のアンケートを生成する。
     * 生成のみで DB には保存しない（プレビュー→一括保存は bulk-save で行う）。
     */
    public function rest_survey_ai_generate_questions(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        if ( $user_id <= 0 ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'ログインが必要です。'], 401);
        }

        // 連打防止（30秒）
        $throttle_key = 'gcrev_survey_gen_' . $user_id;
        if ( get_transient( $throttle_key ) ) {
            return new \WP_REST_Response([
                'success' => false,
                'message' => '連続生成はできません。30秒後に再度お試しください。',
            ], 429);
        }
        set_transient( $throttle_key, 1, 30 );

        $params = $request->get_json_params();

        // 上限事前チェック: survey_id が指定されていて既存件数を取得
        // target_count = min(30, 残りスロット) で生成する
        $survey_id_for_check = absint( $params['survey_id'] ?? 0 );
        $target_count = 30;
        if ( $survey_id_for_check > 0 ) {
            $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
            $existing_count = (int) $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$t_questions} WHERE survey_id = %d",
                $survey_id_for_check
            ) );
            $available_slots = self::SURVEY_QUESTION_LIMIT - $existing_count;
            if ( $available_slots <= 0 ) {
                delete_transient( $throttle_key );
                return new \WP_REST_Response([
                    'success' => false,
                    'message' => sprintf(
                        '質問の上限（%d件）に達しています。不要な質問を削除してから再度お試しください。',
                        self::SURVEY_QUESTION_LIMIT
                    ),
                    'limit'           => self::SURVEY_QUESTION_LIMIT,
                    'count'           => $existing_count,
                    'available_slots' => 0,
                ], 400);
            }
            // 残り枠に合わせて生成数を決定（ただし最低 2 問は確保したい: required + optional textarea）
            if ( $available_slots < 30 ) {
                $target_count = max( 2, $available_slots );
            }
        }

        // クライアント情報を読み込んでデフォルト値として使用
        $client = function_exists( 'gcrev_get_client_settings' ) ? gcrev_get_client_settings( $user_id ) : [];

        // 業種: 上書き > クライアント情報の industry（ラベル整形済み）
        $industry = sanitize_text_field( $params['industry'] ?? '' );
        if ( $industry === '' ) {
            $industry = (string) ( $client['industry'] ?? '' );
        }
        if ( $industry === '' && ! empty( $client['industry_detail'] ) ) {
            $industry = (string) $client['industry_detail'];
        }

        // 他のフィールド: 上書き > クライアント情報
        $service_description = sanitize_textarea_field( $params['service_description'] ?? '' );
        if ( $service_description === '' ) {
            $service_description = (string) ( $client['service_description'] ?? '' );
        }

        $strengths = sanitize_textarea_field( $params['strengths'] ?? '' );
        if ( $strengths === '' ) {
            $strengths = (string) ( $client['strengths'] ?? '' );
        }

        $review_emphasis = sanitize_textarea_field( $params['review_emphasis'] ?? '' );
        if ( $review_emphasis === '' ) {
            $review_emphasis = (string) ( $client['review_emphasis'] ?? '' );
        }

        // ターゲット: 上書き > ペルソナから組み立て
        $target = sanitize_textarea_field( $params['target'] ?? '' );
        if ( $target === '' ) {
            $target = $this->build_target_from_persona( $client );
        }

        // 【今回入力された内容】をアンケートに紐付けて保存（以降クライアント設定の変更で上書きされないよう固定）
        // 生成が失敗しても次回開いた時に同じ内容が保持されるよう、ここで先に保存する
        if ( $survey_id_for_check > 0 ) {
            $ctx_to_save = [
                'industry'            => $industry,
                'service_description' => $service_description,
                'target'              => $target,
                'strengths'           => $strengths,
                'review_emphasis'     => $review_emphasis,
                'updated_at'          => current_time( 'mysql' ),
            ];
            $t_surveys_upd = $wpdb->prefix . 'gcrev_surveys';
            $wpdb->update(
                $t_surveys_upd,
                [
                    'ai_generation_context' => wp_json_encode( $ctx_to_save, JSON_UNESCAPED_UNICODE ),
                    'updated_at'            => current_time( 'mysql' ),
                ],
                [ 'id' => $survey_id_for_check, 'user_id' => $user_id ],
                [ '%s', '%s' ],
                [ '%d', '%d' ]
            );
        }

        // サービス生成
        $service_file = get_template_directory() . '/inc/gcrev-api/modules/class-survey-question-generator-service.php';
        if ( ! file_exists( $service_file ) ) {
            return new \WP_REST_Response(['success' => false, 'message' => '生成サービスが見つかりません。'], 500);
        }
        require_once $service_file;

        if ( ! class_exists( 'Gcrev_Survey_Question_Generator_Service' ) ) {
            return new \WP_REST_Response(['success' => false, 'message' => '生成サービスクラスが読み込めません。'], 500);
        }

        @set_time_limit( 180 );
        $service = new \Gcrev_Survey_Question_Generator_Service();
        $result = $service->generate([
            'industry'            => $industry,
            'service_description' => $service_description,
            'target'              => $target,
            'strengths'           => $strengths,
            'review_emphasis'     => $review_emphasis,
        ], $target_count);

        if ( ! $result['success'] ) {
            return new \WP_REST_Response([
                'success' => false,
                'message' => $result['message'] ?? '生成に失敗しました。',
            ], 500);
        }

        return new \WP_REST_Response([
            'success'        => true,
            'questions'      => $result['questions'],
            'target_count'   => $target_count,
            'industry_label' => $result['industry_label'],
            'design_intent'  => $result['design_intent'],
            'echo'           => [
                'industry'            => $industry,
                'service_description' => $service_description,
                'target'              => $target,
                'strengths'           => $strengths,
                'review_emphasis'     => $review_emphasis,
            ],
        ], 200);
    }

    /**
     * POST survey/questions/bulk-save — 生成済みの複数質問を指定 survey_id に一括挿入する。
     * 既存質問には触れず、末尾に追加する。
     */
    public function rest_survey_questions_bulk_save(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params    = $request->get_json_params();
        $survey_id = absint( $params['survey_id'] ?? 0 );
        $user_id   = get_current_user_id();

        if ( ! $this->can_access_survey( $survey_id, $user_id ) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $questions = $params['questions'] ?? [];
        if ( ! is_array( $questions ) || empty( $questions ) ) {
            return new \WP_REST_Response(['success' => false, 'message' => '保存する質問がありません。'], 400);
        }

        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';

        // 上限チェック: 既存 + 今回追加 > 60 なら拒否
        $existing_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$t_questions} WHERE survey_id = %d",
            $survey_id
        ) );
        $available_slots = self::SURVEY_QUESTION_LIMIT - $existing_count;
        if ( $available_slots <= 0 ) {
            return new \WP_REST_Response([
                'success' => false,
                'message' => sprintf(
                    '質問は1アンケートあたり最大%d件までです。現在すでに %d 件あるため追加できません。不要な質問を削除してから再度お試しください。',
                    self::SURVEY_QUESTION_LIMIT, $existing_count
                ),
                'limit' => self::SURVEY_QUESTION_LIMIT,
                'count' => $existing_count,
            ], 400);
        }
        if ( count( $questions ) > $available_slots ) {
            return new \WP_REST_Response([
                'success' => false,
                'message' => sprintf(
                    '質問の上限（%d件）を超えます。現在 %d 件あり、残り %d 件まで追加可能です（今回の送信数: %d 件）。',
                    self::SURVEY_QUESTION_LIMIT, $existing_count, $available_slots, count( $questions )
                ),
                'limit'           => self::SURVEY_QUESTION_LIMIT,
                'count'           => $existing_count,
                'available_slots' => $available_slots,
                'incoming_count'  => count( $questions ),
            ], 400);
        }

        // 既存の最大 sort_order を取得
        $max_sort = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COALESCE(MAX(sort_order), 0) FROM {$t_questions} WHERE survey_id = %d",
            $survey_id
        ) );

        $valid_types = [ 'textarea', 'radio', 'checkbox', 'text', 'select' ];
        $inserted = 0;
        $skipped  = 0;

        foreach ( $questions as $q ) {
            if ( ! is_array( $q ) ) { $skipped++; continue; }
            $label = sanitize_text_field( $q['label'] ?? '' );
            if ( $label === '' ) { $skipped++; continue; }

            $type = sanitize_text_field( $q['type'] ?? 'textarea' );
            if ( ! in_array( $type, $valid_types, true ) ) { $type = 'textarea'; }

            $description = sanitize_text_field( $q['description'] ?? '' );
            $placeholder = sanitize_text_field( $q['placeholder'] ?? '' );
            $required    = ! empty( $q['required'] ) ? 1 : 0;
            $is_fixed    = ! empty( $q['is_fixed'] ) ? 1 : 0;

            $category = sanitize_text_field( $q['category'] ?? '' );
            if ( mb_strlen( $category ) > 32 ) { $category = mb_substr( $category, 0, 32 ); }

            $options_raw = $q['options'] ?? [];
            if ( ! is_array( $options_raw ) ) { $options_raw = []; }
            $options_clean = [];
            foreach ( $options_raw as $opt ) {
                $opt = sanitize_text_field( $opt );
                if ( $opt !== '' ) { $options_clean[] = $opt; }
            }
            $options_json = ! empty( $options_clean ) ? wp_json_encode( $options_clean, JSON_UNESCAPED_UNICODE ) : '';

            $max_sort++;
            $wpdb->insert(
                $t_questions,
                [
                    'survey_id'   => $survey_id,
                    'type'        => $type,
                    'label'       => $label,
                    'description' => $description,
                    'placeholder' => $placeholder,
                    'options'     => $options_json,
                    'required'    => $required,
                    'sort_order'  => $max_sort,
                    'is_active'   => 1,
                    'category'    => $category,
                    'is_fixed'    => $is_fixed,
                ],
                [ '%d', '%s', '%s', '%s', '%s', '%s', '%d', '%d', '%d', '%s', '%d' ]
            );
            $inserted++;
        }

        // survey の updated_at を更新
        $wpdb->update( $t_surveys, [ 'updated_at' => current_time( 'mysql' ) ], [ 'id' => $survey_id ], [ '%s' ], [ '%d' ] );

        return new \WP_REST_Response([
            'success'  => true,
            'inserted' => $inserted,
            'skipped'  => $skipped,
            'message'  => sprintf( '%d問を追加しました。', $inserted ),
        ], 200);
    }

    /**
     * POST /gcrev/v1/survey/generate-extra-prompt
     *
     * 参考口コミテキストを受け取り、Gemini で分析して
     * 追加プロンプトブロック（■参考口コミの傾向 + ■追加ルール）を生成する。
     * 生成結果は DB には保存せず、フロントに返すのみ。
     */
    public function rest_survey_generate_extra_prompt( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id = get_current_user_id();
        if ( $user_id <= 0 ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'ログインが必要です。' ], 401 );
        }

        // 連打防止（30秒）
        $throttle_key = 'gcrev_extra_prompt_gen_' . $user_id;
        if ( get_transient( $throttle_key ) ) {
            return new \WP_REST_Response( [
                'success' => false,
                'message' => '連続実行はできません。30秒後に再度お試しください。',
            ], 429 );
        }
        set_transient( $throttle_key, 1, 30 );

        $params = $request->get_json_params();
        $reviews_text = isset( $params['reviews'] ) ? sanitize_textarea_field( $params['reviews'] ) : '';

        if ( trim( $reviews_text ) === '' ) {
            delete_transient( $throttle_key );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => '参考口コミを入力してください。',
            ], 400 );
        }

        $service_file = get_template_directory() . '/inc/gcrev-api/modules/class-extra-prompt-generator-service.php';
        if ( ! file_exists( $service_file ) ) {
            delete_transient( $throttle_key );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '生成サービスが見つかりません。' ], 500 );
        }
        require_once $service_file;

        if ( ! class_exists( 'Gcrev_Extra_Prompt_Generator_Service' ) ) {
            delete_transient( $throttle_key );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '生成サービスクラスが読み込めません。' ], 500 );
        }

        @set_time_limit( 120 );
        try {
            $service = new \Gcrev_Extra_Prompt_Generator_Service();
            $result  = $service->generate( $reviews_text );

            if ( ! $result['success'] ) {
                return new \WP_REST_Response( $result, 502 );
            }
            return new \WP_REST_Response( $result, 200 );
        } catch ( \Throwable $e ) {
            file_put_contents(
                '/tmp/gcrev_extra_prompt_debug.log',
                date( 'Y-m-d H:i:s' ) . ' rest error: ' . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => 'サーバーエラー: ' . $e->getMessage(),
            ], 500 );
        }
    }

    /**
     * クライアント情報のペルソナ関連フィールドから、AI プロンプト用のターゲット記述を組み立てる。
     */
    private function build_target_from_persona( array $client ): string {
        $parts = [];

        $one_liner = trim( (string) ( $client['persona_one_liner'] ?? '' ) );
        if ( $one_liner !== '' ) {
            $parts[] = $one_liner;
        }

        $ages = is_array( $client['persona_age_ranges'] ?? null ) ? $client['persona_age_ranges'] : [];
        $genders = is_array( $client['persona_genders'] ?? null ) ? $client['persona_genders'] : [];
        $attrs = is_array( $client['persona_attributes'] ?? null ) ? $client['persona_attributes'] : [];

        $age_map = [
            'teens' => '10代', '20s' => '20代', '30s' => '30代',
            '40s' => '40代', '50s' => '50代', '60plus' => '60代以上',
        ];
        $gender_map = [ 'male' => '男性', 'female' => '女性', 'any' => '指定なし' ];
        $attr_map = [
            'family' => 'ファミリー層', 'single' => '単身者', 'dinks' => 'DINKS',
            'senior' => 'シニア', 'student' => '学生', 'business' => 'ビジネスパーソン',
            'owner' => '経営者・個人事業主', 'highincome' => '富裕層',
            'local' => '地元住民', 'tourist' => '観光客・旅行者',
        ];

        $age_labels = array_values( array_filter( array_map( static function ( $v ) use ( $age_map ) {
            return $age_map[ $v ] ?? $v;
        }, $ages ) ) );
        $gender_labels = array_values( array_filter( array_map( static function ( $v ) use ( $gender_map ) {
            return $gender_map[ $v ] ?? $v;
        }, $genders ) ) );
        $attr_labels = array_values( array_filter( array_map( static function ( $v ) use ( $attr_map ) {
            return $attr_map[ $v ] ?? $v;
        }, $attrs ) ) );

        if ( ! empty( $age_labels ) || ! empty( $gender_labels ) ) {
            $parts[] = sprintf(
                '年齢層: %s / 性別: %s',
                ! empty( $age_labels ) ? implode( '・', $age_labels ) : '指定なし',
                ! empty( $gender_labels ) ? implode( '・', $gender_labels ) : '指定なし'
            );
        }
        if ( ! empty( $attr_labels ) ) {
            $parts[] = '属性: ' . implode( '・', $attr_labels );
        }

        return implode( ' / ', $parts );
    }

    /**
     * POST survey/question/delete — 質問削除
     */
    public function rest_survey_question_delete(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params      = $request->get_json_params();
        $survey_id   = absint($params['survey_id'] ?? 0);
        $question_id = absint($params['question_id'] ?? 0);
        $user_id     = get_current_user_id();

        if (!$this->can_access_survey($survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';

        $wpdb->delete($t_questions, ['id' => $question_id, 'survey_id' => $survey_id], ['%d', '%d']);
        $wpdb->update($t_surveys, ['updated_at' => current_time('mysql')], ['id' => $survey_id], ['%s'], ['%d']);

        return new \WP_REST_Response(['success' => true], 200);
    }

    /**
     * POST survey/questions/bulk-delete — 質問一括削除
     * ペイロード:
     *   - { survey_id, question_ids: [1,2,3] } → 指定IDを削除
     *   - { survey_id, all: true } → 当該アンケートの全質問を削除
     */
    public function rest_survey_questions_bulk_delete(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params    = $request->get_json_params();
        $survey_id = absint($params['survey_id'] ?? 0);
        $all_flag  = ! empty($params['all']);
        $ids_raw   = $params['question_ids'] ?? [];
        $user_id   = get_current_user_id();

        if (!$this->can_access_survey($survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';

        if ($all_flag) {
            // 全削除
            $deleted = (int) $wpdb->delete($t_questions, ['survey_id' => $survey_id], ['%d']);
        } else {
            // ID 配列による一括削除
            if (!is_array($ids_raw) || empty($ids_raw)) {
                return new \WP_REST_Response(['success' => false, 'message' => '削除対象の質問が指定されていません。'], 400);
            }
            $ids = array_values(array_unique(array_filter(array_map('absint', $ids_raw), static function($v){ return $v > 0; })));
            if (empty($ids)) {
                return new \WP_REST_Response(['success' => false, 'message' => '削除対象の ID が不正です。'], 400);
            }

            // 安全な prepared statement（IN 句）を組み立て
            $placeholders = implode(',', array_fill(0, count($ids), '%d'));
            $sql = "DELETE FROM {$t_questions} WHERE survey_id = %d AND id IN ({$placeholders})";
            $args = array_merge([$survey_id], $ids);
            $deleted = (int) $wpdb->query($wpdb->prepare($sql, ...$args));
        }

        $wpdb->update($t_surveys, ['updated_at' => current_time('mysql')], ['id' => $survey_id], ['%s'], ['%d']);

        return new \WP_REST_Response([
            'success' => true,
            'deleted' => $deleted,
            'message' => $all_flag
                ? sprintf('%d件の質問をすべて削除しました。', $deleted)
                : sprintf('%d件の質問を削除しました。', $deleted),
        ], 200);
    }

    /**
     * POST survey/questions/classify — 質問を AI で 11 カテゴリに一括振り分け
     *
     * ペイロード:
     *   - { survey_id, only_uncategorized?: true } (デフォルト: true = 未分類のみ対象)
     *   - only_uncategorized=false の場合は全質問を再分類
     */
    public function rest_survey_questions_classify(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params    = $request->get_json_params();
        $survey_id = absint( $params['survey_id'] ?? 0 );
        $only_uncategorized = isset( $params['only_uncategorized'] ) ? (bool) $params['only_uncategorized'] : true;
        $user_id   = get_current_user_id();

        if ( ! $this->can_access_survey( $survey_id, $user_id ) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        // 連打防止（30秒）
        $throttle_key = 'gcrev_classify_' . $user_id;
        if ( get_transient( $throttle_key ) ) {
            return new \WP_REST_Response([
                'success' => false,
                'message' => '連続実行はできません。30秒後に再度お試しください。',
            ], 429);
        }
        set_transient( $throttle_key, 1, 30 );

        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $all_rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT id, label, category, type FROM {$t_questions} WHERE survey_id = %d ORDER BY sort_order ASC, id ASC",
            $survey_id
        ) );

        $valid_categories = [
            '不安・課題', '比較・検討', '決め手', '対応・コミュニケーション',
            '提案・特徴', '結果・体験', '他社との違い', 'おすすめ',
            '総合評価', '感情・印象', '自由回答',
        ];

        // 分類対象を絞り込み
        $targets = [];
        foreach ( $all_rows as $row ) {
            $cat = (string) ( $row->category ?? '' );
            if ( $only_uncategorized && in_array( $cat, $valid_categories, true ) ) {
                continue; // 既に正しいカテゴリなのでスキップ
            }
            $targets[] = [
                'id'    => (int) $row->id,
                'label' => (string) $row->label,
                'type'  => (string) $row->type,
            ];
        }

        if ( empty( $targets ) ) {
            delete_transient( $throttle_key );
            return new \WP_REST_Response([
                'success'    => true,
                'classified' => 0,
                'skipped'    => 0,
                'message'    => '分類対象の質問がありませんでした（すべて分類済み）。',
            ], 200);
        }

        // プロンプト構築: 質問リスト + カテゴリ一覧
        $question_lines = [];
        foreach ( $targets as $t ) {
            $question_lines[] = sprintf( '%d: [%s] %s', $t['id'], $t['type'], $t['label'] );
        }
        $cat_list = implode( ' / ', $valid_categories );
        $question_block = implode( "\n", $question_lines );

        $prompt = <<<PROMPT
以下の口コミアンケートの質問を、11 カテゴリのいずれかに分類してください。

# カテゴリ一覧
{$cat_list}

# カテゴリの説明
- 不安・課題: 利用前の悩み・不安・困っていたこと
- 比較・検討: 他社との比較、複数候補からの選定
- 決め手: 選んだ理由・決定打
- 対応・コミュニケーション: スタッフ・担当者の対応、連絡、説明の印象
- 提案・特徴: 受けた提案内容、サービスの特徴
- 結果・体験: 利用後の変化、感じた効果、体験エピソード
- 他社との違い: 他と比べて感じた違い
- おすすめ: 他者に勧めたいか、推奨度
- 総合評価: 全体満足度、星評価的な問い
- 感情・印象: 一言で言うと、感情表現、印象
- 自由回答: 自由記述、ひとこと、メッセージ、その他

# 分類対象の質問（ID: [質問タイプ] 質問文）
{$question_block}

# 出力要件
以下の JSON 形式のみを出力してください。説明文やコードフェンスは不要です。
各質問ID に対して、最も適切なカテゴリ（上記11種類のうち1つ）を割り当ててください。

{
  "assignments": [
    { "id": 123, "category": "不安・課題" },
    { "id": 124, "category": "決め手" }
  ]
}

# 厳守
- category は必ず上記11種類のいずれかの文字列
- 自由記述の textarea タイプの質問は基本的に「自由回答」を割り当てる
- どうしても判断できないものは「自由回答」にする
PROMPT;

        // AI 呼び出し（OpenAI 優先・Gemini フォールバック）
        try {
            $raw = $this->call_review_generation_api( $prompt );
        } catch ( \Throwable $e ) {
            delete_transient( $throttle_key );
            return new \WP_REST_Response([
                'success' => false,
                'message' => 'AI 呼び出しに失敗しました: ' . $e->getMessage(),
            ], 500);
        }

        // JSON パース
        $cleaned = preg_replace( '/```(?:json)?\s*/i', '', $raw );
        $cleaned = preg_replace( '/```\s*/', '', $cleaned );
        $cleaned = trim( $cleaned );
        $parsed = json_decode( $cleaned, true );
        if ( ! is_array( $parsed ) ) {
            // フォールバックで JSON ブロック抽出
            if ( preg_match( '/\{[\s\S]*\}/', $raw, $m ) ) {
                $parsed = json_decode( $m[0], true );
            }
        }
        $assignments = ( is_array( $parsed ) && isset( $parsed['assignments'] ) && is_array( $parsed['assignments'] ) )
            ? $parsed['assignments'] : [];

        if ( empty( $assignments ) ) {
            return new \WP_REST_Response([
                'success' => false,
                'message' => 'AI 応答から分類結果を抽出できませんでした。もう一度お試しください。',
            ], 500);
        }

        // マップ化 + 正規化
        $id_to_category = [];
        foreach ( $assignments as $a ) {
            if ( ! is_array( $a ) ) { continue; }
            $qid = absint( $a['id'] ?? 0 );
            $cat = (string) ( $a['category'] ?? '' );
            if ( $qid <= 0 ) { continue; }
            if ( ! in_array( $cat, $valid_categories, true ) ) { continue; }
            $id_to_category[ $qid ] = $cat;
        }

        // DB 更新
        $target_ids = array_column( $targets, 'id' );
        $classified = 0;
        $skipped    = 0;
        foreach ( $target_ids as $qid ) {
            if ( isset( $id_to_category[ $qid ] ) ) {
                $wpdb->update(
                    $t_questions,
                    [ 'category' => $id_to_category[ $qid ] ],
                    [ 'id' => $qid, 'survey_id' => $survey_id ],
                    [ '%s' ], [ '%d', '%d' ]
                );
                $classified++;
            } else {
                $skipped++;
            }
        }

        // survey の updated_at を更新
        $t_surveys = $wpdb->prefix . 'gcrev_surveys';
        $wpdb->update( $t_surveys, [ 'updated_at' => current_time( 'mysql' ) ], [ 'id' => $survey_id ], [ '%s' ], [ '%d' ] );

        return new \WP_REST_Response([
            'success'    => true,
            'classified' => $classified,
            'skipped'    => $skipped,
            'target'     => count( $targets ),
            'message'    => sprintf( '%d件の質問をカテゴリに振り分けました。%s',
                $classified,
                $skipped > 0 ? "（{$skipped}件は判定不可でスキップ）" : ''
            ),
        ], 200);
    }

    /**
     * POST survey/question/reorder — 質問並び順一括更新
     */
    public function rest_survey_question_reorder(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params    = $request->get_json_params();
        $survey_id = absint($params['survey_id'] ?? 0);
        $order     = $params['order'] ?? [];
        $user_id   = get_current_user_id();

        if (!$this->can_access_survey($survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        if (!is_array($order)) {
            return new \WP_REST_Response(['success' => false, 'message' => '並び順データが不正です。'], 400);
        }

        $t_questions = $wpdb->prefix . 'gcrev_survey_questions';
        $t_surveys   = $wpdb->prefix . 'gcrev_surveys';

        foreach ($order as $item) {
            $qid   = absint($item['id'] ?? 0);
            $sort   = absint($item['sort_order'] ?? 0);
            if ($qid <= 0) continue;
            $wpdb->update(
                $t_questions,
                ['sort_order' => $sort],
                ['id' => $qid, 'survey_id' => $survey_id],
                ['%d'],
                ['%d', '%d']
            );
        }

        $wpdb->update($t_surveys, ['updated_at' => current_time('mysql')], ['id' => $survey_id], ['%s'], ['%d']);

        return new \WP_REST_Response(['success' => true], 200);
    }

    // =========================================================
    // アンケート回答管理 REST API
    // =========================================================

    /**
     * GET survey/responses — 回答一覧（フィルタ・ページネーション）
     */
    public function rest_survey_responses(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $user_id   = get_current_user_id();
        $is_admin  = current_user_can('manage_options');
        $t_resp    = $wpdb->prefix . 'gcrev_survey_responses';
        $t_surv    = $wpdb->prefix . 'gcrev_surveys';
        $t_ai_gen  = $wpdb->prefix . 'gcrev_survey_ai_generations';

        $survey_id = absint($request->get_param('survey_id'));
        $status    = sanitize_text_field($request->get_param('status') ?? '');
        $ai_status = sanitize_text_field($request->get_param('ai_status') ?? '');
        $keyword   = sanitize_text_field($request->get_param('keyword') ?? '');
        $date_from = sanitize_text_field($request->get_param('date_from') ?? '');
        $date_to   = sanitize_text_field($request->get_param('date_to') ?? '');
        $page      = max(1, absint($request->get_param('page') ?? 1));
        $per_page  = min(100, max(1, absint($request->get_param('per_page') ?? 20)));

        $where = [];
        $args  = [];

        if ( ! $is_admin ) {
            $where[] = 's.user_id = %d';
            $args[]  = $user_id;
        }
        if ($survey_id > 0) {
            $where[] = 'r.survey_id = %d';
            $args[]  = $survey_id;
        }
        if (in_array($status, ['new', 'reviewed', 'utilized'], true)) {
            $where[] = 'r.status = %s';
            $args[]  = $status;
        }
        if ($date_from && preg_match('/^\d{4}-\d{2}-\d{2}$/', $date_from)) {
            $where[] = 'r.created_at >= %s';
            $args[]  = $date_from . ' 00:00:00';
        }
        if ($date_to && preg_match('/^\d{4}-\d{2}-\d{2}$/', $date_to)) {
            $where[] = 'r.created_at <= %s';
            $args[]  = $date_to . ' 23:59:59';
        }
        if ($keyword !== '') {
            $like = '%' . $wpdb->esc_like($keyword) . '%';
            $where[] = '(r.respondent_name LIKE %s OR r.admin_notes LIKE %s)';
            $args[]  = $like;
            $args[]  = $like;
        }

        $where_sql = $where ? 'WHERE ' . implode(' AND ', $where) : '';

        // Count
        $count_sql = "SELECT COUNT(DISTINCT r.id) FROM {$t_resp} r INNER JOIN {$t_surv} s ON r.survey_id = s.id {$where_sql}";
        $total = (int) ($args ? $wpdb->get_var($wpdb->prepare($count_sql, ...$args)) : $wpdb->get_var($count_sql));

        // Data
        $offset   = ($page - 1) * $per_page;
        $data_sql = "SELECT r.*, s.title AS survey_title,
                     (SELECT COUNT(*) FROM {$t_ai_gen} g WHERE g.response_id = r.id) AS ai_count
                     FROM {$t_resp} r
                     INNER JOIN {$t_surv} s ON r.survey_id = s.id
                     {$where_sql}
                     ORDER BY r.created_at DESC
                     LIMIT %d OFFSET %d";
        $data_args = array_merge($args, [$per_page, $offset]);
        $rows = $wpdb->get_results($wpdb->prepare($data_sql, ...$data_args));

        // ai_status フィルタ（後処理）
        if ($ai_status !== '') {
            $rows = array_values(array_filter($rows, function($r) use ($ai_status) {
                if ($ai_status === 'has_generated') return (int) $r->ai_count > 0;
                if ($ai_status === 'none') return (int) $r->ai_count === 0;
                return true;
            }));
        }

        $responses = array_map(function($r) {
            return [
                'id'              => (int) $r->id,
                'survey_id'       => (int) $r->survey_id,
                'survey_title'    => $r->survey_title,
                'respondent_name' => $r->respondent_name,
                'status'          => $r->status ?: 'new',
                'consent_ai'      => (bool) $r->consent_ai,
                'consent_review'  => (bool) $r->consent_review,
                'ai_count'        => (int) $r->ai_count,
                'created_at'      => $r->created_at,
            ];
        }, $rows);

        return new \WP_REST_Response([
            'responses'   => $responses,
            'total'       => $total,
            'page'        => $page,
            'per_page'    => $per_page,
            'total_pages' => max(1, (int) ceil($total / $per_page)),
        ], 200);
    }

    /**
     * GET survey/response/detail — 回答詳細（回答+質問+AI生成文）
     */
    public function rest_survey_response_detail(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $response_id = absint($request->get_param('response_id'));
        $user_id     = get_current_user_id();

        $t_resp    = $wpdb->prefix . 'gcrev_survey_responses';
        $t_surv    = $wpdb->prefix . 'gcrev_surveys';
        $t_ans     = $wpdb->prefix . 'gcrev_survey_response_answers';
        $t_q       = $wpdb->prefix . 'gcrev_survey_questions';
        $t_ai_gen  = $wpdb->prefix . 'gcrev_survey_ai_generations';

        $resp = $wpdb->get_row($wpdb->prepare(
            "SELECT r.*, s.title AS survey_title FROM {$t_resp} r INNER JOIN {$t_surv} s ON r.survey_id = s.id WHERE r.id = %d",
            $response_id
        ));
        if (!$resp) {
            return new \WP_REST_Response(['success' => false, 'message' => '回答が見つかりません。'], 404);
        }
        if (!$this->can_access_survey((int) $resp->survey_id, $user_id)) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        // 質問 + 回答
        $answers = $wpdb->get_results($wpdb->prepare(
            "SELECT a.question_id, a.answer, q.label AS question_label, q.type AS question_type
             FROM {$t_ans} a
             LEFT JOIN {$t_q} q ON a.question_id = q.id
             WHERE a.response_id = %d
             ORDER BY q.sort_order ASC, a.id ASC",
            $response_id
        ));

        $answer_list = array_map(function($a) {
            $answer_val = $a->answer;
            $decoded = json_decode($answer_val, true);
            if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
                $answer_val = $decoded;
            }
            return [
                'question_id'    => (int) $a->question_id,
                'question_label' => $a->question_label ?: '(削除された質問)',
                'question_type'  => $a->question_type ?: 'text',
                'answer'         => $answer_val,
            ];
        }, $answers);

        // AI生成文
        $ai_gens = $wpdb->get_results($wpdb->prepare(
            "SELECT * FROM {$t_ai_gen} WHERE response_id = %d ORDER BY created_at DESC",
            $response_id
        ));
        $ai_list = array_map(function($g) {
            return [
                'id'             => (int) $g->id,
                'generated_text' => $g->generated_text,
                'review_type'    => $g->review_type,
                'version'        => (int) $g->version,
                'status'         => $g->status,
                'generation_params' => $g->generation_params ? json_decode($g->generation_params, true) : null,
                'created_at'     => $g->created_at,
            ];
        }, $ai_gens);

        return new \WP_REST_Response([
            'success'  => true,
            'response' => [
                'id'              => (int) $resp->id,
                'survey_id'       => (int) $resp->survey_id,
                'survey_title'    => $resp->survey_title,
                'respondent_name' => $resp->respondent_name,
                'status'          => $resp->status ?: 'new',
                'consent_ai'      => (bool) $resp->consent_ai,
                'consent_review'  => (bool) $resp->consent_review,
                'admin_notes'     => $resp->admin_notes ?: '',
                'created_at'      => $resp->created_at,
            ],
            'answers'      => $answer_list,
            'ai_generations' => $ai_list,
        ], 200);
    }

    /**
     * POST survey/response/status — 回答ステータス更新
     */
    public function rest_survey_response_status(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params      = $request->get_json_params();
        $response_id = absint($params['response_id'] ?? 0);
        $new_status  = sanitize_text_field($params['status'] ?? '');
        $user_id     = get_current_user_id();

        if ( ! in_array($new_status, ['new', 'reviewed', 'utilized'], true) ) {
            return new \WP_REST_Response(['success' => false, 'message' => '無効なステータスです。'], 400);
        }

        $t_resp = $wpdb->prefix . 'gcrev_survey_responses';
        $survey_id = (int) $wpdb->get_var($wpdb->prepare("SELECT survey_id FROM {$t_resp} WHERE id = %d", $response_id));
        if ( ! $this->can_access_survey($survey_id, $user_id) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $wpdb->update($t_resp, ['status' => $new_status], ['id' => $response_id], ['%s'], ['%d']);

        return new \WP_REST_Response(['success' => true], 200);
    }

