        return new \WP_REST_Response(['success' => true], 200);
    }

    // =========================================================
    // アンケートAI生成管理 REST API
    // =========================================================

    /**
     * POST survey/ai-generate — 既存回答からAI口コミ文を再生成
     */
    public function rest_survey_ai_generate(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params      = $request->get_json_params();
        $response_id = absint($params['response_id'] ?? 0);
        $tone        = sanitize_text_field($params['tone'] ?? '');
        $emphasis    = sanitize_text_field($params['emphasis'] ?? '');
        $user_id     = get_current_user_id();

        $t_resp   = $wpdb->prefix . 'gcrev_survey_responses';
        $t_ans    = $wpdb->prefix . 'gcrev_survey_response_answers';
        $t_q      = $wpdb->prefix . 'gcrev_survey_questions';
        $t_ai_gen = $wpdb->prefix . 'gcrev_survey_ai_generations';

        $resp = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$t_resp} WHERE id = %d", $response_id));
        if ( ! $resp ) {
            return new \WP_REST_Response(['success' => false, 'message' => '回答が見つかりません。'], 404);
        }
        if ( ! $this->can_access_survey((int) $resp->survey_id, $user_id) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        // 回答データを再構築
        $raw_answers = $wpdb->get_results($wpdb->prepare(
            "SELECT a.answer, q.label AS question FROM {$t_ans} a LEFT JOIN {$t_q} q ON a.question_id = q.id WHERE a.response_id = %d ORDER BY q.sort_order ASC",
            $response_id
        ));

        $answers = [];
        foreach ($raw_answers as $ra) {
            $answer = $ra->answer;
            $decoded = json_decode($answer, true);
            if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
                $answer = $decoded;
            }
            $answers[] = ['question' => $ra->question ?: '', 'answer' => $answer];
        }

        $answer_text = $this->format_review_answers($answers);
        if (empty($answer_text)) {
            return new \WP_REST_Response(['success' => false, 'message' => '有効な回答データがありません。'], 400);
        }

        $business_name = function_exists('gcrev_get_business_name')
            ? gcrev_get_business_name((int) $resp->user_id)
            : (get_user_meta((int) $resp->user_id, 'gcrev_business_name', true) ?: '');

        // アンケートに紐づく AI 設定（キーワード・追加プロンプト・参考口コミサンプル）も反映
        $t_surveys_for_ai = $wpdb->prefix . 'gcrev_surveys';
        $survey_ai = $wpdb->get_row($wpdb->prepare(
            "SELECT ai_keywords, ai_extra_prompt, ai_reference_reviews FROM {$t_surveys_for_ai} WHERE id = %d",
            (int) $resp->survey_id
        ));
        $ai_keywords          = $survey_ai && !empty($survey_ai->ai_keywords)     ? (string) $survey_ai->ai_keywords     : '';
        $ai_extra_prompt      = $survey_ai && !empty($survey_ai->ai_extra_prompt) ? (string) $survey_ai->ai_extra_prompt : '';
        $ai_reference_reviews = [];
        if ($survey_ai && !empty($survey_ai->ai_reference_reviews)) {
            $decoded_refs = json_decode((string) $survey_ai->ai_reference_reviews, true);
            if (is_array($decoded_refs)) { $ai_reference_reviews = $decoded_refs; }
        }

        // 業種・サービス内容・ターゲット・強み・口コミ重点を解決
        // アンケートに保存された ai_generation_context（モーダルで入力した値）を優先、
        // 空欄フィールドのみクライアント設定でフォールバック補完する
        $client_info = $this->resolve_review_generation_context( (int) $resp->survey_id, (int) $resp->user_id );

        $prompt = $this->build_review_prompt($answer_text, $business_name, $ai_keywords, $ai_extra_prompt, $ai_reference_reviews, $client_info);

        // トーン・強調指定がある場合、プロンプトに追加
        if ($tone || $emphasis) {
            $extra_instructions = "\n\n## 追加指示\n";
            if ($tone) $extra_instructions .= "- 口調: {$tone}\n";
            if ($emphasis) $extra_instructions .= "- 強調ポイント: {$emphasis}\n";
            $prompt .= $extra_instructions;
        }

        try {
            // 生成＋禁止フレーズ検出＋自動再生成
            // 店舗名が本文に混入した場合も禁止扱いで再生成される
            $parsed = $this->generate_review_with_retry( $prompt, (string) $business_name );
            if ($parsed === null) {
                file_put_contents('/tmp/gcrev_review_debug.log',
                    date('Y-m-d H:i:s') . " AI re-generate parse failed (after retry)\n",
                    FILE_APPEND
                );
                return new \WP_REST_Response(['success' => false, 'message' => '口コミ案の生成に失敗しました。'], 500);
            }

            $now = current_time('mysql');
            $gen_params = wp_json_encode([
                'tone'     => $tone,
                'emphasis' => $emphasis,
                'model'    => $this->config->get_gemini_model(),
            ], JSON_UNESCAPED_UNICODE);

            // 2026年4月以降は 'normal' 1本のみ生成する方針
            $results = [];
            $text = (string) ($parsed['normal_review'] ?? '');
            if ($text !== '') {
                $max_ver = (int) $wpdb->get_var($wpdb->prepare(
                    "SELECT COALESCE(MAX(version), 0) FROM {$t_ai_gen} WHERE response_id = %d AND review_type = %s",
                    $response_id, 'normal'
                ));
                $wpdb->insert($t_ai_gen, [
                    'response_id'       => $response_id,
                    'survey_id'         => (int) $resp->survey_id,
                    'user_id'           => (int) $resp->user_id,
                    'generated_text'    => $text,
                    'review_type'       => 'normal',
                    'version'           => $max_ver + 1,
                    'status'            => 'generated',
                    'generation_params' => $gen_params,
                    'created_at'        => $now,
                ], ['%d', '%d', '%d', '%s', '%s', '%d', '%s', '%s', '%s']);
                $results[] = [
                    'id'             => (int) $wpdb->insert_id,
                    'review_type'    => 'normal',
                    'generated_text' => $text,
                    'version'        => $max_ver + 1,
                ];
            }

            return new \WP_REST_Response(['success' => true, 'generations' => $results], 200);

        } catch (\Exception $e) {
            file_put_contents('/tmp/gcrev_review_debug.log',
                date('Y-m-d H:i:s') . " AI re-generate error: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response(['success' => false, 'message' => '口コミ案の生成に失敗しました。'], 500);
        }
    }

    /**
     * GET survey/ai-generations — AI生成履歴一覧
     */
    public function rest_survey_ai_generations(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $user_id   = get_current_user_id();
        $is_admin  = current_user_can('manage_options');
        $t_ai_gen  = $wpdb->prefix . 'gcrev_survey_ai_generations';
        $t_surv    = $wpdb->prefix . 'gcrev_surveys';
        $t_resp    = $wpdb->prefix . 'gcrev_survey_responses';

        $survey_id = absint($request->get_param('survey_id'));
        $status    = sanitize_text_field($request->get_param('status') ?? '');
        $date_from = sanitize_text_field($request->get_param('date_from') ?? '');
        $date_to   = sanitize_text_field($request->get_param('date_to') ?? '');
        $page      = max(1, absint($request->get_param('page') ?? 1));
        $per_page  = min(100, max(1, absint($request->get_param('per_page') ?? 20)));

        $where = [];
        $args  = [];

        if ( ! $is_admin ) {
            $where[] = 'g.user_id = %d';
            $args[]  = $user_id;
        }
        if ($survey_id > 0) {
            $where[] = 'g.survey_id = %d';
            $args[]  = $survey_id;
        }
        if (in_array($status, ['generated', 'adopted', 'rejected', 'posted'], true)) {
            $where[] = 'g.status = %s';
            $args[]  = $status;
        }
        if ($date_from && preg_match('/^\d{4}-\d{2}-\d{2}$/', $date_from)) {
            $where[] = 'g.created_at >= %s';
            $args[]  = $date_from . ' 00:00:00';
        }
        if ($date_to && preg_match('/^\d{4}-\d{2}-\d{2}$/', $date_to)) {
            $where[] = 'g.created_at <= %s';
            $args[]  = $date_to . ' 23:59:59';
        }

        $where_sql = $where ? 'WHERE ' . implode(' AND ', $where) : '';

        $count_sql = "SELECT COUNT(*) FROM {$t_ai_gen} g {$where_sql}";
        $total = (int) ($args ? $wpdb->get_var($wpdb->prepare($count_sql, ...$args)) : $wpdb->get_var($count_sql));

        $offset   = ($page - 1) * $per_page;
        $data_sql = "SELECT g.*, s.title AS survey_title, r.respondent_name
                     FROM {$t_ai_gen} g
                     INNER JOIN {$t_surv} s ON g.survey_id = s.id
                     LEFT JOIN {$t_resp} r ON g.response_id = r.id
                     {$where_sql}
                     ORDER BY g.created_at DESC
                     LIMIT %d OFFSET %d";
        $data_args = array_merge($args, [$per_page, $offset]);
        $rows = $wpdb->get_results($wpdb->prepare($data_sql, ...$data_args));

        $generations = array_map(function($g) {
            return [
                'id'              => (int) $g->id,
                'response_id'     => (int) $g->response_id,
                'survey_id'       => (int) $g->survey_id,
                'survey_title'    => $g->survey_title,
                'respondent_name' => $g->respondent_name ?: '',
                'generated_text'  => $g->generated_text,
                'review_type'     => $g->review_type,
                'version'         => (int) $g->version,
                'status'          => $g->status,
                'created_at'      => $g->created_at,
            ];
        }, $rows);

        return new \WP_REST_Response([
            'generations' => $generations,
            'total'       => $total,
            'page'        => $page,
            'per_page'    => $per_page,
            'total_pages' => max(1, (int) ceil($total / $per_page)),
        ], 200);
    }

    /**
     * POST survey/ai-generation/status — AI生成文ステータス変更
     */
    public function rest_survey_ai_generation_status(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $params        = $request->get_json_params();
        $generation_id = absint($params['generation_id'] ?? 0);
        $new_status    = sanitize_text_field($params['status'] ?? '');
        $user_id       = get_current_user_id();

        if ( ! in_array($new_status, ['generated', 'adopted', 'rejected', 'posted'], true) ) {
            return new \WP_REST_Response(['success' => false, 'message' => '無効なステータスです。'], 400);
        }

        $t_ai_gen = $wpdb->prefix . 'gcrev_survey_ai_generations';
        $gen = $wpdb->get_row($wpdb->prepare("SELECT survey_id FROM {$t_ai_gen} WHERE id = %d", $generation_id));
        if ( ! $gen || ! $this->can_access_survey((int) $gen->survey_id, $user_id) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $wpdb->update($t_ai_gen, ['status' => $new_status], ['id' => $generation_id], ['%s'], ['%d']);

        return new \WP_REST_Response(['success' => true], 200);
    }

    // =========================================================
    // アンケート集計・分析 REST API
    // =========================================================

    /**
     * GET survey/analytics — 集計データ
     */
    public function rest_survey_analytics(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $user_id   = get_current_user_id();
        $survey_id = absint($request->get_param('survey_id'));
        $date_from = sanitize_text_field($request->get_param('date_from') ?? '');
        $date_to   = sanitize_text_field($request->get_param('date_to') ?? '');

        if ($survey_id <= 0) {
            return new \WP_REST_Response(['success' => false, 'message' => 'survey_id は必須です。'], 400);
        }
        if ( ! $this->can_access_survey($survey_id, $user_id) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $t_resp   = $wpdb->prefix . 'gcrev_survey_responses';
        $t_ans    = $wpdb->prefix . 'gcrev_survey_response_answers';
        $t_q      = $wpdb->prefix . 'gcrev_survey_questions';
        $t_ai_gen = $wpdb->prefix . 'gcrev_survey_ai_generations';

        $date_where = '';
        $date_args  = [$survey_id];
        if ($date_from && preg_match('/^\d{4}-\d{2}-\d{2}$/', $date_from)) {
            $date_where .= ' AND r.created_at >= %s';
            $date_args[] = $date_from . ' 00:00:00';
        }
        if ($date_to && preg_match('/^\d{4}-\d{2}-\d{2}$/', $date_to)) {
            $date_where .= ' AND r.created_at <= %s';
            $date_args[] = $date_to . ' 23:59:59';
        }

        // サマリ
        $total_responses = (int) $wpdb->get_var($wpdb->prepare(
            "SELECT COUNT(*) FROM {$t_resp} r WHERE r.survey_id = %d {$date_where}",
            ...$date_args
        ));
        $by_status = $wpdb->get_results($wpdb->prepare(
            "SELECT r.status, COUNT(*) AS cnt FROM {$t_resp} r WHERE r.survey_id = %d {$date_where} GROUP BY r.status",
            ...$date_args
        ));
        $status_map = [];
        foreach ($by_status as $row) {
            $status_map[$row->status ?: 'new'] = (int) $row->cnt;
        }

        // AI統計
        $ai_stats = $wpdb->get_results($wpdb->prepare(
            "SELECT g.status, COUNT(*) AS cnt FROM {$t_ai_gen} g WHERE g.survey_id = %d GROUP BY g.status",
            $survey_id
        ));
        $ai_map = [];
        $ai_total = 0;
        foreach ($ai_stats as $row) {
            $ai_map[$row->status] = (int) $row->cnt;
            $ai_total += (int) $row->cnt;
        }

        // 質問別回答分布
        $questions = $wpdb->get_results($wpdb->prepare(
            "SELECT * FROM {$t_q} WHERE survey_id = %d AND is_active = 1 ORDER BY sort_order ASC",
            $survey_id
        ));

        $question_stats = [];
        foreach ($questions as $q) {
            $answers = $wpdb->get_col($wpdb->prepare(
                "SELECT a.answer FROM {$t_ans} a INNER JOIN {$t_resp} r ON a.response_id = r.id WHERE a.question_id = %d AND r.survey_id = %d {$date_where}",
                ...array_merge([(int) $q->id], $date_args)
            ));

            $dist = [];
            $total_ans = count($answers);
            if (in_array($q->type, ['checkbox', 'radio'], true)) {
                foreach ($answers as $ans_raw) {
                    $decoded = json_decode($ans_raw, true);
                    $values = (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) ? $decoded : [$ans_raw];
                    foreach ($values as $v) {
                        $v = trim($v);
                        if ($v === '') continue;
                        $dist[$v] = ($dist[$v] ?? 0) + 1;
                    }
                }
                arsort($dist);
            }

            $question_stats[] = [
                'question_id'   => (int) $q->id,
                'label'         => $q->label,
                'type'          => $q->type,
                'is_fixed'      => ! empty( $q->is_fixed ),
                'category'      => $q->category ?? '',
                'total_answers' => $total_ans,
                'distribution'  => $dist,
            ];
        }

        // 回答推移（月別）
        $trend = $wpdb->get_results($wpdb->prepare(
            "SELECT DATE_FORMAT(r.created_at, '%%Y-%%m') AS month, COUNT(*) AS cnt
             FROM {$t_resp} r WHERE r.survey_id = %d {$date_where}
             GROUP BY month ORDER BY month ASC",
            ...$date_args
        ));

        return new \WP_REST_Response([
            'success' => true,
            'summary' => [
                'total_responses' => $total_responses,
                'by_status'       => $status_map,
                'ai_total'        => $ai_total,
                'ai_by_status'    => $ai_map,
            ],
            'questions' => $question_stats,
            'trend'     => array_map(function($t) { return ['month' => $t->month, 'count' => (int) $t->cnt]; }, $trend),
        ], 200);
    }

    /**
     * GET survey/analysis — 分析データ（Gemini AIで分析）
     */
    public function rest_survey_analysis(\WP_REST_Request $request): \WP_REST_Response {
        global $wpdb;
        $user_id   = get_current_user_id();
        $survey_id = absint($request->get_param('survey_id'));

        if ($survey_id <= 0) {
            return new \WP_REST_Response(['success' => false, 'message' => 'survey_id は必須です。'], 400);
        }
        if ( ! $this->can_access_survey($survey_id, $user_id) ) {
            return new \WP_REST_Response(['success' => false, 'message' => 'アクセス権がありません。'], 403);
        }

        $t_resp   = $wpdb->prefix . 'gcrev_survey_responses';
        $t_ans    = $wpdb->prefix . 'gcrev_survey_response_answers';
        $t_q      = $wpdb->prefix . 'gcrev_survey_questions';
        $t_ai_gen = $wpdb->prefix . 'gcrev_survey_ai_generations';

        // キャッシュチェック
        $cache_key = "gcrev_survey_analysis_{$survey_id}";
        $cached = get_transient($cache_key);
        if ($cached !== false) {
            return new \WP_REST_Response(['success' => true, 'analysis' => $cached, 'cached' => true], 200);
        }

        // 回答データ収集
        $response_count = (int) $wpdb->get_var($wpdb->prepare(
            "SELECT COUNT(*) FROM {$t_resp} WHERE survey_id = %d", $survey_id
        ));

        if ($response_count === 0) {
            return new \WP_REST_Response(['success' => true, 'analysis' => null, 'message' => '回答データがまだありません。'], 200);
        }

        // 全回答テキストを集約
        $all_answers = $wpdb->get_results($wpdb->prepare(
            "SELECT q.label AS question, a.answer, q.type AS question_type
             FROM {$t_ans} a
             INNER JOIN {$t_resp} r ON a.response_id = r.id
             LEFT JOIN {$t_q} q ON a.question_id = q.id
             WHERE r.survey_id = %d
             ORDER BY q.sort_order ASC",
            $survey_id
        ));

        // 質問ごとにグルーピング
        $grouped = [];
        foreach ($all_answers as $row) {
            $q_label = $row->question ?: '(不明)';
            if (!isset($grouped[$q_label])) {
                $grouped[$q_label] = ['type' => $row->question_type, 'answers' => []];
            }
            $decoded = json_decode($row->answer, true);
            if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
                $grouped[$q_label]['answers'][] = implode('、', $decoded);
            } else {
                $grouped[$q_label]['answers'][] = $row->answer;
            }
        }

        // AI生成統計
        $ai_adoption = $wpdb->get_results($wpdb->prepare(
            "SELECT status, COUNT(*) AS cnt FROM {$t_ai_gen} WHERE survey_id = %d GROUP BY status",
            $survey_id
        ));

        // プロンプト構築
        $summary_text = "アンケート回答数: {$response_count}件\n\n";
        foreach ($grouped as $q_label => $data) {
            $sample = array_slice($data['answers'], 0, 50);
            $summary_text .= "【{$q_label}】（{$data['type']}型, 回答数: " . count($data['answers']) . "件）\n";
            $summary_text .= implode("\n", $sample) . "\n\n";
        }

        $ai_stats_text = '';
        foreach ($ai_adoption as $row) {
            $ai_stats_text .= "{$row->status}: {$row->cnt}件 / ";
        }

        $prompt = <<<PROMPT
あなたは口コミ・アンケート分析の専門家です。
以下のアンケート回答データを分析し、ビジネス改善に役立つインサイトを提供してください。

## アンケート回答データ
{$summary_text}

## AI口コミ生成統計
{$ai_stats_text}

## 分析して欲しい内容
1. よく選ばれている回答の傾向（satisfaction_trends）
2. 顧客が満足しているポイントTOP5（satisfaction_points）
3. 改善の余地がありそうなポイント（improvement_areas）
4. 自由記述でよく出てくるキーワードTOP10（frequent_keywords）
5. 口コミとして使いやすい内容の候補3つ（review_candidates）
6. 総合コメント（overall_comment）

## 出力形式
以下のJSON形式のみを出力してください。
```json
{
  "satisfaction_trends": ["傾向1", "傾向2", ...],
  "satisfaction_points": ["ポイント1", "ポイント2", ...],
  "improvement_areas": ["改善点1", "改善点2", ...],
  "frequent_keywords": ["キーワード1", "キーワード2", ...],
  "review_candidates": ["候補文1", "候補文2", "候補文3"],
  "overall_comment": "総合的な分析コメント"
}
```
PROMPT;

        try {
            $raw = $this->ai->call_gemini_api($prompt);
            $cleaned = preg_replace('/```(?:json)?\s*/i', '', $raw);
            $cleaned = preg_replace('/```\s*/', '', $cleaned);
            $cleaned = trim($cleaned);
            $analysis = json_decode($cleaned, true);

            if (!is_array($analysis)) {
                file_put_contents('/tmp/gcrev_review_debug.log',
                    date('Y-m-d H:i:s') . " analysis parse failed: " . substr($raw, 0, 500) . "\n",
                    FILE_APPEND
                );
                return new \WP_REST_Response(['success' => false, 'message' => '分析結果の解析に失敗しました。'], 500);
            }

            // 1時間キャッシュ
            set_transient($cache_key, $analysis, HOUR_IN_SECONDS);

            return new \WP_REST_Response(['success' => true, 'analysis' => $analysis, 'cached' => false], 200);

        } catch (\Exception $e) {
            file_put_contents('/tmp/gcrev_review_debug.log',
                date('Y-m-d H:i:s') . " analysis error: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response(['success' => false, 'message' => '分析の実行に失敗しました。'], 500);
        }
    }

    // =========================================================
    // アンケート カラーカスタマイズ
    // =========================================================

    /**
     * アンケートフォームのカラー設定を取得
     */
    public function rest_survey_colors_get(\WP_REST_Request $request): \WP_REST_Response {
        $user_id  = get_current_user_id();
        $defaults = self::survey_color_defaults();
        $colors   = [];
        foreach ($defaults as $key => $default) {
            $val = get_user_meta($user_id, 'gcrev_survey_color_' . $key, true);
            $colors[$key] = ($val !== '' && $val !== false) ? $val : $default;
        }
        return new \WP_REST_Response([
            'success'  => true,
            'colors'   => $colors,
            'defaults' => $defaults,
        ]);
    }

    /**
     * アンケートフォームのカラー設定を保存
     */
    public function rest_survey_colors_save(\WP_REST_Request $request): \WP_REST_Response {
        $user_id = get_current_user_id();
        $params  = $request->get_json_params();
        $colors  = $params['colors'] ?? [];

        $valid_keys = array_keys(self::survey_color_defaults());
        $saved      = [];

        foreach ($valid_keys as $key) {
            if (isset($colors[$key])) {
                $val = sanitize_text_field($colors[$key]);
                if (preg_match('/^#[A-Fa-f0-9]{6}$/', $val)) {
                    update_user_meta($user_id, 'gcrev_survey_color_' . $key, $val);
                    $saved[$key] = $val;
                }
            }
        }

        return new \WP_REST_Response([
            'success' => true,
            'saved'   => $saved,
        ]);
    }

    /**
     * カラー設定デフォルト値
     */
    public static function survey_color_defaults(): array {
        return [
            'header_bg'    => '#2C3E50',
            'heading_text' => '#2C3E40',
            'button_bg'    => '#2C3E50',
            'button_text'  => '#FFFFFF',
            'accent'       => '#3b82f6',
            'accent_text'  => '#FFFFFF',
        ];
    }

    // =========================================================
    // 口コミ管理（GBP Reviews API）
    // =========================================================

    /**
     * ユーザーの GBP ロケーションに対応するアカウント名を取得
     * 結果は user meta にキャッシュする
     */
    public function gbp_get_account_for_location( int $user_id ): ?string {
        $cached = get_user_meta( $user_id, '_gcrev_gbp_account_name', true );
        if ( ! empty( $cached ) ) {
            return $cached;
        }

        $access_token = $this->gbp_get_access_token( $user_id );
        if ( empty( $access_token ) ) {
            return null;
        }

        $location_id = get_user_meta( $user_id, '_gcrev_gbp_location_id', true );
        if ( empty( $location_id ) || strpos( $location_id, 'pending_' ) === 0 ) {
            return null;
        }

        // アカウント一覧取得
        $accounts_url  = 'https://mybusinessaccountmanagement.googleapis.com/v1/accounts';
        $accounts_resp = wp_remote_get( $accounts_url, [
            'headers' => [ 'Authorization' => 'Bearer ' . $access_token ],
            'timeout' => 30,
        ] );
        if ( is_wp_error( $accounts_resp ) || wp_remote_retrieve_response_code( $accounts_resp ) !== 200 ) {
            return null;
        }
        $accounts_data = json_decode( wp_remote_retrieve_body( $accounts_resp ), true );
        $accounts      = $accounts_data['accounts'] ?? [];

        // 各アカウントのロケーションを照合
        foreach ( $accounts as $account ) {
            $account_name = $account['name'] ?? '';
            if ( empty( $account_name ) ) {
                continue;
            }
            $url = "https://mybusinessbusinessinformation.googleapis.com/v1/{$account_name}/locations"
                 . '?' . http_build_query( [ 'readMask' => 'name', 'pageSize' => 100 ], '', '&' );
            $resp = wp_remote_get( $url, [
                'headers' => [ 'Authorization' => 'Bearer ' . $access_token ],
                'timeout' => 30,
            ] );
            if ( is_wp_error( $resp ) || wp_remote_retrieve_response_code( $resp ) !== 200 ) {
                continue;
            }
            $locs = json_decode( wp_remote_retrieve_body( $resp ), true )['locations'] ?? [];
            foreach ( $locs as $loc ) {
                if ( ( $loc['name'] ?? '' ) === $location_id ) {
                    update_user_meta( $user_id, '_gcrev_gbp_account_name', $account_name );
                    return $account_name;
                }
            }
        }
        return null;
    }

    /**
     * GBP Reviews API でレビュー一覧を取得
     */
    public function gbp_fetch_reviews( int $user_id, string $page_token = '' ): array {
        // キャッシュ（ページトークンなしの1ページ目のみ）
        if ( empty( $page_token ) ) {
            $cached = get_transient( "gcrev_reviews_{$user_id}" );
            if ( $cached !== false && is_array( $cached ) ) {
                return $cached;
            }
        }

        $access_token = $this->gbp_get_access_token( $user_id );
        if ( empty( $access_token ) ) {
            return [ 'success' => false, 'message' => 'GBPアクセストークンを取得できません。MEO設定からGoogleアカウントを再接続してください。' ];
        }

        $account_name = $this->gbp_get_account_for_location( $user_id );
        $location_id  = get_user_meta( $user_id, '_gcrev_gbp_location_id', true );
        if ( empty( $account_name ) || empty( $location_id ) ) {
            return [ 'success' => false, 'message' => 'GBPロケーション情報が見つかりません。MEOダッシュボードでロケーションを設定してください。' ];
        }

        $params = [ 'pageSize' => 50 ];
        if ( ! empty( $page_token ) ) {
            $params['pageToken'] = $page_token;
        }

        // Google My Business API v4 で口コミ一覧を取得
        // ※ Google Cloud Console で「Google My Business API」の有効化が必要
        $url = "https://mybusiness.googleapis.com/v4/{$account_name}/{$location_id}/reviews"
             . '?' . http_build_query( $params, '', '&' );

        file_put_contents( '/tmp/gcrev_gbp_debug.log',
            date( 'Y-m-d H:i:s' ) . " reviews API request: {$account_name}/{$location_id}/reviews\n",
            FILE_APPEND );

        $response = wp_remote_get( $url, [
            'headers' => [ 'Authorization' => 'Bearer ' . $access_token ],
            'timeout' => 30,
        ] );

        if ( is_wp_error( $response ) ) {
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " reviews API error: " . $response->get_error_message() . "\n",
                FILE_APPEND );
            return [ 'success' => false, 'message' => 'Google API接続エラー: ' . $response->get_error_message() ];
        }

        $status = wp_remote_retrieve_response_code( $response );
        if ( $status !== 200 ) {
            $body = wp_remote_retrieve_body( $response );
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " reviews API HTTP {$status}: " . substr( $body, 0, 1000 ) . "\n",
                FILE_APPEND );

            // 403: API未有効化の可能性が高い
            if ( $status === 403 ) {
                $error_data = json_decode( $body, true );
                $error_msg  = $error_data['error']['message'] ?? '';

                // API が有効化されていない場合の案内
                if ( strpos( $body, 'has not been used' ) !== false
                  || strpos( $body, 'is not enabled' ) !== false
                  || strpos( $body, 'PERMISSION_DENIED' ) !== false
                  || strpos( $body, 'forbidden' ) !== false ) {
                    return [
                        'success' => false,
                        'message' => "口コミ機能を利用するには、Google Cloud Console で「Google My Business API」を有効化してください。\n"
                            . "手順: Google Cloud Console → APIとサービス → ライブラリ → 「My Business」で検索 → 「Google My Business API」を有効化",
                    ];
                }
                return [ 'success' => false, 'message' => "口コミの取得に失敗しました（HTTP 403）。\nアクセス権限を確認してください。\n詳細: " . substr( $error_msg, 0, 200 ) ];
            }
            return [ 'success' => false, 'message' => "口コミの取得に失敗しました（HTTP {$status}）。" ];
        }

        $data = json_decode( wp_remote_retrieve_body( $response ), true );

        $result = [
            'success'          => true,
            'reviews'          => $data['reviews'] ?? [],
            'totalReviewCount' => (int) ( $data['totalReviewCount'] ?? 0 ),
            'averageRating'    => (float) ( $data['averageRating'] ?? 0 ),
            'nextPageToken'    => $data['nextPageToken'] ?? null,
        ];

        // 1ページ目のみキャッシュ (1時間)
        if ( empty( $page_token ) ) {
            set_transient( "gcrev_reviews_{$user_id}", $result, HOUR_IN_SECONDS );
        }

        return $result;
    }

    /**
     * GBP Reviews API で返信を投稿/更新
     */
    private function gbp_reply_to_review( int $user_id, string $review_name, string $comment ): array {
        $access_token = $this->gbp_get_access_token( $user_id );
        if ( empty( $access_token ) ) {
            return [ 'success' => false, 'message' => 'アクセストークンを取得できません。' ];
        }

        $url = "https://mybusiness.googleapis.com/v4/{$review_name}/reply";
        $response = wp_remote_request( $url, [
            'method'  => 'PUT',
            'headers' => [
                'Authorization' => 'Bearer ' . $access_token,
                'Content-Type'  => 'application/json; charset=utf-8',
            ],
            'body'    => wp_json_encode( [ 'comment' => $comment ], JSON_UNESCAPED_UNICODE ),
            'timeout' => 30,
        ] );

        if ( is_wp_error( $response ) ) {
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " reply API error: " . $response->get_error_message() . "\n",
                FILE_APPEND );
            return [ 'success' => false, 'message' => 'Google API接続エラー: ' . $response->get_error_message() ];
        }

        $status = wp_remote_retrieve_response_code( $response );
        if ( $status !== 200 ) {
            $body = wp_remote_retrieve_body( $response );
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " reply API HTTP {$status}: " . substr( $body, 0, 500 ) . "\n",
                FILE_APPEND );

            $error_data = json_decode( $body, true );
            $error_msg  = $error_data['error']['message'] ?? "返信の投稿に失敗しました（HTTP {$status}）。";
            return [ 'success' => false, 'message' => $error_msg ];
        }

        // キャッシュ無効化
        delete_transient( "gcrev_reviews_{$user_id}" );

        $reply_data = json_decode( wp_remote_retrieve_body( $response ), true );
        return [ 'success' => true, 'message' => '返信を投稿しました。', 'reply' => $reply_data ];
    }

    // --- REST コールバック: 口コミ一覧取得 ---
    public function rest_get_reviews( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id    = get_current_user_id();
        $filter     = sanitize_text_field( $request->get_param( 'filter' ) ?: 'all' );
        $sort       = sanitize_text_field( $request->get_param( 'sort' ) ?: 'newest' );
        $page_token = sanitize_text_field( $request->get_param( 'page_token' ) ?: '' );
        $no_cache   = (int) $request->get_param( 'no_cache' );

        if ( $no_cache ) {
            delete_transient( "gcrev_reviews_{$user_id}" );
        }

        $result = $this->gbp_fetch_reviews( $user_id, $page_token );
        if ( ! ( $result['success'] ?? false ) ) {
            return new \WP_REST_Response( $result, 200 );
        }

        $reviews = $result['reviews'] ?? [];

        // 下書き情報をマージ
        global $wpdb;
        $drafts_table = $wpdb->prefix . 'gcrev_review_drafts';
        $drafts_raw   = $wpdb->get_results( $wpdb->prepare(
            "SELECT review_name, draft_text, ai_generated, updated_at FROM {$drafts_table} WHERE user_id = %d",
            $user_id
        ), ARRAY_A );
        $drafts = [];
        foreach ( $drafts_raw as $d ) {
            $drafts[ $d['review_name'] ] = $d;
        }

        // サマリー集計
        $summary = [ 'total' => count( $reviews ), 'unreplied' => 0, 'replied' => 0, 'low_rating' => 0 ];
        foreach ( $reviews as &$review ) {
            $has_reply = ! empty( $review['reviewReply'] );
            $rating    = (int) $this->gbp_star_to_number( $review['starRating'] ?? '' );
            $name      = $review['name'] ?? '';

            $review['_rating_num'] = $rating;
            $review['_has_reply']  = $has_reply;
            $review['_draft']      = $drafts[ $name ] ?? null;

            if ( $has_reply ) {
                $summary['replied']++;
            } else {
                $summary['unreplied']++;
            }
            if ( $rating <= 2 ) {
                $summary['low_rating']++;
            }
        }
        unset( $review );

        // フィルタ
        if ( $filter !== 'all' ) {
            $reviews = array_filter( $reviews, function ( $r ) use ( $filter ) {
                $rating = $r['_rating_num'];
                switch ( $filter ) {
                    case 'unreplied': return ! $r['_has_reply'];
                    case 'replied':   return $r['_has_reply'];
                    case 'low':       return $rating <= 2;
                    case 'mid':       return $rating === 3;
                    case 'high':      return $rating >= 4;
                    default:          return true;
                }
            } );
            $reviews = array_values( $reviews );
        }

        // ソート
        usort( $reviews, function ( $a, $b ) use ( $sort ) {
            $ta = $a['createTime'] ?? '';
            $tb = $b['createTime'] ?? '';
            return $sort === 'oldest' ? strcmp( $ta, $tb ) : strcmp( $tb, $ta );
        } );

        return new \WP_REST_Response( [
            'success'        => true,
            'reviews'        => $reviews,
            'summary'        => $summary,
            'averageRating'  => $result['averageRating'],
            'nextPageToken'  => $result['nextPageToken'],
        ], 200 );
    }

    /**
     * GBP starRating 文字列を数値に変換
     */
    private function gbp_star_to_number( string $star_rating ): int {
        $map = [ 'ONE' => 1, 'TWO' => 2, 'THREE' => 3, 'FOUR' => 4, 'FIVE' => 5 ];
        return $map[ $star_rating ] ?? 0;
    }

    // --- REST コールバック: 返信投稿 ---
    public function rest_post_review_reply( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id     = get_current_user_id();
        $review_name = sanitize_text_field( $request->get_param( 'review_name' ) );
        $comment     = sanitize_textarea_field( $request->get_param( 'comment' ) );

        if ( empty( $review_name ) || empty( $comment ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '返信内容を入力してください。' ], 400 );
        }

        // 二重送信防止
        $lock_key = "gcrev_reply_lock_{$user_id}_" . md5( $review_name );
        if ( get_transient( $lock_key ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '処理中です。しばらくお待ちください。' ], 429 );
        }
        set_transient( $lock_key, 1, 10 );

        $result = $this->gbp_reply_to_review( $user_id, $review_name, $comment );

        // 成功時に下書き削除
        if ( $result['success'] ) {
            global $wpdb;
            $wpdb->delete(
                $wpdb->prefix . 'gcrev_review_drafts',
                [ 'user_id' => $user_id, 'review_name' => $review_name ],
                [ '%d', '%s' ]
            );
        }

        return new \WP_REST_Response( $result, $result['success'] ? 200 : 500 );
    }

    // --- REST コールバック: AI返信文生成 ---
    public function rest_generate_review_reply( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id      = get_current_user_id();
        $review_name  = sanitize_text_field( $request->get_param( 'review_name' ) );
        $reviewer     = sanitize_text_field( $request->get_param( 'reviewer_name' ) ?: '投稿者' );
        $star_rating  = absint( $request->get_param( 'star_rating' ) );
        $comment_text = sanitize_textarea_field( $request->get_param( 'comment_text' ) ?: '' );

        if ( empty( $review_name ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'パラメータが不足しています。' ], 400 );
        }

        // AI設定取得
        $settings_raw = get_user_meta( $user_id, '_gcrev_review_ai_settings', true );
        $settings     = is_string( $settings_raw ) ? json_decode( $settings_raw, true ) : [];
        if ( ! is_array( $settings ) ) {
            $settings = [];
        }

        $tone_map   = [ 'polite' => '丁寧', 'friendly' => 'やや親しみやすい', 'formal' => 'フォーマル' ];
        $length_map = [ 'short' => '短め（50〜80字）', 'standard' => '標準（80〜150字）', 'long' => 'やや丁寧長め（150〜250字）' ];
        $policy_map = [ 'apology' => 'お詫び重視', 'improvement' => '改善姿勢重視', 'individual' => '個別対応案内重視' ];

        $tone        = $tone_map[ $settings['tone'] ?? '' ] ?? '丁寧';
        $length      = $length_map[ $settings['length'] ?? '' ] ?? '標準（80〜150字）';
        $policy      = $policy_map[ $settings['low_rating_policy'] ?? '' ] ?? 'お詫び重視';
        $biz_name    = $settings['business_name'] ?? get_user_meta( $user_id, '_gcrev_gbp_location_name', true ) ?: '（事業者）';
        $industry    = $settings['industry'] ?? '';

        $prompt = "あなたはGoogle口コミへの返信を作成するプロのライターです。以下の情報をもとに、自然で丁寧な返信文を1つ作成してください。\n\n"
                . "【事業者情報】\n"
                . "- 事業者名: {$biz_name}\n"
                . ( $industry ? "- 業種: {$industry}\n" : '' )
                . "\n【口コミ情報】\n"
                . "- 投稿者名: {$reviewer}\n"
                . "- 星評価: {$star_rating}/5\n"
                . "- 口コミ本文: " . ( $comment_text ?: '（テキストなし）' ) . "\n"
                . "\n【返信方針】\n"
                . "- トーン: {$tone}\n"
                . "- 長さ: {$length}\n"
                . ( $star_rating <= 2 ? "- 低評価口コミへの基本方針: {$policy}\n" : '' )
                . "\n【星評価別の方向性】\n"
                . "★4-5: 感謝を中心に。来店・利用へのお礼。毎回同じ定型文にしない。\n"
                . "★3: お礼を伝える。必要に応じて補足や改善意識を入れる。過剰に明るすぎない。\n"
                . "★1-2: まず真摯に受け止める。反論しない。断定・言い訳・感情的表現を避ける。必要なら個別対応案内。\n"
                . "\n【必須ルール】\n"
                . "- 自然で実務でそのまま使える文面にすること\n"
                . "- 口コミ本文の具体的な内容に必ず触れること\n"
                . "- 投稿者名は「{$reviewer}様」として使うこと\n"
                . "- 定型的な締め文句を避け、口コミの内容に合わせた返信にすること\n"
                . "- 返信文のみを出力してください（JSONや説明文は不要）";

        try {
            $reply_text = $this->ai->call_gemini_api( $prompt, [
                'temperature'     => 0.8,
                'maxOutputTokens' => 1024,
            ] );
            $reply_text = trim( $reply_text );
            // 余分な引用符やマークダウンを除去
            $reply_text = preg_replace( '/^["\'`]+|["\'`]+$/', '', $reply_text );
            $reply_text = preg_replace( '/^```[a-z]*\n?|\n?```$/', '', $reply_text );
            $reply_text = trim( $reply_text );
        } catch ( \Throwable $e ) {
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " AI reply generate error: " . $e->getMessage() . "\n",
                FILE_APPEND );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => 'AI返信文の生成に失敗しました: ' . $e->getMessage(),
            ], 500 );
        }

        // 下書きとして自動保存
        global $wpdb;
        $table = $wpdb->prefix . 'gcrev_review_drafts';
        $now   = current_time( 'mysql' );
        $wpdb->replace( $table, [
            'user_id'      => $user_id,
            'review_name'  => $review_name,
            'draft_text'   => $reply_text,
            'ai_generated' => 1,
            'created_at'   => $now,
            'updated_at'   => $now,
        ], [ '%d', '%s', '%s', '%d', '%s', '%s' ] );

        return new \WP_REST_Response( [
            'success' => true,
            'reply'   => $reply_text,
        ], 200 );
    }

    // --- REST コールバック: 下書き保存 ---
    public function rest_save_review_draft( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id     = get_current_user_id();
        $review_name = sanitize_text_field( $request->get_param( 'review_name' ) );
        $draft_text  = sanitize_textarea_field( $request->get_param( 'draft_text' ) ?? '' );

        if ( empty( $review_name ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'パラメータが不足しています。' ], 400 );
        }

        global $wpdb;
        $table = $wpdb->prefix . 'gcrev_review_drafts';

        if ( $draft_text === '' ) {
            $wpdb->delete( $table, [ 'user_id' => $user_id, 'review_name' => $review_name ], [ '%d', '%s' ] );
        } else {
            $now = current_time( 'mysql' );
            $wpdb->replace( $table, [
                'user_id'      => $user_id,
                'review_name'  => $review_name,
                'draft_text'   => $draft_text,
                'ai_generated' => 0,
                'created_at'   => $now,
                'updated_at'   => $now,
            ], [ '%d', '%s', '%s', '%d', '%s', '%s' ] );
        }

        return new \WP_REST_Response( [ 'success' => true ], 200 );
    }

    // --- REST コールバック: AI返信設定保存 ---
    public function rest_save_review_ai_settings( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id  = get_current_user_id();
        $settings = [
            'tone'              => sanitize_text_field( $request->get_param( 'tone' ) ?: 'polite' ),
            'length'            => sanitize_text_field( $request->get_param( 'length' ) ?: 'standard' ),
            'low_rating_policy' => sanitize_text_field( $request->get_param( 'low_rating_policy' ) ?: 'apology' ),
            'business_name'     => sanitize_text_field( $request->get_param( 'business_name' ) ?: '' ),
            'industry'          => sanitize_text_field( $request->get_param( 'industry' ) ?: '' ),
        ];
        update_user_meta( $user_id, '_gcrev_review_ai_settings', wp_json_encode( $settings, JSON_UNESCAPED_UNICODE ) );

        return new \WP_REST_Response( [ 'success' => true ], 200 );
    }

    // =========================================================
    // GBP 投稿管理 — API メソッド
    // =========================================================

    /**
     * GBP から既存の投稿一覧を取得
     */
    private function gbp_list_local_posts( int $user_id, string $page_token = '' ): array {
        $access_token = $this->gbp_get_access_token( $user_id );
        if ( ! $access_token ) {
            return [ 'success' => false, 'posts' => [], 'message' => 'アクセストークンの取得に失敗しました。' ];
        }

        $account_name = $this->gbp_get_account_for_location( $user_id );
        $location_id  = get_user_meta( $user_id, '_gcrev_gbp_location_id', true );
        if ( ! $account_name || ! $location_id ) {
            return [ 'success' => false, 'posts' => [], 'message' => 'GBPロケーション情報が見つかりません。' ];
        }

        $url = "https://mybusiness.googleapis.com/v4/{$account_name}/{$location_id}/localPosts?pageSize=100";
        if ( ! empty( $page_token ) ) {
            $url .= '&pageToken=' . urlencode( $page_token );
        }

        file_put_contents( '/tmp/gcrev_gbp_debug.log',
            date( 'Y-m-d H:i:s' ) . " list localPosts: url={$url}\n", FILE_APPEND );

        $response = wp_remote_get( $url, [
            'headers' => [ 'Authorization' => 'Bearer ' . $access_token ],
            'timeout' => 30,
        ] );

        if ( is_wp_error( $response ) ) {
            $err = $response->get_error_message();
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " list localPosts WP_Error: {$err}\n", FILE_APPEND );
            return [ 'success' => false, 'posts' => [], 'message' => '通信エラー: ' . $err ];
        }

        $code  = wp_remote_retrieve_response_code( $response );
        $rbody = wp_remote_retrieve_body( $response );

        file_put_contents( '/tmp/gcrev_gbp_debug.log',
            date( 'Y-m-d H:i:s' ) . " list localPosts HTTP {$code}: " . substr( $rbody, 0, 500 ) . "\n", FILE_APPEND );

        if ( $code < 200 || $code >= 300 ) {
            $data = json_decode( $rbody, true );
            $msg  = $data['error']['message'] ?? "HTTP {$code}";
            return [ 'success' => false, 'posts' => [], 'message' => "取得に失敗しました: {$msg}" ];
        }

        $data = json_decode( $rbody, true );
        return [
            'success'       => true,
            'posts'         => $data['localPosts'] ?? [],
            'nextPageToken' => $data['nextPageToken'] ?? null,
        ];
    }

    /**
     * GBP localPosts 用リクエストボディを組み立てる
     */
    private function gbp_build_post_body( array $post ): array {
        $body = [
            'languageCode' => 'ja',
            'topicType'    => $post['topic_type'] ?: 'STANDARD',
            'summary'      => $post['summary'],
        ];

        // CTA
        if ( ! empty( $post['cta_type'] ) ) {
            $body['callToAction'] = [
                'actionType' => $post['cta_type'],
                'url'        => $post['cta_url'] ?? '',
            ];
        }

        // 画像
        $image_url = $post['image_url'] ?? '';
        if ( empty( $image_url ) && ! empty( $post['image_attachment_id'] ) ) {
            $image_url = wp_get_attachment_url( (int) $post['image_attachment_id'] );
        }
        if ( ! empty( $image_url ) ) {
            $body['media'] = [
                [
                    'mediaFormat' => 'PHOTO',
                    'sourceUrl'   => $image_url,
                ],
            ];
        }

        // イベント
        if ( $post['topic_type'] === 'EVENT' && ! empty( $post['event_title'] ) ) {
            $start = new \DateTimeImmutable( $post['event_start'] ?? 'now', wp_timezone() );
            $end   = ! empty( $post['event_end'] )
                ? new \DateTimeImmutable( $post['event_end'], wp_timezone() )
                : $start->modify( '+1 day' );

            $body['event'] = [
                'title'    => $post['event_title'],
                'schedule' => [
                    'startDate' => [
                        'year'  => (int) $start->format( 'Y' ),
                        'month' => (int) $start->format( 'n' ),
                        'day'   => (int) $start->format( 'j' ),
                    ],
                    'startTime' => [
                        'hours'   => (int) $start->format( 'G' ),
                        'minutes' => (int) $start->format( 'i' ),
                    ],
                    'endDate' => [
                        'year'  => (int) $end->format( 'Y' ),
                        'month' => (int) $end->format( 'n' ),
                        'day'   => (int) $end->format( 'j' ),
                    ],
                    'endTime' => [
                        'hours'   => (int) $end->format( 'G' ),
                        'minutes' => (int) $end->format( 'i' ),
                    ],
                ],
            ];
        }

        // オファー
        if ( $post['topic_type'] === 'OFFER' ) {
            $offer = [];
            if ( ! empty( $post['cta_url'] ) ) {
                $offer['redeemOnlineUrl'] = $post['cta_url'];
            }
            if ( ! empty( $offer ) ) {
                $body['offer'] = $offer;
            }
        }

        return $body;
    }

    /**
     * GBP にローカル投稿を作成
     */
    public function gbp_create_local_post( int $user_id, array $post_data ): array {
        $access_token = $this->gbp_get_access_token( $user_id );
        if ( ! $access_token ) {
            return [ 'success' => false, 'gbp_post_name' => '', 'message' => 'アクセストークンの取得に失敗しました。GBP連携を確認してください。' ];
        }

        $account_name = $this->gbp_get_account_for_location( $user_id );
        $location_id  = get_user_meta( $user_id, '_gcrev_gbp_location_id', true );
        if ( ! $account_name || ! $location_id ) {
            return [ 'success' => false, 'gbp_post_name' => '', 'message' => 'GBPロケーション情報が見つかりません。' ];
        }

        $url  = "https://mybusiness.googleapis.com/v4/{$account_name}/{$location_id}/localPosts";
        $body = $this->gbp_build_post_body( $post_data );

        file_put_contents( '/tmp/gcrev_gbp_debug.log',
            date( 'Y-m-d H:i:s' ) . " create localPost: url={$url}, body=" . substr( wp_json_encode( $body, JSON_UNESCAPED_UNICODE ), 0, 500 ) . "\n",
            FILE_APPEND
        );

        $response = wp_remote_post( $url, [
            'headers' => [
                'Authorization' => 'Bearer ' . $access_token,
                'Content-Type'  => 'application/json; charset=utf-8',
            ],
            'body'    => wp_json_encode( $body, JSON_UNESCAPED_UNICODE ),
            'timeout' => 30,
        ] );

        if ( is_wp_error( $response ) ) {
            $err = $response->get_error_message();
            file_put_contents( '/tmp/gcrev_gbp_debug.log',
                date( 'Y-m-d H:i:s' ) . " create localPost WP_Error: {$err}\n", FILE_APPEND );
            return [ 'success' => false, 'gbp_post_name' => '', 'message' => "通信エラー: {$err}" ];
        }

        $code = wp_remote_retrieve_response_code( $response );
        $rbody = wp_remote_retrieve_body( $response );

        file_put_contents( '/tmp/gcrev_gbp_debug.log',
            date( 'Y-m-d H:i:s' ) . " create localPost HTTP {$code}: " . substr( $rbody, 0, 500 ) . "\n",
            FILE_APPEND
        );

        if ( $code < 200 || $code >= 300 ) {
            $data = json_decode( $rbody, true );
            $msg  = $data['error']['message'] ?? "HTTP {$code}";
            return [ 'success' => false, 'gbp_post_name' => '', 'message' => "投稿に失敗しました: {$msg}" ];
        }

        $data = json_decode( $rbody, true );
        return [
            'success'       => true,
            'gbp_post_name' => $data['name'] ?? '',
            'message'       => '',
        ];
    }

    /**
     * GBP のローカル投稿を削除
     */
    private function gbp_delete_local_post( int $user_id, string $gbp_post_name ): array {
        $access_token = $this->gbp_get_access_token( $user_id );
        if ( ! $access_token ) {
            return [ 'success' => false, 'message' => 'アクセストークンの取得に失敗しました。' ];
        }

        $url = "https://mybusiness.googleapis.com/v4/{$gbp_post_name}";
        $response = wp_remote_request( $url, [
            'method'  => 'DELETE',
            'headers' => [ 'Authorization' => 'Bearer ' . $access_token ],
            'timeout' => 30,
        ] );

        if ( is_wp_error( $response ) ) {
            return [ 'success' => false, 'message' => '通信エラー: ' . $response->get_error_message() ];
        }

        $code = wp_remote_retrieve_response_code( $response );
        if ( $code >= 200 && $code < 300 ) {
            return [ 'success' => true, 'message' => '' ];
        }

        $rbody = wp_remote_retrieve_body( $response );
        $data  = json_decode( $rbody, true );
        return [ 'success' => false, 'message' => 'GBP削除エラー: ' . ( $data['error']['message'] ?? "HTTP {$code}" ) ];
    }

    /**
     * GBP のローカル投稿を更新
     */
    private function gbp_update_local_post( int $user_id, string $gbp_post_name, array $post_data ): array {
        $access_token = $this->gbp_get_access_token( $user_id );
        if ( ! $access_token ) {
            return [ 'success' => false, 'gbp_post_name' => '', 'message' => 'アクセストークンの取得に失敗しました。' ];
        }

        $body = $this->gbp_build_post_body( $post_data );
        $url  = "https://mybusiness.googleapis.com/v4/{$gbp_post_name}?updateMask=summary,callToAction,media,event";

        $response = wp_remote_request( $url, [
            'method'  => 'PATCH',
            'headers' => [
                'Authorization' => 'Bearer ' . $access_token,
                'Content-Type'  => 'application/json; charset=utf-8',
            ],
            'body'    => wp_json_encode( $body, JSON_UNESCAPED_UNICODE ),
            'timeout' => 30,
        ] );

        if ( is_wp_error( $response ) ) {
            return [ 'success' => false, 'gbp_post_name' => $gbp_post_name, 'message' => '通信エラー: ' . $response->get_error_message() ];
        }

        $code = wp_remote_retrieve_response_code( $response );
        if ( $code >= 200 && $code < 300 ) {
            return [ 'success' => true, 'gbp_post_name' => $gbp_post_name, 'message' => '' ];
        }

        $rbody = wp_remote_retrieve_body( $response );
        $data  = json_decode( $rbody, true );
        return [ 'success' => false, 'gbp_post_name' => $gbp_post_name, 'message' => '更新エラー: ' . ( $data['error']['message'] ?? "HTTP {$code}" ) ];
    }

    // =========================================================
    // GBP 投稿管理 — REST コールバック
    // =========================================================

    /**
     * 投稿一覧取得
     */
    public function rest_get_gbp_posts( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id  = get_current_user_id();
        $table    = $wpdb->prefix . 'gcrev_gbp_posts';
        $status   = sanitize_text_field( $request->get_param( 'status' ) ?: 'all' );
        $sort     = sanitize_text_field( $request->get_param( 'sort' ) ?: 'newest' );
        $page     = max( 1, absint( $request->get_param( 'page' ) ?: 1 ) );
        $per_page = min( 50, max( 1, absint( $request->get_param( 'per_page' ) ?: 20 ) ) );
        $offset   = ( $page - 1 ) * $per_page;

        $where = $wpdb->prepare( "WHERE user_id = %d", $user_id );
        if ( $status !== 'all' && in_array( $status, [ 'draft', 'scheduled', 'posted', 'failed', 'cancelled' ], true ) ) {
            $where .= $wpdb->prepare( " AND status = %s", $status );
        }

        $order = 'ORDER BY created_at DESC';
        if ( $sort === 'oldest' ) {
            $order = 'ORDER BY created_at ASC';
        } elseif ( $sort === 'scheduled_asc' ) {
            $order = 'ORDER BY COALESCE(scheduled_at, created_at) ASC';
        }

        // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
        $total = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$table} {$where}" );
        // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
        $posts = $wpdb->get_results(
            $wpdb->prepare( "SELECT * FROM {$table} {$where} {$order} LIMIT %d OFFSET %d", $per_page, $offset ),
            ARRAY_A
        );

        return new \WP_REST_Response( [
            'success' => true,
            'posts'   => $posts ?: [],
            'total'   => $total,
            'pages'   => (int) ceil( $total / $per_page ),
            'page'    => $page,
        ], 200 );
    }

    /**
     * 投稿ステータス別件数
     */
    public function rest_get_gbp_posts_summary( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';

        // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
        $rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT status, COUNT(*) as cnt FROM {$table} WHERE user_id = %d GROUP BY status", $user_id
        ), ARRAY_A );

        $summary = [ 'total' => 0, 'draft' => 0, 'scheduled' => 0, 'posted' => 0, 'failed' => 0, 'cancelled' => 0 ];
        foreach ( $rows as $row ) {
            $summary[ $row['status'] ] = (int) $row['cnt'];
            $summary['total'] += (int) $row['cnt'];
        }

        return new \WP_REST_Response( [ 'success' => true, 'summary' => $summary ], 200 );
    }

    /**
     * 投稿を新規作成
     */
    public function rest_create_gbp_post( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $now     = current_time( 'mysql' );

        // 二重送信防止
        $lock_key = "gcrev_lock_gbp_post_{$user_id}";
        if ( get_transient( $lock_key ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '処理中です。しばらくお待ちください。' ], 429 );
        }
        set_transient( $lock_key, 1, 10 );

        $action = sanitize_text_field( $request->get_param( 'action' ) ?: 'draft' );
        $data   = [
            'user_id'            => $user_id,
            'title'              => sanitize_text_field( $request->get_param( 'title' ) ?: '' ),
            'summary'            => sanitize_textarea_field( $request->get_param( 'summary' ) ?: '' ),
            'topic_type'         => sanitize_text_field( $request->get_param( 'topic_type' ) ?: 'STANDARD' ),
            'cta_type'           => sanitize_text_field( $request->get_param( 'cta_type' ) ?: '' ) ?: null,
            'cta_url'            => esc_url_raw( $request->get_param( 'cta_url' ) ?: '' ) ?: null,
            'event_title'        => sanitize_text_field( $request->get_param( 'event_title' ) ?: '' ) ?: null,
            'event_start'        => sanitize_text_field( $request->get_param( 'event_start' ) ?: '' ) ?: null,
            'event_end'          => sanitize_text_field( $request->get_param( 'event_end' ) ?: '' ) ?: null,
            'image_url'          => esc_url_raw( $request->get_param( 'image_url' ) ?: '' ) ?: null,
            'image_attachment_id' => absint( $request->get_param( 'image_attachment_id' ) ?: 0 ) ?: null,
            'status'             => 'draft',
            'scheduled_at'       => null,
            'created_at'         => $now,
            'updated_at'         => $now,
        ];

        if ( empty( $data['summary'] ) ) {
            delete_transient( $lock_key );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿本文は必須です。' ], 400 );
        }
        if ( mb_strlen( $data['summary'] ) > 1500 ) {
            delete_transient( $lock_key );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿本文は1500文字以内にしてください。' ], 400 );
        }

        // 画像URLをattachment_idから解決
        if ( empty( $data['image_url'] ) && ! empty( $data['image_attachment_id'] ) ) {
            $data['image_url'] = wp_get_attachment_url( $data['image_attachment_id'] ) ?: null;
        }

        if ( $action === 'schedule' ) {
            $scheduled_at = sanitize_text_field( $request->get_param( 'scheduled_at' ) ?: '' );
            if ( empty( $scheduled_at ) ) {
                delete_transient( $lock_key );
                return new \WP_REST_Response( [ 'success' => false, 'message' => '予約日時を指定してください。' ], 400 );
            }
            $data['status']       = 'scheduled';
            $data['scheduled_at'] = $scheduled_at;
        }

        if ( $action === 'post_now' ) {
            // 先にDBに保存してからGBPに投稿
            $data['status'] = 'scheduled';
            $wpdb->insert( $table, $data );
            $post_id = $wpdb->insert_id;

            $result = $this->gbp_create_local_post( $user_id, $data );
            if ( $result['success'] ) {
                $wpdb->update( $table, [
                    'status'        => 'posted',
                    'posted_at'     => current_time( 'mysql' ),
                    'gbp_post_name' => $result['gbp_post_name'],
                    'updated_at'    => current_time( 'mysql' ),
                ], [ 'id' => $post_id ] );
            } else {
                $wpdb->update( $table, [
                    'status'        => 'failed',
                    'error_message' => $result['message'],
                    'updated_at'    => current_time( 'mysql' ),
                ], [ 'id' => $post_id ] );
            }

            delete_transient( $lock_key );
            return new \WP_REST_Response( [
                'success' => $result['success'],
                'post_id' => $post_id,
                'message' => $result['success'] ? '投稿しました。' : $result['message'],
            ], $result['success'] ? 200 : 200 );
        }

        // draft or schedule
        $wpdb->insert( $table, $data );
        $post_id = $wpdb->insert_id;

        delete_transient( $lock_key );
        return new \WP_REST_Response( [
            'success' => true,
            'post_id' => $post_id,
            'message' => $action === 'schedule' ? '予約投稿を登録しました。' : '下書きを保存しました。',
        ], 200 );
    }

    /**
     * 投稿を更新
     */
    public function rest_update_gbp_post( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $post_id = absint( $request['id'] );

        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d", $post_id, $user_id
        ), ARRAY_A );
        if ( ! $existing ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿が見つかりません。' ], 404 );
        }

        $action = sanitize_text_field( $request->get_param( 'action' ) ?: 'save' );
        $update = [
            'title'              => sanitize_text_field( $request->get_param( 'title' ) ?: '' ),
            'summary'            => sanitize_textarea_field( $request->get_param( 'summary' ) ?: '' ),
            'topic_type'         => sanitize_text_field( $request->get_param( 'topic_type' ) ?: 'STANDARD' ),
            'cta_type'           => sanitize_text_field( $request->get_param( 'cta_type' ) ?: '' ) ?: null,
            'cta_url'            => esc_url_raw( $request->get_param( 'cta_url' ) ?: '' ) ?: null,
            'event_title'        => sanitize_text_field( $request->get_param( 'event_title' ) ?: '' ) ?: null,
            'event_start'        => sanitize_text_field( $request->get_param( 'event_start' ) ?: '' ) ?: null,
            'event_end'          => sanitize_text_field( $request->get_param( 'event_end' ) ?: '' ) ?: null,
            'image_url'          => esc_url_raw( $request->get_param( 'image_url' ) ?: '' ) ?: null,
            'image_attachment_id' => absint( $request->get_param( 'image_attachment_id' ) ?: 0 ) ?: null,
            'updated_at'         => current_time( 'mysql' ),
        ];

        if ( empty( $update['summary'] ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿本文は必須です。' ], 400 );
        }

        // 画像URLをattachment_idから解決
        if ( empty( $update['image_url'] ) && ! empty( $update['image_attachment_id'] ) ) {
            $update['image_url'] = wp_get_attachment_url( $update['image_attachment_id'] ) ?: null;
        }

        if ( $action === 'schedule' ) {
            $update['status']       = 'scheduled';
            $update['scheduled_at'] = sanitize_text_field( $request->get_param( 'scheduled_at' ) ?: '' );
            $update['retry_count']  = 0;
            $update['error_message'] = null;
        } elseif ( $action === 'draft' ) {
            $update['status'] = 'draft';
        }

        $wpdb->update( $table, $update, [ 'id' => $post_id ] );

        // 投稿済みの場合はGBPも更新
        if ( $existing['status'] === 'posted' && ! empty( $existing['gbp_post_name'] ) && $action === 'save' ) {
            $merged = array_merge( $existing, $update );
            $this->gbp_update_local_post( $user_id, $existing['gbp_post_name'], $merged );
        }

        return new \WP_REST_Response( [ 'success' => true, 'message' => '更新しました。' ], 200 );
    }

    /**
     * 投稿を削除
     */
    public function rest_delete_gbp_post( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $post_id = absint( $request['id'] );

        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d", $post_id, $user_id
        ), ARRAY_A );
        if ( ! $existing ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿が見つかりません。' ], 404 );
        }

        // GBPに投稿済みならGBPからも削除
        if ( $existing['status'] === 'posted' && ! empty( $existing['gbp_post_name'] ) ) {
            $this->gbp_delete_local_post( $user_id, $existing['gbp_post_name'] );
        }

        $wpdb->delete( $table, [ 'id' => $post_id ] );
        return new \WP_REST_Response( [ 'success' => true, 'message' => '削除しました。' ], 200 );
    }

    /**
     * 投稿を複製（下書きとして）
     */
    public function rest_duplicate_gbp_post( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $post_id = absint( $request['id'] );

        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d", $post_id, $user_id
        ), ARRAY_A );
        if ( ! $existing ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿が見つかりません。' ], 404 );
        }

        $now = current_time( 'mysql' );
        $wpdb->insert( $table, [
            'user_id'             => $user_id,
            'title'               => $existing['title'] . '（コピー）',
            'summary'             => $existing['summary'],
            'topic_type'          => $existing['topic_type'],
            'cta_type'            => $existing['cta_type'],
            'cta_url'             => $existing['cta_url'],
            'event_title'         => $existing['event_title'],
            'event_start'         => $existing['event_start'],
            'event_end'           => $existing['event_end'],
            'image_url'           => $existing['image_url'],
            'image_attachment_id' => $existing['image_attachment_id'],
            'status'              => 'draft',
            'created_at'          => $now,
            'updated_at'          => $now,
        ] );

        return new \WP_REST_Response( [ 'success' => true, 'post_id' => $wpdb->insert_id, 'message' => '複製しました。' ], 200 );
    }

    /**
     * 今すぐ投稿
     */
    public function rest_post_gbp_now( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $post_id = absint( $request['id'] );

        $lock_key = "gcrev_lock_gbp_post_{$user_id}";
        if ( get_transient( $lock_key ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '処理中です。' ], 429 );
        }
        set_transient( $lock_key, 1, 10 );

        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d", $post_id, $user_id
        ), ARRAY_A );
        if ( ! $existing ) {
            delete_transient( $lock_key );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿が見つかりません。' ], 404 );
        }

        $result = $this->gbp_create_local_post( $user_id, $existing );
        if ( $result['success'] ) {
            $wpdb->update( $table, [
                'status'        => 'posted',
                'posted_at'     => current_time( 'mysql' ),
                'gbp_post_name' => $result['gbp_post_name'],
                'error_message' => null,
                'updated_at'    => current_time( 'mysql' ),
            ], [ 'id' => $post_id ] );
        } else {
            $wpdb->update( $table, [
                'status'        => 'failed',
                'error_message' => $result['message'],
                'updated_at'    => current_time( 'mysql' ),
            ], [ 'id' => $post_id ] );
        }

        delete_transient( $lock_key );
        return new \WP_REST_Response( [
            'success' => $result['success'],
            'message' => $result['success'] ? '投稿しました。' : $result['message'],
        ], 200 );
    }

    /**
     * 失敗投稿を再実行
     */
    public function rest_retry_gbp_post( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $post_id = absint( $request['id'] );

        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d AND status = 'failed'", $post_id, $user_id
        ), ARRAY_A );
        if ( ! $existing ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '再実行可能な投稿が見つかりません。' ], 404 );
        }

        $wpdb->update( $table, [
            'status'        => 'scheduled',
            'scheduled_at'  => current_time( 'mysql' ),
            'retry_count'   => 0,
            'error_message' => null,
            'updated_at'    => current_time( 'mysql' ),
        ], [ 'id' => $post_id ] );

        return new \WP_REST_Response( [ 'success' => true, 'message' => '再投稿をスケジュールしました。' ], 200 );
    }

    /**
     * 予約をキャンセル
     */
    public function rest_cancel_gbp_post( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $post_id = absint( $request['id'] );

        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d AND status = 'scheduled'", $post_id, $user_id
        ), ARRAY_A );
        if ( ! $existing ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'キャンセル可能な予約が見つかりません。' ], 404 );
        }

        $wpdb->update( $table, [
            'status'     => 'cancelled',
            'updated_at' => current_time( 'mysql' ),
        ], [ 'id' => $post_id ] );

        return new \WP_REST_Response( [ 'success' => true, 'message' => '予約をキャンセルしました。' ], 200 );
    }

    /**
     * 投稿を一括削除
     *
     * 投稿済み（posted）はみまもりウェブ管理データのみ削除（Google側は維持）。
     * それ以外のステータスは通常削除。
     */
    public function rest_bulk_delete_gbp_posts( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $ids_raw = $request->get_param( 'ids' );

        if ( empty( $ids_raw ) || ! is_array( $ids_raw ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '削除対象が指定されていません。' ], 400 );
        }

        // IDをサニタイズ
        $ids = array_map( 'absint', $ids_raw );
        $ids = array_filter( $ids );
        if ( empty( $ids ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '有効なIDがありません。' ], 400 );
        }

        // 自分の投稿のみ取得
        $placeholders = implode( ',', array_fill( 0, count( $ids ), '%d' ) );
        // phpcs:ignore WordPress.DB.PreparedSQLPlaceholders.UnfinishedPrepare
        $posts = $wpdb->get_results( $wpdb->prepare(
            "SELECT id, status, gbp_post_name FROM {$table} WHERE id IN ({$placeholders}) AND user_id = %d",
            array_merge( $ids, [ $user_id ] )
        ), ARRAY_A );

        if ( empty( $posts ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '削除可能な投稿が見つかりません。' ], 404 );
        }

        $deleted       = 0;
        $posted_count  = 0;
        $failed_ids    = [];

        foreach ( $posts as $post ) {
            $post_id = (int) $post['id'];

            if ( $post['status'] === 'posted' ) {
                // 投稿済み: みまもりウェブ上の管理データのみ削除（Google側は維持）
                $posted_count++;
            }

            $result = $wpdb->delete( $table, [ 'id' => $post_id, 'user_id' => $user_id ] );
            if ( $result ) {
                $deleted++;
            } else {
                $failed_ids[] = $post_id;
            }
        }

        $message = "{$deleted}件を削除しました。";
        if ( $posted_count > 0 ) {
            $message .= "（うち投稿済み{$posted_count}件はGoogle上の投稿は維持されます）";
        }
        if ( ! empty( $failed_ids ) ) {
            $message .= " " . count( $failed_ids ) . "件は削除に失敗しました。";
        }

        return new \WP_REST_Response( [
            'success'      => true,
            'deleted'      => $deleted,
            'posted_kept'  => $posted_count,
            'failed_count' => count( $failed_ids ),
            'message'      => $message,
        ], 200 );
    }

    /**
     * 期限超過の予約投稿を手動で一括処理（管理者限定）
     */
    public function rest_process_overdue_gbp_posts( \WP_REST_Request $request ): \WP_REST_Response {
        $result = Gcrev_Bootstrap::process_overdue_gbp_posts();
        return new \WP_REST_Response( [
            'success'   => true,
            'message'   => "処理完了: {$result['processed']}件中 成功={$result['success']} 失敗={$result['failed']}",
            'processed' => $result['processed'],
            'success_count' => $result['success'],
            'failed_count'  => $result['failed'],
            'details'   => $result['details'],
        ], 200 );
    }

    /**
     * GBP上の既存投稿一覧を取得
     */
    public function rest_get_gbp_remote_posts( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id    = get_current_user_id();
        $page_token = sanitize_text_field( $request->get_param( 'page_token' ) ?: '' );

        // キャッシュ（1時間）
        $cache_key = "gcrev_gbp_posts_{$user_id}";
        if ( empty( $page_token ) ) {
            $cached = get_transient( $cache_key );
            if ( $cached !== false ) {
                return new \WP_REST_Response( $cached, 200 );
            }
        }

        $result = $this->gbp_list_local_posts( $user_id, $page_token );
        if ( ! $result['success'] ) {
            return new \WP_REST_Response( [
                'success' => false,
                'message' => $result['message'],
                'posts'   => [],
            ], 200 );
        }

        // GBP投稿を整形
        $posts = [];
        foreach ( $result['posts'] as $gp ) {
            $topic_type = $gp['topicType'] ?? 'STANDARD';
            $summary    = $gp['summary'] ?? '';
            $state      = $gp['state'] ?? 'LIVE';
            $media      = $gp['media'][0]['googleUrl'] ?? ( $gp['media'][0]['sourceUrl'] ?? '' );
            $cta_type   = $gp['callToAction']['actionType'] ?? '';
            $cta_url    = $gp['callToAction']['url'] ?? '';
            $event_title = $gp['event']['title'] ?? '';
            $create_time = $gp['createTime'] ?? '';
            $update_time = $gp['updateTime'] ?? '';
            $search_url  = $gp['searchUrl'] ?? '';

            $posts[] = [
                'gbp_name'    => $gp['name'] ?? '',
                'topic_type'  => $topic_type,
                'summary'     => $summary,
                'state'       => $state,
                'image_url'   => $media,
                'cta_type'    => $cta_type,
                'cta_url'     => $cta_url,
                'event_title' => $event_title,
                'create_time' => $create_time,
                'update_time' => $update_time,
                'search_url'  => $search_url,
            ];
        }

        $response_data = [
            'success'       => true,
            'posts'         => $posts,
            'nextPageToken' => $result['nextPageToken'] ?? null,
        ];

        // 1ページ目のみキャッシュ
        if ( empty( $page_token ) ) {
            set_transient( $cache_key, $response_data, HOUR_IN_SECONDS );
        }

        return new \WP_REST_Response( $response_data, 200 );
    }

    /**
     * GBP上の投稿を直接更新
     */
    public function rest_update_gbp_remote_post( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id  = get_current_user_id();
        $gbp_name = sanitize_text_field( $request->get_param( 'gbp_name' ) ?: '' );

        if ( empty( $gbp_name ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿IDが指定されていません。' ], 400 );
        }

        // 二重送信防止
        $lock_key = "gcrev_lock_gbp_post_{$user_id}";
        if ( get_transient( $lock_key ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '処理中です。' ], 429 );
        }
        set_transient( $lock_key, 1, 10 );

        $post_data = [
            'summary'     => sanitize_textarea_field( $request->get_param( 'summary' ) ?: '' ),
            'topic_type'  => sanitize_text_field( $request->get_param( 'topic_type' ) ?: 'STANDARD' ),
            'cta_type'    => sanitize_text_field( $request->get_param( 'cta_type' ) ?: '' ) ?: null,
            'cta_url'     => esc_url_raw( $request->get_param( 'cta_url' ) ?: '' ) ?: null,
            'event_title' => sanitize_text_field( $request->get_param( 'event_title' ) ?: '' ) ?: null,
            'event_start' => sanitize_text_field( $request->get_param( 'event_start' ) ?: '' ) ?: null,
            'event_end'   => sanitize_text_field( $request->get_param( 'event_end' ) ?: '' ) ?: null,
            'image_url'   => esc_url_raw( $request->get_param( 'image_url' ) ?: '' ) ?: null,
            'image_attachment_id' => absint( $request->get_param( 'image_attachment_id' ) ?: 0 ) ?: null,
        ];

        if ( empty( $post_data['summary'] ) ) {
            delete_transient( $lock_key );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿本文は必須です。' ], 400 );
        }

        // 画像URLをattachment_idから解決
        if ( empty( $post_data['image_url'] ) && ! empty( $post_data['image_attachment_id'] ) ) {
            $post_data['image_url'] = wp_get_attachment_url( $post_data['image_attachment_id'] ) ?: null;
        }

        $result = $this->gbp_update_local_post( $user_id, $gbp_name, $post_data );

        // キャッシュ無効化
        delete_transient( "gcrev_gbp_posts_{$user_id}" );

        delete_transient( $lock_key );
        return new \WP_REST_Response( [
            'success' => $result['success'],
            'message' => $result['success'] ? '更新しました。' : $result['message'],
        ], 200 );
    }

    /**
     * GBP上の投稿を直接削除
     */
    public function rest_delete_gbp_remote_post( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id  = get_current_user_id();
        $gbp_name = sanitize_text_field( $request->get_param( 'gbp_name' ) ?: '' );

        if ( empty( $gbp_name ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '投稿IDが指定されていません。' ], 400 );
        }

        $result = $this->gbp_delete_local_post( $user_id, $gbp_name );

        // キャッシュ無効化
        delete_transient( "gcrev_gbp_posts_{$user_id}" );

        return new \WP_REST_Response( [
            'success' => $result['success'],
            'message' => $result['success'] ? '削除しました。' : $result['message'],
        ], 200 );
    }

    // =========================================================
    // AI 画像生成 — サービスメソッド
    // =========================================================

    /**
     * 投稿本文からテーマを分類
     */
    private function classify_post_theme( string $summary, string $topic_type, string $industry ): string {
        $themes = 'seasonal, service, event, offer, update, customer_story, tips, behind_scenes';
        $prompt = "Classify the following Japanese business post into exactly ONE theme keyword.\nAllowed themes: {$themes}\nPost type: {$topic_type}\nIndustry: {$industry}\nPost content: " . mb_substr( $summary, 0, 300 ) . "\n\nReturn ONLY the theme keyword, nothing else.";

        try {
            $result = $this->ai->call_gemini_api( $prompt, [ 'temperature' => 0.1, 'maxOutputTokens' => 20 ] );
            $theme  = strtolower( trim( $result ) );
            $valid  = [ 'seasonal', 'service', 'event', 'offer', 'update', 'customer_story', 'tips', 'behind_scenes' ];
            return in_array( $theme, $valid, true ) ? $theme : 'update';
        } catch ( \Throwable $e ) {
            return 'update';
        }
    }

    /**
     * テーマ + ブランド設定から画像生成プロンプトを構築
     */
    private function build_image_prompt( string $summary, string $theme, array $brand ): string {
        $theme_directions = [
            'seasonal'       => 'warm seasonal atmosphere, nature elements, festive mood appropriate to the current season',
            'service'        => 'professional service showcase, clean modern environment, trustworthy business imagery',
            'event'          => 'exciting event atmosphere, people gathering, celebration mood',
            'offer'          => 'attractive promotional imagery, bright and inviting, special deal atmosphere',
            'update'         => 'modern business communication, professional update imagery, clean design',
            'customer_story' => 'satisfied customers, positive testimonial atmosphere, trust and reliability',
            'tips'           => 'educational and helpful imagery, clear informative visual, expert guidance',
            'behind_scenes'  => 'authentic workplace scenery, team spirit, behind the scenes of a business',
        ];
        $direction = $theme_directions[ $theme ] ?? $theme_directions['update'];

        $style_map = [
            'photographic' => 'photorealistic, high-quality photograph style',
            'illustration' => 'modern flat illustration style, clean vector aesthetic',
            'minimalist'   => 'minimalist clean design, simple shapes, lots of white space',
        ];
        $style = $style_map[ $brand['visual_style'] ?? 'photographic' ] ?? $style_map['photographic'];

        $tone_map = [
            'warm'         => 'warm and inviting color tones, soft lighting',
            'professional' => 'professional and corporate feel, cool neutral tones',
            'playful'      => 'bright and playful colors, energetic mood',
            'elegant'      => 'elegant and sophisticated, refined color palette',
        ];
        $tone = $tone_map[ $brand['tone'] ?? 'warm' ] ?? $tone_map['warm'];

        $industry = ! empty( $brand['industry'] ) ? "for a {$brand['industry']} business" : '';
        $color_hint = '';
        if ( ! empty( $brand['color_primary'] ) ) {
            $color_hint = "Color palette should incorporate {$brand['color_primary']}";
            if ( ! empty( $brand['color_secondary'] ) ) {
                $color_hint .= " and {$brand['color_secondary']}";
            }
            $color_hint .= '. ';
        }

        $custom = ! empty( $brand['custom_instructions'] ) ? $brand['custom_instructions'] . '. ' : '';

        $prompt = "Create a professional, high-quality image for a Google Business Profile post {$industry}. "
            . "Visual direction: {$direction}. "
            . "Style: {$style}. "
            . "Mood: {$tone}. "
            . $color_hint
            . $custom
            . "The image should be clean, trustworthy, and suitable for a business social media post. "
            . "IMPORTANT: No text overlays. No watermarks. No logos. No written words in the image.";

        return $prompt;
    }

    /**
     * Base64画像をWordPressメディアライブラリに保存
     */
    private function save_base64_to_media( int $user_id, string $base64, string $mime_type, string $filename ): array {
        $decoded = base64_decode( $base64 );
        if ( $decoded === false ) {
            return [ 'success' => false, 'attachment_id' => 0, 'url' => '', 'error' => 'Base64デコードに失敗しました。' ];
        }

        $ext_map = [ 'image/png' => '.png', 'image/jpeg' => '.jpg', 'image/webp' => '.webp' ];
        $ext     = $ext_map[ $mime_type ] ?? '.png';
        $file    = $filename . $ext;

        $upload = wp_upload_bits( $file, null, $decoded );
        if ( ! empty( $upload['error'] ) ) {
            return [ 'success' => false, 'attachment_id' => 0, 'url' => '', 'error' => 'ファイル保存エラー: ' . $upload['error'] ];
        }

        $attachment = [
            'post_mime_type' => $mime_type,
            'post_title'     => sanitize_file_name( $filename ),
            'post_content'   => '',
            'post_status'    => 'inherit',
            'post_author'    => $user_id,
        ];
        $attach_id = wp_insert_attachment( $attachment, $upload['file'] );
        if ( is_wp_error( $attach_id ) ) {
            return [ 'success' => false, 'attachment_id' => 0, 'url' => '', 'error' => 'メディア登録エラー。' ];
        }

        require_once ABSPATH . 'wp-admin/includes/image.php';
        $metadata = wp_generate_attachment_metadata( $attach_id, $upload['file'] );
        wp_update_attachment_metadata( $attach_id, $metadata );

        return [
            'success'       => true,
            'attachment_id' => $attach_id,
            'url'           => $upload['url'],
            'error'         => '',
        ];
    }

    /**
     * 単一投稿のAI画像を生成
     */
    private function generate_post_image( int $post_id, int $user_id, bool $force = false ): array {
        global $wpdb;
        $table = $wpdb->prefix . 'gcrev_gbp_posts';

        $post = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d", $post_id, $user_id
        ), ARRAY_A );

        if ( ! $post ) {
            return [ 'success' => false, 'image_url' => '', 'attachment_id' => 0, 'message' => '投稿が見つかりません。' ];
        }

        // 手動差し替え済みで強制再生成でない場合はスキップ
        if ( ! $force && (int) $post['ai_image_manual_override'] === 1 ) {
            return [ 'success' => false, 'image_url' => $post['image_url'] ?? '', 'attachment_id' => 0, 'message' => '手動設定の画像が優先されています。' ];
        }

        // 同時生成防止
        if ( $post['ai_image_status'] === 'generating' ) {
            return [ 'success' => false, 'image_url' => '', 'attachment_id' => 0, 'message' => '画像生成中です。' ];
        }

        // ステータスを generating に更新
        $wpdb->update( $table, [ 'ai_image_status' => 'generating', 'updated_at' => current_time( 'mysql' ) ], [ 'id' => $post_id ] );

        // ブランド設定取得
        $brand_raw = get_user_meta( $user_id, '_gcrev_gbp_brand_settings', true );
        $brand     = is_string( $brand_raw ) ? json_decode( $brand_raw, true ) : [];
        if ( ! is_array( $brand ) ) $brand = [];

        $industry   = $brand['industry'] ?? '';
        $theme      = $this->classify_post_theme( $post['summary'], $post['topic_type'], $industry );
        $prompt     = $this->build_image_prompt( $post['summary'], $theme, $brand );
        $aspect     = $brand['aspect_ratio'] ?? '16:9';

        // プロンプト保存
        $wpdb->update( $table, [ 'ai_image_prompt' => $prompt ], [ 'id' => $post_id ] );

        // 画像生成
        $result = $this->ai->generate_image( $prompt, [ 'aspect_ratio' => $aspect ] );

        if ( ! $result['success'] ) {
            $wpdb->update( $table, [
                'ai_image_status' => 'failed',
                'ai_image_error'  => mb_substr( $result['error'], 0, 500 ),
                'updated_at'      => current_time( 'mysql' ),
            ], [ 'id' => $post_id ] );
            return [ 'success' => false, 'image_url' => '', 'attachment_id' => 0, 'message' => $result['error'] ];
        }

        // メディアライブラリに保存
        $filename = 'gbp-post-' . $post_id . '-' . time();
        $media    = $this->save_base64_to_media( $user_id, $result['base64_data'], $result['mime_type'], $filename );

        if ( ! $media['success'] ) {
            $wpdb->update( $table, [
                'ai_image_status' => 'failed',
                'ai_image_error'  => $media['error'],
                'updated_at'      => current_time( 'mysql' ),
            ], [ 'id' => $post_id ] );
            return [ 'success' => false, 'image_url' => '', 'attachment_id' => 0, 'message' => $media['error'] ];
        }

        // 成功 → DB更新
        $wpdb->update( $table, [
            'image_url'              => $media['url'],
            'image_attachment_id'    => $media['attachment_id'],
            'ai_image_status'        => 'done',
            'ai_image_error'         => null,
            'ai_image_generated_at'  => current_time( 'mysql' ),
            'ai_image_manual_override' => 0,
            'updated_at'             => current_time( 'mysql' ),
        ], [ 'id' => $post_id ] );

        return [
            'success'       => true,
            'image_url'     => $media['url'],
            'attachment_id' => $media['attachment_id'],
            'message'       => '画像を生成しました。',
        ];
    }

    // =========================================================
    // AI 画像生成 — REST コールバック
    // =========================================================

    /**
     * 単一投稿のAI画像生成
     */
    public function rest_generate_post_image( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id = get_current_user_id();
        $post_id = absint( $request['id'] );
        $force   = (bool) $request->get_param( 'force' );

        $result = $this->generate_post_image( $post_id, $user_id, $force );
        return new \WP_REST_Response( $result, 200 );
    }

    /**
     * AI画像一括生成
     */
    public function rest_bulk_generate_images( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id    = get_current_user_id();
        $table      = $wpdb->prefix . 'gcrev_gbp_posts';
        $chunk_size = min( 2, max( 1, absint( $request->get_param( 'chunk_size' ) ?: 1 ) ) );

        // 全体の未生成件数を先に取得
        $total_remaining = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$table} WHERE user_id = %d AND (image_url IS NULL OR image_url = '') AND ai_image_status NOT IN ('generating','manual','done')",
            $user_id
        ) );

        // このチャンクで処理する投稿を取得
        $posts = $wpdb->get_results( $wpdb->prepare(
            "SELECT id FROM {$table} WHERE user_id = %d AND (image_url IS NULL OR image_url = '') AND ai_image_status NOT IN ('generating','manual','done') ORDER BY scheduled_at ASC, created_at ASC LIMIT %d",
            $user_id, $chunk_size
        ), ARRAY_A );

        $succeeded = 0;
        $failed    = 0;

        foreach ( $posts as $row ) {
            $r = $this->generate_post_image( (int) $row['id'], $user_id );
            if ( $r['success'] ) {
                $succeeded++;
            } else {
                $failed++;
            }
            // API レート制限対策: 各生成間に10秒待機
            if ( next( $posts ) !== false ) {
                sleep( 10 );
            }
        }

        $processed = $succeeded + $failed;
        $after_remaining = max( 0, $total_remaining - $processed );

        return new \WP_REST_Response( [
            'success'         => true,
            'processed'       => $processed,
            'succeeded'       => $succeeded,
            'failed'          => $failed,
            'total'           => $total_remaining,
            'remaining'       => $after_remaining,
            'has_more'        => $after_remaining > 0,
            'message'         => "{$succeeded}件生成、{$failed}件失敗。残り{$after_remaining}件。",
        ], 200 );
    }

    /**
     * ブランド設定取得
     */
    public function rest_get_brand_settings( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id  = get_current_user_id();
        $raw      = get_user_meta( $user_id, '_gcrev_gbp_brand_settings', true );
        $settings = is_string( $raw ) ? json_decode( $raw, true ) : [];
        if ( ! is_array( $settings ) ) $settings = [];

        $defaults = [
            'color_primary'      => '',
            'color_secondary'    => '',
            'visual_style'       => 'photographic',
            'tone'               => 'warm',
            'industry'           => '',
            'business_name'      => '',
            'custom_instructions' => '',
            'auto_generate'      => true,
            'aspect_ratio'       => '16:9',
        ];

        return new \WP_REST_Response( [ 'success' => true, 'settings' => array_merge( $defaults, $settings ) ], 200 );
    }

    /**
     * ブランド設定保存
     */
    public function rest_save_brand_settings( \WP_REST_Request $request ): \WP_REST_Response {
        $user_id  = get_current_user_id();
        $settings = [
            'color_primary'      => sanitize_text_field( $request->get_param( 'color_primary' ) ?: '' ),
            'color_secondary'    => sanitize_text_field( $request->get_param( 'color_secondary' ) ?: '' ),
            'visual_style'       => sanitize_text_field( $request->get_param( 'visual_style' ) ?: 'photographic' ),
            'tone'               => sanitize_text_field( $request->get_param( 'tone' ) ?: 'warm' ),
            'industry'           => sanitize_text_field( $request->get_param( 'industry' ) ?: '' ),
            'business_name'      => sanitize_text_field( $request->get_param( 'business_name' ) ?: '' ),
            'custom_instructions' => sanitize_textarea_field( mb_substr( $request->get_param( 'custom_instructions' ) ?: '', 0, 200 ) ),
            'auto_generate'      => (bool) $request->get_param( 'auto_generate' ),
            'aspect_ratio'       => sanitize_text_field( $request->get_param( 'aspect_ratio' ) ?: '16:9' ),
        ];
        update_user_meta( $user_id, '_gcrev_gbp_brand_settings', wp_json_encode( $settings, JSON_UNESCAPED_UNICODE ) );

        return new \WP_REST_Response( [ 'success' => true, 'message' => 'ブランド設定を保存しました。' ], 200 );
    }

    /**
     * CSVテンプレートダウンロード
     */
    public function rest_get_csv_template( \WP_REST_Request $request ): \WP_REST_Response {
        $bom     = "\xEF\xBB\xBF";
        $header  = "投稿日時,種類,本文,CTAタイプ,CTAリンク,イベントタイトル,イベント開始,イベント終了,画像URL";
        $example1 = "2026-04-01 10:00,,今週のおすすめ情報です！,LEARN_MORE,https://example.com,,,,";
        $example2 = "2026-04-08 10:00,EVENT,春のイベント開催！,,,春祭り,2026-04-08 10:00,2026-04-08 18:00,";
        $csv = $bom . $header . "\n" . $example1 . "\n" . $example2 . "\n";

        header( 'Content-Type: text/csv; charset=UTF-8' );
        header( 'Content-Disposition: attachment; filename="gbp-posts-template.csv"' );
        // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
        echo $csv;
        exit;
    }

    /**
     * CSV一括取込
     */
    public function rest_import_gbp_posts_csv( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_gbp_posts';
        $preview = (bool) $request->get_param( 'preview' );

        $files = $request->get_file_params();
        if ( empty( $files['file']['tmp_name'] ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'CSVファイルを選択してください。' ], 400 );
        }

        $content = file_get_contents( $files['file']['tmp_name'] );
        // BOM除去
        $content = ltrim( $content, "\xEF\xBB\xBF" );
        $lines   = explode( "\n", str_replace( "\r\n", "\n", $content ) );

        if ( count( $lines ) < 2 ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'CSVにデータ行がありません。' ], 400 );
        }

        // ヘッダースキップ
        array_shift( $lines );

        $valid_cta_types  = [ '', 'BOOK', 'ORDER', 'SHOP', 'LEARN_MORE', 'SIGN_UP', 'CALL' ];
        $valid_topic_types = [ '', 'STANDARD', 'EVENT', 'OFFER' ];
        $rows    = [];
        $errors  = [];
        $line_no = 1;
        $now     = current_time( 'mysql' );

        foreach ( $lines as $line ) {
            $line_no++;
            $line = trim( $line );
            if ( $line === '' ) continue;

            $cols = str_getcsv( $line );
            if ( count( $cols ) < 3 ) {
                $errors[] = [ 'line' => $line_no, 'reason' => '列数が不足しています（最低3列必要）。' ];
                continue;
            }

            $scheduled_at  = trim( $cols[0] ?? '' );
            $topic_type    = strtoupper( trim( $cols[1] ?? '' ) ) ?: 'STANDARD';
            $summary       = trim( $cols[2] ?? '' );
            $cta_type      = strtoupper( trim( $cols[3] ?? '' ) );
            $cta_url       = trim( $cols[4] ?? '' );
            $event_title   = trim( $cols[5] ?? '' );
            $event_start   = trim( $cols[6] ?? '' );
            $event_end     = trim( $cols[7] ?? '' );
            $image_url     = trim( $cols[8] ?? '' );

            $row_errors = [];

            // バリデーション
            if ( empty( $summary ) ) {
                $row_errors[] = '本文が空です。';
            } elseif ( mb_strlen( $summary ) > 1500 ) {
                $row_errors[] = '本文が1500文字を超えています。';
            }

            if ( ! in_array( $topic_type, $valid_topic_types, true ) ) {
                $row_errors[] = "種類「{$topic_type}」は無効です（STANDARD/EVENT/OFFER）。";
            }

            if ( ! empty( $cta_type ) && ! in_array( $cta_type, $valid_cta_types, true ) ) {
                $row_errors[] = "CTAタイプ「{$cta_type}」は無効です。";
            }

            if ( ! empty( $cta_type ) && empty( $cta_url ) ) {
                $row_errors[] = 'CTAタイプを指定した場合、CTAリンクは必須です。';
            }

            if ( ! empty( $cta_url ) && ! filter_var( $cta_url, FILTER_VALIDATE_URL ) ) {
                $row_errors[] = 'CTAリンクのURL形式が不正です。';
            }

            if ( $topic_type === 'EVENT' ) {
                if ( empty( $event_title ) ) $row_errors[] = 'イベントにはイベントタイトルが必須です。';
                if ( empty( $event_start ) ) $row_errors[] = 'イベントには開始日時が必須です。';
            }

            if ( ! empty( $image_url ) && ! filter_var( $image_url, FILTER_VALIDATE_URL ) ) {
                $row_errors[] = '画像URLの形式が不正です。';
            }

            $status = 'draft';
            if ( ! empty( $scheduled_at ) ) {
                if ( ! preg_match( '/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/', $scheduled_at ) ) {
                    $row_errors[] = '投稿日時の形式が不正です（例: 2026-04-01 10:00）。';
                } else {
                    $status = 'scheduled';
                }
            }

            if ( ! empty( $row_errors ) ) {
                $errors[] = [ 'line' => $line_no, 'reason' => implode( ' / ', $row_errors ) ];
                continue;
            }

            $rows[] = [
                'user_id'     => $user_id,
                'title'       => '',
                'summary'     => $summary,
                'topic_type'  => $topic_type,
                'cta_type'    => $cta_type ?: null,
                'cta_url'     => $cta_url ?: null,
                'event_title' => $event_title ?: null,
                'event_start' => $event_start ?: null,
                'event_end'   => $event_end ?: null,
                'image_url'   => $image_url ?: null,
                'status'      => $status,
                'scheduled_at' => $status === 'scheduled' ? $scheduled_at . ':00' : null,
                'csv_import'  => 1,
                'created_at'  => $now,
                'updated_at'  => $now,
            ];

            if ( count( $rows ) >= 100 ) {
                break;
            }
        }

        if ( $preview ) {
            return new \WP_REST_Response( [
                'success'      => true,
                'preview'      => true,
                'valid_count'  => count( $rows ),
                'error_count'  => count( $errors ),
                'preview_rows' => array_slice( $rows, 0, 20 ),
                'errors'       => $errors,
            ], 200 );
        }

        // 実登録
        $imported = 0;
        foreach ( $rows as $row ) {
            $wpdb->insert( $table, $row );
            if ( $wpdb->insert_id ) $imported++;
        }

        return new \WP_REST_Response( [
            'success'        => true,
            'imported_count' => $imported,
            'error_count'    => count( $errors ),
            'errors'         => $errors,
            'message'        => "{$imported}件を登録しました。",
        ], 200 );
    }

    // =========================================================
    // ページ分析 — REST ハンドラー
    // =========================================================

    /**
     * ページ分析の有効な page_type 値
     */
    private static $valid_page_types = [
        'top', 'service', 'lp', 'contact', 'blog',
        'company', 'access', 'staff', 'price', 'other',
    ];

    /**
     * GET /gcrev/v1/page-analysis/pages — 一覧取得
     */
    public function rest_get_page_analysis_pages( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_page_analysis';

        $rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE user_id = %d AND status = 'active' ORDER BY sort_order ASC, id ASC",
            $user_id
        ), ARRAY_A );

        // attachment ID → URL に変換
        foreach ( $rows as &$row ) {
            $row['screenshot_pc_url']     = $row['screenshot_pc'] ? wp_get_attachment_url( (int) $row['screenshot_pc'] ) : null;
            $row['screenshot_mobile_url'] = $row['screenshot_mobile'] ? wp_get_attachment_url( (int) $row['screenshot_mobile'] ) : null;
            $row['clarity_data']          = $row['clarity_data'] ? json_decode( $row['clarity_data'], true ) : null;
            $row['ai_insights']           = $row['ai_insights'] ? json_decode( $row['ai_insights'], true ) : null;
        }
        unset( $row );

        return new \WP_REST_Response( [ 'success' => true, 'data' => [ 'pages' => $rows ] ], 200 );
    }

    /**
     * POST /gcrev/v1/page-analysis/pages — ページ追加/更新
     */
    public function rest_save_page_analysis_page( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $table   = $wpdb->prefix . 'gcrev_page_analysis';
        $data    = $request->get_json_params();

        $page_url = isset( $data['page_url'] ) ? esc_url_raw( trim( $data['page_url'] ) ) : '';
        if ( $page_url === '' ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'URLは必須です' ], 400 );
        }

        $page_type = isset( $data['page_type'] ) ? sanitize_text_field( $data['page_type'] ) : 'other';
        if ( ! in_array( $page_type, self::$valid_page_types, true ) ) {
            $page_type = 'other';
        }

        $page_title   = isset( $data['page_title'] ) ? sanitize_text_field( $data['page_title'] ) : '';
        $page_purpose = isset( $data['page_purpose'] ) ? sanitize_text_field( $data['page_purpose'] ) : '';
        $page_cta     = isset( $data['page_cta'] ) ? sanitize_text_field( $data['page_cta'] ) : '';

        // タイトル自動取得（未指定の場合）
        if ( $page_title === '' ) {
            $page_title = $this->fetch_page_title( $page_url );
        }

        // 既存レコード確認
        $existing = $wpdb->get_row( $wpdb->prepare(
            "SELECT id, status FROM {$table} WHERE user_id = %d AND page_url = %s",
            $user_id,
            $page_url
        ), ARRAY_A );

        if ( $existing ) {
            // 削除済みなら復元、既存なら更新
            $wpdb->update(
                $table,
                [
                    'page_title'   => $page_title,
                    'page_type'    => $page_type,
                    'page_purpose' => $page_purpose,
                    'page_cta'     => $page_cta,
                    'status'       => 'active',
                ],
                [ 'id' => (int) $existing['id'] ],
                [ '%s', '%s', '%s', '%s', '%s' ],
                [ '%d' ]
            );
            $row_id = (int) $existing['id'];
        } else {
            $wpdb->insert(
                $table,
                [
                    'user_id'      => $user_id,
                    'page_url'     => $page_url,
                    'page_title'   => $page_title,
                    'page_type'    => $page_type,
                    'page_purpose' => $page_purpose,
                    'page_cta'     => $page_cta,
                ],
                [ '%d', '%s', '%s', '%s', '%s', '%s' ]
            );
            $row_id = (int) $wpdb->insert_id;
        }

        $saved = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d",
            $row_id
        ), ARRAY_A );

        return new \WP_REST_Response( [ 'success' => true, 'data' => $saved ], 200 );
    }

    /**
     * PUT /gcrev/v1/page-analysis/pages/{id} — ページ情報更新
     */
    public function rest_update_page_analysis_page( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $id      = absint( $request->get_param( 'id' ) );
        $table   = $wpdb->prefix . 'gcrev_page_analysis';
        $data    = $request->get_json_params();

        // 所有権確認
        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT id FROM {$table} WHERE id = %d AND user_id = %d AND status = 'active'",
            $id, $user_id
        ), ARRAY_A );

        if ( ! $row ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '対象が見つかりません' ], 404 );
        }

        $update = [];
        $format = [];

        if ( isset( $data['page_type'] ) ) {
            $pt = sanitize_text_field( $data['page_type'] );
            if ( in_array( $pt, self::$valid_page_types, true ) ) {
                $update['page_type'] = $pt;
                $format[]            = '%s';
            }
        }
        if ( isset( $data['page_purpose'] ) ) {
            $update['page_purpose'] = sanitize_text_field( $data['page_purpose'] );
            $format[]               = '%s';
        }
        if ( isset( $data['page_cta'] ) ) {
            $update['page_cta'] = sanitize_text_field( $data['page_cta'] );
            $format[]           = '%s';
        }
        if ( isset( $data['page_title'] ) ) {
            $update['page_title'] = sanitize_text_field( $data['page_title'] );
            $format[]             = '%s';
        }

        if ( empty( $update ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '更新対象がありません' ], 400 );
        }

        $wpdb->update( $table, $update, [ 'id' => $id ], $format, [ '%d' ] );

        $saved = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d", $id
        ), ARRAY_A );

        return new \WP_REST_Response( [ 'success' => true, 'data' => $saved ], 200 );
    }

    /**
     * DELETE /gcrev/v1/page-analysis/pages/{id} — 論理削除
     */
    public function rest_delete_page_analysis_page( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $id      = absint( $request->get_param( 'id' ) );
        $table   = $wpdb->prefix . 'gcrev_page_analysis';

        $affected = $wpdb->update(
            $table,
            [ 'status' => 'deleted' ],
            [ 'id' => $id, 'user_id' => $user_id ],
            [ '%s' ],
            [ '%d', '%d' ]
        );

        if ( $affected === 0 ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '対象が見つかりません' ], 404 );
        }

        return new \WP_REST_Response( [ 'success' => true ], 200 );
    }

    /**
     * GET /gcrev/v1/page-analysis/pages/{id}/detail — 詳細取得
     */
    public function rest_get_page_analysis_detail( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id = get_current_user_id();
        $id      = absint( $request->get_param( 'id' ) );
        $table   = $wpdb->prefix . 'gcrev_page_analysis';

        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d AND status = 'active'",
            $id,
            $user_id
        ), ARRAY_A );

        if ( ! $row ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '対象が見つかりません' ], 404 );
        }

        // フルサイズURL（WordPress 5.3+ の -scaled 自動リサイズを回避し、元画像URLを使用）
        $row['screenshot_pc_url']     = $row['screenshot_pc'] ? wp_get_attachment_image_url( (int) $row['screenshot_pc'], 'full' ) : null;
        $row['screenshot_mobile_url'] = $row['screenshot_mobile'] ? wp_get_attachment_image_url( (int) $row['screenshot_mobile'], 'full' ) : null;
        // 元画像URL（-scaled を除去した真のオリジナル）
        $row['screenshot_pc_original']     = $row['screenshot_pc'] ? wp_get_original_image_url( (int) $row['screenshot_pc'] ) : null;
        $row['screenshot_mobile_original'] = $row['screenshot_mobile'] ? wp_get_original_image_url( (int) $row['screenshot_mobile'] ) : null;
        // サムネイルURL（パネル表示用）
        $row['screenshot_pc_thumb']     = $row['screenshot_pc'] ? ( wp_get_attachment_image_url( (int) $row['screenshot_pc'], 'large' ) ?: $row['screenshot_pc_url'] ) : null;
        $row['screenshot_mobile_thumb'] = $row['screenshot_mobile'] ? ( wp_get_attachment_image_url( (int) $row['screenshot_mobile'], 'medium' ) ?: $row['screenshot_mobile_url'] ) : null;

        $row['clarity_data']          = $row['clarity_data'] ? json_decode( $row['clarity_data'], true ) : null;
        $row['ai_insights']           = $row['ai_insights'] ? json_decode( $row['ai_insights'], true ) : null;

        // Clarity プロジェクトID（行動データタブのリンク用）
        $row['clarity_project_id'] = get_user_meta( $user_id, '_gcrev_clarity_project_id', true ) ?: null;

        // スナップショット履歴
        $snap_table = $wpdb->prefix . 'gcrev_page_snapshots';
        $snapshots  = $wpdb->get_results( $wpdb->prepare(
            "SELECT id, device_type, attachment_id, captured_at FROM {$snap_table} WHERE page_analysis_id = %d ORDER BY captured_at DESC LIMIT 20",
            $id
        ), ARRAY_A );

        foreach ( $snapshots as &$snap ) {
            $snap['url'] = wp_get_attachment_url( (int) $snap['attachment_id'] );
        }
        unset( $snap );

        $row['snapshots'] = $snapshots;

        return new \WP_REST_Response( [ 'success' => true, 'data' => $row ], 200 );
    }

    /**
     * POST /gcrev/v1/page-analysis/pages/{id}/snapshot — スクリーンショットアップロード
     */
    public function rest_upload_page_snapshot( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $log = '/tmp/gcrev_page_analysis_debug.log';
        $user_id = get_current_user_id();
        $id      = absint( $request->get_param( 'id' ) );
        $table   = $wpdb->prefix . 'gcrev_page_analysis';

        file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " upload_snapshot: id={$id}, user={$user_id}\n", FILE_APPEND );

        // 所有権チェック
        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT id FROM {$table} WHERE id = %d AND user_id = %d AND status = 'active'",
            $id,
            $user_id
        ) );
        if ( ! $row ) {
            file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " upload_snapshot: 所有権チェック失敗\n", FILE_APPEND );
            return new \WP_REST_Response( [ 'success' => false, 'message' => '対象が見つかりません' ], 404 );
        }

        $files = $request->get_file_params();
        file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " upload_snapshot: files=" . wp_json_encode( array_keys( $files ), JSON_UNESCAPED_UNICODE ) . ", file_size=" . ( isset( $files['file']['size'] ) ? $files['file']['size'] : 'N/A' ) . "\n", FILE_APPEND );
        if ( empty( $files['file'] ) ) {
            file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " upload_snapshot: ファイルなし\n", FILE_APPEND );
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'ファイルが必要です' ], 400 );
        }

        $device_type = sanitize_text_field( $request->get_param( 'device_type' ) ?: 'pc' );
        if ( ! in_array( $device_type, [ 'pc', 'mobile' ], true ) ) {
            $device_type = 'pc';
        }

        // アップロード処理
        require_once ABSPATH . 'wp-admin/includes/file.php';
        require_once ABSPATH . 'wp-admin/includes/image.php';
        require_once ABSPATH . 'wp-admin/includes/media.php';

        $file = $files['file'];

        // MIMEタイプ検証
        $allowed = [ 'image/jpeg', 'image/png', 'image/webp' ];
        $check   = wp_check_filetype( $file['name'] );
        if ( ! $check['type'] || ! in_array( $check['type'], $allowed, true ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'JPEG/PNG/WebP画像のみ対応しています' ], 400 );
        }

        // ファイル名を一意な名前に自動変換（pa_<pageId>_<device>_<タイムスタンプ>_<ランダム>.<拡張子>）
        $ext = pathinfo( $file['name'], PATHINFO_EXTENSION );
        $file['name'] = sprintf( 'pa_%d_%s_%s_%s.%s', $id, $device_type, date( 'Ymd_His' ), substr( bin2hex( random_bytes( 4 ) ), 0, 8 ), $ext );

        $upload = wp_handle_upload( $file, [ 'test_form' => false ] );
        if ( isset( $upload['error'] ) ) {
            file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " upload_snapshot: wp_handle_upload error=" . $upload['error'] . "\n", FILE_APPEND );
            return new \WP_REST_Response( [ 'success' => false, 'message' => $upload['error'] ], 500 );
        }
        file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " upload_snapshot: upload OK, file=" . $upload['file'] . "\n", FILE_APPEND );

        $attachment_data = [
            'post_mime_type' => $upload['type'],
            'post_title'     => sanitize_file_name( $file['name'] ),
            'post_content'   => '',
            'post_status'    => 'inherit',
        ];
        $attachment_id = wp_insert_attachment( $attachment_data, $upload['file'] );

        if ( is_wp_error( $attachment_id ) ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => 'アップロードに失敗しました' ], 500 );
        }

        $metadata = wp_generate_attachment_metadata( $attachment_id, $upload['file'] );
        wp_update_attachment_metadata( $attachment_id, $metadata );

        // ページ分析テーブル更新
        $col = $device_type === 'mobile' ? 'screenshot_mobile' : 'screenshot_pc';
        $wpdb->update(
            $table,
            [
                $col           => $attachment_id,
                'capture_date' => current_time( 'mysql' ),
            ],
            [ 'id' => $id ],
            [ '%d', '%s' ],
            [ '%d' ]
        );

        // スナップショット履歴に追加
        $snap_table = $wpdb->prefix . 'gcrev_page_snapshots';
        $wpdb->insert(
            $snap_table,
            [
                'page_analysis_id' => $id,
                'device_type'      => $device_type,
                'attachment_id'    => $attachment_id,
            ],
            [ '%d', '%s', '%d' ]
        );

        return new \WP_REST_Response( [
            'success' => true,
            'data'    => [
                'attachment_id' => $attachment_id,
                'url'           => wp_get_attachment_url( $attachment_id ),
            ],
        ], 200 );
    }

    /**
     * DELETE /gcrev/v1/page-analysis/pages/{id}/snapshot — スクリーンショット削除
     */
    public function rest_delete_page_snapshot( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $user_id     = get_current_user_id();
        $id          = absint( $request->get_param( 'id' ) );
        $device_type = sanitize_text_field( $request->get_param( 'device_type' ) ?: 'pc' );
        if ( ! in_array( $device_type, [ 'pc', 'mobile' ], true ) ) {
            $device_type = 'pc';
        }

        $table = $wpdb->prefix . 'gcrev_page_analysis';

        // 所有権チェック
        $col = $device_type === 'mobile' ? 'screenshot_mobile' : 'screenshot_pc';
        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT id, {$col} AS attachment_id FROM {$table} WHERE id = %d AND user_id = %d AND status = 'active'",
            $id,
            $user_id
        ) );
        if ( ! $row ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '対象が見つかりません' ], 404 );
        }

        $attachment_id = absint( $row->attachment_id );

        // 添付ファイル削除
        if ( $attachment_id > 0 ) {
            wp_delete_attachment( $attachment_id, true );
        }

        // ページ分析テーブル更新（NULLに戻す）
        $wpdb->update(
            $table,
            [ $col => null ],
            [ 'id' => $id ],
            [ null ],
            [ '%d' ]
        );

        // capture_date を更新（もう片方も空なら NULL にする）
        $other_col = $device_type === 'mobile' ? 'screenshot_pc' : 'screenshot_mobile';
        $other_val = $wpdb->get_var( $wpdb->prepare(
            "SELECT {$other_col} FROM {$table} WHERE id = %d",
            $id
        ) );
        if ( empty( $other_val ) ) {
            $wpdb->update( $table, [ 'capture_date' => null ], [ 'id' => $id ], [ null ], [ '%d' ] );
        }

        return new \WP_REST_Response( [ 'success' => true ], 200 );
    }

    /**
     * POST /gcrev/v1/page-analysis/pages/{id}/analyze — AI分析トリガー（Phase 1 プレースホルダー）
     */
    public function rest_trigger_page_analysis( \WP_REST_Request $request ): \WP_REST_Response {
        global $wpdb;
        $log     = '/tmp/gcrev_page_analysis_debug.log';
        $user_id = get_current_user_id();
        $id      = absint( $request->get_param( 'id' ) );
        $table   = $wpdb->prefix . 'gcrev_page_analysis';
        // TODO: 版管理導入後は $row['current_version_id'] を取得し、
        //       AI改善案を page_ai_insights テーブルに version_id 紐づけで保存する。
        //       既存の ai_summary / ai_analysis_date カラムは後方互換で残す。

        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$table} WHERE id = %d AND user_id = %d AND status = 'active'",
            $id, $user_id
        ), ARRAY_A );

        if ( ! $row ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => '対象が見つかりません' ], 404 );
        }

        // 画像を収集（元画像からファーストビュー相当を切り出してBase64エンコード）
        $images = [];
        foreach ( [ 'screenshot_pc' => 'pc', 'screenshot_mobile' => 'mobile' ] as $field => $device_label ) {
            $att_id = (int) ( $row[ $field ] ?? 0 );
            if ( $att_id <= 0 ) continue;

            // 元画像パスを取得（-scaled版は超縦長画像で幅が潰れるため使わない）
            $file_path = function_exists( 'wp_get_original_image_path' )
                ? wp_get_original_image_path( $att_id )
                : get_attached_file( $att_id );
            if ( ! $file_path || ! file_exists( $file_path ) ) continue;

            // GDで自動分割してAI分析に最適なサイズに（超縦長画像は複数枚に分割）
            $img_parts = $this->prepare_image_for_ai( $file_path, $device_label );
            foreach ( $img_parts as $part ) {
                $images[] = $part;
            }
        }

        // ===== 分析コンテキストの構築 =====
        $analysis_context = $this->build_page_analysis_context( $row, $user_id );

        // プロンプト構築（構造化コンテキスト + 段階的評価指示）
        $prompt = $this->build_page_analysis_prompt( $analysis_context, count( $images ) > 0 );

        // OpenAI Responses API で改善コメント生成（gpt-5.4-mini）
        $ai_result = $this->call_openai_page_analysis( $prompt, $images );
        if ( is_wp_error( $ai_result ) ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " OpenAI analyze ERROR: " . $ai_result->get_error_message() . "\n",
                FILE_APPEND
            );
            return new \WP_REST_Response( [
                'success' => false,
                'message' => 'AI改善案の生成に失敗しました: ' . $ai_result->get_error_message(),
            ], 500 );
        }
        $ai_text = $ai_result;

        // 結果を保存
        $now = current_time( 'mysql' );
        $wpdb->update(
            $table,
            [
                'ai_summary'       => $ai_text,
                'ai_analysis_date' => $now,
            ],
            [ 'id' => $id ],
            [ '%s', '%s' ],
            [ '%d' ]
        );

        return new \WP_REST_Response( [
            'success'          => true,
            'message'          => 'AI改善案を生成しました',
            'ai_summary'       => $ai_text,
            'ai_analysis_date' => $now,
        ], 200 );
    }

    /**
     * Clarityデータからプロンプト用の行動サマリーテキストを構築
     */
    /**
     * AI分析用に画像を最適化（超縦長画像は自動分割して複数枚に）
     *
     * ページ全体のスクリーンショットを上部から順に自動分割し、
     * Geminiが各セクションを正確に読み取れるサイズにする。
     *
     * @param string $file_path 元画像ファイルパス
     * @param string $device    'pc' or 'mobile'
     * @return array            [ ['mime_type' => ..., 'data' => base64], ... ]
     */
    private function prepare_image_for_ai( string $file_path, string $device ): array {
        $log = '/tmp/gcrev_page_analysis_debug.log';

        $info = @getimagesize( $file_path );
        if ( ! $info ) return [];

        $orig_w = $info[0];
        $orig_h = $info[1];
        $mime   = $info['mime'] ?? 'image/png';

        // 画像サイズが適切なら（幅300px以上 & 高さが幅の4倍以内）そのまま使用
        if ( $orig_w >= 300 && $orig_h <= $orig_w * 4 && filesize( $file_path ) <= 4 * 1024 * 1024 ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " ai_img: {$device} using original {$orig_w}x{$orig_h} (1 part)\n", FILE_APPEND );
            return [[
                'mime_type' => $mime,
                'data'      => base64_encode( file_get_contents( $file_path ) ),
            ]];
        }

        // GDで分割 + リサイズ
        if ( ! function_exists( 'imagecreatefrompng' ) ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " ai_img: {$device} GD unavailable, sending raw\n", FILE_APPEND );
            return [[
                'mime_type' => $mime,
                'data'      => base64_encode( file_get_contents( $file_path ) ),
            ]];
        }

        // 元画像読み込み
        $src = null;
        switch ( $mime ) {
            case 'image/png':  $src = @imagecreatefrompng( $file_path ); break;
            case 'image/jpeg': $src = @imagecreatefromjpeg( $file_path ); break;
            case 'image/webp': $src = @imagecreatefromwebp( $file_path ); break;
        }
        if ( ! $src ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " ai_img: {$device} GD failed to load {$mime}\n", FILE_APPEND );
            return [];
        }

        // 分割設定: 各パートの高さ = 幅 × 2.5（約2.5画面分）、最大5分割
        $part_h   = (int) round( $orig_w * 2.5 );
        $max_parts = 5;
        $num_parts = min( $max_parts, (int) ceil( $orig_h / $part_h ) );
        $max_w     = 1200;
        $out_w     = min( $orig_w, $max_w );
        $scale     = $out_w / $orig_w;

        $results = [];
        for ( $i = 0; $i < $num_parts; $i++ ) {
            $src_y = $i * $part_h;
            $src_h = min( $part_h, $orig_h - $src_y );
            if ( $src_h <= 0 ) break;

            $out_h = (int) round( $src_h * $scale );

            $dst = imagecreatetruecolor( $out_w, $out_h );
            imagealphablending( $dst, false );
            imagesavealpha( $dst, true );
            imagecopyresampled( $dst, $src, 0, 0, 0, $src_y, $out_w, $out_h, $orig_w, $src_h );

            ob_start();
            imagejpeg( $dst, null, 85 );
            $jpeg_data = ob_get_clean();
            imagedestroy( $dst );

            $results[] = [
                'mime_type' => 'image/jpeg',
                'data'      => base64_encode( $jpeg_data ),
            ];
        }

        imagedestroy( $src );

        file_put_contents( $log,
            date( 'Y-m-d H:i:s' ) . " ai_img: {$device} split {$orig_w}x{$orig_h} → {$num_parts} parts"
            . " (each ~{$out_w}x" . round( $part_h * $scale ) . ")\n",
            FILE_APPEND
        );

        return $results;
    }

    /**
     * ページ分析用の構造化コンテキストを構築（GA4 + Clarity + ページ情報統合）
     */
    private function build_page_analysis_context( array $row, int $user_id ): array {
        $log = '/tmp/gcrev_page_analysis_debug.log';

        // --- ページ基本情報 ---
        $type_names = [
            'top' => 'トップページ', 'service' => 'サービス紹介', 'lp' => 'LP',
            'contact' => 'お問い合わせ', 'blog' => 'ブログ', 'company' => '会社概要',
            'access' => 'アクセス', 'staff' => 'スタッフ', 'price' => '料金', 'other' => 'その他',
        ];
        $page_info = [
            'url'          => $row['page_url'],
            'title'        => $row['page_title'],
            'page_type'    => $type_names[ $row['page_type'] ] ?? $row['page_type'],
            'purpose'      => $row['page_purpose'] ?: '未設定',
            'main_cta'     => $row['page_cta'] ?: '未設定',
        ];

        // --- 期間設定（直近30日） ---
        $tz    = wp_timezone();
        $end   = new \DateTimeImmutable( 'today', $tz );
        $start = $end->modify( '-30 days' );
        $period = [
            'start'    => $start->format( 'Y-m-d' ),
            'end'      => $end->format( 'Y-m-d' ),
            'days'     => 30,
            'timezone' => $tz->getName(),
        ];

        // --- GA4データ取得（既存 GA4 Fetcher を活用） ---
        $ga4_data = null;
        // 解析対象/除外URL条件（サイト全体の集計に適用）
        $inc_paths_pa = get_user_meta( $user_id, '_gcrev_include_paths', true );
        $exc_paths_pa = get_user_meta( $user_id, '_gcrev_exclude_paths', true );
        $inc_paths_pa = is_array( $inc_paths_pa ) ? $inc_paths_pa : [];
        $exc_paths_pa = is_array( $exc_paths_pa ) ? $exc_paths_pa : [];
        $has_user_path_filter = ! empty( $inc_paths_pa ) || ! empty( $exc_paths_pa );

        try {
            $property_id = trim( (string) get_user_meta( $user_id, 'ga4_property_id', true ) );
            if ( $property_id ) {
                // 国フィルター設定（海外除外対応）
                $exclude_foreign = get_user_meta( $user_id, 'report_exclude_foreign', true );
                if ( $exclude_foreign ) {
                    $this->ga4->set_country_filter( 'Japan' );
                }

                // ページURLのパスを抽出
                $page_path = wp_parse_url( $row['page_url'], PHP_URL_PATH ) ?: '/';

                // ページパスで絞り込んでGA4データ取得（このページ単体のメトリクス）
                $this->ga4->set_page_path_filter( $page_path );
                $pages = $this->ga4->fetch_page_details( $property_id, $period['start'], $period['end'] );
                $this->ga4->set_page_path_filter( null ); // フィルタクリア

                // ここから先のサイト全体集計（流入チャネル・地域・デバイス）には
                // クライアント設定の解析対象/除外URL条件を適用する。
                // /media/ などを除外していれば、それらの配下ページのアクセスは
                // AI 診断のサイト全体コンテキストに含めない。
                if ( $has_user_path_filter ) {
                    $this->ga4->set_include_paths_filter( $inc_paths_pa );
                    $this->ga4->set_exclude_paths_filter( $exc_paths_pa );
                }

                // 対象ページを特定
                $target = null;
                foreach ( $pages as $pg ) {
                    if ( rtrim( $pg['page'], '/' ) === rtrim( $page_path, '/' ) || $pg['page'] === $page_path ) {
                        $target = $pg;
                        break;
                    }
                }
                if ( ! $target && ! empty( $pages ) ) {
                    $target = $pages[0];
                }

                if ( $target ) {
                    $ga4_data = [
                        'sessions'                => (int) $target['sessions'],
                        'pageViews'               => (int) $target['pageViews'],
                        'engagement_rate_percent'  => round( (float) $target['engagementRate'], 1 ),
                        'avg_duration_sec'         => round( (float) $target['avgDuration'], 1 ),
                        'bounce_rate_percent'      => round( (float) $target['bounceRate'], 1 ),
                        'period'                   => "{$period['start']}〜{$period['end']}",
                    ];
                }

                // --- 流入チャネル（サイト全体、同期間） ---
                try {
                    $source_raw = $this->ga4->fetch_source_data_from_ga4( $property_id, $period['start'], $period['end'] );
                    if ( ! empty( $source_raw['channels'] ) ) {
                        $channels_top = array_slice( $source_raw['channels'], 0, 5 );
                        $ga4_data['channels'] = array_map( function( $ch ) {
                            return [
                                'channel'  => $ch['channel'] ?? $ch['sessionDefaultChannelGroup'] ?? '',
                                'sessions' => (int) ( $ch['sessions'] ?? 0 ),
                            ];
                        }, $channels_top );
                    }
                    if ( ! empty( $source_raw['sources'] ) ) {
                        $sources_top = array_slice( $source_raw['sources'], 0, 5 );
                        $ga4_data['sources'] = array_map( function( $s ) {
                            return [
                                'source_medium' => ( $s['source'] ?? '' ) . ' / ' . ( $s['medium'] ?? '' ),
                                'sessions'      => (int) ( $s['sessions'] ?? 0 ),
                            ];
                        }, $sources_top );
                    }
                } catch ( \Exception $e ) {
                    file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " GA4 source ERROR: " . $e->getMessage() . "\n", FILE_APPEND );
                }

                // --- 地域別（上位5） ---
                try {
                    $regions_raw = $this->ga4->fetch_region_details( $property_id, $period['start'], $period['end'] );
                    if ( ! empty( $regions_raw ) ) {
                        $ga4_data['regions'] = array_map( function( $r ) {
                            return [
                                'region'   => $r['region'] ?? '',
                                'sessions' => (int) ( $r['sessions'] ?? 0 ),
                            ];
                        }, array_slice( $regions_raw, 0, 5 ) );
                    }
                } catch ( \Exception $e ) {
                    file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " GA4 region ERROR: " . $e->getMessage() . "\n", FILE_APPEND );
                }

                // --- デバイス別 ---
                try {
                    $devices_raw = $this->ga4->fetch_device_details( $property_id, $period['start'], $period['end'] );
                    if ( ! empty( $devices_raw ) ) {
                        $ga4_data['devices'] = array_map( function( $d ) {
                            return [
                                'device'   => $d['device'] ?? $d['deviceCategory'] ?? '',
                                'sessions' => (int) ( $d['sessions'] ?? 0 ),
                            ];
                        }, $devices_raw );
                    }
                } catch ( \Exception $e ) {
                    file_put_contents( $log, date( 'Y-m-d H:i:s' ) . " GA4 device ERROR: " . $e->getMessage() . "\n", FILE_APPEND );
                }

                // 解析対象/除外URL条件フィルタを解除（次の呼び出しに影響させない）
                if ( $has_user_path_filter ) {
                    $this->ga4->clear_include_paths_filter();
                    $this->ga4->set_page_path_filter( null );
                }

                // 国フィルタクリア
                if ( $exclude_foreign ) {
                    $this->ga4->set_country_filter( null );
                }
            }
        } catch ( \Exception $e ) {
            // 例外時もフィルタを必ず解除
            if ( $has_user_path_filter ) {
                $this->ga4->clear_include_paths_filter();
                $this->ga4->set_page_path_filter( null );
            }
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " GA4 for analysis ERROR: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
        }

        // --- GSC（検索キーワード）取得 ---
        $gsc_data = null;
        try {
            $user_config = $this->config->get_user_config( $user_id );
            $gsc_url = $user_config['gsc_url'] ?? '';
            if ( $gsc_url ) {
                // 解析対象/除外URL条件を反映
                $this->gsc->apply_user_path_filters( $user_id );
                try {
                    $gsc_raw = $this->gsc->fetch_gsc_data( $gsc_url, $period['start'], $period['end'] );
                } finally {
                    $this->gsc->clear_path_filters();
                }
                if ( ! empty( $gsc_raw['keywords'] ) ) {
                    $gsc_data = [
                        'total_impressions' => $gsc_raw['total']['impressions'] ?? 0,
                        'total_clicks'      => $gsc_raw['total']['clicks'] ?? 0,
                        'total_ctr'         => $gsc_raw['total']['ctr'] ?? '',
                        'top_keywords'      => array_slice( $gsc_raw['keywords'], 0, 10 ),
                    ];
                }
            }
        } catch ( \Exception $e ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " GSC for analysis ERROR: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
        }

        // --- Clarityデータ整形 ---
        $clarity_raw  = $row['clarity_data'] ? json_decode( $row['clarity_data'], true ) : [];
        $clarity_data = $this->extract_clarity_for_analysis( $clarity_raw );

        // --- 注記 ---
        $notes = [
            'CTAは「見えているか」「意味が伝わるか」「押したくなるか」を分けて評価すること',
        ];
        // 海外アクセス注意
        $exclude_foreign = get_user_meta( $user_id, 'report_exclude_foreign', true );
        if ( $exclude_foreign ) {
            $notes[] = '海外アクセスはGA4データから除外済み（日本国内のみ）';
        }
        // Clarity同期日
        if ( $row['clarity_sync_date'] ) {
            $notes[] = 'Clarity最終同期: ' . $row['clarity_sync_date'] . '（直近数日のサマリー）';
        }

        // --- データ信頼度の算出 ---
        $data_reliability = $this->assess_data_reliability( $ga4_data, $clarity_data );
        if ( $data_reliability['level'] !== 'sufficient' ) {
            $notes[] = $data_reliability['note'];
        }

        return [
            'page'             => $page_info,
            'period'           => $period,
            'ga4'              => $ga4_data,
            'gsc'              => $gsc_data,
            'clarity'          => $clarity_data,
            'notes'            => $notes,
            'data_reliability' => $data_reliability,
        ];
    }

    /**
     * GA4/Clarityのデータ量からコメント信頼度を判定
     *
     * @return array ['level'=>string, 'label'=>string, 'note'=>string]
     *   level: 'sufficient' | 'reference' | 'hypothesis'
     */
    private function assess_data_reliability( ?array $ga4, ?array $clarity ): array {
        $ga4_sessions = $ga4['sessions'] ?? 0;

        // Clarityの合計セッション
        $clarity_sessions = 0;
        if ( $clarity && ! empty( $clarity['devices'] ) ) {
            foreach ( $clarity['devices'] as $cd ) {
                $clarity_sessions += (int) ( $cd['sessions'] ?? 0 );
            }
        }

        $total = max( $ga4_sessions, $clarity_sessions );

        if ( $total >= 100 ) {
            return [
                'level' => 'sufficient',
                'label' => '十分なデータあり',
                'note'  => '',
            ];
        }
        if ( $total >= 20 ) {
            return [
                'level' => 'reference',
                'label' => '参考傾向',
                'note'  => "セッション数が{$total}件のため、改善提案は参考傾向としてお読みください。継続的なデータ蓄積により精度が向上します。",
            ];
        }
        return [
            'level' => 'hypothesis',
            'label' => '件数不足のため仮説レベル',
            'note'  => "セッション数が{$total}件と少ないため、以下の改善提案は仮説レベルです。断定的な判断は避け、データが蓄積されてから再分析することをお勧めします。",
        ];
    }

    /**
     * Clarityデータから分析用構造を抽出
     */
    private function extract_clarity_for_analysis( array $clarity ): ?array {
        if ( empty( $clarity['metrics'] ) ) return null;

        $result = [ 'devices' => [] ];
        $site_wide = $clarity['site_wide']['by_device'] ?? [];

        foreach ( [ 'PC' => 'PC', 'Mobile' => 'スマホ' ] as $key => $label ) {
            $dev = $site_wide[ $key ] ?? [];
            if ( empty( $dev ) ) continue;

            $t  = $dev['traffic'] ?? [];
            $sd = $dev['scroll_depth'] ?? [];
            $et = $dev['engagement_time'] ?? [];
            $dc = $dev['dead_click_count'] ?? [];
            $rc = $dev['rage_click_count'] ?? [];
            $ec = $dev['error_click_count'] ?? [];
            $qb = $dev['quickback_click'] ?? [];

            $sessions = $t['sessionsWithMetricCount'] ?? ( $t['subTotal'] ?? ( $t['sessionsCount'] ?? null ) );
            $scroll   = $sd['averageScrollDepth'] ?? ( $sd['sessionsWithMetricPercentage'] ?? null );
            $engage   = $et['activeTime'] ?? ( $et['totalTime'] ?? null );
            $dead     = $dc['subTotal'] ?? ( $dc['sessionsWithMetricCount'] ?? null );
            $rage     = $rc['subTotal'] ?? ( $rc['sessionsWithMetricCount'] ?? null );
            $error    = $ec['subTotal'] ?? ( $ec['sessionsWithMetricCount'] ?? null );
            $quick    = $qb['subTotal'] ?? ( $qb['sessionsWithMetricCount'] ?? null );

            $result['devices'][] = [
                'device'                  => $label,
                'sessions'                => $sessions,
                'scroll_depth_percent'    => $scroll !== null ? round( (float) $scroll, 1 ) : null,
                'engagement_time_sec'     => $engage !== null ? round( (float) $engage ) : null,
                'dead_clicks'             => $dead,
                'rage_clicks'             => $rage,
                'error_clicks'            => $error,
                'quick_backs'             => $quick,
            ];
        }

        return $result;
    }

    /**
     * 分析コンテキストから改善案生成用プロンプトを構築
     */
    private function build_page_analysis_prompt( array $ctx, bool $has_images ): string {
        $p = $ctx['page'];
        $period = $ctx['period'];

        // --- セクション1: 分析コンテキスト ---
        $prompt = "あなたはWebサイトの改善コンサルタントです。\n"
            . "以下の分析データとページ画像を総合的に判断し、ホームページ運用の初心者にもわかりやすい改善提案を3〜5点出してください。\n\n"
            . "===== 分析データ =====\n\n"
            . "【ページ情報】\n"
            . "- URL: {$p['url']}\n"
            . "- ページ名: {$p['title']}\n"
            . "- 種別: {$p['page_type']}\n"
            . "- 主な目的: {$p['purpose']}\n"
            . "- 主要CTA: {$p['main_cta']}\n\n";

        // --- GA4データ ---
        $ga4 = $ctx['ga4'];
        if ( $ga4 ) {
            $prompt .= "【GA4ページデータ（{$ga4['period']}）】\n"
                . "- セッション数: {$ga4['sessions']}\n"
                . "- ページビュー: {$ga4['pageViews']}\n"
                . "- エンゲージメント率: {$ga4['engagement_rate_percent']}%\n"
                . "- 平均滞在時間: {$ga4['avg_duration_sec']}秒\n"
                . "- 直帰率: {$ga4['bounce_rate_percent']}%\n\n";

            // 流入チャネル
            if ( ! empty( $ga4['channels'] ) ) {
                $prompt .= "【流入チャネル（サイト全体・同期間）】\n";
                foreach ( $ga4['channels'] as $ch ) {
                    $prompt .= "- {$ch['channel']}: {$ch['sessions']}セッション\n";
                }
                $prompt .= "\n";
            }

            // 流入元トップ5
            if ( ! empty( $ga4['sources'] ) ) {
                $prompt .= "【流入元 Top5】\n";
                foreach ( $ga4['sources'] as $s ) {
                    $prompt .= "- {$s['source_medium']}: {$s['sessions']}セッション\n";
                }
                $prompt .= "\n";
            }

            // 地域別
            if ( ! empty( $ga4['regions'] ) ) {
                $prompt .= "【アクセス地域 Top5】\n";
                foreach ( $ga4['regions'] as $r ) {
                    $prompt .= "- {$r['region']}: {$r['sessions']}セッション\n";
                }
                $prompt .= "\n";
            }

            // デバイス別
            if ( ! empty( $ga4['devices'] ) ) {
                $prompt .= "【デバイス別セッション】\n";
                foreach ( $ga4['devices'] as $d ) {
                    $prompt .= "- {$d['device']}: {$d['sessions']}セッション\n";
                }
                $prompt .= "\n";
            }
        } else {
            $prompt .= "【GA4データ】\n未取得（GA4未接続または対象ページのデータなし）\n\n";
        }

        // --- GSC（検索キーワード） ---
        $gsc = $ctx['gsc'] ?? null;
        if ( $gsc ) {
            $prompt .= "【検索キーワード（Google Search Console・同期間）】\n"
                . "- 合計表示回数: {$gsc['total_impressions']}\n"
                . "- 合計クリック数: {$gsc['total_clicks']}\n"
                . "- 平均CTR: {$gsc['total_ctr']}\n"
                . "上位キーワード:\n";
            foreach ( $gsc['top_keywords'] as $kw ) {
                $prompt .= "  - 「{$kw['query']}」 表示:{$kw['impressions']} クリック:{$kw['clicks']} 順位:{$kw['position']}\n";
            }
            $prompt .= "\n";
        }

        // --- Clarityデータ ---
        $clarity = $ctx['clarity'];
        if ( $clarity && ! empty( $clarity['devices'] ) ) {
            $prompt .= "【Clarityデータ（直近数日のサマリー）】\n";
            foreach ( $clarity['devices'] as $cd ) {
                $scroll  = $cd['scroll_depth_percent'] !== null ? "{$cd['scroll_depth_percent']}%" : '-';
                $engage  = $cd['engagement_time_sec'] !== null ? "{$cd['engagement_time_sec']}秒" : '-';
                $prompt .= "- {$cd['device']}: セッション" . ( $cd['sessions'] ?? '-' )
                    . ", スクロール深度{$scroll}, エンゲージメント{$engage}"
                    . ", Dead Click " . ( $cd['dead_clicks'] ?? '-' )
                    . ", Rage Click " . ( $cd['rage_clicks'] ?? '-' );
                if ( $cd['quick_backs'] !== null ) {
                    $prompt .= ", Quick Back {$cd['quick_backs']}";
                }
                $prompt .= "\n";
            }
            $prompt .= "\n";
        } else {
            $prompt .= "【Clarityデータ】\n未取得\n\n";
        }

        // --- データ信頼度 ---
        $rel = $ctx['data_reliability'] ?? [ 'level' => 'sufficient', 'label' => '', 'note' => '' ];
        if ( $rel['level'] !== 'sufficient' ) {
            $prompt .= "【⚠ データ信頼度: {$rel['label']}】\n"
                . "{$rel['note']}\n";
            if ( $rel['level'] === 'hypothesis' ) {
                $prompt .= "改善提案は断定口調を一切使わず、すべて「〜の可能性があります」「〜かもしれません」「〜を検討する価値があります」のような仮説ベースの表現にしてください。\n"
                    . "冒頭に「※ データ件数が少ないため、以下は仮説ベースの参考所見です。データが蓄積されてから改めて分析することをお勧めします。」と必ず書いてください。\n";
            } elseif ( $rel['level'] === 'reference' ) {
                $prompt .= "改善提案は「〜の傾向が見られます」「〜の可能性があります」のような参考ベースの表現を優先してください。\n"
                    . "冒頭に「※ データ件数がまだ十分ではないため、以下は参考傾向としてお読みください。」と書いてください。\n";
            }
            $prompt .= "\n";
        }

        // --- 注記 ---
        if ( ! empty( $ctx['notes'] ) ) {
            $prompt .= "【分析上の注記】\n";
            foreach ( $ctx['notes'] as $note ) {
                $prompt .= "- {$note}\n";
            }
            $prompt .= "\n";
        }

        // --- セクション2: 画像について ---
        if ( $has_images ) {
            $prompt .= "===== 画像について =====\n"
                . "添付画像はこのページのPC版・スマホ版のスクリーンショットです。ページ全体を上から順に分割して添付しています。\n"
                . "すべての画像を確認した上でページ全体を評価してください。\n\n";
        }

        // --- セクション3: 評価ルール ---
        $prompt .= "===== 評価ルール（必ず従うこと） =====\n\n"
            . "【スマホ版画像の固定フッターについて】\n"
            . "スマホ版スクリーンショットの最下部に電話番号ボタンやお問い合わせボタン等が横並びで表示されている場合、それは画面に常時固定表示されている「固定フッターバー」です。\n"
            . "ユーザーがどこまでスクロールしても常に表示されます。「CTAが見つからない」「問い合わせ導線がない」という指摘は不適切です。\n\n"
            . "【CTA評価ルール】\n"
            . "CTAボタンは以下の順で評価すること:\n"
            . "1. ボタンは物理的に見えているか（大きさ・色・位置）\n"
            . "2. ボタンの意味はすぐ理解できるか\n"
            . "3. 押したくなる理由が周辺情報から自然に伝わるか\n"
            . "大きく目立つCTAに対して「目立ちにくい」「視認性が低い」とは書かないこと。\n"
            . "課題がある場合は「ボタンの視認性は確保されている一方で、CTAを押す理由づけの補強余地がある」のように書くこと。\n\n"
            . "【表現ルール】\n"
            . "- 数値だけで原因を断定しない。「〜の可能性があります」と書く\n"
            . "- スクロール深度が低くても「情報が多すぎる」と断定しない。「ファーストビュー以降に進んでいない可能性がある」程度に留める\n"
            . "- テンプレ的な一般論ではなく、実際の画面に即した具体的な内容にする\n"
            . "- 改善の軸は「訴求の明確化」「理解の速さ」「行動理由の補強」に置く\n\n"
            . "【流入背景を踏まえた分析ルール】\n"
            . "- ページ内行動だけでなく、流入背景（チャネル・地域・キーワード）を見たうえで判断すること\n"
            . "- ターゲット外流入が多い場合、ページだけの問題とは断定しないこと\n"
            . "- 流入キーワードとファーストビュー訴求にズレがあるなら、その旨を指摘すること\n"
            . "- ページ課題と集客課題を分けて評価すること\n"
            . "- 検索キーワードデータがある場合、検索意図とページ内容の整合性を必ず評価すること\n\n"
            . "【分析の段階的アプローチ】\n"
            . "以下の順で判断した上で改善案を出すこと:\n"
            . "Step1. 流入背景を確認（どこから・誰が・どんな意図で来ているか）\n"
            . "Step2. 画像から見て言える事実（CTAの有無・大きさ・色、情報量、レイアウト）\n"
            . "Step3. GA4から言えること（流入量・エンゲージメント・デバイス傾向・流入チャネル）\n"
            . "Step4. 検索キーワードから言えること（検索意図とページ訴求の一致度）\n"
            . "Step5. Clarityから言えること（スクロール深度・Dead Click・Quick Back等）\n"
            . "Step6. ページ課題と流入課題を分けて原因仮説を述べる（可能性ベース）\n"
            . "Step7. 改善案を出す（ページ改善と集客導線改善を区別）\n\n"
            . "===== 出力形式 =====\n\n"
            . "以下の構造で、必ずこの順番で出力してください:\n\n"
            . "## 流入背景\n"
            . "GA4とSearch Consoleのデータから、このページにどんなユーザーが来ているかを2〜4行でまとめる。\n"
            . "含めるべき情報: 主な流入チャネル、主要流入地域、デバイス比率、主な検索キーワード（あれば）。\n"
            . "ターゲット地域との一致度、検索意図とページ訴求の整合性についても触れる。\n"
            . "データが不足している場合は取得できた範囲で書き、不明点は断定しない。\n\n"
            . "## 良かった点\n"
            . "画面やデータから事実ベースで評価できるプラスのポイントを1〜3点挙げる。\n"
            . "流入背景も含め、総合的に評価できる点を書く。\n"
            . "例: CTAの視認性が高い、ターゲット地域からの流入が多い、自然検索中心で指名検索もある等\n"
            . "各項目は「### 項目タイトル」の見出しを付け、1〜2行で簡潔に書く。\n\n"
            . "## 現状の見立て\n"
            . "画面・GA4流入データ・Clarity行動データを総合して、現状を3〜5行でまとめる。\n"
            . "ページ自体の課題と、流入の質やターゲティングの課題を分けて言及すること。\n"
            . "例: 「ターゲット地域からの流入は確保できているが、スマホでの離脱が早い」等。\n\n"
            . "## 改善提案\n"
            . "3〜5点の改善案を、それぞれ「### 提案タイトル」の見出しと具体的な内容2〜3行で書く。\n"
            . "見出しは**太字**にし、本文との区切りを明確にすること。\n"
            . "改善案の観点（ページ課題と流入課題を区別して提案する）:\n"
            . "1. ファーストビューの訴求力（流入キーワードの検索意図とマッチしているか）\n"
            . "2. CTA訴求導線の自然さ\n"
            . "3. スクロール離脱を防ぐ構成\n"
            . "4. スマホでの操作性と理解の速さ\n"
            . "5. Dead Click/Rage Clickが示す問題点\n"
            . "6. 流入チャネルや検索意図とページ訴求のズレがあればその改善\n"
            . "7. ターゲット外流入が多い場合、集客導線の見直し余地\n\n"
            . "===== 文体ルール =====\n"
            . "- 専門用語は避け、わかりやすい日本語で書く\n"
            . "- 汎用的なテンプレート改善案ではなく、この画面の実際の状態に即した具体的な内容にする\n"
            . "- 各セクション見出し（## 流入背景、## 良かった点、## 現状の見立て、## 改善提案）は必ず付ける\n"
            . "- 各改善項目の見出し（### タイトル）も必ず付ける\n"
            . "- 要点は**太字**で強調する\n"
            . "- 厳しすぎず、前向きで実務的なトーンにする\n"
            . "- ページ課題と流入課題は区別して言及する\n"
            . "- 「この分析はページ画像・GA4の流入データ・Clarityの行動データ・Search Consoleの検索データを総合して判断しています」というニュアンスが伝わるようにする\n";

        return $prompt;
    }

    /**
     * OpenAI Responses API を使ってページ改善コメントを生成
     *
     * @param string $prompt テキストプロンプト
     * @param array  $images 画像配列 [['mime_type'=>'image/jpeg','data'=>base64], ...]
     * @return string|\WP_Error 生成テキストまたはエラー
     */
    private function call_openai_page_analysis( string $prompt, array $images ) {
        $api_key = defined( 'MIMAMORI_OPENAI_API_KEY' ) ? MIMAMORI_OPENAI_API_KEY : '';
        if ( empty( $api_key ) ) {
            return new \WP_Error( 'no_api_key', 'MIMAMORI_OPENAI_API_KEY が未設定です' );
        }

        $log   = '/tmp/gcrev_page_analysis_debug.log';
        $model = 'gpt-4.1-mini';

        // --- input 配列を構築 ---
        $content = [];

        // テキストプロンプト
        $content[] = [
            'type' => 'input_text',
            'text' => $prompt,
        ];

        // 画像（base64 data URL形式）
        foreach ( $images as $img ) {
            $mime = $img['mime_type'] ?? 'image/jpeg';
            $data = $img['data'] ?? '';
            if ( empty( $data ) ) continue;
            $content[] = [
                'type'      => 'input_image',
                'image_url' => "data:{$mime};base64,{$data}",
            ];
        }

        $body = wp_json_encode( [
            'model' => $model,
            'input' => [
                [
                    'role'    => 'user',
                    'content' => $content,
                ],
            ],
        ], JSON_UNESCAPED_UNICODE );

        file_put_contents( $log,
            date( 'Y-m-d H:i:s' ) . " OpenAI request: model={$model}, images=" . count( $images )
            . ", prompt_len=" . mb_strlen( $prompt ) . "\n",
            FILE_APPEND
        );

        // --- API呼び出し ---
        $response = wp_remote_post( 'https://api.openai.com/v1/responses', [
            'timeout' => 120,
            'headers' => [
                'Content-Type'  => 'application/json',
                'Authorization' => 'Bearer ' . $api_key,
            ],
            'body' => $body,
        ] );

        if ( is_wp_error( $response ) ) {
            return new \WP_Error( 'request_failed', 'OpenAI APIリクエスト失敗: ' . $response->get_error_message() );
        }

        $status = wp_remote_retrieve_response_code( $response );
        $body_text = wp_remote_retrieve_body( $response );

        if ( $status !== 200 ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " OpenAI ERROR: status={$status}, body=" . substr( $body_text, 0, 500 ) . "\n",
                FILE_APPEND
            );
            $err_data = json_decode( $body_text, true );
            $err_msg  = $err_data['error']['message'] ?? "HTTP {$status}";
            return new \WP_Error( 'api_error', "OpenAI APIエラー: {$err_msg}" );
        }

        $result = json_decode( $body_text, true );

        // Responses API のレスポンスからテキストを抽出
        $output_text = '';
        $output_items = $result['output'] ?? [];
        foreach ( $output_items as $item ) {
            if ( ( $item['type'] ?? '' ) === 'message' ) {
                $msg_content = $item['content'] ?? [];
                foreach ( $msg_content as $mc ) {
                    if ( ( $mc['type'] ?? '' ) === 'output_text' ) {
                        $output_text .= $mc['text'];
                    }
                }
            }
        }

        if ( empty( $output_text ) ) {
            file_put_contents( $log,
                date( 'Y-m-d H:i:s' ) . " OpenAI: empty output, raw=" . substr( $body_text, 0, 500 ) . "\n",
                FILE_APPEND
            );
            return new \WP_Error( 'empty_response', 'OpenAI APIから空のレスポンスが返されました' );
        }

        file_put_contents( $log,
            date( 'Y-m-d H:i:s' ) . " OpenAI OK: output_len=" . mb_strlen( $output_text ) . "\n",
            FILE_APPEND
        );

        return $output_text;
    }

    private function build_behavior_summary_text( array $clarity ): string {
        if ( empty( $clarity['metrics'] ) ) {
            return "【行動データ】\nデータ未取得\n";
        }

        $text = "【行動データ（直近3日間のサマリー）】\n";
        $site_wide = $clarity['site_wide']['by_device'] ?? [];

        foreach ( [ 'PC' => 'PC版', 'Mobile' => 'スマホ版' ] as $key => $label ) {
            $dev = $site_wide[ $key ] ?? [];
            if ( empty( $dev ) ) continue;

            $t  = $dev['traffic'] ?? [];
            $sd = $dev['scroll_depth'] ?? [];
            $et = $dev['engagement_time'] ?? [];
            $dc = $dev['dead_click_count'] ?? [];
            $rc = $dev['rage_click_count'] ?? [];

            $sessions   = $t['sessionsCount'] ?? '-';
            $scroll     = $sd['averageScrollDepth'] ?? ( $sd['sessionsWithMetricPercentage'] ?? '-' );
            $engagement = $et['activeTime'] ?? ( $et['totalTime'] ?? '-' );
            $dead       = $dc['subTotal'] ?? ( $dc['sessionsCount'] ?? '-' );
            $rage       = $rc['subTotal'] ?? ( $rc['sessionsCount'] ?? '-' );

            $scroll_str = is_numeric( $scroll ) ? round( (float) $scroll, 1 ) . '%' : $scroll;
            $eng_str    = is_numeric( $engagement ) ? round( (float) $engagement ) . '秒' : $engagement;

            $text .= "- {$label}: セッション{$sessions}, スクロール深度{$scroll_str}, エンゲージメント{$eng_str}, Dead Click {$dead}, Rage Click {$rage}\n";
        }

        return $text;
    }

    /**
     * ページタイトルをURLから自動取得
     *
     * @param string $url
     * @return string タイトル文字列（取得失敗時は空文字）
     */
    private function fetch_page_title( string $url ): string {
        $response = wp_remote_get( $url, [
            'timeout'    => 5,
            'user-agent' => 'MimamoriWeb/1.0',
            'sslverify'  => false,
        ] );

        if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) !== 200 ) {
            return '';
        }

        $body = wp_remote_retrieve_body( $response );
        if ( preg_match( '/<title[^>]*>([^<]+)<\/title>/i', $body, $m ) ) {
            $title = trim( $m[1] );
            // 文字コード変換（Shift_JIS等対応）
            if ( preg_match( '/charset=["\']?([^"\'\s;>]+)/i', $body, $cm ) ) {
                $charset = strtolower( $cm[1] );
                if ( $charset !== 'utf-8' && $charset !== 'utf8' ) {
                    $converted = mb_convert_encoding( $title, 'UTF-8', $charset );
                    if ( $converted !== false ) {
                        $title = $converted;
                    }
                }
            }
            return sanitize_text_field( $title );
        }

        return '';
    }

