    /**
     * GET /aio-serp/keyword/{id} — 単一キーワード詳細
     */
    public function rest_get_aio_serp_keyword_detail( \WP_REST_Request $request ): \WP_REST_Response {
        try {
            $user_id = get_current_user_id();
            if ( ! $user_id ) {
                return new \WP_REST_Response( [ 'success' => false, 'message' => '未ログイン' ], 401 );
            }

            $keyword_id = absint( $request['id'] );
            $service    = $this->get_aio_serp_service();
            if ( ! $service ) {
                return new \WP_REST_Response( [ 'success' => false, 'message' => 'AIO SERP service not available' ], 500 );
            }

            $detail = $service->get_keyword_detail( $keyword_id );

            return new \WP_REST_Response( [
                'success' => true,
                'data'    => $detail,
            ], 200 );
        } catch ( \Exception $e ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => $e->getMessage() ], 500 );
        }
    }

    /**
     * POST /aio-serp/fetch — 手動取得トリガー
     *
     * 全ユーザーが利用可能。一般ユーザーは週1回制限（管理者は制限なし）。
     * desktop + mobile の両デバイスで自動取得する。
     */
    public function rest_aio_serp_fetch( \WP_REST_Request $request ): \WP_REST_Response {
        try {
            $current_user_id = get_current_user_id();
            if ( ! $current_user_id ) {
                return new \WP_REST_Response( [ 'success' => false, 'message' => '未ログイン' ], 401 );
            }

            $is_admin = current_user_can( 'manage_options' );

            // 管理者は target_user_id 指定可能、一般ユーザーは自分のみ
            $target_user_id = $is_admin ? absint( $request->get_param( 'user_id' ) ) : $current_user_id;
            if ( ! $target_user_id ) {
                $target_user_id = $current_user_id;
            }

            // 週1回制限（管理者は免除）
            $cooldown_key = "gcrev_aio_serp_last_fetch_{$target_user_id}";
            if ( ! $is_admin ) {
                $last_fetch = get_transient( $cooldown_key );
                if ( $last_fetch ) {
                    $next_ts = (int) $last_fetch + ( 7 * DAY_IN_SECONDS );
                    return new \WP_REST_Response( [
                        'success' => false,
                        'message' => '次回取得可能日時: ' . wp_date( 'Y/m/d H:i', $next_ts ),
                    ], 429 );
                }
            }

            // バックグラウンドで SERP 取得 + ページ分析を実行
            // 即座にレスポンスを返し、ステータスポーリングで完了を待つ
            update_user_meta( $target_user_id, 'gcrev_aio_fetch_status', 'fetching' );

            // クールダウン設定（7日間）— 先にセットして二重実行を防止
            set_transient( $cooldown_key, time(), 7 * DAY_IN_SECONDS );

            // 5秒後にバックグラウンドジョブを開始
            wp_schedule_single_event( time() + 5, 'gcrev_aio_serp_bg_fetch_event', [ $target_user_id ] );

            return new \WP_REST_Response( [
                'success' => true,
                'data'    => [ 'status' => 'fetching', 'message' => 'バックグラウンドでデータ取得を開始しました' ],
            ], 200 );
        } catch ( \Exception $e ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => $e->getMessage() ], 500 );
        }
    }

    /**
     * POST /aio-serp/settings — 設定保存（管理者のみ）
     */
    public function rest_save_aio_serp_settings( \WP_REST_Request $request ): \WP_REST_Response {
        try {
            $user_id = get_current_user_id();
            if ( ! $user_id ) {
                return new \WP_REST_Response( [ 'success' => false, 'message' => '未ログイン' ], 401 );
            }

            $self_domains = sanitize_textarea_field( $request->get_param( 'self_domains' ) ?? '' );
            $region       = sanitize_text_field( $request->get_param( 'region' ) ?? 'jp' );
            $language     = sanitize_text_field( $request->get_param( 'language' ) ?? 'ja' );
            $device       = sanitize_text_field( $request->get_param( 'device' ) ?? 'desktop' );

            // 対象ユーザー（管理者は他ユーザーの設定も変更可能）
            $target_user = absint( $request->get_param( 'target_user_id' ) ) ?: $user_id;

            update_user_meta( $target_user, 'gcrev_aio_self_domains', $self_domains );
            update_user_meta( $target_user, 'gcrev_aio_serp_region', $region );
            update_user_meta( $target_user, 'gcrev_aio_serp_language', $language );
            update_user_meta( $target_user, 'gcrev_aio_serp_device', $device );

            return new \WP_REST_Response( [ 'success' => true, 'message' => '設定を保存しました' ], 200 );
        } catch ( \Exception $e ) {
            return new \WP_REST_Response( [ 'success' => false, 'message' => $e->getMessage() ], 500 );
        }
    }

