    // =========================================================
    // QA Prompt Registry REST コールバック（Phase 3）
    //
    // 前提:
    //   - Mimamori_QA_Prompt_Registry / Mimamori_QA_Intent_Resolver は
    //     functions.php 経由で既にロード済み
    //   - Mimamori_QA_Run_Comparator はここで lazy-load する
    // =========================================================

    /**
     * Comparator など QA 系クラスを必要時に読み込む。
     */
    private function qa_registry_ensure_classes(): void {
        if ( ! class_exists( 'Mimamori_QA_Run_Comparator' ) ) {
            $path = get_template_directory() . '/inc/gcrev-api/utils/class-qa-run-comparator.php';
            if ( file_exists( $path ) ) {
                require_once $path;
            }
        }
    }

    /**
     * run_id / case_id の形式を検証。
     */
    private function qa_registry_validate_run_id( string $run_id ): bool {
        return (bool) preg_match( '/^[0-9]{8}_[0-9]{6}$/', $run_id );
    }

    private function qa_registry_validate_case_id( string $case_id ): bool {
        return (bool) preg_match( '/^[a-z0-9_]+$/i', $case_id );
    }

    private function qa_registry_error( string $code, string $message, int $status ): \WP_Error {
        return new \WP_Error( $code, $message, [ 'status' => $status ] );
    }

    /**
     * GET /qa-registry
     */
    public function rest_qa_registry_get( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $reg = \Mimamori_QA_Prompt_Registry::get_registry();
        return new \WP_REST_Response( [
            'success'  => true,
            'registry' => $reg,
        ], 200 );
    }

    /**
     * GET /qa-registry/history?limit=10
     */
    public function rest_qa_registry_history( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $limit = max( 1, min( 50, absint( $req->get_param( 'limit' ) ?: 10 ) ) );
        return new \WP_REST_Response( [
            'success' => true,
            'history' => \Mimamori_QA_Prompt_Registry::get_history( $limit ),
        ], 200 );
    }

    /**
     * POST /qa-registry/promote
     * { run_id, case_id, revision_no, intent, edited_addendum? }
     *
     * improvements/<case_id>.json を読み、指定 revision_no を active に昇格する。
     */
    public function rest_qa_registry_promote( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }

        $params = $req->get_json_params();
        if ( ! is_array( $params ) ) {
            $params = $req->get_params();
        }

        $run_id      = sanitize_text_field( (string) ( $params['run_id'] ?? '' ) );
        $case_id     = sanitize_text_field( (string) ( $params['case_id'] ?? '' ) );
        $revision_no = absint( $params['revision_no'] ?? 0 );
        $intent_raw  = sanitize_text_field( (string) ( $params['intent'] ?? '' ) );
        $edited      = isset( $params['edited_addendum'] )
            ? sanitize_textarea_field( (string) $params['edited_addendum'] )
            : null;

        if ( ! $this->qa_registry_validate_run_id( $run_id ) ) {
            return $this->qa_registry_error( 'invalid_run_id', 'invalid run_id', 400 );
        }
        if ( ! $this->qa_registry_validate_case_id( $case_id ) ) {
            return $this->qa_registry_error( 'invalid_case_id', 'invalid case_id', 400 );
        }
        if ( $intent_raw === '' || $intent_raw === \Mimamori_QA_Prompt_Registry::GLOBAL_KEY ) {
            return $this->qa_registry_error( 'invalid_intent', '_global cannot be manually promoted', 400 );
        }

        $intent = class_exists( 'Mimamori_QA_Intent_Resolver' )
            ? \Mimamori_QA_Intent_Resolver::coerce( $intent_raw )
            : $intent_raw;

        // improvements/<case_id>.json を読む
        $upload      = wp_upload_dir();
        $improve_dir = trailingslashit( $upload['basedir'] ) . 'mimamori/qa_runs/' . $run_id . '/improvements';
        $json_path   = $improve_dir . '/' . sanitize_file_name( $case_id ) . '.json';

        if ( ! file_exists( $json_path ) ) {
            return $this->qa_registry_error( 'revision_not_found', 'revision JSON not found', 404 );
        }
        // phpcs:ignore WordPress.WP.AlternativeFunctions.file_get_contents_file_get_contents
        $raw = @file_get_contents( $json_path );
        $data = $raw === false ? null : json_decode( $raw, true );
        if ( ! is_array( $data ) || ! is_array( $data['revisions'] ?? null ) ) {
            return $this->qa_registry_error( 'revision_parse_error', 'cannot parse revision json', 500 );
        }

        // revision_no に対応する revision を抽出
        $target = null;
        foreach ( $data['revisions'] as $rev ) {
            if ( (int) ( $rev['revision_no'] ?? -1 ) === $revision_no ) {
                $target = $rev;
                break;
            }
        }
        if ( ! is_array( $target ) ) {
            return $this->qa_registry_error( 'revision_index_miss', 'revision_no not found in file', 404 );
        }

        // score_before/after を差し込む（registry::promote が score_impact に使う）
        $target['score_before'] = (int) ( $data['initial_score'] ?? ( $data['revisions'][0]['score_total'] ?? 0 ) );
        $target['score_after']  = (int) ( $target['score_total'] ?? 0 );

        try {
            $new_version = \Mimamori_QA_Prompt_Registry::promote(
                $intent,
                $target,
                [
                    'run_id'      => $run_id,
                    'case_id'     => $case_id,
                    'revision_no' => $revision_no,
                ],
                (int) get_current_user_id(),
                $edited
            );
        } catch ( \Throwable $e ) {
            return $this->qa_registry_error( 'promote_error', $e->getMessage(), 400 );
        }

        return new \WP_REST_Response( [
            'success'        => true,
            'new_version'    => $new_version,
            'intent'         => $intent,
        ], 200 );
    }

    /**
     * POST /qa-registry/rollback
     * { version }
     */
    public function rest_qa_registry_rollback( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $params = $req->get_json_params();
        if ( ! is_array( $params ) ) {
            $params = $req->get_params();
        }
        $version = sanitize_text_field( (string) ( $params['version'] ?? '' ) );
        if ( ! preg_match( '/^v\d{8}-[a-z]/', $version ) ) {
            return $this->qa_registry_error( 'invalid_version', 'invalid version format', 400 );
        }
        $ok = \Mimamori_QA_Prompt_Registry::rollback_to( $version, (int) get_current_user_id() );
        if ( ! $ok ) {
            return $this->qa_registry_error( 'rollback_failed', 'version not found in history', 404 );
        }
        return new \WP_REST_Response( [ 'success' => true, 'active_version' => $version ], 200 );
    }

    /**
     * POST /qa-registry/reject
     * { run_id, case_id, revision_no, reason }
     */
    public function rest_qa_registry_reject( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $params = $req->get_json_params();
        if ( ! is_array( $params ) ) {
            $params = $req->get_params();
        }
        $run_id      = sanitize_text_field( (string) ( $params['run_id'] ?? '' ) );
        $case_id     = sanitize_text_field( (string) ( $params['case_id'] ?? '' ) );
        $revision_no = absint( $params['revision_no'] ?? 0 );
        $reason      = sanitize_text_field( (string) ( $params['reason'] ?? '' ) );

        if ( ! $this->qa_registry_validate_run_id( $run_id ) ) {
            return $this->qa_registry_error( 'invalid_run_id', 'invalid run_id', 400 );
        }
        if ( ! $this->qa_registry_validate_case_id( $case_id ) ) {
            return $this->qa_registry_error( 'invalid_case_id', 'invalid case_id', 400 );
        }
        \Mimamori_QA_Prompt_Registry::reject( $run_id, $case_id, $revision_no, (int) get_current_user_id(), $reason );
        return new \WP_REST_Response( [ 'success' => true ], 200 );
    }

    /**
     * GET /qa-registry/runs?limit=14
     *
     * 直近 N 回の run の meta.json を新しい順で返す。
     */
    public function rest_qa_registry_runs( \WP_REST_Request $req ) {
        $limit  = max( 1, min( 60, absint( $req->get_param( 'limit' ) ?: 14 ) ) );
        $upload = wp_upload_dir();
        $base   = trailingslashit( $upload['basedir'] ) . 'mimamori/qa_runs';
        if ( ! is_dir( $base ) ) {
            return new \WP_REST_Response( [ 'success' => true, 'runs' => [] ], 200 );
        }
        $dirs = glob( $base . '/*', GLOB_ONLYDIR );
        if ( ! is_array( $dirs ) ) {
            return new \WP_REST_Response( [ 'success' => true, 'runs' => [] ], 200 );
        }
        $ids = [];
        foreach ( $dirs as $d ) {
            $id = basename( $d );
            if ( preg_match( '/^\d{8}_\d{6}$/', $id ) ) {
                $ids[] = $id;
            }
        }
        rsort( $ids );
        $ids = array_slice( $ids, 0, $limit );

        $runs = [];
        foreach ( $ids as $id ) {
            $meta_path = $base . '/' . $id . '/meta.json';
            if ( ! file_exists( $meta_path ) ) {
                continue;
            }
            // phpcs:ignore WordPress.WP.AlternativeFunctions.file_get_contents_file_get_contents
            $raw  = @file_get_contents( $meta_path );
            $meta = $raw === false ? null : json_decode( $raw, true );
            if ( ! is_array( $meta ) ) {
                continue;
            }
            $runs[] = [
                'run_id'          => $id,
                'user_id'         => (int) ( $meta['user_id'] ?? 0 ),
                'n'               => (int) ( $meta['n'] ?? 0 ),
                'mode'            => (string) ( $meta['mode'] ?? '' ),
                'avg_score'       => (float) ( $meta['avg_score'] ?? 0 ),
                'success_count'   => (int) ( $meta['success_count'] ?? 0 ),
                'fail_count'      => (int) ( $meta['fail_count'] ?? 0 ),
                'started_at'      => (string) ( $meta['started_at'] ?? '' ),
                'ended_at'        => (string) ( $meta['ended_at'] ?? '' ),
                'prompt_version'  => (string) ( $meta['prompt_version'] ?? '' ),
                'intent_versions' => is_array( $meta['intent_versions'] ?? null ) ? $meta['intent_versions'] : [],
            ];
        }
        return new \WP_REST_Response( [ 'success' => true, 'runs' => $runs ], 200 );
    }

    /**
     * GET /qa-registry/compare?current=&previous=
     */
    public function rest_qa_registry_compare( \WP_REST_Request $req ) {
        $this->qa_registry_ensure_classes();
        if ( ! class_exists( 'Mimamori_QA_Run_Comparator' ) ) {
            return $this->qa_registry_error( 'comparator_missing', 'Comparator class not loaded', 500 );
        }
        $current  = sanitize_text_field( (string) ( $req->get_param( 'current' ) ?? '' ) );
        $previous = sanitize_text_field( (string) ( $req->get_param( 'previous' ) ?? '' ) );
        if ( ! $this->qa_registry_validate_run_id( $current ) ) {
            return $this->qa_registry_error( 'invalid_run_id', 'invalid current run_id', 400 );
        }

        $comparator = new \Mimamori_QA_Run_Comparator();

        if ( $previous === '' ) {
            $prev_detected = $comparator->find_previous_run( $current );
            $previous      = $prev_detected ?: '';
        }
        if ( ! $this->qa_registry_validate_run_id( $previous ) ) {
            return new \WP_REST_Response( [
                'success'  => true,
                'message'  => 'no previous run available',
                'current'  => $current,
                'previous' => null,
                'diff'     => null,
            ], 200 );
        }

        $diff = $comparator->compare( $current, $previous );
        return new \WP_REST_Response( [
            'success'  => true,
            'current'  => $current,
            'previous' => $previous,
            'diff'     => $diff,
        ], 200 );
    }

    // =========================================================
    // QA Prompt Registry Staged Rollout REST コールバック（Phase 4）
    // =========================================================

    /**
     * POST /qa-registry/stage
     * { intent, user_ids: [int...] }
     */
    public function rest_qa_registry_stage( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $params = $req->get_json_params();
        if ( ! is_array( $params ) ) { $params = $req->get_params(); }

        $intent    = sanitize_text_field( (string) ( $params['intent'] ?? '' ) );
        $user_ids  = is_array( $params['user_ids'] ?? null ) ? $params['user_ids'] : [];

        if ( $intent === '' || $intent === \Mimamori_QA_Prompt_Registry::GLOBAL_KEY ) {
            return $this->qa_registry_error( 'invalid_intent', 'invalid intent', 400 );
        }
        if ( empty( $user_ids ) ) {
            return $this->qa_registry_error( 'empty_users', 'user_ids must not be empty', 400 );
        }

        try {
            \Mimamori_QA_Prompt_Registry::stage( $intent, $user_ids, (int) get_current_user_id() );
        } catch ( \Throwable $e ) {
            return $this->qa_registry_error( 'stage_error', $e->getMessage(), 400 );
        }

        $active = \Mimamori_QA_Prompt_Registry::get_active_intent( $intent, 0 );
        return new \WP_REST_Response( [
            'success' => true,
            'intent'  => $intent,
            'stage'   => $active['intent']['stage'] ?? null,
        ], 200 );
    }

    /**
     * POST /qa-registry/unstage
     * { intent }
     */
    public function rest_qa_registry_unstage( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $params = $req->get_json_params();
        if ( ! is_array( $params ) ) { $params = $req->get_params(); }

        $intent = sanitize_text_field( (string) ( $params['intent'] ?? '' ) );
        if ( $intent === '' || $intent === \Mimamori_QA_Prompt_Registry::GLOBAL_KEY ) {
            return $this->qa_registry_error( 'invalid_intent', 'invalid intent', 400 );
        }

        try {
            \Mimamori_QA_Prompt_Registry::unstage( $intent, (int) get_current_user_id() );
        } catch ( \Throwable $e ) {
            return $this->qa_registry_error( 'unstage_error', $e->getMessage(), 400 );
        }

        return new \WP_REST_Response( [
            'success' => true,
            'intent'  => $intent,
            'stage'   => [ 'mode' => 'full', 'user_ids' => [] ],
        ], 200 );
    }

    /**
     * GET /qa-registry/canary
     */
    public function rest_qa_registry_canary_get( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        return new \WP_REST_Response( [
            'success'  => true,
            'user_ids' => \Mimamori_QA_Prompt_Registry::get_canary_users(),
        ], 200 );
    }

    /**
     * POST /qa-registry/canary
     * { user_ids: [int...] }
     *
     * 空配列なら canary 解除。
     */
    public function rest_qa_registry_canary_set( \WP_REST_Request $req ) {
        if ( ! class_exists( 'Mimamori_QA_Prompt_Registry' ) ) {
            return $this->qa_registry_error( 'qa_registry_missing', 'QA registry class not loaded', 500 );
        }
        $params = $req->get_json_params();
        if ( ! is_array( $params ) ) { $params = $req->get_params(); }

        $user_ids = is_array( $params['user_ids'] ?? null ) ? $params['user_ids'] : [];
        \Mimamori_QA_Prompt_Registry::set_canary_users( $user_ids );

        return new \WP_REST_Response( [
            'success'  => true,
            'user_ids' => \Mimamori_QA_Prompt_Registry::get_canary_users(),
        ], 200 );
    }

    // =========================================================
    // 戦略（Strategy）API コールバック — 戦略連動型 月次レポート PR2
    // =========================================================

    /** Strategy_Repository の遅延インスタンス化（毎回 new ではなく一度だけ） */
    private ?Gcrev_Strategy_Repository $strategy_repo = null;

    private function strategy_repo(): Gcrev_Strategy_Repository {
        if ( $this->strategy_repo === null ) {
            $this->strategy_repo = new Gcrev_Strategy_Repository();
        }
        return $this->strategy_repo;
    }

    /**
     * REST ハンドラ用: ログイン中ユーザーIDを取得（無ければ 401）
     */
    private function strategy_current_user_id(): int {
        $uid = get_current_user_id();
        if ( $uid <= 0 ) {
            return 0;
        }
        return (int) $uid;
    }

    private function strategy_json_response( $data, int $status = 200 ): WP_REST_Response {
        $resp = new WP_REST_Response( $data, $status );
        return $resp;
    }

    /** GET /strategy — 自分の現在 active な戦略 */
    public function rest_strategy_get_active( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $row = $this->strategy_repo()->get_active( $uid );
        return $this->strategy_json_response( [
            'success'  => true,
            'strategy' => $row,  // null 可（未設定状態）
        ] );
    }

    /** GET /strategy/active-for-month?year_month=YYYY-MM */
    public function rest_strategy_get_active_for_month( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $year_month = (string) $req->get_param( 'year_month' );
        if ( ! preg_match( '/^\d{4}-\d{2}$/', $year_month ) ) {
            return $this->strategy_json_response( [ 'error' => 'invalid year_month' ], 400 );
        }
        $row = $this->strategy_repo()->get_active_for_month( $uid, $year_month );
        return $this->strategy_json_response( [
            'success'  => true,
            'strategy' => $row,
        ] );
    }

    /** GET /strategy/versions — バージョン履歴 */
    public function rest_strategy_get_versions( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $rows = $this->strategy_repo()->get_versions( $uid, 50 );
        return $this->strategy_json_response( [
            'success'  => true,
            'versions' => $rows,
        ] );
    }

    /** GET /strategy/draft/latest — 編集中の draft 復元 */
    public function rest_strategy_get_latest_draft( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $row = $this->strategy_repo()->get_latest_draft( $uid );
        return $this->strategy_json_response( [
            'success' => true,
            'draft'   => $row,
        ] );
    }

    /**
     * POST /strategy/draft — 新規 draft 作成
     * Body: { strategy: { ... 戦略JSON ... } }
     */
    public function rest_strategy_create_draft( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $body = $req->get_json_params();
        if ( ! is_array( $body ) || ! is_array( $body['strategy'] ?? null ) ) {
            return $this->strategy_json_response( [ 'error' => 'strategy object is required' ], 400 );
        }

        $validation = Gcrev_Strategy_Schema_Validator::validate( $body['strategy'] );
        // draft の場合は必須エラーがあっても保存を許可（編集中状態を保持）
        $normalized = $validation['normalized'];

        try {
            $id = $this->strategy_repo()->create_version(
                $uid,
                $normalized,
                'draft',
                'manual',
                $uid,
                null
            );
        } catch ( \Throwable $e ) {
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " create_draft failed user={$uid}: " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return $this->strategy_json_response( [ 'error' => 'failed to save draft' ], 500 );
        }

        return $this->strategy_json_response( [
            'success'     => true,
            'strategy_id' => $id,
            'warnings'    => $validation['errors'], // 必須未充足は警告として返す
            'normalized'  => $normalized,
        ], 201 );
    }

    /**
     * PUT /strategy/draft/{id} — draft を上書き保存
     */
    public function rest_strategy_update_draft( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $id = (int) $req->get_param( 'id' );
        if ( $id <= 0 ) {
            return $this->strategy_json_response( [ 'error' => 'invalid id' ], 400 );
        }

        $row = $this->strategy_repo()->get_by_id( $id );
        if ( ! $row || (int) $row['user_id'] !== $uid ) {
            return $this->strategy_json_response( [ 'error' => 'not found' ], 404 );
        }
        if ( $row['status'] !== 'draft' ) {
            return $this->strategy_json_response( [ 'error' => 'only draft can be updated' ], 409 );
        }

        $body = $req->get_json_params();
        if ( ! is_array( $body ) || ! is_array( $body['strategy'] ?? null ) ) {
            return $this->strategy_json_response( [ 'error' => 'strategy object is required' ], 400 );
        }
        $validation = Gcrev_Strategy_Schema_Validator::validate( $body['strategy'] );
        $ok = $this->strategy_repo()->update_draft( $id, $validation['normalized'] );

        if ( ! $ok ) {
            return $this->strategy_json_response( [ 'error' => 'update failed' ], 500 );
        }
        return $this->strategy_json_response( [
            'success'    => true,
            'warnings'   => $validation['errors'],
            'normalized' => $validation['normalized'],
        ] );
    }

    /**
     * DELETE /strategy/draft/{id} — draft 削除
     */
    public function rest_strategy_delete_draft( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $id = (int) $req->get_param( 'id' );
        if ( $id <= 0 ) {
            return $this->strategy_json_response( [ 'error' => 'invalid id' ], 400 );
        }
        $row = $this->strategy_repo()->get_by_id( $id );
        if ( ! $row || (int) $row['user_id'] !== $uid ) {
            return $this->strategy_json_response( [ 'error' => 'not found' ], 404 );
        }
        if ( $row['status'] !== 'draft' ) {
            return $this->strategy_json_response( [ 'error' => 'only draft can be deleted' ], 409 );
        }
        $ok = $this->strategy_repo()->delete_draft( $id );
        return $this->strategy_json_response( [ 'success' => (bool) $ok ] );
    }

    /**
     * POST /strategy/draft/{id}/activate — draft を active に昇格
     * 必須項目が揃っていない場合は 422 で errors を返す
     */
    public function rest_strategy_activate_draft( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $id = (int) $req->get_param( 'id' );
        if ( $id <= 0 ) {
            return $this->strategy_json_response( [ 'error' => 'invalid id' ], 400 );
        }
        $row = $this->strategy_repo()->get_by_id( $id );
        if ( ! $row || (int) $row['user_id'] !== $uid ) {
            return $this->strategy_json_response( [ 'error' => 'not found' ], 404 );
        }
        if ( $row['status'] !== 'draft' ) {
            return $this->strategy_json_response( [ 'error' => 'only draft can be activated' ], 409 );
        }

        // active 化前に必須項目を厳格チェック
        $validation = Gcrev_Strategy_Schema_Validator::validate( $row['strategy_json'] );
        if ( ! $validation['valid'] ) {
            return $this->strategy_json_response( [
                'error'   => 'validation failed',
                'errors'  => $validation['errors'],
            ], 422 );
        }

        $ok = $this->strategy_repo()->activate_draft( $id );
        if ( ! $ok ) {
            return $this->strategy_json_response( [ 'error' => 'activate failed' ], 500 );
        }
        $active = $this->strategy_repo()->get_active( $uid );
        return $this->strategy_json_response( [
            'success'  => true,
            'strategy' => $active,
        ] );
    }

    /**
     * POST /strategy/extract-pdf — PDF アップロード → AI 抽出 → draft 作成
     * Form: multipart/form-data with field "file" (PDF)
     */
    public function rest_strategy_extract_pdf( WP_REST_Request $req ): WP_REST_Response {
        // 入口ログ（認可チェックより前に記録 — リクエストが PHP に到達した事実を残す）
        file_put_contents(
            '/tmp/gcrev_strategy_debug.log',
            date( 'Y-m-d H:i:s' ) . " extract_pdf: ENTERED rest_strategy_extract_pdf (raw user_id=" . get_current_user_id() . ")\n",
            FILE_APPEND
        );

        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " extract_pdf: REJECTED unauthorized (user_id=0)\n",
                FILE_APPEND
            );
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }

        $log_pfx = "extract_pdf user={$uid}";
        file_put_contents(
            '/tmp/gcrev_strategy_debug.log',
            date( 'Y-m-d H:i:s' ) . " {$log_pfx}: REST_start\n",
            FILE_APPEND
        );

        // 同時アップロード防止ロック（3分）。force=1 で強制解除（前回ハング後の復旧用）
        $lock_key = 'gcrev_lock_strategy_pdf_' . $uid;
        $force = (string) ( $req->get_param( 'force' ) ?? '' ) === '1';
        if ( $force ) {
            delete_transient( $lock_key );
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " {$log_pfx}: lock force-cleared by client\n",
                FILE_APPEND
            );
        }
        if ( get_transient( $lock_key ) ) {
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " {$log_pfx}: REJECTED (lock present — 前回処理が残っている可能性)\n",
                FILE_APPEND
            );
            return $this->strategy_json_response( [
                'error' => 'another extraction is in progress（前回処理が残っています。3分以内なら待つか、force=1 で強制解除してください）',
                'lock'  => true,
            ], 429 );
        }
        set_transient( $lock_key, 1, 3 * MINUTE_IN_SECONDS );

        try {
            $files = $req->get_file_params();
            if ( empty( $files['file'] ) || ! is_array( $files['file'] ) ) {
                return $this->strategy_json_response( [ 'error' => 'file is required' ], 400 );
            }
            $file = $files['file'];

            // MIME とサイズ検証
            $allowed_mime = [ 'application/pdf' ];
            $type = $file['type'] ?? '';
            if ( ! in_array( $type, $allowed_mime, true ) ) {
                // ブラウザによっては type 空のことあり。拡張子でも判定
                $name = (string) ( $file['name'] ?? '' );
                if ( strtolower( pathinfo( $name, PATHINFO_EXTENSION ) ) !== 'pdf' ) {
                    return $this->strategy_json_response( [ 'error' => 'PDFファイルのみアップロード可能です' ], 400 );
                }
            }
            if ( (int) ( $file['size'] ?? 0 ) > Gcrev_Strategy_Pdf_Extractor::MAX_FILE_SIZE ) {
                return $this->strategy_json_response( [ 'error' => 'ファイルサイズが上限を超えています（最大20MB）' ], 413 );
            }
            if ( (int) ( $file['error'] ?? UPLOAD_ERR_NO_FILE ) !== UPLOAD_ERR_OK ) {
                return $this->strategy_json_response( [ 'error' => 'アップロードに失敗しました（' . (int) $file['error'] . '）' ], 400 );
            }

            // wp_handle_upload を使うために必要なファイル群を読み込む
            if ( ! function_exists( 'wp_handle_upload' ) ) {
                require_once ABSPATH . 'wp-admin/includes/file.php';
            }
            if ( ! function_exists( 'wp_insert_attachment' ) ) {
                require_once ABSPATH . 'wp-admin/includes/image.php';
                require_once ABSPATH . 'wp-admin/includes/media.php';
            }

            $overrides = [
                'test_form' => false,
                'mimes'     => [ 'pdf' => 'application/pdf' ],
            ];
            $uploaded = wp_handle_upload( $file, $overrides );
            if ( isset( $uploaded['error'] ) ) {
                return $this->strategy_json_response( [ 'error' => 'アップロード失敗: ' . $uploaded['error'] ], 400 );
            }

            // attachment 作成（プライベート: post_status=private）
            $attachment_id = wp_insert_attachment( [
                'post_mime_type' => $uploaded['type'],
                'post_title'     => sanitize_file_name( $file['name'] ?? 'strategy.pdf' ),
                'post_content'   => '',
                'post_status'    => 'private',
                'post_author'    => $uid,
            ], $uploaded['file'] );

            if ( is_wp_error( $attachment_id ) || ! $attachment_id ) {
                return $this->strategy_json_response( [ 'error' => 'attachment 作成に失敗しました' ], 500 );
            }
            wp_update_attachment_metadata( $attachment_id, wp_generate_attachment_metadata( $attachment_id, $uploaded['file'] ) );

            // PDF 抽出（functions.php で早期ロード済みのはずだが、念のため再 require）
            if ( ! class_exists( 'Gcrev_Strategy_Pdf_Extractor' ) ) {
                $pdf_class_path = __DIR__ . '/gcrev-api/modules/class-strategy-pdf-extractor.php';
                file_put_contents(
                    '/tmp/gcrev_strategy_debug.log',
                    date( 'Y-m-d H:i:s' ) . " {$log_pfx}: loading PdfExtractor from {$pdf_class_path} (exists=" . ( file_exists( $pdf_class_path ) ? '1' : '0' ) . ")\n",
                    FILE_APPEND
                );
                if ( file_exists( $pdf_class_path ) ) {
                    require_once $pdf_class_path;
                }
            }
            if ( ! class_exists( 'Gcrev_Strategy_Pdf_Extractor' ) ) {
                throw new \Exception( 'Gcrev_Strategy_Pdf_Extractor クラスがロードできません。デプロイが正しく反映されているか確認してください。' );
            }
            $extractor = new Gcrev_Strategy_Pdf_Extractor( $this->ai );
            $result    = $extractor->extract_from_attachment( (int) $attachment_id );

            // draft として保存（必須項目が揃っていなくても draft なので保存OK）
            $draft_id = $this->strategy_repo()->create_version(
                $uid,
                $result['normalized'],
                'draft',
                'pdf',
                $uid,
                (int) $attachment_id
            );

            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " {$log_pfx}: REST_ok draft_id={$draft_id}\n",
                FILE_APPEND
            );
            return $this->strategy_json_response( [
                'success'        => true,
                'strategy_id'    => $draft_id,
                'attachment_id'  => (int) $attachment_id,
                'warnings'       => $result['errors'],
                'normalized'     => $result['normalized'],
            ], 201 );
        } catch ( \Throwable $e ) {
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " {$log_pfx}: REST_FAILED " . $e->getMessage() . "\n",
                FILE_APPEND
            );
            return $this->strategy_json_response( [ 'error' => $e->getMessage() ], 500 );
        } finally {
            delete_transient( $lock_key );
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " {$log_pfx}: REST_end (lock cleared)\n",
                FILE_APPEND
            );
        }
    }

    // =========================================================
    // 戦略レポート（Strategy Report）API コールバック — PR5
    // =========================================================

    private ?Gcrev_Strategy_Report_Repository $strategy_report_repo = null;

    private function strategy_report_repo(): Gcrev_Strategy_Report_Repository {
        if ( $this->strategy_report_repo === null ) {
            $this->strategy_report_repo = new Gcrev_Strategy_Report_Repository();
        }
        return $this->strategy_report_repo;
    }

    /** 公開向けに行を整形（HTMLは含めず軽量にする） */
    private function strategy_report_serialize( ?array $row, bool $include_html = false ): ?array {
        if ( ! $row ) return null;
        $out = [
            'id'                => (int) $row['id'],
            'user_id'           => (int) $row['user_id'],
            'year_month'        => (string) $row['year_month'],
            'strategy_id'       => (int) $row['strategy_id'],
            'status'            => (string) $row['status'],
            'alignment_score'   => $row['alignment_score'] ?? null,
            'ai_model'          => $row['ai_model'] ?? null,
            'generation_source' => (string) ( $row['generation_source'] ?? '' ),
            'attempts'          => (int) ( $row['attempts'] ?? 0 ),
            'started_at'        => $row['started_at']  ?? null,
            'finished_at'       => $row['finished_at'] ?? null,
            'created_at'        => $row['created_at']  ?? null,
            'error_message'     => $row['error_message'] ?? null,
            'sections'          => is_array( $row['report_json'] ?? null ) ? ( $row['report_json']['sections'] ?? null ) : null,
        ];
        if ( $include_html ) {
            $out['rendered_html'] = (string) ( $row['rendered_html'] ?? '' );
        }
        return $out;
    }

    /** GET /strategy-report/current — 自分の最新 completed レポート */
    public function rest_strategy_report_current( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $row = $this->strategy_report_repo()->get_latest_completed( $uid );
        return $this->strategy_json_response( [
            'success' => true,
            'report'  => $this->strategy_report_serialize( $row, true ),
        ] );
    }

    /** GET /strategy-report/status?year_month=YYYY-MM — 進捗確認用 */
    public function rest_strategy_report_status( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $year_month = (string) $req->get_param( 'year_month' );
        $row = $this->strategy_report_repo()->get_by_user_month( $uid, $year_month );
        return $this->strategy_json_response( [
            'success' => true,
            'report'  => $this->strategy_report_serialize( $row, true ),
        ] );
    }

    /** GET /strategy-report/history — バージョン履歴（軽量） */
    public function rest_strategy_report_history( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $limit = max( 1, min( 60, (int) ( $req->get_param( 'limit' ) ?: 24 ) ) );
        $rows = $this->strategy_report_repo()->get_history( $uid, $limit );
        return $this->strategy_json_response( [
            'success' => true,
            'reports' => $rows,
        ] );
    }

    /** GET /strategy-report/{id} — 本人のレポートのみ */
    public function rest_strategy_report_get_by_id( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }
        $id = (int) $req->get_param( 'id' );
        if ( $id <= 0 ) {
            return $this->strategy_json_response( [ 'error' => 'invalid id' ], 400 );
        }
        $row = $this->strategy_report_repo()->get_by_id( $id );
        if ( ! $row || (int) $row['user_id'] !== $uid ) {
            return $this->strategy_json_response( [ 'error' => 'not found' ], 404 );
        }
        return $this->strategy_json_response( [
            'success' => true,
            'report'  => $this->strategy_report_serialize( $row, true ),
        ] );
    }

    /**
     * POST /strategy-report/generate — 手動キュー投入
     * Body: { year_month?: 'YYYY-MM' }  省略時は前月
     * 同期処理ではなく wp_schedule_single_event でバックグラウンド実行
     */
    public function rest_strategy_report_generate( WP_REST_Request $req ): WP_REST_Response {
        $uid = $this->strategy_current_user_id();
        if ( $uid === 0 ) {
            return $this->strategy_json_response( [ 'error' => 'unauthorized' ], 401 );
        }

        $body = $req->get_json_params();
        $year_month = is_array( $body ) ? (string) ( $body['year_month'] ?? '' ) : '';
        if ( $year_month === '' ) {
            // デフォルト: 前月
            $year_month = ( new \DateTimeImmutable( 'first day of last month', wp_timezone() ) )->format( 'Y-m' );
        }
        if ( ! preg_match( '/^\d{4}-\d{2}$/', $year_month ) ) {
            return $this->strategy_json_response( [ 'error' => 'invalid year_month' ], 400 );
        }

        // レート制限: 同月3回まで（24h カウンタ）
        // 開発環境（MIMAMORI_ENV='development'）では検証のため制限スキップ
        $rate_key = 'gcrev_rl_strategy_report_' . $uid . '_' . $year_month;
        $is_dev = ( defined( 'MIMAMORI_ENV' ) && MIMAMORI_ENV === 'development' );
        if ( ! $is_dev ) {
            $count = (int) get_transient( $rate_key );
            if ( $count >= 3 ) {
                return $this->strategy_json_response( [
                    'error' => '同月の手動生成は3回までです（24時間でリセット）',
                ], 429 );
            }
        } else {
            $count = 0;
        }

        // 既に running なら 409
        $existing = $this->strategy_report_repo()->get_by_user_month( $uid, $year_month );
        if ( $existing && $existing['status'] === 'running' ) {
            return $this->strategy_json_response( [
                'error'  => 'すでに生成中です',
                'report' => $this->strategy_report_serialize( $existing ),
            ], 409 );
        }

        // 行を pending として upsert
        $report_id = $this->strategy_report_repo()->start_generation(
            $uid,
            $year_month,
            ( $existing && (int) $existing['strategy_id'] > 0 ) ? (int) $existing['strategy_id'] : 0,
            'manual_user'
        );

        // レート制限カウンタ +1（dev では加算しない）
        if ( ! $is_dev ) {
            set_transient( $rate_key, $count + 1, DAY_IN_SECONDS );
        }

        file_put_contents(
            '/tmp/gcrev_strategy_debug.log',
            date( 'Y-m-d H:i:s' ) . " rest_generate user={$uid} ym={$year_month} report_id={$report_id} sending_response_then_bg" . ( $is_dev ? ' (DEV: rate_limit_skipped)' : '' ) . "\n",
            FILE_APPEND
        );

        // 1) クライアントに 202 を直接送信
        nocache_headers();
        status_header( 202 );
        header( 'Content-Type: application/json; charset=utf-8' );
        echo wp_json_encode( [
            'success'    => true,
            'report_id'  => $report_id,
            'year_month' => $year_month,
            'status'     => 'pending',
            'message'    => 'バックグラウンドで生成を開始しました（30秒〜2分）。',
        ], JSON_UNESCAPED_UNICODE );

        // 2) FastCGI 接続を切る（PHP-FPM のみ。なければ flush）
        if ( function_exists( 'fastcgi_finish_request' ) ) {
            @fastcgi_finish_request();
        } else {
            @flush();
        }

        // 3) ここから先はクライアントから切り離されたバックグラウンド処理
        @ignore_user_abort( true );
        @set_time_limit( 300 );

        file_put_contents(
            '/tmp/gcrev_strategy_debug.log',
            date( 'Y-m-d H:i:s' ) . " bg_generate START user={$uid} ym={$year_month}\n",
            FILE_APPEND
        );

        try {
            if ( ! class_exists( 'Gcrev_Strategy_Report_Service' ) ) {
                require_once __DIR__ . '/gcrev-api/modules/class-strategy-report-service.php';
            }
            $service = new Gcrev_Strategy_Report_Service(
                $this->config, $this->ai, $this->ga4, $this->gsc
            );
            $result = $service->generate( $uid, $year_month, 'manual_user' );
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " bg_generate END user={$uid} ym={$year_month} result_status=" . ( $result['status'] ?? 'unknown' ) . "\n",
                FILE_APPEND
            );
        } catch ( \Throwable $e ) {
            file_put_contents(
                '/tmp/gcrev_strategy_debug.log',
                date( 'Y-m-d H:i:s' ) . " bg_generate FAILED user={$uid} ym={$year_month}: " . $e->getMessage() . "\n  trace_head=" . substr( $e->getTraceAsString(), 0, 500 ) . "\n",
                FILE_APPEND
            );
        }

        // WP REST に追加で何も処理させない
        exit;
    }

    } // class Gcrev_Insight_API の閉じ括弧

    new Gcrev_Insight_API();

    // =========================================================
    // CPT登録（classの外）
    // =========================================================
    add_action('init', function() {
        register_post_type('gcrev_report', [
            'labels' => [
                'name'          => '月次レポート',
                'singular_name' => '月次レポート',
            ],
            'public'              => false,
            'show_ui'             => false, // 管理画面に表示しない
            'has_archive'         => false,
            'rewrite'             => false,
            'supports'            => ['title'],
            'capability_type'     => 'post',
            'map_meta_cap'        => true,
        ]);
    });

